// Ensure Admin SDK initialized
try {
  if (!getApps().length) {
    initializeApp();
  }
} catch {
  logger.info("Admin already initialized for keyword suggestions function");
}
const db = getFirestore();

// Optimized HttpsOptions for keyword suggestions
const httpsOptions: HttpsOptions = {
  timeoutSeconds: 120,
  memory: "1GiB", // Increased from 512MiB for better performance
  minInstances: 0,
  maxInstances: 10,
  concurrency: 80,
  region: "australia-southeast2",
  // secrets: ["GOOGLE_AI_API_KEY", "GEMINI_API_KEY"], // Temporarily disabled for deployment
};

interface KeywordSuggestionsRequest {
  query: string;
  language?: string;
  count?: number;
  includeMetrics?: boolean;
  forceReal?: boolean;
  crawlUrls?: string[]; // optional seed URLs to crawl for context
}

interface KeywordSuggestion {
  keyword: string;
  searchVolume?: number;
  competition?: "low" | "medium" | "high";
  difficulty?: number;
  intent?: "informational" | "commercial" | "transactional" | "navigational";
  semanticCluster?: string;
  topicalRelevance?: number;
  opportunities?: string[];
}

interface KeywordSuggestionsResponse {
  suggestions: KeywordSuggestion[];
  relatedQueries?: string[];
  totalProcessingTime: number;
  cacheHit: boolean;
  plan?: string;
  quota?: { limit: number; used: number; remaining: number };
  rateLimited?: boolean;
  source?: "live" | "cache" | "fallback";
}

// Simple in-memory cache for function instances
const cache = new Map<string, { data: KeywordSuggestionsResponse; expiry: number; }>();
const CACHE_TTL = 60 * 60 * 1000; // 1 hour

/**
 * Enhanced keyword suggestions function with comprehensive error handling
 */
export const getKeywordSuggestionsEnhanced = onCall(httpsOptions, async (request) => {
  const startTime = Date.now();
  const userId = request.auth?.uid || "anonymous";

  try {
    // Authentication check
    if (!request.auth) {
      throw new HttpsError("unauthenticated", "Authentication required");
    }

    // Fetch user plan (default free)
    let plan = "free";
    try {
      const userDoc = await db.collection("users").doc(userId).get();
      plan = (userDoc.data()?.subscriptionTier || userDoc.data()?.role || "free").toLowerCase();
    } catch {
      logger.warn("Could not fetch user plan, defaulting to free", { userId });
    }

    // Quota limits per plan (-1 == unlimited)
    const quotaLimits: Record<string, number> = {
      free: 10,
      starter: 50,
      agency: 200,
      enterprise: 1000,
      admin: -1,
    };

    const quotaLimit = quotaLimits[plan] ?? 10;

    // Simple rate limiting (1 request / second) using rateLimits collection
    const rateLimitRef = db.collection("rateLimits").doc(userId);
    const rateDoc = await rateLimitRef.get();
    const now = Date.now();
    if (rateDoc.exists) {
      const last = rateDoc.data()?.lastRequest?.toMillis?.() || 0;
      if (now - last < 1000) {
        // Soft rate limit response
        throw new HttpsError("resource-exhausted", "Too many requests – slow down");
      }
    }

    // Daily usage count (start of UTC day)
    const startOfDay = new Date();
    startOfDay.setUTCHours(0, 0, 0, 0);
    let used = 0;
    try {
      const snapshot = await db
        .collection("keywordResearch")
        .where("userId", "==", userId)
        .where("createdAt", ">=", startOfDay)
        .select("userId")
        .get();
      used = snapshot.size;
    } catch {
      logger.warn("Failed to compute daily keyword usage", { userId });
    }

    if (quotaLimit !== -1 && used >= quotaLimit) {
      throw new HttpsError("resource-exhausted", "Daily keyword research limit reached");
    }

    // Input validation
    const data = request.data as KeywordSuggestionsRequest;
    if (!data?.query || typeof data.query !== "string") {
      throw new HttpsError("invalid-argument", "Query is required and must be a string");
    }

    if (data.query.length > 200) {
      throw new HttpsError("invalid-argument", "Query too long (max 200 characters)");
    }

    // Set defaults
    const query = data.query.trim();
    const language = data.language || "en";
    const count = Math.min(Math.max(data.count || 10, 1), 50);
    const includeMetrics = data.includeMetrics !== false;

    logger.info("Keyword suggestions request", {
      userId,
      query: query.substring(0, 50),
      language,
      count
    });

    // Check cache
    const cacheKey = `${query}-${language}-${count}`;
    const cached = cache.get(cacheKey);
    if (cached && Date.now() < cached.expiry) {
      logger.info("Cache hit for keyword suggestions", { userId, query: query.substring(0, 50) });
      // Update rate limit timestamp
      await rateLimitRef.set({ lastRequest: FieldValue.serverTimestamp() }, { merge: true });
      return { ...cached.data, cacheHit: true, source: "cache", plan, quota: { limit: quotaLimit, used, remaining: quotaLimit === -1 ? -1 : quotaLimit - used } };
    }

    // Build historical corpus sample (recent docs for this user + global)
    let corpusSummary = '';
    try {
      const recentSnap = await db.collection('keywordResearch').where('userId', '==', userId).orderBy('createdAt', 'desc').limit(5).get();
      const globalSnap = await db.collectionGroup('keywordResearch').orderBy('createdAt', 'desc').limit(25).get();
      const clusters: Record<string, number> = {}; let _total = 0;
      globalSnap.forEach(d => {
        const s = d.data() as Record<string, unknown>;
        const sugg = Array.isArray(s['suggestions']) ? (s['suggestions'] as unknown[]) : [];
        sugg.slice(0, 15).forEach(item => {
          if (item && typeof item === 'object' && 'semanticCluster' in item) {
            const c = String((item as Record<string, unknown>).semanticCluster || 'general');
            clusters[c] = (clusters[c] || 0) + 1;
            _total++;
          }
        });
      });
      const topClusters = Object.entries(clusters).sort((a, b) => b[1] - a[1]).slice(0, 8).map(([c, f]) => `${c}(${f})`).join(', ');
      corpusSummary = `GlobalClusters:${topClusters}`;
      if (!recentSnap.empty) {
        const recKw: string[] = [];
        recentSnap.forEach(d => {
          const s = d.data() as Record<string, unknown>;
          const suggArr = Array.isArray(s['suggestions']) ? (s['suggestions'] as unknown[]) : [];
          suggArr.slice(0, 5).forEach(item => {
            if (item && typeof item === 'object' && 'keyword' in item) {
              recKw.push(String((item as Record<string, unknown>).keyword));
            }
          });
        });
        corpusSummary += ` | UserRecent:${recKw.slice(0, 10).join(', ')}`;
      }
    } catch (e) {
      logger.warn('corpus_build_failed', { error: e instanceof Error ? e.message : String(e) });
    }

    // Optional Firecrawl context (first provided crawlUrls or simple search URL if pattern)
    let crawlContext = '';
    if (process.env.FIRECRAWL_API_KEY && (data.crawlUrls?.length || query.split(' ').length <= 4)) {
      try {
        const targetList = (data.crawlUrls && data.crawlUrls.length > 0) ? data.crawlUrls.slice(0, 3) : [`https://www.google.com/search?q=${encodeURIComponent(query)}`];
        for (const u of targetList) {
          const resp = await fetch('https://api.firecrawl.dev/v1/scrape', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${process.env.FIRECRAWL_API_KEY}` },
            body: JSON.stringify({ url: u, formats: ['markdown'], onlyMainContent: true, mobile: true })
          });
          if (resp.ok) {
            const j = await resp.json();
            const md = (j && typeof j === 'object' && 'markdown' in j) ? String((j as Record<string, unknown>).markdown) : '';
            if (md) crawlContext += `\nURL:${u}\n${md.slice(0, 800)}`;
          }
          if (crawlContext.length > 2400) break;
        }
      } catch (e) {
        logger.warn('firecrawl_keyword_context_failed', { error: e instanceof Error ? e.message : String(e) });
      }
    }

    const suggestions = await generateKeywords(query, language, count, includeMetrics, { forceReal: plan === "admin" || data.forceReal, corpusSummary, crawlContext });
    const relatedQueries = await generateRelatedQueries(query, language, { corpusSummary });

    const response: KeywordSuggestionsResponse = {
      suggestions,
      relatedQueries,
      totalProcessingTime: Date.now() - startTime,
      cacheHit: false,
      plan,
      quota: { limit: quotaLimit, used, remaining: quotaLimit === -1 ? -1 : quotaLimit - used - 1 },
      source: "live"
    };

    // Cache the result
    cache.set(cacheKey, {
      data: response,
      expiry: Date.now() + CACHE_TTL
    });

    // Cleanup old cache entries periodically
    cleanupCache();

    // Persist research document (trim suggestions if very large)
    try {
      await db.collection("keywordResearch").add({
        userId,
        query,
        language,
        countRequested: count,
        suggestions: suggestions.slice(0, 50),
        suggestionsCount: suggestions.length,
        relatedQueries: relatedQueries || [],
        plan,
        cacheHit: false,
        processingMs: response.totalProcessingTime,
        createdAt: FieldValue.serverTimestamp(),
      });
    } catch (persistError) {
      logger.warn("Failed to persist keyword research doc", {
        userId,
        error: persistError instanceof Error ? persistError.message : String(persistError),
      });
    }

    // Update rate limit timestamp
    await rateLimitRef.set({ lastRequest: FieldValue.serverTimestamp() }, { merge: true });

    logger.info("Keyword suggestions completed", {
      userId,
      plan,
      suggestionsCount: suggestions.length,
      duration: Date.now() - startTime,
      cacheHit: false,
    });

    return response;

  } catch (error) {
    logger.error("Keyword suggestions function failed", {
      userId,
      error: error instanceof Error ? error.message : String(error),
      stack: error instanceof Error ? error.stack : undefined,
      duration: Date.now() - startTime
    });

    if (error instanceof HttpsError) {
      throw error;
    }

    throw new HttpsError("internal", "An internal error occurred while generating keyword suggestions");
  }
});

async function generateKeywords(
  query: string,
  language: string,
  count: number,
  includeMetrics: boolean,
  context?: { forceReal?: boolean; corpusSummary?: string; crawlContext?: string }
): Promise<KeywordSuggestion[]> {
  try {
    const prompt = `ROLE: Senior SEO & Keyword Research Strategist.
TASK: Generate ${count} high-quality keyword suggestions for "${query}" (${language}).
CONTEXT_CORPUS: ${context?.corpusSummary || 'none'}
CRAWL_CONTEXT_SNIPPETS:${context?.crawlContext ? context.crawlContext.slice(0, 1500) : 'none'}
OUTPUT REQUIREMENTS:
1. Mix: 40% head, 60% long-tail.
2. Each keyword fields: keyword, searchVolume (integer realistic), competition (low|medium|high), difficulty (1-100), intent (informational|commercial|transactional|navigational), semanticCluster, topicalRelevance (0-100), opportunities (1-3 concise strings), rationale (short why included), serpFeatures (array subset of ['featured_snippet','people_also_ask','local_pack','videos','images']).
3. Avoid duplicates, ensure diversity across clusters.
4. Estimate volumes & difficulty realistically (no all identical numbers).
5. STRICT JSON ONLY: { "keywords": [ ... ] }`;

    const useReal = context?.forceReal || (process.env.USE_REAL_AI === "true");
    let rawOutput: any;
    if (useReal) {
      try {
        const ai = getGenkitAI();
        const gen = await ai.generate(prompt) as { text?: () => string } | string;
        rawOutput = typeof gen === 'string' ? gen : gen?.text?.();
      } catch (realErr) {
        logger.warn("Real AI generation failed, falling back to mock", { error: realErr instanceof Error ? realErr.message : String(realErr) });
      }
    }
    if (!rawOutput) {
      rawOutput = await getMockAI(prompt, undefined, { temperature: 0.7, maxOutputTokens: 1000 });
    }
    let parsedResult: any = {};
    try {
      parsedResult = JSON.parse(rawOutput);
    } catch {
      logger.warn("AI returned non-JSON content, using fallback generation", { snippet: rawOutput?.slice(0, 120) });
      return getFallbackKeywords(query, count);
    }
    const raw: KeywordSuggestion[] = Array.isArray(parsedResult.keywords) ? parsedResult.keywords : [];
    if (!raw.length) {
      logger.warn("AI returned empty keywords array, using fallback generation");
      return getFallbackKeywords(query, count);
    }
    const normalized = raw.map(k => ({
      ...k,
      difficulty: clampNumber(k.difficulty, 1, 100),
      topicalRelevance: clampNumber(k.topicalRelevance, 0, 100),
      semanticCluster: k.semanticCluster || deriveCluster(k.keyword),
      opportunities: Array.isArray(k.opportunities) ? k.opportunities.slice(0, 3) : [],
    }));
    return normalized;
  } catch (error) {
    logger.warn("AI keyword generation failed, using fallback", {
      error: error instanceof Error ? error.message : String(error),
      query: query.substring(0, 50)
    });
    return getFallbackKeywords(query, count);
  }
}

async function generateRelatedQueries(query: string, language: string, ctx?: { corpusSummary?: string }): Promise<string[]> {
  try {
    const prompt = `Generate 5 related search queries for "${query}" in ${language} considering corpus: ${ctx?.corpusSummary || 'none'}. Return JSON array of strings.`;
    let output: any;
    try {
      if (process.env.USE_REAL_AI === "true") {
        const ai = getGenkitAI();
        const gen = await ai.generate(prompt) as { text?: () => string } | string;
        output = typeof gen === 'string' ? gen : gen?.text?.();
      }
    } catch (e) {
      logger.warn("Real AI related queries failed, falling back to mock", { error: e instanceof Error ? e.message : String(e) });
    }
    if (!output) {
      output = await getMockAI(prompt, undefined, { temperature: 0.8, maxOutputTokens: 200 });
    }
    try {
      return JSON.parse(output);
    } catch {
      return [];
    }
  } catch (error) {
    logger.warn("Related queries generation failed", {
      error: error instanceof Error ? error.message : String(error),
      query: query.substring(0, 50)
    });
    return [];
  }
}

function getFallbackKeywords(query: string, count: number): KeywordSuggestion[] {
  const variations = [
    `${query} guide`,
    `${query} tips`,
    `best ${query}`,
    `${query} tutorial`,
    `how to ${query}`,
    `${query} examples`,
    `${query} benefits`,
    `${query} cost`,
    `${query} comparison`,
    `${query} review`,
    `${query} vs`,
    `${query} free`,
    `${query} online`,
    `${query} 2025`,
    `${query} strategy`
  ];

  return variations.slice(0, count).map((keyword, index) => ({
    keyword,
    searchVolume: Math.floor(Math.random() * 10000) + 100,
    competition: ["low", "medium", "high"][index % 3] as "low" | "medium" | "high",
    difficulty: Math.floor(Math.random() * 100) + 1,
    intent: ["informational", "commercial", "transactional", "navigational"][index % 4] as any,
    semanticCluster: deriveCluster(keyword),
    topicalRelevance: Math.floor(Math.random() * 100),
    opportunities: ["Improve CTR", "Capture long-tail"].slice(0, Math.floor(Math.random() * 2) + 1),
  }));
}

function cleanupCache() {
  const now = Date.now();
  for (const [key, value] of cache.entries()) {
    if (now >= value.expiry) {
      cache.delete(key);
    }
  }
}

// Utility helpers for normalization & lightweight semantic grouping
function clampNumber(val: unknown, min: number, max: number) {
  const n = typeof val === "number" && !isNaN(val) ? val : min;
  return Math.min(Math.max(n, min), max);
}

function deriveCluster(keyword: string): string {
  if (!keyword) return "general";
  const parts = keyword.toLowerCase().split(/\s+/).slice(0, 2).join(" ");
  return parts || "general";
}

import { onSchedule } from "firebase-functions/v2/scheduler";
import { logger } from "firebase-functions/v2";
import { getFirestore } from "firebase-admin/firestore";
import { getApps, initializeApp } from "firebase-admin/app";

const ACCEPTED_RETENTION_DAYS = Number(process.env.INVITES_ACCEPTED_RETENTION_DAYS || 30);
const EXPIRED_RETENTION_DAYS = Number(process.env.INVITES_EXPIRED_RETENTION_DAYS || 14);

function days(ms: number) { return ms / (1000 * 60 * 60 * 24); }

function toMillis(v: unknown): number | undefined {
  if (v == null) return undefined;
  if (typeof v === "number") return v;
  if (v instanceof Date) return v.getTime();
  if (typeof v === "object" && v !== null && "toDate" in v) {
    const maybeToDate = (v as { toDate?: unknown }).toDate;
    if (typeof maybeToDate === "function") return (v as { toDate: () => Date }).toDate().getTime();
  }
  return undefined;
}

export const cleanupInvites = onSchedule({
    schedule: "every 24 hours",
    timeZone: "Etc/UTC",
    region: "australia-southeast2"
}, async () => {
    if (!getApps().length) initializeApp();
    const db = getFirestore();
    const now = Date.now();
    let markedExpired = 0, deletedAccepted = 0, deletedExpired = 0, orphanIndexes = 0;
    try {
        const teams = await db.collection('teams').get();
        for (const t of teams.docs) {
            const invitesSnap = await db.collection('teams').doc(t.id).collection('invites').get();
            for (const inv of invitesSnap.docs) {
                const data = inv.data() as Record<string, unknown>;
                const expiresAt = toMillis(data['expiresAt']);
                if (String(data['status']) === 'pending' && expiresAt && expiresAt < now) {
                    await inv.ref.update({ status: 'expired', expiredAt: new Date() });
                    await db.collection('invites_index').doc(inv.id).set({ teamId: t.id, status: 'expired', updatedAt: new Date() }, { merge: true });
                    markedExpired++;
                }
                if (String(data['status']) === 'accepted') {
                    const acceptedAt = toMillis(data['acceptedAt']) || 0;
                    if (acceptedAt && days(now - acceptedAt) > ACCEPTED_RETENTION_DAYS) {
                        await inv.ref.delete();
                        await db.collection('invites_index').doc(inv.id).delete().catch(() => { });
                        deletedAccepted++;
                    }
                } else if (String(data['status']) === 'expired') {
                    const expiredAt = toMillis(data['expiredAt']) || (expiresAt || 0);
                    if (expiredAt && days(now - expiredAt) > EXPIRED_RETENTION_DAYS) {
                        await inv.ref.delete();
                        await db.collection('invites_index').doc(inv.id).delete().catch(() => { });
                        deletedExpired++;
                    }
                }
            }
        }
        // Orphan indexes
        const indexSnap = await db.collection('invites_index').get();
        for (const idx of indexSnap.docs) {
            const teamId = (idx.data() as any).teamId;
            if (!teamId) { orphanIndexes++; await idx.ref.delete().catch(() => { }); continue; }
            const invDoc = await db.collection('teams').doc(teamId).collection('invites').doc(idx.id).get();
            if (!invDoc.exists) { await idx.ref.delete().catch(() => { }); orphanIndexes++; }
        }
        logger.info("cleanupInvites summary", { markedExpired, deletedAccepted, deletedExpired, orphanIndexes });
    } catch (e) {
        logger.error('cleanupInvites error', e as any);
        throw e;
    }
});

import { onSchedule } from 'firebase-functions/v2/scheduler';
import { logger } from 'firebase-functions/v2';
import { getApps, initializeApp } from 'firebase-admin/app';
import { getFirestore, FieldValue } from 'firebase-admin/firestore';

/**
 * Daily KPI Snapshot Function (T16)
 * Purpose: Persist a compact daily KPI aggregate document (collection: kpiDaily)
 * focusing on AI usage & cost plus placeholders for future KPI expansion.
 * Retention: purge snapshots older than 90 days.
 * NOTE: We intentionally limit scope to readily available server-side data (aiUsageDaily)
 * since full KPI derivation utilities live in the Next.js app bundle and are not shared here.
 */

const RETENTION_DAYS = 90;

export interface KpiDailyDoc {
    date: string;              // YYYY-MM-DD
    aiTokensIn: number;        // summed across providers
    aiTokensOut: number;       // summed across providers
    aiCostEstimate: number;    // USD approximate
    revenueMrr?: number;       // Sum paid invoice amounts for current month
    revenueOutstanding?: number; // Count unpaid invoices current month
    revenueOnTimePct?: number;   // On-time % for paid invoices current month
    // Newly added Phase 2 (T16 extension): provenance coverage + latency percentiles (placeholders until export pipeline wired)
    provenanceCoveragePct?: number | null; // Placeholder: null (unavailable in isolated CF env) or numeric if future export populates
    p90LatencyOverall?: number | null;     // Average across routes (null until wired)
    p95LatencyOverall?: number | null;
    p99LatencyOverall?: number | null;
    // Adoption & rate limit utilization (T14/T15 enrichment)
    crawlerAggregateAdoptionPct?: number | null;
    semanticMapAggregateAdoptionPct?: number | null;
    teamRateLimitUtilizationPct?: number | null;
    fallbackRatePct?: number | null; // AI fallback rate (% of responses)
    cacheHitRatio?: number | null; // Cache hit percentage (edge/runtime aggregate)
    rateLimitRejectionRate?: number | null; // % of requests rejected by limiters
    // Server-side precomputed MA7 overlays (additive; enables client to skip recompute)
    ma7Provenance?: number | null;
    ma7CrawlerAdoption?: number | null;
    ma7SemanticAdoption?: number | null;
    ma7FallbackRate?: number | null;
    ma7LatencyP95?: number | null;
    ma7CacheHitRatio?: number | null;
    ma7RateLimitRejectionRate?: number | null;
    // Exponential smoothing (alpha=0.3) for provenance & latency p95 (faster response to trend than MA7)
    smoothedProvenance?: number | null;
    smoothedLatencyP95?: number | null;
    smoothedCrawlerAdoption?: number | null;
    smoothedSemanticAdoption?: number | null;
    createdAt: FirebaseFirestore.Timestamp | FirebaseFirestore.FieldValue | null;            // Firestore Timestamp
    updatedAt: FirebaseFirestore.Timestamp | FirebaseFirestore.FieldValue | null;            // Firestore Timestamp
    _schema: 1;                // simple schema version for future migrations
}

export async function runKpiDailySnapshot(now: Date = new Date()) {
    if (!getApps().length) initializeApp();
    const db = getFirestore();
    const dateKey = now.toISOString().slice(0, 10); // YYYY-MM-DD (UTC)

    // Aggregate today's AI usage (already persisted incrementally by ai-memory-manager)
    let aiTokensIn = 0, aiTokensOut = 0, aiCost = 0;
    try {
        const usageSnap = await db.collection('aiUsageDaily').where('date', '==', dateKey).get();
        usageSnap.docs.forEach(d => {
            const data = d.data() as Record<string, unknown>;
            aiTokensIn += (data.tokensIn as number) || 0;
            aiTokensOut += (data.tokensOut as number) || 0;
            aiCost += (data.costEstimate as number) || 0;
        });
    } catch (e) {
        logger.warn('kpiDailySnapshot.aiUsageQueryFailed', (e as any)?.message);
    }
    aiCost = +aiCost.toFixed(4);

    // Revenue aggregation (best-effort; failures logged & omitted)
    let revenueMrr = 0, revenueOutstanding = 0, revenueOnTimePct: number | undefined;
    try {
        const periodKey = dateKey.slice(0, 7); // YYYY-MM
        const revSnap = await db.collection('financeInvoices').where('period', '==', periodKey).limit(5000).get();
        if (!revSnap.empty) {
            const paid: Record<string, unknown>[] = []; const all: Record<string, unknown>[] = [];
            revSnap.docs.forEach(d => { const data = d.data() as Record<string, unknown>; all.push(data); if (data.status === 'paid') paid.push(data); });
            revenueMrr = paid.reduce((s, i) => s + ((i as any).amount || 0), 0);
            revenueOutstanding = all.filter(i => (i as any).status !== 'paid').length;
            if (paid.length) {
                const onTime = paid.filter(i => { const paidAt = (i as any).paidAt?.toDate?.(); const due = (i as any).dueAt?.toDate?.(); return paidAt && due && paidAt.getTime() <= due.getTime(); });
                revenueOnTimePct = +(onTime.length / paid.length * 100).toFixed(1);
            } else revenueOnTimePct = 0;
        }
    } catch (e) {
        logger.warn('kpiDailySnapshot.revenueAggregationFailed', (e as any)?.message);
    }

    const ref = db.collection('kpiDaily').doc(dateKey);

    // Load unified metrics daily export if available (written by /api/health in app runtime)
    let provenanceCoveragePct: number | null = null;
    let p90LatencyOverall: number | null = null;
    let p95LatencyOverall: number | null = null;
    let p99LatencyOverall: number | null = null;
    let crawlerAggregateAdoptionPct: number | null = null;
    let semanticMapAggregateAdoptionPct: number | null = null;
    let teamRateLimitUtilizationPct: number | null = null;
    let fallbackRatePct: number | null = null;
    let cacheHitRatio: number | null = null;
    let rateLimitRejectionRate: number | null = null;
    try {
        const uDoc = await db.collection('unifiedMetricsDaily').doc(dateKey).get();
        if (uDoc.exists) {
            const u = uDoc.data() as Record<string, unknown> | undefined;
            provenanceCoveragePct = typeof (u as any)?.provenanceCoveragePct === 'number' ? (u as any).provenanceCoveragePct : null;
            p90LatencyOverall = typeof (u as any)?.p90LatencyOverall === 'number' ? (u as any).p90LatencyOverall : null;
            p95LatencyOverall = typeof (u as any)?.p95LatencyOverall === 'number' ? (u as any).p95LatencyOverall : null;
            p99LatencyOverall = typeof (u as any)?.p99LatencyOverall === 'number' ? (u as any).p99LatencyOverall : null;
            crawlerAggregateAdoptionPct = typeof (u as any)?.crawlerAggregateAdoptionPct === 'number' ? (u as any).crawlerAggregateAdoptionPct : null;
            semanticMapAggregateAdoptionPct = typeof (u as any)?.semanticMapAggregateAdoptionPct === 'number' ? (u as any).semanticMapAggregateAdoptionPct : null;
            teamRateLimitUtilizationPct = typeof (u as any)?.teamRateLimitUtilizationPct === 'number' ? (u as any).teamRateLimitUtilizationPct : null;
            fallbackRatePct = typeof (u as any)?.fallbackRate === 'number' ? (u as any).fallbackRate : (typeof (u as any)?.fallbackRatePct === 'number' ? (u as any).fallbackRatePct : null);
            cacheHitRatio = typeof (u as any)?.cacheHitRatio === 'number' ? (u as any).cacheHitRatio : null;
            rateLimitRejectionRate = typeof (u as any)?.rateLimitRejectionRate === 'number' ? (u as any).rateLimitRejectionRate : null;
        }
    } catch (e) {
        logger.warn('kpiDailySnapshot.unifiedMetricsLoadFailed', (e as any)?.message);
    }
    // Normalize undefined numeric fields to 0/null to satisfy Firestore serializer
    if (revenueOnTimePct === undefined) revenueOnTimePct = 0;
    await db.runTransaction(async tx => {
        const snap = await tx.get(ref);
        const base: Partial<KpiDailyDoc> = {
            date: dateKey,
            aiTokensIn,
            aiTokensOut,
            aiCostEstimate: aiCost,
            revenueMrr,
            revenueOutstanding,
            revenueOnTimePct,
            provenanceCoveragePct,
            p90LatencyOverall,
            p95LatencyOverall,
            p99LatencyOverall,
            crawlerAggregateAdoptionPct,
            semanticMapAggregateAdoptionPct,
            teamRateLimitUtilizationPct,
            fallbackRatePct,
            cacheHitRatio,
            rateLimitRejectionRate,
            updatedAt: FieldValue.serverTimestamp(),
            _schema: 1
        };
        if (!snap.exists) {
            tx.set(ref, { ...base, createdAt: FieldValue.serverTimestamp() });
        } else {
            tx.update(ref, base);
        }
    });

    // Derive and persist alert snapshot (kpiAlertsDaily) using same threshold logic as /api/health (keep in sync)
    try {
        const alerts: Array<{ type: string; level: 'warn' | 'critical'; message: string; value: number | null; threshold: number }> = [];
        const push = (cond: boolean, level: 'warn' | 'critical', type: string, value: number | null, threshold: number, message: string) => { if (cond) alerts.push({ type, level, message, value, threshold }); };
        // Use values loaded above (provenanceCoveragePct etc.)
        push((provenanceCoveragePct ?? 0) < 100, 'critical', 'provenanceCoverage', provenanceCoveragePct ?? null, 100, 'Provenance coverage below 100%');
        if (fallbackRatePct != null) push(fallbackRatePct > 18, 'warn', 'fallbackRate', fallbackRatePct, 18, 'Fallback rate above target');
        // Adoption thresholds (critical <50, warn 50-80)
        if (crawlerAggregateAdoptionPct != null) {
            push(crawlerAggregateAdoptionPct < 50, 'critical', 'crawlerAggregateAdoption', crawlerAggregateAdoptionPct, 50, 'Crawler aggregate adoption below 50%');
            if (crawlerAggregateAdoptionPct >= 50) push(crawlerAggregateAdoptionPct < 80, 'warn', 'crawlerAggregateAdoption', crawlerAggregateAdoptionPct, 80, 'Crawler aggregate adoption below 80%');
        }
        if (semanticMapAggregateAdoptionPct != null) {
            push(semanticMapAggregateAdoptionPct < 50, 'critical', 'semanticMapAggregateAdoption', semanticMapAggregateAdoptionPct, 50, 'Semantic map aggregate adoption below 50%');
            if (semanticMapAggregateAdoptionPct >= 50) push(semanticMapAggregateAdoptionPct < 80, 'warn', 'semanticMapAggregateAdoption', semanticMapAggregateAdoptionPct, 80, 'Semantic map aggregate adoption below 80%');
        }
        // Latency (overall p95 derived) thresholds: warn >600, critical >1200
        if (p95LatencyOverall != null) {
            push(p95LatencyOverall > 1200, 'critical', 'latencyOverallP95', p95LatencyOverall, 1200, 'Overall p95 latency >1200ms');
            if (p95LatencyOverall > 600 && p95LatencyOverall <= 1200) push(true, 'warn', 'latencyOverallP95', p95LatencyOverall, 600, 'Overall p95 latency >600ms');
        }
        // Cache hit ratio below 45 warn
        if (cacheHitRatio != null) push(cacheHitRatio < 45, 'warn', 'cacheHitRatio', cacheHitRatio, 45, 'Cache hit ratio below target');
        // Rate limit rejection rate >3 warn
        if (rateLimitRejectionRate != null) push(rateLimitRejectionRate > 3, 'warn', 'rateLimitRejectionRate', rateLimitRejectionRate, 3, 'Rate limit rejection rate above target');

        // Compute 7-day moving averages for key metrics (including current day if present)
        let ma7Provenance: number | null = null;
        let ma7CrawlerAdoption: number | null = null;
        let ma7SemanticAdoption: number | null = null;
        let ma7FallbackRate: number | null = null;
        let ma7LatencyP95: number | null = null;
        let ma7CacheHitRatio: number | null = null;
        let ma7RateLimitRejectionRate: number | null = null;
        // Compute 7-day moving averages for key metrics (including current day if present)
        try {
            const recentSnap = await db.collection('kpiDaily').orderBy('date', 'desc').limit(7).get();
            const rows = recentSnap.docs.map(d => d.data() as Record<string, unknown>);
            const avg = (arr: number[]) => arr.length ? +(arr.reduce((s, v) => s + v, 0) / arr.length).toFixed(2) : null;
            ma7Provenance = avg(rows.map(r => (r as any).provenanceCoveragePct).filter((v: number) => typeof v === 'number'));
            ma7CrawlerAdoption = avg(rows.map(r => (r as any).crawlerAggregateAdoptionPct).filter((v: number) => typeof v === 'number'));
            ma7SemanticAdoption = avg(rows.map(r => (r as any).semanticMapAggregateAdoptionPct).filter((v: number) => typeof v === 'number'));
            ma7FallbackRate = avg(rows.map(r => (r as any).fallbackRatePct ?? (r as any).fallbackRate).filter((v: number) => typeof v === 'number'));
            ma7LatencyP95 = avg(rows.map(r => (r as any).p95LatencyOverall).filter((v: number) => typeof v === 'number'));
            ma7CacheHitRatio = avg(rows.map(r => (r as any).cacheHitRatio).filter((v: number) => typeof v === 'number'));
            ma7RateLimitRejectionRate = avg(rows.map(r => (r as any).rateLimitRejectionRate).filter((v: number) => typeof v === 'number'));
            // Exponential smoothing (alpha=0.3) using existing kpiDaily order (rows newest->oldest)
            const alpha = 0.3;
            const provenanceSeries = rows.map(r => r.provenanceCoveragePct).filter((v: any) => typeof v === 'number').slice().reverse(); // oldest->newest
            const latencySeries = rows.map(r => r.p95LatencyOverall).filter((v: any) => typeof v === 'number').slice().reverse();
            const smooth = (series: number[]) => {
                if (!series.length) return null;
                let s = series[0];
                for (let i = 1; i < series.length; i++) s = alpha * series[i] + (1 - alpha) * s;
                return +s.toFixed(2);
            };
            const smoothedProvenance = smooth(provenanceSeries);
            const smoothedLatencyP95 = smooth(latencySeries);
            const crawlerSeries = rows.map(r => r.crawlerAggregateAdoptionPct).filter((v: any) => typeof v === 'number').slice().reverse();
            const semanticSeries = rows.map(r => r.semanticMapAggregateAdoptionPct).filter((v: any) => typeof v === 'number').slice().reverse();
            const smoothedCrawlerAdoption = smooth(crawlerSeries);
            const smoothedSemanticAdoption = smooth(semanticSeries);
            // Persist smoothing onto kpiDaily doc alongside MA7
            try {
                await db.collection('kpiDaily').doc(dateKey).update({ smoothedProvenance, smoothedLatencyP95, smoothedCrawlerAdoption, smoothedSemanticAdoption, updatedAt: FieldValue.serverTimestamp() });
            } catch (e) {
                logger.warn('kpiDailySnapshot.smoothingPersistFailed', (e as unknown as { message?: string })?.message);
            }
            // Include smoothing fields when writing alerts snapshot below
            (globalThis as unknown as Record<string, unknown>).__SMOOTHING = { smoothedProvenance, smoothedLatencyP95, smoothedCrawlerAdoption, smoothedSemanticAdoption };
        } catch (e) {
            logger.warn('kpiAlertsDaily.movingAverageFailed', (e as any)?.message);
        }
        const alertsRef = db.collection('kpiAlertsDaily').doc(dateKey);
        // Persist MA7 overlays onto kpiDaily (update only – doc already written earlier)
        try {
            await db.collection('kpiDaily').doc(dateKey).update({
                ma7Provenance,
                ma7CrawlerAdoption,
                ma7SemanticAdoption,
                ma7FallbackRate,
                ma7LatencyP95,
                ma7CacheHitRatio,
                ma7RateLimitRejectionRate,
                updatedAt: FieldValue.serverTimestamp()
            });
        } catch (e) {
            logger.warn('kpiDailySnapshot.ma7PersistFailed', (e as unknown as { message?: string })?.message);
        }
        await db.runTransaction(async tx => {
            const aSnap = await tx.get(alertsRef);
            const smoothing = (globalThis as unknown as Record<string, unknown>).__SMOOTHING || {};
            const base = { date: dateKey, alerts, ma7Provenance, ma7CrawlerAdoption, ma7SemanticAdoption, ma7FallbackRate, ma7LatencyP95, ma7CacheHitRatio, ma7RateLimitRejectionRate, ...smoothing, updatedAt: FieldValue.serverTimestamp() };
            if (!aSnap.exists) tx.set(alertsRef, { ...base, createdAt: FieldValue.serverTimestamp() }); else tx.update(alertsRef, base);
        });
        // Retention purge for alert snapshots
        try {
            const cutoff = new Date(now.getTime() - RETENTION_DAYS * 86400_000).toISOString().slice(0, 10);
            const old = await db.collection('kpiAlertsDaily').where('date', '<', cutoff).limit(50).get();
            if (!old.empty) {
                const batch = db.batch();
                old.docs.forEach(d => batch.delete(d.ref));
                await batch.commit();
            }
        } catch (e) {
            logger.warn('kpiAlertsDaily.retentionFailed', (e as unknown as { message?: string })?.message);
        }
    } catch (e) {
        logger.warn('kpiAlertsDaily.persistFailed', (e as unknown as { message?: string })?.message);
    }

    // Retention purge (older than RETENTION_DAYS)
    try {
        const cutoff = new Date(now.getTime() - RETENTION_DAYS * 86400_000).toISOString().slice(0, 10);
        // Because IDs are dateKey, lexicographic comparison works for YYYY-MM-DD
        const oldSnap = await db.collection('kpiDaily').where('date', '<', cutoff).limit(50).get();
        const batch = db.batch();
        oldSnap.docs.forEach(d => batch.delete(d.ref));
        if (!oldSnap.empty) await batch.commit();
    } catch (e) {
        logger.warn('kpiDailySnapshot.retentionFailed', (e as unknown as { message?: string })?.message);
    }

    logger.info('kpiDailySnapshot.complete', { date: dateKey, aiTokensIn, aiTokensOut, aiCostEstimate: aiCost });
    return { date: dateKey, aiTokensIn, aiTokensOut, aiCostEstimate: aiCost };
}

