import { onCall } from "firebase-functions/v2/https";
import * as admin from "firebase-admin";

if (!admin.apps.length) {
    admin.initializeApp();
}

const db = admin.firestore();

async function collectUserData(userId: string) {
    const exportPayload: Record<string, any[]> = {};
    const collections = [
        { path: `users/${userId}`, single: true },
        { path: `users/${userId}/activities` },
        { path: `users/${userId}/audits` },
        { path: `users/${userId}/keywords` },
        { path: `users/${userId}/reports` },
    ];

    for (const c of collections) {
        if (c.single) {
            const docSnap = await db.doc(c.path).get();
            exportPayload["profile"] = docSnap.exists ? [{ id: docSnap.id, ...docSnap.data() }] : [];
        } else {
            const snap = await db.collection(c.path).limit(500).get();
            exportPayload[c.path.split("/").pop() || c.path] = snap.docs.map(d => ({ id: d.id, ...d.data() }));
        }
    }
    return exportPayload;
}

export const exportUserData = onCall<{ userId?: string }, any>(async (req) => {
    const authUid = req.auth?.uid;
    const targetUserId = req.data?.userId || authUid;
    if (!authUid || !targetUserId || authUid !== targetUserId) {
        throw new Error("unauthorized");
    }
    const payload = await collectUserData(targetUserId);
    return { generatedAt: new Date().toISOString(), data: payload };
});

export const requestAccountDeletion = onCall<{ userId?: string }, any>(async (req) => {
    const authUid = req.auth?.uid;
    const targetUserId = req.data?.userId || authUid;
    if (!authUid || !targetUserId || authUid !== targetUserId) {
        throw new Error("unauthorized");
    }
    await db.doc(`users/${targetUserId}`).set({ deletionRequestedAt: admin.firestore.FieldValue.serverTimestamp(), status: "pending_deletion" }, { merge: true });
    const activitiesRef = db.collection(`users/${targetUserId}/activities`).limit(200);
    const actSnap = await activitiesRef.get();
    const batch = db.batch();
    actSnap.docs.forEach(doc => { batch.update(doc.ref, { userId: null }); });
    await batch.commit();
    return { status: "scheduled", userId: targetUserId };
});

import { ErrorReporting } from "@google-cloud/error-reporting";
import { logger } from "firebase-functions";

// Initialize Error Reporting
const errors = new ErrorReporting({
  reportMode: "always",
  serviceContext: {
    service: "rankpilot",
    version: process.env.npm_package_version || "unknown",
  },
});

export interface ErrorDetails {
  code?: string;
  message: string;
  stack?: string;
  context?: Record<string, any>;
}

interface ErrorContext {
  user?: string;
  httpRequest?: {
    method?: string;
    url?: string;
    userAgent?: string;
    referrer?: string;
    responseStatusCode?: number;
    remoteIp?: string;
  };
  [key: string]: any;
}

export function logError(error: Error | ErrorDetails, context?: ErrorContext) {
  // Log to Firebase Functions logger
  logger.error("Error occurred:", {
    error:
      error instanceof Error
        ? {
          message: error.message,
          stack: error.stack,
          ...context,
        }
        : error,
    context,
  });

  // Report to Error Reporting
  if (error instanceof Error) {
    errors.report(error);
  } else {
    const errorInstance = new Error(error.message);
    if (error.stack) {
      errorInstance.stack = error.stack;
    }
    errors.report(errorInstance);
  }
}

export function wrapAsync<T>(fn: (...args: any[]) => Promise<T>) {
  return async (...args: any[]): Promise<T> => {
    try {
      return await fn(...args);
    } catch (error) {
      logError(
        error instanceof Error ? error : { message: "Unknown error occurred" }
      );
      throw error;
    }
  };
}

