    });

    // Also check for users with admin tier (incorrect configuration)
    const adminTierQuery = query(
      usersRef,
      where("subscriptionTier", "==", "admin")
    );
    const adminTierSnapshot = await getDocs(adminTierQuery);

    if (adminTierSnapshot.size > 0) {
