/**
 * Navigation & FeatureGate Consistency Audit
 *
 * Validations:
 * 1. Every nav item with requiredTier >= starter must have a feature key OR be explicitly allowlisted.
 * 2. Every nav item with a feature key must have that feature defined in FEATURE_ACCESS.
 * 3. Each page route referenced by a nav item with a feature must include a FeatureGate usage.
 * 4. Each FeatureGate usage references an existing feature key.
 * 5. Report orphan features (defined but unused in nav or FeatureGate) excluding admin-only.
 */
import fs from 'fs';
import path from 'path';

const projectRoot = process.cwd();
const navFile = path.join(projectRoot, 'src/constants/enhanced-nav.ts');
const accessFile = path.join(projectRoot, 'src/lib/access-control.ts');
const appDir = path.join(projectRoot, 'src/app/(app)');

type NavItem = { title: string; href: string; requiredTier?: string; feature?: string; adminOnly?: boolean; };

interface Finding { severity: 'ERROR' | 'WARN' | 'INFO'; code: string; message: string; context?: any; }

const findings: Finding[] = [];

function readFile(p: string) {
    return fs.existsSync(p) ? fs.readFileSync(p, 'utf8') : '';
}

const navSource = readFile(navFile);
const accessSource = readFile(accessFile);
if (!navSource || !accessSource) {
    console.error('Required source files missing.');
    process.exit(1);
}

// Extract feature map keys from access-control (FEATURE_ACCESS object keys)
// Match feature keys whether requiredTier/requiresAdmin appears on same line or next line
const featureKeyRegex = /\b([a-zA-Z0-9_]+): \{[^}]*?(requiredTier|requiresAdmin)/g;
const featureKeys = new Set<string>();
for (const m of accessSource.matchAll(featureKeyRegex)) {
    featureKeys.add(m[1]);
}

// Extract nav items: rudimentary regex for objects with href
const navItemRegex = /{[^}]*href:\s*\"([^\"]+)\"[^}]*}/gms;
const navItems: NavItem[] = [];
for (const block of navSource.matchAll(navItemRegex)) {
    const obj = block[0];
    const href = block[1];
    const requiredTier = /requiredTier:\s*\"(starter|agency|enterprise)\"/.exec(obj)?.[1];
    const feature = /feature:\s*\"([a-zA-Z0-9_]+)\"/.exec(obj)?.[1];
    const adminOnly = /adminOnly:\s*true/.test(obj);
    navItems.push({ title: /title:\s*\"([^\"]+)\"/.exec(obj)?.[1] || href, href, requiredTier, feature, adminOnly });
}

// Allowlist: items intentionally without feature key but tiered (if any)
const allowNoFeature = new Set<string>([
    '/sales/pipeline',
    '/sales/deals',
    '/sales/outreach',
    '/dashboard',
    '/insights',
    '/performance',
]);

// Scan app directory for FeatureGate usages
const featureGateUsages = new Map<string, string[]>();
function walk(dir: string) {
    for (const entry of fs.readdirSync(dir)) {
        const full = path.join(dir, entry);
        const stat = fs.statSync(full);
        if (stat.isDirectory()) walk(full);
        else if (/page\.(t|j)sx?$/.test(entry)) {
            const content = readFile(full);
            const regex = /<FeatureGate[^>]*feature=\"([a-zA-Z0-9_]+)\"/g;
            for (const m of content.matchAll(regex)) {
                const f = m[1];
                if (!featureGateUsages.has(f)) featureGateUsages.set(f, []);
                featureGateUsages.get(f)!.push(full.replace(projectRoot + '/', ''));
            }
        }
    }
}
walk(appDir);

// 1 & 2: Validate nav items
for (const item of navItems) {
    if (item.requiredTier && !item.feature && !allowNoFeature.has(item.href) && !item.adminOnly) {
        findings.push({ severity: 'WARN', code: 'NAV_NO_FEATURE', message: `Nav item ${item.href} has tier ${item.requiredTier} but no feature key`, context: item });
    }
    if (item.feature && !featureKeys.has(item.feature)) {
        findings.push({ severity: 'ERROR', code: 'UNKNOWN_FEATURE', message: `Nav item ${item.href} references unknown feature ${item.feature}`, context: item });
    }
}

// 3: Ensure pages for nav items with feature keys use FeatureGate
for (const item of navItems.filter(i => i.feature)) {
    const routePath = path.join(appDir, item.href.replace(/^\//, ''));
    let matched = false;
    const candidates = [
        path.join(routePath, 'page.tsx'),
        path.join(routePath, 'page.jsx'),
    ];
    for (const candidate of candidates) {
        if (fs.existsSync(candidate)) {
            const src = readFile(candidate);
            if (new RegExp(`<FeatureGate[^>]*feature=\\"${item.feature}\\"`).test(src)) { matched = true; break; }
        }
    }
    if (!matched) {
        findings.push({ severity: 'WARN', code: 'MISSING_FEATURE_GATE', message: `Route ${item.href} with feature ${item.feature} missing FeatureGate wrapper`, context: item });
    }
}

// 4: FeatureGate usages reference existing features
for (const [feature, files] of featureGateUsages.entries()) {
    if (!featureKeys.has(feature)) {
        findings.push({ severity: 'ERROR', code: 'GATE_UNKNOWN_FEATURE', message: `FeatureGate uses unknown feature ${feature}`, context: { files } });
    }
}

// 5: Orphan features (with suppression support via inline annotations)
// Annotation format preceding feature key line:
// // audit:ignore-orphan category=<token> rationale="<reason>"
const usedFeatures = new Set<string>([...navItems.filter(i => i.feature).map(i => i.feature!), ...featureGateUsages.keys()]);
// Precompute ignore lines
const ignoreOrphanLines = new Map<string, { category: string; rationale: string }>();
const accessLines = accessSource.split(/\n/);
for (let i = 0; i < accessLines.length; i++) {
    const line = accessLines[i].trim();
    if (line.startsWith('// audit:ignore-orphan')) {
        // Parse category and rationale
        const categoryMatch = /category=([a-zA-Z0-9_-]+)/.exec(line);
        const rationaleMatch = /rationale="([^"]+)"/.exec(line);
        // Look ahead for next feature key line pattern 'feature_key: {'
        for (let j = i + 1; j < Math.min(i + 4, accessLines.length); j++) {
            const featureLineMatch = /^(\s*)([a-zA-Z0-9_]+):\s*\{/.exec(accessLines[j]);
            if (featureLineMatch) {
                const fk = featureLineMatch[2];
                ignoreOrphanLines.set(fk, { category: categoryMatch?.[1] || 'unspecified', rationale: rationaleMatch?.[1] || '' });
                break;
            }
        }
    }
}
for (const fk of featureKeys) {
    if (!usedFeatures.has(fk)) {
        if (ignoreOrphanLines.has(fk)) continue; // suppressed
        const adminPattern = new RegExp(`${fk}: {\n\s+requiresAdmin: true`);
        if (adminPattern.test(accessSource)) continue; // admin-only auto-suppressed
        findings.push({ severity: 'INFO', code: 'ORPHAN_FEATURE', message: `Feature ${fk} not referenced in nav or page gates`, context: fk });
    }
}

const errors = findings.filter(f => f.severity === 'ERROR').length;
const warns = findings.filter(f => f.severity === 'WARN').length;
const infos = findings.filter(f => f.severity === 'INFO').length;

const report = { stats: { errors, warns, infos, total: findings.length }, findings };

if (errors) {
    console.error('[NAV_FEATURE_AUDIT] FAIL', JSON.stringify(report, null, 2));
    process.exitCode = 1;
} else if (warns) {
    console.warn('[NAV_FEATURE_AUDIT] WARN', JSON.stringify(report, null, 2));
} else {
    console.log('[NAV_FEATURE_AUDIT] PASS', JSON.stringify(report, null, 2));
}

#!/usr/bin/env ts-node
/** PROV-01: Provenance Coverage Audit
 * Enumerates API route files and heuristically checks for enforceProvenance / withProvenance usage or explicit __provenance assignment.
 * Fails (exit 1) if any route appears AI-related (contains 'ai'|'neuroseo'|'marketing' patterns) and lacks provenance markers.
 */
import fs from 'fs';
import path from 'path';
import { setTimeout as sleep } from 'timers/promises';

const ROOT = path.resolve(process.cwd(), 'src/app/api');
const CONFIG_PATH = path.resolve(process.cwd(), '.provenance-audit.json');
// Narrow hints to reduce false positives on non-AI operational endpoints.
const AI_HINTS = [
    /\/ai\//i,
    /neuroseo\/(?!metrics)/i,
    /automation\//i,
    /competitive/i,
    /conversational-seo/i,
    /multi-model/i,
    /insights\/stream/i,
    /seo-audit\/run/i,
    /\/chat\//i,
    /\/chat\/admin\//i,
    /\/admin\/stream\//i,
];
const PROV_MARKERS = [/enforceProvenance/, /withProvenance/, /__provenance\s*:/];

// Optional exemption list (exact relative file paths) for documented reasons (see PROVENANCE_POLICY.md)
const EXEMPTIONS = new Set<string>([/* intentionally empty; deprecated automation run-due endpoint removed */]);

const STRICT = process.env.PROV_STRICT === '1'; // when enabled, require withProvenance for non-streaming AI routes

// Optional JSON config structure
type RuntimeCheck = { path: string; type: 'json' | 'csv' | 'sse' };
interface AuditConfig {
    extraHints?: string[]; // regex strings
    extraRuntimeUrls?: RuntimeCheck[]; // paths (prefixed with /) relative to origin
    exemptions?: string[]; // relative file paths
}

function loadConfig(): AuditConfig {
    try {
        if (fs.existsSync(CONFIG_PATH)) {
            const raw = fs.readFileSync(CONFIG_PATH, 'utf8');
            return JSON.parse(raw) as AuditConfig;
        }
    } catch (e) {
        console.warn('[provenance-audit] Failed to load .provenance-audit.json:', (e as any)?.message);
    }
    return {};
}

const CONFIG = loadConfig();

interface Finding { file: string; reason: string }

function walk(dir: string, acc: string[]) {
    for (const entry of fs.readdirSync(dir)) {
        const full = path.join(dir, entry);
        const stat = fs.statSync(full);
        if (stat.isDirectory()) walk(full, acc);
        else if (entry === 'route.ts' || entry.endsWith('.ts')) acc.push(full);
    }
    return acc;
}

const files = walk(ROOT, []);
const violations: Finding[] = [];
files.forEach(f => {
    const txt = fs.readFileSync(f, 'utf8');
    // Path-based hints + configurable hints
    const extraHints = (CONFIG.extraHints || []).map((s) => {
        try { return new RegExp(s, 'i'); } catch { return null; }
    }).filter(Boolean) as RegExp[];
    const pathHints = [...AI_HINTS, ...extraHints];
    // Content-based hints (providers/keywords)
    const contentHints = /(openai|gemini|anthropic|llm|ai-)/i.test(txt);
    const aiRelated = pathHints.some(r => r.test(f)) || contentHints;
    if (!aiRelated) return;
    const rel = path.relative(process.cwd(), f);
    if (EXEMPTIONS.has(rel) || (CONFIG.exemptions || []).includes(rel)) return;
    const hasMarker = PROV_MARKERS.some(r => r.test(txt));
    if (!hasMarker) {
        violations.push({ file: path.relative(process.cwd(), f), reason: 'No provenance marker heuristically detected' });
        return;
    }
    if (STRICT) {
        // If handler is not streaming (no enforceProvenanceOnChunk) prefer withProvenance usage for consistency
        const isStreaming = /enforceProvenanceOnChunk/.test(txt);
        if (!isStreaming && !/withProvenance/.test(txt)) {
            violations.push({ file: rel, reason: 'Strict mode: missing withProvenance wrapper' });
        }
        // Streaming routes should explicitly use enforceProvenanceOnChunk
        if (/\/stream\//.test(f) && !/enforceProvenanceOnChunk/.test(txt)) {
            violations.push({ file: rel, reason: 'Strict mode: streaming endpoint missing enforceProvenanceOnChunk' });
        }
    }
});

function finalize() {
    // Emit machine-readable report
    try {
        const outDir = path.resolve(process.cwd(), 'testing/reports');
        fs.mkdirSync(outDir, { recursive: true });
        fs.writeFileSync(path.join(outDir, 'provenance-audit.json'), JSON.stringify({ count: violations.length, violations }, null, 2));
    } catch { }

    if (violations.length) {
        console.error('Provenance coverage audit FAILED');
        // Compact summary lines
        for (const v of violations) {
            console.error(`PROV: [FAIL] ${v.file} - ${v.reason}`);
            if (process.env.CI) {
                // GitHub Actions annotation format (warning style to surface in logs)
                console.error(`::warning file=${v.file}::Provenance violation: ${v.reason}`);
            }
        }
        console.error(JSON.stringify({ count: violations.length, violations }, null, 2));
        process.exit(1);
    } else {
        console.log('Provenance coverage audit PASS');
    }
}

function parseArgs(argv: string[]): Record<string, string> {
    const out: Record<string, string> = {};
    for (const a of argv) {
        if (a.startsWith('--')) {
            const [k, v] = a.replace(/^--/, '').split('=');
            out[k] = v ?? '1';
        }
    }
    return out;
}

async function fetchWithRetry(url: string, opts: RequestInit & { retries?: number; retryDelayMs?: number } = {}): Promise<Response> {
    const { retries = 1, retryDelayMs = 300, ...rest } = opts;
    let lastErr: any;
    for (let i = 0; i <= retries; i++) {
        try {
            const res = await fetch(url, rest);
            return res;
        } catch (e) {
            lastErr = e;
            if (i < retries) await sleep(retryDelayMs);
        }
    }
    throw lastErr;
}

async function runTableDataProvenanceChecks(origin: string, timeoutMs: number): Promise<Finding[]> {
    const out: Finding[] = [];
    const controller = new AbortController();
    const t = setTimeout(() => controller.abort(), timeoutMs);
    try {
        // JSON check: __provenance must exist
        const jsonUrl = `${origin}/api/table-data?widgetId=prov-audit&format=json&page=0&pageSize=1`;
        const jsonRes = await fetchWithRetry(jsonUrl, { signal: controller.signal, retries: 1 });
        if (jsonRes.ok) {
            const body = await jsonRes.json();
            if (!('__provenance' in body)) {
                out.push({ file: 'runtime:/api/table-data?format=json', reason: 'Missing __provenance on JSON payload' });
            }
        } else {
            out.push({ file: 'runtime:/api/table-data?format=json', reason: `HTTP ${jsonRes.status} calling table-data` });
        }

        // CSV check: x-provenance header must exist
        const csvUrl = `${origin}/api/table-data?widgetId=prov-audit&format=csv&page=0&pageSize=1`;
        const csvRes = await fetchWithRetry(csvUrl, { signal: controller.signal, retries: 1 });
        if (csvRes.ok) {
            const prov = csvRes.headers.get('x-provenance');
            if (!prov) {
                out.push({ file: 'runtime:/api/table-data?format=csv', reason: 'Missing x-provenance header on CSV response' });
            }
        } else {
            out.push({ file: 'runtime:/api/table-data?format=csv', reason: `HTTP ${csvRes.status} calling table-data` });
        }
    } catch (e: any) {
        const requireServer = process.env.PROV_REQUIRE_SERVER === '1';
        if (requireServer) {
            out.push({ file: 'runtime:/api/table-data', reason: `Server unavailable for runtime provenance audit: ${e?.message || e}` });
        } else {
            console.warn('[provenance-audit] Skipping runtime /api/table-data checks (server not available).');
        }
    } finally {
        clearTimeout(t);
    }
    return out;
}

async function runExtraRuntimeChecks(origin: string, timeoutMs: number): Promise<Finding[]> {
    const out: Finding[] = [];
    const extra = CONFIG.extraRuntimeUrls || [];
    if (!extra.length) return out;
    for (const check of extra) {
        const url = check.path.startsWith('http') ? check.path : `${origin}${check.path}`;
        const controller = new AbortController();
        const t = setTimeout(() => controller.abort(), timeoutMs);
        try {
            const res = await fetchWithRetry(url, { signal: controller.signal, retries: 1 });
            if (!res.ok) {
                // If auth is required, skip failing and fallback to static code scan as requested
                if (res.status === 401 || res.status === 403) {
                    console.warn(`[provenance-audit] Skipping ${check.path} (${check.type}) due to auth (${res.status}). Falling back to static scan.`);
                    continue;
                }
                out.push({ file: `runtime:${check.path}`, reason: `HTTP ${res.status} calling ${check.type}` });
                continue;
            }
            if (check.type === 'json') {
                const body = await res.json().catch(() => ({}));
                if (!('__provenance' in body)) out.push({ file: `runtime:${check.path}`, reason: 'Missing __provenance on JSON payload' });
            } else if (check.type === 'csv') {
                const prov = res.headers.get('x-provenance');
                if (!prov) out.push({ file: `runtime:${check.path}`, reason: 'Missing x-provenance header on CSV response' });
            } else if (check.type === 'sse') {
                const ct = res.headers.get('content-type') || '';
                if (!ct.includes('text/event-stream')) out.push({ file: `runtime:${check.path}`, reason: 'SSE endpoint missing text/event-stream content-type' });
                // Optional: attempt to read a small portion of the body to ensure stream
                // Note: Node fetch body is a web ReadableStream in modern Node.
                try {
                    const reader = (res.body as any)?.getReader?.();
                    if (reader) {
                        const r = await Promise.race([
                            reader.read(),
                            sleep(500).then(() => ({ done: true, value: undefined }))
                        ]);
                        if (!r || (r as any).done) {
                            out.push({ file: `runtime:${check.path}`, reason: 'SSE stream did not yield initial chunk' });
                        }
                    }
                } catch { }
            }
        } catch (e: any) {
            const requireServer = process.env.PROV_REQUIRE_SERVER === '1';
            if (requireServer) out.push({ file: `runtime:${check.path}`, reason: `Server unavailable: ${e?.message || e}` });
            else console.warn(`[provenance-audit] Skipping runtime ${check.path} (${check.type}) check (server not available).`);
        } finally {
            clearTimeout(t);
        }
    }
    return out;
}

// Run optional runtime checks then finalize
(async () => {
    const args = parseArgs(process.argv.slice(2));
    const origin = args.origin || process.env.PROV_ORIGIN || 'http://localhost:3000';
    const timeoutMs = Number(args.timeoutMs || process.env.PROV_TIMEOUT_MS || 5000);
    const findingsA = await runTableDataProvenanceChecks(origin, timeoutMs);
    const findingsB = await runExtraRuntimeChecks(origin, timeoutMs);
    if (findingsA.length) violations.push(...findingsA);
    if (findingsB.length) violations.push(...findingsB);
    finalize();
})().catch(() => finalize());

/**
 * Backfill Script: Re-summarize / normalize pending actions to exclude completed ones.
 * Usage:
 *   npx ts-node scripts/backfill-chat-action-progress.ts            (fast filter only)
 *   npx ts-node scripts/backfill-chat-action-progress.ts --full     (re-run summarizer when mismatch)
 *
 * Behavior:
 * 1. Iterates chatLogs collection user docs and their nested session documents
 * 2. If actionProgress has completed items that still appear in pendingActions, removes them immediately.
 * 3. When --full flag supplied AND messageCount >= interval threshold, invokes maybeSummarizeSession for a richer refresh.
 * 4. Stores actionStats { totalCompleted, totalPending, completionRate, lastBackfill }.
 */
import 'dotenv/config';
import { adminDb } from '../src/lib/firebase-admin';
import { maybeSummarizeSession } from '../src/lib/chat/sessionSummarizer';

async function run() {
    const argv = process.argv.slice(2);
    const doFull = argv.includes('--full');
    const usersCol = await adminDb.collection('chatLogs').listDocuments();
    let examined = 0, modified = 0, summarized = 0;
    for (const userDoc of usersCol) {
        const sessionsColRef = userDoc.collection('sessions');
        const sessionDocs = await sessionsColRef.listDocuments();
        for (const sRef of sessionDocs) {
            examined++;
            const snap = await sRef.get();
            if (!snap.exists) continue;
            const data = snap.data() as any;
            const pending: string[] = Array.isArray(data?.pendingActions) ? data.pendingActions : [];
            const progress = data?.actionProgress || {};
            if (!pending.length || !progress || typeof progress !== 'object') continue;
            const completedSet = new Set(Object.entries(progress).filter(([, v]) => !!v).map(([k]) => k.toLowerCase().trim()));
            if (!completedSet.size) continue;
            const filtered = pending.filter(p => !completedSet.has(String(p).toLowerCase().trim()));
            let changed = filtered.length !== pending.length;
            if (changed) {
                const totalCompleted = completedSet.size;
                const totalPending = filtered.length;
                const denominator = totalCompleted + totalPending;
                const completionRate = denominator === 0 ? (totalCompleted > 0 ? 1 : 0) : totalCompleted / denominator;
                await sRef.set({
                    pendingActions: filtered,
                    actionStats: {
                        totalCompleted,
                        totalPending,
                        completionRate,
                        lastBackfill: new Date(),
                    },
                }, { merge: true });
                modified++;
            }
            if (doFull && data.messageCount >= 6) { // respect summarizer interval (MESSAGE_INTERVAL)
                try {
                    await maybeSummarizeSession({ uid: userDoc.id, sessionId: sRef.id });
                    summarized++;
                } catch { /* ignore */ }
            }
        }
    }
    console.log(JSON.stringify({ examined, modified, summarized, fullMode: doFull }, null, 2));
}

run().then(() => process.exit(0)).catch(e => { console.error(e); process.exit(1); });

#!/usr/bin/env ts-node
/*
 * T14 Backfill: Generate compact aggregate docs for legacy neuralCrawlerResults.
 * Idempotent: skips if an aggregate with matching historyId already exists (or url+user fallback).
 * Usage:
 *   npm run backfill:neural-crawler-agg              # live run
 *   DRY_RUN=1 npm run backfill:neural-crawler-agg    # dry run (counts only)
 *   BATCH_SIZE=200 npm run backfill:neural-crawler-agg
 */
import { initializeApp, getApps } from 'firebase-admin/app';
import type { QueryDocumentSnapshot } from 'firebase-admin/firestore';
import { getFirestore } from 'firebase-admin/firestore';

interface LegacyDoc {
    userId: string;
    historyId?: string;
    url: string;
    wordCount?: number;
    readingTime?: number;
    images?: any[];
    links?: Array<{ type: 'internal' | 'external' }>;
    seoAnalysis?: { titleLength?: number; metaDescriptionLength?: number };
    issues?: any[];
    entities?: any[];
    headings?: Record<string, string[]>;
    createdAt?: any;
}

function deriveAggregate(d: LegacyDoc) {
    const internalLinks = d.links?.filter(l => l.type === 'internal').length || 0;
    const externalLinks = d.links?.filter(l => l.type === 'external').length || 0;
    const headingsCounts = d.headings ? Object.fromEntries(Object.entries(d.headings).map(([k, v]) => [k, Array.isArray(v) ? v.length : 0])) : {};
    return {
        userId: d.userId,
        historyId: d.historyId || null,
        url: d.url,
        wordCount: d.wordCount || 0,
        readingTime: d.readingTime || 0,
        imagesCount: d.images?.length || 0,
        linksInternal: internalLinks,
        linksExternal: externalLinks,
        titleLength: d.seoAnalysis?.titleLength ?? null,
        metaDescriptionLength: d.seoAnalysis?.metaDescriptionLength ?? null,
        issuesCount: d.issues?.length || 0,
        entitiesCount: d.entities?.length || 0,
        headings: headingsCounts,
        version: 1,
        createdAt: d.createdAt || new Date()
    };
}

async function aggregateExists(db: FirebaseFirestore.Firestore, legacy: LegacyDoc): Promise<boolean> {
    if (legacy.historyId) {
        const q = await db.collection('neuralCrawlerResultsAgg').where('historyId', '==', legacy.historyId).limit(1).get();
        if (!q.empty) return true;
    }
    const q2 = await db.collection('neuralCrawlerResultsAgg').where('userId', '==', legacy.userId).where('url', '==', legacy.url).limit(1).get();
    return !q2.empty;
}

async function processBatch(db: FirebaseFirestore.Firestore, snaps: QueryDocumentSnapshot[], dryRun: boolean) {
    let written = 0; let skipped = 0;
    for (const doc of snaps) {
        const data = doc.data() as LegacyDoc;
        if (!data.userId || !data.url) { skipped++; continue; }
        const exists = await aggregateExists(db, data);
        if (exists) { skipped++; continue; }
        if (!dryRun) {
            const agg = deriveAggregate(data);
            await db.collection('neuralCrawlerResultsAgg').add(agg);
        }
        written++;
    }
    return { written, skipped };
}

async function main() {
    if (!getApps().length) initializeApp();
    const db = getFirestore();
    const batchSize = parseInt(process.env.BATCH_SIZE || '100', 10);
    const dryRun = !!process.env.DRY_RUN;
    console.log(`[backfill-neural-crawler-aggregate] start batchSize=${batchSize} dryRun=${dryRun}`);
    let last: QueryDocumentSnapshot | undefined;
    let totalWritten = 0, totalSkipped = 0, totalScanned = 0;
    while (true) {
        let query = db.collection('neuralCrawlerResults').limit(batchSize);
        if (last) query = query.startAfter(last);
        const snap = await query.get();
        if (snap.empty) break;
        const docs = snap.docs;
        const { written, skipped } = await processBatch(db, docs, dryRun);
        last = docs[docs.length - 1];
        totalWritten += written; totalSkipped += skipped; totalScanned += docs.length;
        console.log(`[backfill] scanned=${totalScanned} written=${totalWritten} skipped=${totalSkipped}`);
        if (docs.length < batchSize) break;
    }
    console.log(`[backfill-neural-crawler-aggregate] complete scanned=${totalScanned} written=${totalWritten} skipped=${totalSkipped}`);
}

main().catch(e => { console.error('Backfill FAILED', e); process.exit(1); });

#!/usr/bin/env ts-node
/*
 * T14 Backfill: Generate compact aggregate docs for legacy semanticMapResults.
 * Idempotent: skips if an aggregate with matching (userId,url) exists OR doc id already processed.
 * Usage:
 *   npm run backfill:semantic-map-agg              # live run
 *   DRY_RUN=1 npm run backfill:semantic-map-agg    # dry run (counts only)
 *   BATCH_SIZE=200 npm run backfill:semantic-map-agg
 */
import { initializeApp, getApps } from 'firebase-admin/app';
import type { QueryDocumentSnapshot} from 'firebase-admin/firestore';
import { getFirestore, FieldValue } from 'firebase-admin/firestore';
import { deriveSemanticMapAggregate } from './scan-neuroseo-large-docs';

interface LegacySemanticDoc {
    userId?: string; url?: string; overallScore?: number;
    topicClusters?: any[]; keywordAnalysis?: any[]; contentAnalysis?: any;
    semanticGraph?: { nodes?: any[]; edges?: any[] }; recommendations?: any[]; createdAt?: any;
}

async function aggregateExists(db: FirebaseFirestore.Firestore, legacy: LegacySemanticDoc): Promise<boolean> {
    if (!legacy.userId || !legacy.url) return false;
    const q = await db.collection('semanticMapResultsAgg').where('userId', '==', legacy.userId).where('url', '==', legacy.url).limit(1).get();
    return !q.empty;
}

async function processBatch(db: FirebaseFirestore.Firestore, snaps: QueryDocumentSnapshot[], dryRun: boolean) {
    let written = 0; let skipped = 0; let oversizedConsidered = 0;
    for (const doc of snaps) {
        const data = doc.data() as LegacySemanticDoc;
        if (!data.userId || !data.url) { skipped++; continue; }
        // Approx size gate (>2.5KB) to focus on large docs first
        const size = Buffer.byteLength(JSON.stringify(data));
        if (size < 2500) { skipped++; continue; }
        oversizedConsidered++;
        const exists = await aggregateExists(db, data);
        if (exists) { skipped++; continue; }
        const agg = deriveSemanticMapAggregate(data);
        if (!dryRun) {
            await db.collection('semanticMapResultsAgg').add({ ...agg, createdAt: agg.createdAt || FieldValue.serverTimestamp() });
        }
        written++;
    }
    return { written, skipped, oversizedConsidered };
}

async function main() {
    if (!getApps().length) initializeApp();
    const db = getFirestore();
    const batchSize = parseInt(process.env.BATCH_SIZE || '100', 10);
    const dryRun = !!process.env.DRY_RUN;
    console.log(`[backfill-semantic-map-aggregate] start batchSize=${batchSize} dryRun=${dryRun}`);
    let last: QueryDocumentSnapshot | undefined;
    let totalWritten = 0, totalSkipped = 0, totalScanned = 0, totalOversized = 0;
    while (true) {
        let query = db.collection('semanticMapResults').limit(batchSize);
        if (last) query = query.startAfter(last);
        const snap = await query.get();
        if (snap.empty) break;
        const docs = snap.docs;
        const { written, skipped, oversizedConsidered } = await processBatch(db, docs, dryRun);
        last = docs[docs.length - 1];
        totalWritten += written; totalSkipped += skipped; totalScanned += docs.length; totalOversized += oversizedConsidered;
        console.log(`[backfill] scanned=${totalScanned} oversized=${totalOversized} written=${totalWritten} skipped=${totalSkipped}`);
        if (docs.length < batchSize) break;
    }
    console.log(`[backfill-semantic-map-aggregate] complete scanned=${totalScanned} oversized=${totalOversized} written=${totalWritten} skipped=${totalSkipped}`);
    if (dryRun) console.log('[backfill] DRY RUN ONLY – no writes performed.');
}

main().catch(e => { console.error('Backfill FAILED', e); process.exit(1); });

/** Backfill embeddings for existing site content chunks missing vectors.
 * Usage:
 *   RANKPILOT_ENABLE_EMBEDDINGS=1 OPENAI_API_KEY=sk-... npx ts-node scripts/backfill-site-embeddings.ts --uid <userId> [--collection default] [--limit 100] [--dry]
 */
import 'dotenv/config';
import OpenAI from 'openai';
import { adminDb } from '../src/lib/firebase-admin';

interface Args { uid?: string; collection?: string; limit?: number; dry?: boolean; }
function parseArgs(): Args {
    const a = process.argv.slice(2); const out: Args = {};
    for (let i = 0; i < a.length; i++) {
        if (a[i] === '--uid') out.uid = a[++i];
        else if (a[i] === '--collection') out.collection = a[++i];
        else if (a[i] === '--limit') out.limit = Number(a[++i]);
        else if (a[i] === '--dry') out.dry = true;
    }
    return out;
}

async function backfill({ uid, collection = 'default', limit = 250, dry = false }: { uid: string; collection: string; limit: number; dry: boolean; }) {
    const apiKey = process.env.OPENAI_API_KEY;
    if (!apiKey) throw new Error('OPENAI_API_KEY missing');
    const client = new OpenAI({ apiKey });
    const collRef = adminDb.collection('siteContent').doc(uid).collection(collection);
    const snapshot = await collRef.limit(limit).get();
    let processed = 0, embedded = 0, skipped = 0, errors = 0;
    for (const doc of snapshot.docs) {
        processed++;
        const data: any = doc.data();
        if (Array.isArray(data.embedding) && data.embedding.length > 10) { skipped++; continue; }
        if (dry) { embedded++; continue; }
        try {
            const text: string = data.content?.slice(0, 3000) || '';
            if (!text) { skipped++; continue; }
            const emb = await client.embeddings.create({ model: 'text-embedding-3-small', input: text });
            const vector = emb.data?.[0]?.embedding;
            if (Array.isArray(vector)) {
                await doc.ref.set({ embedding: vector, embeddingModel: 'text-embedding-3-small', embeddingUpdatedAt: new Date() }, { merge: true });
                embedded++;
            } else { skipped++; }
        } catch (e: any) {
            errors++;
            if ((e.message || '').includes('rate limit')) {
                await new Promise(r => setTimeout(r, 4000));
            }
        }
    }
    return { processed, embedded, skipped, errors };
}

async function run() {
    const { uid, collection, limit, dry } = parseArgs();
    if (!uid) { console.error('Missing --uid'); process.exit(1); }
    if (process.env.RANKPILOT_ENABLE_EMBEDDINGS !== '1') {
        console.warn('RANKPILOT_ENABLE_EMBEDDINGS not set to 1; proceeding anyway (override)');
    }
    const res = await backfill({ uid, collection: collection || 'default', limit: limit || 250, dry: !!dry });
    console.log('Backfill summary:', res);
}

run().catch(e => { console.error(e); process.exit(1); });

import type { ServiceAccount } from 'firebase-admin/app';
import { initializeApp, cert } from 'firebase-admin/app';
import { getFirestore } from 'firebase-admin/firestore';
import fs from 'fs';

let appInited = false;
function init() {
    if (appInited) return;
    try {
        const raw = fs.readFileSync('serviceAccount.json', 'utf8');
        const sa = JSON.parse(raw) as ServiceAccount;
        initializeApp({ credential: cert(sa) });
        appInited = true;
    } catch (e) {
        console.error('Failed to initialize Firebase Admin (missing serviceAccount.json)', e);
        process.exit(1);
    }
}

async function run() {
    init();
    const db = getFirestore();
    const teamsSnap = await db.collection('teams').get();
    let processed = 0;
    for (const doc of teamsSnap.docs) {
        const data: any = doc.data();
        const members: any[] = Array.isArray(data.members) ? data.members : [];
        if (!members.length) continue;
        const subSnap = await db.collection('teams').doc(doc.id).collection('members').limit(1).get();
        if (!subSnap.empty) continue;
        for (const m of members) {
            const id = m.userId || m.id || m.email;
            if (!id) continue;
            await db.collection('teams').doc(doc.id).collection('members').doc(id).set({
                userId: m.userId || null,
                email: m.email || null,
                role: m.role || 'member',
                status: m.status || 'active',
                name: m.name || null,
                avatar: m.avatar || null,
                joinedAt: m.joinedAt || new Date(),
                lastActive: m.lastActive || new Date(),
                source: 'backfill_phase2'
            }, { merge: true });
        }
        processed++;
        console.log(`Backfilled team ${doc.id} with ${members.length} members`);
    }
    console.log(`Completed backfill for ${processed} teams.`);
}

run().catch(e => { console.error(e); process.exit(1); });

#!/usr/bin/env node
import fs from 'fs';
