export function getRegistry(): ToolRunner[] {
  const base = [
    OpenAIPlanner, CodexRunner, AiderRunner, MCPFirecrawl, MCPSequential, MCPGitHub, MCPZapier, TerminalRunner,
    TypecheckRunner, ESLintRunner, PlaywrightRunner
  ];
  try {
    const plugins = loadPlugins();
    if (plugins.runners.length) return [...base, ...plugins.runners];
  } catch { }
  return base;
}

export function getRunnersFor(domain: string, cfg?: any): ToolRunner[] {
  const base = getRegistry();
  const byToggle = (r: ToolRunner) => {
    if (!cfg || !cfg.tools) return true;
    const map: Record<string, string> = {
      OpenAIPlanner: 'openaiPlanner', CodexRunner: 'codex', AiderRunner: 'aider', MCPFirecrawl: 'firecrawl', MCPSequential: 'sequential', MCPGitHub: 'github', MCPZapier: 'zapier', TerminalRunner: 'terminal',
      TypecheckRunner: 'typecheck', ESLintRunner: 'eslint', PlaywrightRunner: 'playwright'
    };
    const key = map[r.name as keyof typeof map];
    return typeof key === 'string' ? cfg.tools[key] !== false : true;
  };
  return base.filter((r) => r.supports(domain)).filter(byToggle).slice(0, 10);
}

export default { getRegistry, getRunnersFor };

export function splitPlan(steps: any[], cfg: any): any[][] {
  const maxTasks = (cfg?.governance?.maxBatchTasks ?? 10) || 10;
  const splitLoc = (cfg?.governance?.splitThresholdLoc ?? 300) || 300;
  const approxLoc = steps.length * 30;
  const chunkSize = Math.min(maxTasks, Math.max(1, Math.floor(splitLoc / 30)));
  if (approxLoc <= splitLoc && steps.length <= maxTasks) return [steps];
  const out: any[][] = [];
  for (let i = 0; i < steps.length; i += chunkSize) out.push(steps.slice(i, i + chunkSize));
  return out;
}

import fs from 'fs';
import path from 'path';
import { collectDiagnostics } from '../diagnostics/collect';
import type { MemoryEvent } from '../state/memory';

let recordMemory: undefined | ((ev: MemoryEvent) => void);
try { recordMemory = require('../state/memory').recordMemory as (ev: MemoryEvent) => void; } catch { }

export interface Mission {
    ts: number;
    summary: string;
    diagnostics: {
        typecheck: { errors: number; rawExcerpt: string };
        lint: { errors: number; warnings: number; rawExcerpt: string };
    };
    immediateSteps: { id: string; title: string; rationale: string }[];
    status: 'active' | 'clean';
}


export function runMissionCycle(): Mission {
    const thinkDir = path.join(process.cwd(), 'artifacts', 'brain');
    fs.mkdirSync(thinkDir, { recursive: true });
    // Preserve previous mission for delta reporting
    try {
        const currentMissionPath = path.join(thinkDir, 'currentMission.json');
        const prevMissionPath = path.join(thinkDir, 'previousMission.json');
        if (fs.existsSync(currentMissionPath)) {
            fs.copyFileSync(currentMissionPath, prevMissionPath);
        }
    } catch { /* ignore */ }

    const diag = collectDiagnostics();
    const missionHistoryFile = path.join(thinkDir, 'mission-history.jsonl');
    const tsErrors = diag.typecheck.errors;
    const lintErrors = diag.lint.errors;
    const lintWarnings = diag.lint.warnings;

    const thoughts: string[] = [];
    thoughts.push(`# Brain Thinking @ ${new Date().toISOString()}`);
    thoughts.push(`TypeScript errors: ${tsErrors}`);
    thoughts.push(`ESLint errors: ${lintErrors}, warnings: ${lintWarnings}`);
    if (tsErrors > 0) thoughts.push('Observation: Type errors present; prioritizing type stability.');
    if (lintErrors > 0) thoughts.push('Observation: Lint errors degrade code health; auto-fix recommended.');
    if (lintWarnings > 100) thoughts.push('Observation: High warning volume; consider rule refinement or batch suppression strategy.');

    const immediateSteps: Mission['immediateSteps'] = [];
    if (tsErrors > 0) immediateSteps.push({ id: 'fix-types', title: 'Resolve top TypeScript errors', rationale: 'Type stability prerequisite for further refactors.' });
    if (lintErrors > 0) immediateSteps.push({ id: 'lint-autofix', title: 'Run ESLint autofix for safe rules', rationale: 'Reduce toil and surface structural issues.' });
    if (lintWarnings > 0 && lintWarnings <= 200) immediateSteps.push({ id: 'lint-triage', title: 'Triage remaining lint warnings', rationale: 'Convert noisy rules or batch address readability issues.' });
    // Derive top offending TS error files for targeted steps (first 3 unique files)
    if (tsErrors > 0) {
        try {
            const lines = diag.typecheck.rawExcerpt.split(/\n/);
            const fileRe = /(\S+\.ts)\((\d+),(\d+)\): error TS\d+:/;
            const files: string[] = [];
            for (const l of lines) {
                const m = l.match(fileRe);
                if (m) {
                    const f = m[1];
                    if (!files.includes(f)) files.push(f);
                    if (files.length >= 3) break;
                }
            }
            files.forEach((f, idx) => immediateSteps.push({ id: `fix-ts-${idx + 1}`, title: `Fix TS errors in ${f}`, rationale: 'Reduce compiler error count for stability.' }));
        } catch { /* ignore */ }
    }
    if (!immediateSteps.length) thoughts.push('System clean: no immediate remediation required.');

    const mission: Mission = {
        ts: Date.now(),
        summary: immediateSteps.length ? 'Remediation required' : 'Codebase clean',
        diagnostics: {
            typecheck: { errors: tsErrors, rawExcerpt: diag.typecheck.rawExcerpt },
            lint: { errors: lintErrors, warnings: lintWarnings, rawExcerpt: diag.lint.rawExcerpt }
        },
        immediateSteps,
        status: immediateSteps.length ? 'active' : 'clean'
    };

    const thinkingFile = path.join(thinkDir, 'brainThinking.txt');
    fs.appendFileSync(thinkingFile, thoughts.join('\n') + '\n\n');
    const thinkingJsonl = path.join(thinkDir, 'brainThinking.jsonl');
    fs.appendFileSync(thinkingJsonl, JSON.stringify({ ts: mission.ts, thoughts, metrics: { tsErrors, lintErrors, lintWarnings } }) + '\n');

    const missionFile = path.join(thinkDir, 'currentMission.json');
    fs.writeFileSync(missionFile, JSON.stringify(mission, null, 2));
    // Append concise history line
    try { fs.appendFileSync(missionHistoryFile, JSON.stringify({ ts: mission.ts, tsErrors, lintErrors, lintWarnings, steps: mission.immediateSteps.length }) + '\n'); } catch { }

    try { recordMemory && recordMemory({ ts: mission.ts, source: 'brain', kind: 'mission-set', status: mission.status, meta: { tsErrors, lintErrors, lintWarnings, steps: mission.immediateSteps.length } }); } catch { }

    // Optional: enqueue immediate steps into delegation queue with lineage (mission id)
    if (process.env.BRAIN_ENQUEUE_MISSION_STEPS === '1' && mission.immediateSteps.length) {
        try {
            const queueFile = 'sessions/aider-queue.jsonl';
            const nowIso = new Date(mission.ts).toISOString();
            if (!fs.existsSync(queueFile)) {
                fs.mkdirSync('sessions', { recursive: true });
                fs.writeFileSync(queueFile, JSON.stringify({ meta: 'delegation queue (JSON Lines). Each line: pending task.' }) + '\n');
            }
            const existing = fs.readFileSync(queueFile, 'utf8').trim().split(/\n/).slice(1).map((l: string) => { try { return JSON.parse(l); } catch { return null; } }).filter(Boolean);
            const existingIds = new Set(existing.map((t: any) => t.taskId));
            const lineage = 'MISSION-' + mission.ts;
            const newLines: string[] = [];
            mission.immediateSteps.forEach((step, idx) => {
                const taskId = `${lineage}-S${idx + 1}`;
                if (existingIds.has(taskId)) return;
                const task = {
                    taskId,
                    summary: `[Mission] ${step.title}`,
                    files: [],
                    status: 'pending',
                    createdAt: nowIso,
                    updatedAt: nowIso,
                    lineage: { missionTs: mission.ts, missionSummary: mission.summary, stepId: step.id }
                };
                newLines.push(JSON.stringify(task));
            });
            if (newLines.length) fs.appendFileSync(queueFile, newLines.join('\n') + '\n');
            try { recordMemory && recordMemory({ ts: Date.now(), source: 'brain', kind: 'mission-enqueue', status: 'ok', meta: { lineage, enqueued: newLines.length } }); } catch { }
        } catch { /* swallow */ }
    }

    return mission;
}

export default { runMissionCycle };

import fs from 'fs';
import OpenAI from 'openai';
import path from 'path';
import type { Task } from '../../../types/brain';
import { sampleContext } from '../core/contextSampler';
import type { NormalizedStep } from './stepSchema';
import { normalizeSteps } from './stepSchema';

// Minimal shapes to avoid pervasive `any` usage.
interface MissionDiagnostics { typecheck?: { errors?: number }; lint?: { errors?: number; warnings?: number }; }
interface MissionLike { summary?: string; diagnostics?: MissionDiagnostics; immediateSteps?: { title: string; rationale: string }[] }
interface MemoryEventLike { source?: string; kind?: string; status?: string; id?: string }
export interface BrainPlan { steps: NormalizedStep[] | { kind: string; taskId: string; domain: string; contextNote?: string }[]; strategy: 'openai' | 'heuristic'; meta?: { model?: string; promptTokens?: number; completionTokens?: number; totalTokens?: number; fallback?: boolean } }

function loadMission(): MissionLike | undefined {
  try {
    const f = path.join(process.cwd(), 'artifacts/brain/currentMission.json');
    if (fs.existsSync(f)) return JSON.parse(fs.readFileSync(f, 'utf8')) as MissionLike;
  } catch (_err) { /* ignore errors reading mission */ }
  return undefined;
}

function loadRecentMemory(limit = 40): MemoryEventLike[] {
  try {
    const f = path.join(process.cwd(), 'artifacts/brain/memory.jsonl');
    if (!fs.existsSync(f)) return [] as MemoryEventLike[];
    const lines = fs.readFileSync(f, 'utf8').trim().split(/\n/).slice(-limit);
    return lines
      .map(l => { try { return JSON.parse(l) as MemoryEventLike; } catch (_err) { return null; } })
      .filter((v): v is MemoryEventLike => Boolean(v));
  } catch (_err) { return []; }
}

export function plan(batch: Task[], opts?: { contextKb?: number }): BrainPlan {
  const ctx = sampleContext(opts?.contextKb ?? 8);
  const mem = loadRecentMemory();
  const mission = loadMission();
  const tsErrors = mission?.diagnostics?.typecheck?.errors;
  const lintErrors = mission?.diagnostics?.lint?.errors;
  const lintWarnings = mission?.diagnostics?.lint?.warnings;
  // Prioritize failed codex tasks from memory
  const failedIds = new Set(mem.filter(m => m.kind === 'task-complete' && m.status === 'fail').map(m => m.id).filter((v): v is string => Boolean(v)));
  const prioritized = [...batch.filter(b => failedIds.has(b.id)), ...batch.filter(b => !failedIds.has(b.id))];
  const diagNote = (tsErrors !== undefined) ? ` diag:ts=${tsErrors},lintE=${lintErrors},lintW=${lintWarnings}` : '';
  const forceCodex = process.env.BRAIN_FORCE_CODEX === '1';
  const steps = prioritized.map((t) => ({ kind: 'do-task', taskId: t.id, domain: t.domain || 'docs', contextNote: `files:${ctx.files.length}${diagNote}`, runners: forceCodex ? ['codex'] : undefined }));
  return { steps, strategy: 'heuristic' };
}

export function savePlanText(runId: string, planObj: unknown): void {
  try {
    const dir = path.join(process.cwd(), 'artifacts', 'brain');
    fs.mkdirSync(dir, { recursive: true });
    fs.writeFileSync(path.join(dir, `plan-${runId}.txt`), typeof planObj === 'string' ? planObj : JSON.stringify(planObj, null, 2));
  } catch (_err) { /* ignore write errors */ }
}

interface PlannerCfg { tools?: Record<string, unknown>; tokens?: { plannerModel?: string; temperature?: number };[k: string]: unknown }
export async function planWithOpenAI(batch: Task[], cfg: PlannerCfg, ctxKb = 8): Promise<BrainPlan> {
  // Fallback: if primary key missing but GPT5 specific present, map it (in‑process only)
  if (!process.env.OPENAI_API_KEY && process.env.OPENAI_GPT5_KEY) {
    process.env.OPENAI_API_KEY = process.env.OPENAI_GPT5_KEY;
  }
  const use = Boolean(cfg?.tools && (cfg.tools as Record<string, unknown>).openaiPlanner) && process.env.OPENAI_API_KEY && process.env.BRAIN_USE_OPENAI === '1';
  if (process.env.BRAIN_PLANNER_DEBUG === '1') {
    try {
      console.log(`[planner:openai] useFlag=${process.env.BRAIN_USE_OPENAI} keyPresent=${!!process.env.OPENAI_API_KEY} keyLen=${(process.env.OPENAI_API_KEY || '').length} gpt5Len=${(process.env.OPENAI_GPT5_KEY || '').length} orgLen=${(process.env.OPENAI_ORGANIZATION || '').length} model=${process.env.BRAIN_OPENAI_MODEL || cfg?.tokens?.plannerModel || 'gpt-4o-mini'} temp=${cfg?.tokens?.temperature ?? 0.2}`);
    } catch (_err) { /* ignore logging errors */ }
  }
  if (!use && process.env.BRAIN_FORCE_OPENAI_STRATEGY !== '1') return plan(batch, { contextKb: ctxKb });
  const mem = loadRecentMemory();
  const ctx = sampleContext(ctxKb);
  const mission = loadMission();
  const missionLines = mission ? [
    'Mission summary: ' + mission.summary + ` (tsErrors=${mission.diagnostics?.typecheck?.errors}, lintErrors=${mission.diagnostics?.lint?.errors}, lintWarnings=${mission.diagnostics?.lint?.warnings})`,
    'Immediate mission steps:',
    ...(mission.immediateSteps || []).slice(0, 3).map((s, i: number) => `  ${i + 1}. ${s.title} :: ${s.rationale}`)
  ] : ['Mission summary: none'];
  const prompt = [
    'You are the RankPilot Brain planner. Generate ordered atomic remediation steps.',
    'Context notes:',
    ...ctx.notes,
    ...missionLines,
    'Recent memory events:',
    ...mem.slice(-10).map(m => ` - ${m.source}:${m.kind}:${m.status || ''}:${m.id || ''}`),
    'Tasks (include a concise files array suggestion referencing likely touched repo-relative paths; omit files only if purely conceptual):',
    ...batch.map(t => ` - (${t.id}) ${t.title} [domain=${t.domain}]`),
    'Return ONLY a JSON array of steps: [{"taskId":"id","kind":"do-task","runners":["codex"],"reason":"why","files":["src/..","scripts/..." ]}]',
    'Rules:',
    ' - Prefer ≤4 files per step; if many, split into multiple steps each with ≤4 files',
    ' - Use exact existing paths; do not invent directories',
    ' - If task is documentation-only, point to relevant .md file under docs/ or README.md',
    ' - If unsure of exact file, pick the most central candidate (e.g., src/lib/..., or scripts/... )'
  ].join('\n');
  try {
    const client = new OpenAI({ apiKey: process.env.OPENAI_API_KEY!, organization: process.env.OPENAI_ORGANIZATION });
    const model = process.env.BRAIN_OPENAI_MODEL || cfg.tokens?.plannerModel || 'gpt-4o-mini';
    const temperature = cfg.tokens?.temperature ?? 0.2;
    const resp = await client.chat.completions.create({
      model,
      messages: [
        { role: 'system', content: 'You are an expert software planner. Output ONLY a JSON array of planning steps. No commentary.' },
        { role: 'user', content: prompt }
      ],
      temperature
    });
    const raw = resp.choices?.[0]?.message?.content || '';
    let text = raw.trim();
    // Strip code fences
    const fence = text.match(/```(?:json)?([\s\S]*?)```/i);
    if (fence) text = fence[1].trim();
    // Attempt direct JSON parse; fall back to extracting first array substring
    let parsed: unknown[] = [];
    const tryParse = (s: string): unknown[] | undefined => { try { const v = JSON.parse(s); if (Array.isArray(v)) return v; } catch (_err) { /* ignore JSON parse errors */ } return undefined; };
    parsed = tryParse(text) || [];
    if (!parsed.length) {
      const start = text.indexOf('[');
      if (start >= 0) {
        let depth = 0; let buf = '';
        for (let i = start; i < text.length; i++) {
          const ch = text[i];
          buf += ch;
          if (ch === '[') depth++;
          else if (ch === ']') { depth--; if (depth === 0) break; }
        }
        if (buf.endsWith(']')) parsed = tryParse(buf) || [];
      }
    }
    if (!parsed.length) console.error('[planner:openai] parse-fail; rawLen=', raw.length);
    if (!Array.isArray(parsed) || !parsed.length) {
      if (process.env.BRAIN_FORCE_OPENAI_STRATEGY === '1') {
        const fb = plan(batch, { contextKb: ctxKb });
        return { steps: fb.steps as NormalizedStep[], strategy: 'openai' };
      }
      return plan(batch, { contextKb: ctxKb });
    }
    // Attach files from parsed if provided
    const parsedArr = Array.isArray(parsed) ? parsed as any[] : [];
    const { steps, errors } = normalizeSteps(parsedArr, batch);
    // Map files into steps (extend NormalizedStep at runtime with files for enqueue path)
    const stepFilesMap: Record<string, string[] | undefined> = {};
    for (const p of parsedArr) {
      if (p && typeof p === 'object' && p.taskId && Array.isArray(p.files)) {
        stepFilesMap[p.taskId] = p.files.filter((f: string) => typeof f === 'string' && f.length < 260);
      }
    }
    // Simple file existence filter (keep only existing or plausible src/ docs/ scripts/ paths)
    const exists = (p: string) => { try { return fs.existsSync(path.join(process.cwd(), p)); } catch (_err) { return false; } };
    for (const s of steps as any[]) {
      const cand = stepFilesMap[s.taskId];
      if (cand && cand.length) {
        s.files = cand.filter(f => /^(src|scripts|docs|functions|package\.json|README\.md)/.test(f) && (exists(f) || /package\.json|README\.md$/.test(f))).slice(0, 4);
      }
    }
    if (process.env.BRAIN_PLANNER_DEBUG === '1' && errors.length) {
      console.warn('[planner:openai] step schema issues:', errors.join('; '));
    }
    const usage = resp.usage || {} as { prompt_tokens?: number; completion_tokens?: number; total_tokens?: number };
    const meta = { model, promptTokens: usage.prompt_tokens, completionTokens: usage.completion_tokens, totalTokens: usage.total_tokens };
    return { steps, strategy: 'openai', meta };
  } catch (e) {
    const msg = (e && typeof e === 'object' && 'message' in e) ? (e as { message?: string }).message : String(e);
    console.error('[planner:openai] error -> fallback:', msg);
    if (process.env.BRAIN_FORCE_OPENAI_STRATEGY === '1') {
      const fb = plan(batch, { contextKb: ctxKb });
      return { steps: fb.steps as NormalizedStep[], strategy: 'openai', meta: { fallback: true, model: (process.env.BRAIN_OPENAI_MODEL as string) || (cfg as PlannerCfg).tokens?.plannerModel || 'gpt-4o-mini' } };
    }
    return plan(batch, { contextKb: ctxKb });
  }
}

export default { plan };

// Step schema validation & normalization for planner output
import type { Task } from '../../../types/brain';

export interface RawStep { taskId?: string; id?: string; kind?: string; runners?: string[]; reason?: string; domain?: string; }
export interface NormalizedStep { taskId: string; kind: string; runners: string[]; domain: string; reason?: string; }

const VALID_KINDS = new Set(['do-task']);
const VALID_RUNNERS = new Set(['codex', 'aider']);
// If set, always prefer codex (disables aider selection even for docs domains)
const FORCE_CODEX = process.env.BRAIN_FORCE_CODEX === '1';

export function assignRunners(domain: string, requested?: string[] | undefined): string[] {
    if (FORCE_CODEX) return ['codex'];
    const filtered = (requested || []).filter(r => VALID_RUNNERS.has(r));
    if (filtered.length) return filtered;
    // Previously docs defaulted to 'aider'; we now converge on 'codex' unless explicitly requested.
    if (/front|back|infra|ops|data|doc/i.test(domain)) return ['codex'];
    return ['codex'];
}

export function normalizeSteps(raw: any[], batch: Task[]): { steps: NormalizedStep[]; errors: string[] } {
    const errors: string[] = [];
    const steps: NormalizedStep[] = [];
    const seen = new Set<string>();
    for (const r of raw as RawStep[]) {
        const taskId = r.taskId || r.id;
        if (!taskId) { errors.push('missing taskId'); continue; }
        if (seen.has(taskId)) continue; seen.add(taskId);
        const task = batch.find(b => b.id === taskId);
        const domain = r.domain || task?.domain || 'docs';
        const kind = VALID_KINDS.has(r.kind || '') ? (r.kind as string) : 'do-task';
        const runners = assignRunners(domain, r.runners);
        steps.push({ taskId, kind, runners, domain, reason: r.reason });
    }
    return { steps, errors };
}

export default { normalizeSteps, assignRunners };

import fs from 'fs';
import path from 'path';
import type { ToolRunner } from '../../../types/brain';

export interface BrainPluginModule {
    runners?: ToolRunner[];
    validators?: Array<(ctx: any) => Promise<{ name: string; status: string; note?: string }>>;
}

export interface LoadedPlugins {
    runners: ToolRunner[];
    validators: BrainPluginModule['validators'];
    names: string[];
}

export function loadPlugins(): LoadedPlugins {
    // Detect whether we're executing from the compiled dist output or directly from TS sources.
    // When compiled, this file lives at dist/brain/scripts/brain/plugins/index.js and __dirname points there.
    // In that scenario we must NOT attempt to require .ts source files (Node cannot parse TS) – instead load the .js artifacts.
    const compiledDirCandidate = __dirname; // if running from dist this exists with .js files
    const sourceDirCandidate = path.join(process.cwd(), 'scripts', 'brain', 'plugins');
    const runningFromDist = /dist[\\/ ]brain[\\/ ]/.test(compiledDirCandidate) && fs.existsSync(path.join(compiledDirCandidate, 'index.js'));
    const dir = runningFromDist && fs.existsSync(compiledDirCandidate)
        ? compiledDirCandidate
        : sourceDirCandidate;

    let runners: ToolRunner[] = [];
    let validators: LoadedPlugins['validators'] = [];
    const names: string[] = [];
    try {
        // Only include .ts plugins when running directly from sources (dev / ts-node scenario)
        const allowTs = !runningFromDist;
        const files = fs.readdirSync(dir).filter(f => (
            f.endsWith('.plugin.js') || (allowTs && f.endsWith('.plugin.ts'))
        ));
        for (const f of files) {
            if (f === 'index.ts' || f === 'index.js') continue;
            try {
                const full = path.join(dir, f);
                const mod = require(full) as BrainPluginModule;
                if (mod.runners?.length) runners.push(...mod.runners);
                if (mod.validators?.length) validators.push(...mod.validators);
                names.push(f.replace(/\.(plugin\.ts|plugin\.js)$/, ''));
            } catch (e) {
                names.push('error:' + f);
                console.error('[plugins] failed to load module', f, e);
            }
        }
    } catch (e) {
        // Swallow directory read errors silently; absence of plugins is acceptable.
        console.error('[plugins] plugin directory read failed', (e as Error).message);
    }
    return { runners, validators, names };
}

export default { loadPlugins };

