 */
import { spawnSync } from 'child_process';
import { existsSync, mkdirSync, readFileSync, writeFileSync } from 'fs';
import path from 'path';

function runInherit(cmd: string, args: string[]) {
    const res = spawnSync(cmd, args, { stdio: 'inherit' });
    return res.status === 0;
}

function runCapture(cmd: string, args: string[]) {
    const res = spawnSync(cmd, args, { encoding: 'utf8' });
    return { ok: res.status === 0, stdout: res.stdout || '', stderr: res.stderr || '' };
}

function main() {
    const intervalMs = Number(process.env.TWO_AGENT_INTERVAL_MS || 120000); // 2 min default
    const drain = process.env.TWO_AGENT_DRAIN === '1';
    if (process.env.TWO_AGENT_ONCE === '1' || drain) {
        runDrainLoop({ drain });
        return;
    }
    console.log(`[two-agent:watch] starting interval=${intervalMs}ms`);
    setInterval(() => runDrainLoop({ drain: false }), intervalMs);
    runDrainLoop({ drain: false });
}

interface DrainOptions { drain: boolean }

function runDrainLoop(opts: DrainOptions) {
    const {
        TWO_AGENT_AUTOFIX_FIRST,
        TWO_AGENT_SELF_PROCESS,
        TWO_AGENT_SELF_PROCESS_ROUNDS,
        TWO_AGENT_MAX_DRAIN_CYCLES
    } = process.env as Record<string, string | undefined>;

    const maxDrainCycles = Number(TWO_AGENT_MAX_DRAIN_CYCLES || 20);
    const selfProcessRounds = Number(TWO_AGENT_SELF_PROCESS_ROUNDS || 3);

    let cycleIndex = 0;
    while (true) {
        cycleIndex++;
        console.log(`[two-agent:watch] === DrainCycle ${cycleIndex} ===`);
        if (TWO_AGENT_AUTOFIX_FIRST === '1') {
            console.log('[two-agent:watch] running eslint autofix pass...');
            runInherit('npm', ['run', 'eslint:autofix-all']);
        }
        const issuesBefore = generateLintReportGetCount();
        console.log(`[two-agent:watch] issues before planning: ${issuesBefore}`);
        const planResult = runPlanningCycle();
        if (planResult && planResult.planned && TWO_AGENT_SELF_PROCESS === '1') {
            for (let i = 0; i < selfProcessRounds; i++) {
                console.log(`[two-agent:watch] self-processing delegation queue round ${i + 1}/${selfProcessRounds}`);
                const handled = runInherit('npm', ['run', 'delegation:process']);
                if (!handled) break;
            }
        }
        const issuesAfter = generateLintReportGetCount();
        console.log(`[two-agent:watch] issues after processing: ${issuesAfter}`);
        const improved = issuesAfter < issuesBefore;
        if (!opts.drain) break;
        if (issuesAfter === 0) {
            console.log('[two-agent:watch] all lint issues resolved. Exiting drain loop.');
            break;
        }
        if (!improved && (planResult?.planned || 0) === 0) {
            console.log('[two-agent:watch] no improvements and no new tasks; stopping to avoid churn.');
            break;
        }
        if (cycleIndex >= maxDrainCycles) {
            console.log('[two-agent:watch] reached max drain cycles limit.');
            break;
        }
    }
}

function runPlanningCycle() {
    console.log('[two-agent:watch] planning remediation tasks...');
    const cycle = runCapture('npm', ['run', '--silent', 'brain:two-agent:lint-cycle']);
    if (!cycle.ok) {
        console.warn('[two-agent:watch] planning cycle failed');
        if (cycle.stderr) console.warn(cycle.stderr.trim());
        return undefined;
    }
    const lines = cycle.stdout.trim().split(/\r?\n/);
    const last = lines.reverse().find(l => l.trim().startsWith('{') && l.trim().endsWith('}'));
    if (!last) {
        console.warn('[two-agent:watch] no JSON line detected in cycle output');
        return undefined;
    }
    try {
        const parsed = JSON.parse(last);
        summarizeCycle(parsed);
        return parsed;
    } catch (e) {
        console.warn('[two-agent:watch] failed to parse JSON output', (e as any)?.message);
        return undefined;
    }
}

function generateLintReportGetCount(): number {
    console.log('[two-agent:watch] generating lint report...');
    runInherit('npm', ['run', 'lint:report:json']);
    try {
        const raw = readFileSync('artifacts/eslint-report.json', 'utf8');
        const data = JSON.parse(raw);
        if (!Array.isArray(data)) return 0;
        let total = 0;
        for (const fileRes of data) {
            if (fileRes && Array.isArray(fileRes.messages)) total += fileRes.messages.length;
        }
        return total;
    } catch {
        return 0;
    }
}

function summarizeCycle(result: any) {
    const { planned, drift, adaptiveMax, considered, skippedDueToHash } = result || {};
    const summary = {
        planned, drift, adaptiveMax, considered, skippedDueToHash,
        taskIds: Array.isArray(result?.taskIds) ? result.taskIds : undefined,
        timestamp: result?.timestamp || new Date().toISOString()
    };
    const concise = `[two-agent:watch] cycle planned=${planned} drift=${drift ?? 'n/a'} adaptiveMax=${adaptiveMax ?? 'n/a'} considered=${considered ?? 'n/a'}${skippedDueToHash ? ' (skippedDueToHash)' : ''}`;
    if (!process.env.TWO_AGENT_JSON_ONLY) console.log(concise);
    try {
        const artifactsDir = path.resolve('artifacts');
        if (!existsSync(artifactsDir)) mkdirSync(artifactsDir, { recursive: true });
        writeFileSync(path.join(artifactsDir, 'two-agent-last-cycle.json'), JSON.stringify(summary, null, 2));
    } catch { /* ignore */ }
    if (process.env.TWO_AGENT_EMIT_JSON_LINE === '1') {
        process.stdout.write(`${JSON.stringify(summary)}\n`);
    }
}

if (require.main === module) main();

#!/usr/bin/env ts-node
/** Cleanup Job: Prune Accepted / Expired Invites & Index Docs
 * Purpose: Reduce storage + keep invites_index lean.
 * Behavior:
 * 1. Mark pending invites whose expiresAt < now as status='expired' (if not already accepted/expired).
 * 2. Delete accepted invites older than ACCEPTED_RETENTION_DAYS (default 30) and their index docs.
 * 3. Delete expired invites older than EXPIRED_RETENTION_DAYS (default 14) and their index docs.
 * 4. Remove orphan index docs referencing missing invite docs.
 * Environment: Requires Firebase Admin initialized (uses src/lib/firebase-admin.ts)
 * Safe to run idempotently.
 */
// Using relative import to avoid ts-node path mapping issues in standalone script execution
import { adminDb } from '../src/lib/firebase-admin';
import { recordInviteMaintenance } from '../src/lib/metrics/unified-metrics';

const ACCEPTED_RETENTION_DAYS = Number(process.env.INVITES_ACCEPTED_RETENTION_DAYS || 30);
const EXPIRED_RETENTION_DAYS = Number(process.env.INVITES_EXPIRED_RETENTION_DAYS || 14);

function days(ms: number) { return ms / (1000 * 60 * 60 * 24); }

async function run() {
    const now = Date.now();
    let markedExpired = 0, deletedAccepted = 0, deletedExpired = 0, orphanIndexes = 0;
    const teams = await adminDb.collection('teams').get();
    for (const t of teams.docs) {
        const invitesSnap = await adminDb.collection('teams').doc(t.id).collection('invites').get();
        for (const inv of invitesSnap.docs) {
            const data: any = inv.data();
            const expiresAt = data.expiresAt?.toDate ? data.expiresAt.toDate().getTime() : (data.expiresAt instanceof Date ? data.expiresAt.getTime() : undefined);
            if (data.status === 'pending' && expiresAt && expiresAt < now) {
                await inv.ref.update({ status: 'expired', expiredAt: new Date() });
                await adminDb.collection('invites_index').doc(inv.id).set({ status: 'expired', updatedAt: new Date() }, { merge: true });
                markedExpired++;
            }
            if (data.status === 'accepted') {
                const acceptedAt = data.acceptedAt?.toDate ? data.acceptedAt.toDate().getTime() : (data.acceptedAt instanceof Date ? data.acceptedAt.getTime() : 0);
                if (acceptedAt && days(now - acceptedAt) > ACCEPTED_RETENTION_DAYS) {
                    await inv.ref.delete();
                    await adminDb.collection('invites_index').doc(inv.id).delete().catch(() => { });
                    deletedAccepted++;
                }
            } else if (data.status === 'expired') {
                const expiredAt = data.expiredAt?.toDate ? data.expiredAt.toDate().getTime() : (data.expiredAt instanceof Date ? data.expiredAt.getTime() : (expiresAt || 0));
                if (expiredAt && days(now - expiredAt) > EXPIRED_RETENTION_DAYS) {
                    await inv.ref.delete();
                    await adminDb.collection('invites_index').doc(inv.id).delete().catch(() => { });
                    deletedExpired++;
                }
            }
        }
    }
    // Orphan indexes
    const indexSnap = await adminDb.collection('invites_index').get();
    for (const idx of indexSnap.docs) {
        const teamId = (idx.data() as any).teamId;
        if (!teamId) { orphanIndexes++; await idx.ref.delete().catch(() => { }); continue; }
        const invDoc = await adminDb.collection('teams').doc(teamId).collection('invites').doc(idx.id).get();
        if (!invDoc.exists) { await idx.ref.delete().catch(() => { }); orphanIndexes++; }
    }
    recordInviteMaintenance({ markedExpired, deletedAccepted, deletedExpired, orphanIndexes });
    console.log(JSON.stringify({ markedExpired, deletedAccepted, deletedExpired, orphanIndexes }, null, 2));
}

run().catch(e => { console.error('cleanup-invites error', e); process.exit(1); });

#!/usr/bin/env node
/**
 * prune-unused-vars.js
 * Dry-run friendly codemod that removes safe, clearly unused local variables & function parameters.
 * Safety heuristics:
 *  - Only acts on .ts / .tsx files (skip d.ts) inside src/ excluding test & story files.
 *  - Ignores exported declarations (looks for export keyword on same line).
 *  - Ignores React component first param (props) even if unused.
 *  - Skips any identifier starting with _ (conventionally intentional ignore).
 *  - Removes simple variable declarators "const foo = ...;" where foo never referenced.
 *  - Removes function parameters that are trailing and unused.
 *  - Dry-run by default: set APPLY=1 env to write changes.
 */
import fs from 'node:fs';
import path from 'node:path';

const root = process.cwd();
const APPLY = process.env.APPLY === '1';

const targetDirs = [path.join(root,'src')];
const exts = new Set(['.ts','.tsx']);

function walk(dir, acc){
  for(const e of fs.readdirSync(dir,{withFileTypes:true})){
    if(e.name.startsWith('.')) continue;
    const full = path.join(dir,e.name);
    if(e.isDirectory()) { walk(full,acc); continue; }
    const ext = path.extname(e.name);
    if(!exts.has(ext)) continue;
    if(e.name.endsWith('.d.ts')) continue;
    if(/(\.test|\.spec|stories)\./.test(e.name)) continue;
    acc.push(full);
  }
  return acc;
}

function collectRefs(code){
  const refs = new Set();
  // crude identifier match (skip keywords)
  const re = /\b([a-zA-Z_$][\w$]*)\b/g;
  const keywords = new Set(['if','for','while','return','const','let','var','function','class','switch','case','break','import','from','export','default','extends','implements','new','try','catch','finally','throw','await','async','type','interface']);
  let m; while((m=re.exec(code))){ if(!keywords.has(m[1])) refs.add(m[1]); }
  return refs;
}

function processFile(file){
  const original = fs.readFileSync(file,'utf8');
  const lines = original.split(/\n/);
  const refs = collectRefs(original);
  const changes = [];
  let modified = false;
  // Pass 1: variable declarators
  for(let i=0;i<lines.length;i++){
    const line = lines[i];
    if(/export\s+/.test(line)) continue; // exported surface
    // const foo = / let foo = / var foo =
    const m = /^(\s*)(const|let|var)\s+([a-zA-Z_$][\w$]*)\s*=/.exec(line);
    if(m){
      const name = m[3];
      if(name.startsWith('_')) continue;
      // ensure appears exactly once (this declarator) in file; remove if unused elsewhere
      let occurrences = 0;
      if (refs.has(name)) {
        const occRe = new RegExp('\\b' + name + '\\b', 'g');
        let mm;
        while ((mm = occRe.exec(original))) {
          occurrences++;
          if (occurrences > 1) break;
        }
      }
      if (occurrences === 1) {
        lines[i] = ''; // remove line
        modified = true;
        changes.push({ type: 'var', name, line: i + 1 });
      }
    }
  }
  // NOTE: Parameter pruning disabled after discovering structural breakage in multi-line / complex signatures.
  // Future iteration could reintroduce with full parser (AST) rather than regex heuristics.
  // (Parameter pruning skipped)
  if(!modified) return null;
  const newContent = lines.join('\n');
  if(APPLY) fs.writeFileSync(file,newContent,'utf8');
  return { file, changes };
}

const files = targetDirs.flatMap(d=> walk(d,[]));
const report = [];
for(const f of files){
  const r = processFile(f);
  if(r) report.push(r);
}

const summary = { filesScanned: files.length, filesModified: report.length, totalRemovals: report.reduce((a,r)=> a + r.changes.length,0), apply: APPLY };
console.log(JSON.stringify(summary));
if(report.length) console.log(JSON.stringify(report,null,2));

