import fs from 'fs';
import path from 'path';
import { readQueue, writeQueue } from './queue-utils';

interface CandidateSpec { taskId: string; summary: string; files: string[]; message?: string; }

const ROOT = process.cwd();
const CHECKLIST = path.resolve(ROOT, 'checkList.txt');

function fileExists(rel: string) { return fs.existsSync(path.resolve(ROOT, rel)); }

const TASK_MAPPINGS: Record<string, () => CandidateSpec | null> = {
