        if (existingIds.has(spec.taskId)) continue;
        // Basic file presence filter: skip if none of the target dir/files exist yet (prevents noise)
        if (!spec.files.some(f => fileExists(f) || f.endsWith('/'))) continue;
        queue.push({
            taskId: spec.taskId,
            summary: spec.summary,
            files: spec.files,
            status: 'pending',
            createdAt: new Date().toISOString(),
            updatedAt: new Date().toISOString(),
            // @ts-ignore
            message: spec.message
        } as any);
        added++;
    }
    if (added) writeQueue(queue);
    console.log(JSON.stringify({ autoEnqueue: { considered: targetIds.length, present: Array.from(present), enqueued: added } }));
}

main();

#!/usr/bin/env ts-node
/**
 * Unified autorun for two-agent planning + queue processing.
 * Steps:
 * 1. Run planning cycle (generates artifacts + enqueues tasks if hash changed).
 * 2. Process delegation queue (autorun mode) for a configurable number of tasks or minutes.
 * 3. Repeat until max iterations or time budget.
 */
import { spawnSync } from 'child_process';
import { existsSync, readFileSync, unlinkSync } from 'fs';

const queueUtils = require('./queue-utils.ts');
const readQueue = queueUtils.readQueue as () => { status: string }[];
// Lazy-load TS module to avoid .js path resolution issues in ts-node NodeNext mode.
async function loadTwoAgent() {
    // Use require to load TS directly; ts-node registers for this script context.

    const mod = require('../../src/lib/brain/supervisor/twoAgentOrchestration.ts');
    return mod.runTwoAgentLintCycle as (opts: { maxTasks?: number }) => Promise<any>;
}

const MAX_ITERS = Number(process.env.TWO_AGENT_AUTORUN_ITERS || 3);
const MAX_MINUTES = Number(process.env.TWO_AGENT_AUTORUN_MINUTES || 10);
const START = Date.now();

function minutesElapsed() { return (Date.now() - START) / 60000; }

const FORCE_REPLAN_AFTER = Number(process.env.TWO_AGENT_FORCE_REPLAN_AFTER || 2); // consecutive zero cycles
const FORCE_REPLAN_QUEUE_MIN = Number(process.env.TWO_AGENT_FORCE_REPLAN_QUEUE_MIN || 5); // pending threshold
const FORCE_REPLAN_ENABLED = process.env.TWO_AGENT_FORCE_REPLAN !== '0';
const LAST_HASH_FILE = '.codex/tmp/two-agent-last-hash.txt';

async function main() {
    let consecutiveZero = 0;
    for (let iter = 1; iter <= MAX_ITERS; iter++) {
        if (minutesElapsed() > MAX_MINUTES) break;
        const runTwoAgentLintCycle = await loadTwoAgent();
        const cycle = await runTwoAgentLintCycle({ maxTasks: Number(process.env.TWO_AGENT_MAX_TASKS || 5) });
        // Always process queue in autorun mode if OPENAI key exists.
        if (process.env.OPENAI_API_KEY || process.env.OPENAI_GPT5_KEY) {
            const res = spawnSync('ts-node', ['-P', 'scripts/tsconfig.json', 'scripts/delegation/process-delegation-queue.ts'], { stdio: 'inherit' });
            if (res.status !== 0) {
                console.warn('[autorun] queue processor exit', res.status);
            }
        } else {
            console.log('[autorun] OPENAI_API_KEY missing; skipping aider run.');
        }
        const remaining = readQueue().filter(t => t.status === 'pending').length;
        console.log(`[autorun] iter=${iter} planned=${cycle.planned} remainingPending=${remaining}`);
        if (cycle.planned === 0) {
            consecutiveZero++;
        } else {
            consecutiveZero = 0;
        }
        // Force replan logic: if queue still large but planner hash unchanged for N consecutive iterations
        if (FORCE_REPLAN_ENABLED && consecutiveZero >= FORCE_REPLAN_AFTER && remaining >= FORCE_REPLAN_QUEUE_MIN) {
            try {
                if (existsSync(LAST_HASH_FILE)) {
                    const prev = readFileSync(LAST_HASH_FILE, 'utf8').trim();
                    unlinkSync(LAST_HASH_FILE);
                    console.log(`[autorun][force-replan] cleared-hash prevHash=${prev} zeroCycles=${consecutiveZero} pending=${remaining} after>=${FORCE_REPLAN_AFTER}`);
                    try { require('fs').appendFileSync('metrics-snapshots.log', `twoAgentForceReplan ${Date.now()} zeroCycles=${consecutiveZero} pending=${remaining} prevHash=${prev}\n`); } catch { /* ignore */ }
                    consecutiveZero = 0; // reset so next iter replans
                }
            } catch (e) {
                console.warn('[autorun] force-replan hash clear failed', (e as any)?.message || e);
            }
        }
        if (!cycle.planned && remaining === 0) break; // nothing new & empty queue
    }
}

main().catch(e => {
    console.error('[autorun] fatal', (e as any)?.message || e);
    process.exit(1);
});

/* Codex concurrent execution loop
   Purpose: Similar to aider delegation loop but allows limited parallel codex-driven executions.
   Concurrency safeguards:
     - Max PARALLEL (env CODEX_MAX_PARALLEL, default 2)
     - Avoid editing same file in two active tasks (simple file lock map)
*/
import { spawn } from 'child_process';
import fs from 'fs';
import path from 'path';
// Queue metrics (best-effort)
// eslint-disable-next-line @typescript-eslint/no-require-imports
let queueMetrics: undefined | { recordQueueStart: (c?: number) => void; recordQueueDone: (success: boolean, c?: number) => void } = (() => { try { return require('../../src/lib/metrics/queue-metrics'); } catch { return undefined; } })();
// Lazy import of memory recorder to avoid hard failure if brain build not present
let recordMemory: undefined | ((ev: any) => void);
try { recordMemory = require('../brain/state/memory').recordMemory; } catch { /* memory layer optional */ }

interface QueueTask { taskId: string; summary: string; files?: string[]; status: string; updatedAt?: string; createdAt?: string }

const QUEUE_FILE = path.resolve('sessions/aider-queue.jsonl');
const LEDGER = path.resolve('.codex/codex-ledger.jsonl');
const PARALLEL = parseInt(process.env.CODEX_MAX_PARALLEL || '2', 10);
const INTERVAL_MS = parseInt(process.env.CODEX_LOOP_INTERVAL || '12000', 10);
const SELECTIVE = process.env.CODEX_SELECTIVE === '1' || process.env.CODEX_SELECTIVE === 'true';
const locks = new Map<string, number>(); // file -> active count
const active = new Map<string, { proc: any; files: string[]; started: number }>();
let lastSnapshotHash = '';
const STALE_MS = parseInt(process.env.CODEX_STALE_MS || '300000', 10); // 5m default
// Optional recycle window for failed tasks (disabled by default). If >0, failed tasks older than this
// age will be set back to pending (respecting a max attempts guard) so the loop can retry tail issues.
const RECYCLE_FAILED_MS = parseInt(process.env.CODEX_RECYCLE_FAILED_MS || '0', 10); // disabled unless set
const MAX_FAILED_ATTEMPTS = parseInt(process.env.CODEX_MAX_FAILED_ATTEMPTS || '2', 10);

function countAttempts(taskId: string): number {
    // Lightweight attempt counter: scan ledger lazily (ledger expected small). If large, could cache.
    try {
        if (!fs.existsSync(LEDGER)) return 0;
        const lines = fs.readFileSync(LEDGER, 'utf8').trim().split(/\n/);
        let c = 0;
        for (const line of lines) {
            try {
                const obj = JSON.parse(line);
                if (obj.taskId === taskId) c++;
            } catch { /* ignore */ }
        }
        return c;
    } catch { return 0; }
}

function readQueue(): QueueTask[] {
    if (!fs.existsSync(QUEUE_FILE)) return [];
    const lines = fs.readFileSync(QUEUE_FILE, 'utf8').trim().split(/\n/);
    const tasks: QueueTask[] = [];
    for (const line of lines.slice(1)) { // skip header
        try { tasks.push(JSON.parse(line)); } catch { /* ignore */ }
    }
    return tasks;
}

function hashTasks(tasks: QueueTask[]) { return tasks.map(t => `${t.taskId}:${t.status}:${t.updatedAt}`).join('|'); }

function writeQueue(tasks: QueueTask[]) {
    if (!fs.existsSync(QUEUE_FILE)) return; // keep format stable (header preserved)
    const raw = fs.readFileSync(QUEUE_FILE, 'utf8').split(/\n/);
    const header = raw[0] || JSON.stringify({ meta: 'delegation queue (JSON Lines). Each line: pending task.' });
    const byId = new Map(tasks.map(t => [t.taskId, t]));
    const out: string[] = [header];
    for (const line of raw.slice(1)) {
        if (!line.trim()) continue;
        try { const obj = JSON.parse(line); if (byId.has(obj.taskId)) out.push(JSON.stringify(byId.get(obj.taskId))); else out.push(line); } catch { out.push(line); }
    }
    fs.writeFileSync(QUEUE_FILE, out.join('\n') + '\n');
}

function acquireFiles(files: string[]): boolean {
    for (const f of files) { if (locks.get(f)) return false; }
    for (const f of files) { locks.set(f, 1); }
    return true;
}
function releaseFiles(files: string[]) { for (const f of files) locks.delete(f); }

function markRunning(task: QueueTask) {
    const tasks = readQueue();
    const now = new Date().toISOString();
    for (const t of tasks) {
        if (t.taskId === task.taskId && t.status === 'pending') { t.status = 'running'; t.updatedAt = now; }
    }
    writeQueue(tasks);
    try { queueMetrics?.recordQueueStart(1); } catch { }
}

function markDone(taskId: string, success: boolean) {
    const tasks = readQueue();
    const now = new Date().toISOString();
    for (const t of tasks) {
        if (t.taskId === taskId && t.status === 'running') { t.status = success ? 'done' : 'failed'; t.updatedAt = now; }
    }
    writeQueue(tasks);
    try { queueMetrics?.recordQueueDone(success, 1); } catch { }
}

function ledger(taskId: string, durationMs: number, success: boolean, meta: any = {}) {
    const line = { ts: Date.now(), taskId, durationMs, success, ...meta };
    fs.appendFileSync(LEDGER, JSON.stringify(line) + '\n');
    try { recordMemory && recordMemory({ ts: Date.now(), source: 'codex', kind: 'task-complete', id: taskId, status: success ? 'ok' : 'fail', meta: { durationMs } }); } catch { }
}

function launch(task: QueueTask) {
    const files = task.files || [];
    if (files.length && !acquireFiles(files)) return false;
    markRunning(task);
    const started = Date.now();
    const cmd = process.env.CODEX_EXEC_CMD || 'npm run delegate:process';
    const parts = cmd.split(/\s+/);
    const proc = spawn(parts.shift()!, parts, { stdio: 'inherit', env: { ...process.env, CODEX_MODE: '1', TARGET_TASK: task.taskId } });
    active.set(task.taskId, { proc, files, started });
    proc.on('exit', (code) => {
        const dur = Date.now() - started;
        if (files.length) releaseFiles(files);
        active.delete(task.taskId);
        markDone(task.taskId, code === 0);
        ledger(task.taskId, dur, code === 0, { parallelRemaining: active.size });
    });
    return true;
}

function cycle() {
    const tasks = readQueue();
    // Recycle stale running tasks with no active process
    const now = Date.now();
    let recycled = false;
    for (const t of tasks) {
        if (t.status === 'running' && !active.has(t.taskId) && t.updatedAt) {
            const age = now - Date.parse(t.updatedAt);
            if (age > STALE_MS) { t.status = 'pending'; t.updatedAt = new Date().toISOString(); recycled = true; try { recordMemory && recordMemory({ ts: Date.now(), source: 'codex', kind: 'task-recycled', id: t.taskId, status: 'pending', meta: { ageMs: age } }); } catch { } }
        }
    }
    // Optional: recycle failed tasks after cooldown if attempts below limit
    if (RECYCLE_FAILED_MS > 0) {
        for (const t of tasks) {
            if (t.status === 'failed' && t.updatedAt) {
                const age = now - Date.parse(t.updatedAt);
                if (age > RECYCLE_FAILED_MS) {
                    const attempts = countAttempts(t.taskId);
                    if (attempts < MAX_FAILED_ATTEMPTS) {
                        t.status = 'pending';
                        t.updatedAt = new Date().toISOString();
                        recycled = true;
                        try { recordMemory && recordMemory({ ts: Date.now(), source: 'codex', kind: 'task-retry', id: t.taskId, status: 'pending', meta: { attempts, ageMs: age } }); } catch { }
                    }
                }
            }
        }
    }
    if (recycled) writeQueue(tasks);
    const hash = hashTasks(tasks);
    if (hash !== lastSnapshotHash) {
        lastSnapshotHash = hash;
        const inst = process.env.CODEX_INSTANCE ? `#${process.env.CODEX_INSTANCE}` : '';
        console.log(`[codex:loop${inst}] snapshot`, tasks.map(t => `${t.taskId}:${t.status}`).join(', '));
    }
    if (active.size >= PARALLEL) return;
    for (const t of tasks) {
        if (active.size >= PARALLEL) break;
        if (t.status !== 'pending') continue;
        if (SELECTIVE) {
            // Only process tasks explicitly tagged for Codex via summary prefix
            if (!t.summary || !t.summary.startsWith('[CODEX]')) continue;
        }
        const files = t.files || [];
        if (!files.length || files.every(f => !locks.get(f))) launch(t);
    }
}

setInterval(cycle, INTERVAL_MS);
cycle();

process.on('SIGINT', () => { console.log('\n[codex:loop] shutdown'); process.exit(0); });

#!/usr/bin/env ts-node
/**
 * Hose / purge delegation queue utility.
 *
 * Examples:
 *  ts-node scripts/delegation/hose-or-purge-queue.ts --hose --match AI-LINT-
 *  ts-node scripts/delegation/hose-or-purge-queue.ts --purge --status failed
 *  ts-node scripts/delegation/hose-or-purge-queue.ts --purge --all
 *
 * Flags:
 *  --hose           Mark matching tasks as done (adds notes hose_close)
 *  --purge          Remove matching tasks entirely
 *  --all            Match all tasks (overrides other match filters)
 *  --match <substr> Substring match on taskId OR summary
 *  --status <s>     Filter by status (pending|running|done|failed)
 *  --olderMinutes N Only match tasks with updatedAt older than N minutes
 *  --dry            Dry run (show counts, no mutation)
 */
// Use require to ensure CommonJS interop in ts-node NodeNext mode (matches other delegation scripts)

const qu = require('./queue-utils.ts') || (globalThis as any).__QUEUE_UTILS__;
import type * as Q from './queue-utils';
const hoseTasks = qu.hoseTasks as Q['hoseTasks'];
const purgeTasks = qu.purgeTasks as Q['purgeTasks'];
const readQueue = qu.readQueue as Q['readQueue'];

interface Args { [k: string]: string | boolean | undefined; }
function parseArgs(): Args {
    const out: Args = {};
    const argv = process.argv.slice(2);
    for (let i = 0; i < argv.length; i++) {
        const a = argv[i];
        if (a.startsWith('--')) {
            const key = a.slice(2);
            const next = argv[i + 1];
            if (next && !next.startsWith('--')) { out[key] = next; i++; }
            else out[key] = true;
        }
    }
    return out;
}

const args = parseArgs();
const doHose = !!args.hose;
const doPurge = !!args.purge;
if (!doHose && !doPurge) {
    console.error('Specify --hose or --purge');
    process.exit(1);
}
const all = !!args.all;
const match = typeof args.match === 'string' ? args.match : undefined;
const status = typeof args.status === 'string' ? args.status : undefined;
const olderMinutes = args.olderMinutes ? Number(args.olderMinutes) : undefined;
const dry = !!args.dry;

const now = Date.now();
const queue = readQueue();
const predicate = (t: any) => {
    if (all) return true;
    if (match && !(t.taskId.includes(match) || (t.summary || '').includes(match))) return false;
    if (status && t.status !== status) return false;
    if (olderMinutes && (now - new Date(t.updatedAt).getTime()) < olderMinutes * 60_000) return false;
    return true;
};

const matches = queue.filter(predicate);
console.log(`Matched ${matches.length} tasks (total ${queue.length}). Mode=${doHose ? 'HOSE' : 'PURGE'}${dry ? ' DRY' : ''}`);
if (dry) process.exit(0);

if (doHose) {
    const updated = hoseTasks(predicate);
    console.log(`Hosed ${updated} tasks.`);
} else if (doPurge) {
    const removed = purgeTasks(predicate);
    console.log(`Purged ${removed} tasks.`);
}

#!/usr/bin/env ts-node
import { execSync, spawnSync } from 'child_process';
import fs from 'fs';
import path from 'path';
// Prefer require for interop; fallback to global attached by queue-utils

const qu = require('./queue-utils.ts') || (globalThis as any).__QUEUE_UTILS__;
const readQueue = qu.readQueue as () => any[];
const writeQueue = qu.writeQueue as (tasks: any[]) => void;

// Lightweight env loader (avoids external dotenv dep). Loads .env.local then .env if present BEFORE key checks.
(() => {
    const candidateFiles = ['.env.local', '.env'];
    for (const file of candidateFiles) {
        try {
            if (!fs.existsSync(file)) continue;
            const content = fs.readFileSync(file, 'utf8');
            for (const lineRaw of content.split(/\n/)) {
                const line = lineRaw.trim();
                if (!line || line.startsWith('#')) continue;
                const eq = line.indexOf('=');
                if (eq === -1) continue;
                const key = line.slice(0, eq).trim();
                // Preserve existing env vars (never overwrite runtime / exported values)
                if (process.env[key] !== undefined) continue;
                let val = line.slice(eq + 1).trim();
                // Strip surrounding quotes if present
                if ((val.startsWith('"') && val.endsWith('"')) || (val.startsWith("'") && val.endsWith("'"))) {
                    val = val.slice(1, -1);
                }
                // Unescape common \n sequences for private keys
                if (val.includes('\\n')) val = val.replace(/\\n/g, '\n');
                process.env[key] = val;
            }
            // Only process first existing file in priority order
        } catch {
            // Silent: env loading is best-effort
        }
    }
})();

// Environment & runtime flags
const AIDER_AUTORUN = process.env.AIDER_AUTORUN === '1';
// Prefer modern OpenAI model names; allow candidate override via AIDER_MODEL_CANDIDATES
const MODEL_CANDIDATES = (process.env.AIDER_MODEL_CANDIDATES || 'gpt-5-mini,gpt-4.1-mini,gpt-4.1,gpt-4o-mini,gpt-4o').split(',').map(s => s.trim()).filter(Boolean);
const MODEL = process.env.AIDER_MODEL || MODEL_CANDIDATES[0] || 'gpt-4.1-mini';
const DRY_RUN = process.env.DRY_RUN === '1';
const RUN_TESTS = process.env.DELEGATION_RUN_TESTS === '1'; // optional post-success quality gate
const TEST_SCRIPT = process.env.DELEGATION_TEST_SCRIPT || 'test:delegation-smoke';
// Permit passing additional non-interactive aider CLI flags (space separated) via AIDER_ARGS
const AIDER_ARGS = (process.env.AIDER_ARGS || '').trim().split(/\s+/).filter(Boolean);
// Convenience: if OPENAI_API_KEY absent but OPENAI_GPT5_KEY present, map it (local only; never persisted)
if (!process.env.OPENAI_API_KEY && process.env.OPENAI_GPT5_KEY) {
    process.env.OPENAI_API_KEY = process.env.OPENAI_GPT5_KEY;
}

// Validation thresholds / policies
// Validation thresholds (restored to baseline after large-file remediation strategy introduced).
// Baseline: single 80KB, aggregate 40KB. Large monolith files can now be processed via
// segmented tasks that specify a line range in the task.message (see validateTask).
const MAX_FILE_BYTES = 80 * 1024; // single file guard (~80KB)
const MAX_AGG_BYTES = 40 * 1024;  // aggregate soft cap (~40KB)
const LOG_ROTATE_BYTES = 200 * 1024; // rotate aide log after 200KB
const EXT_ALLOW = new Set(['.ts', '.tsx', '.js', '.mjs', '.cjs', '.json', '.md', '.yml', '.yaml', '.css']);

// Extend task type at runtime with optional message support (not persisted in strict schema yet)
type DelegationTask = ReturnType<typeof readQueue>[number] & { message?: string };
const tasks = readQueue() as DelegationTask[];
let changed = false;

const LOG_FILE = path.resolve('sessions/aider-log.jsonl');
function appendLog(entry: unknown): void {
    try {
        if (!fs.existsSync(path.dirname(LOG_FILE))) fs.mkdirSync(path.dirname(LOG_FILE), { recursive: true });
        if (!fs.existsSync(LOG_FILE)) {
            fs.writeFileSync(LOG_FILE, JSON.stringify({ meta: 'aider delegation log (JSON Lines). Append one object per completed delegated task; rotate when file >200KB.' }) + '\n');
        }
        fs.appendFileSync(LOG_FILE, JSON.stringify(entry) + '\n');
        // Rotate if oversized
        try {
            const stat = fs.statSync(LOG_FILE);
            if (stat.size > LOG_ROTATE_BYTES) {
                const rotated = LOG_FILE.replace(/\.jsonl$/, '') + `.${Date.now()}.jsonl`;
                fs.renameSync(LOG_FILE, rotated);
                fs.writeFileSync(LOG_FILE, JSON.stringify({ meta: 'aider delegation log (rotated)' }) + '\n');
            }
        } catch { /* noop */ }
    } catch (e) {
        console.error('[delegation] failed to append log', (e as any)?.message);
    }
}

function computeLocDelta(files: string[]): { added: number; removed: number } {
    try {
        // Use git diff --numstat to aggregate changes for the provided files (against HEAD)
        const cmd = `git diff --numstat ${files.map(f => `'${f}'`).join(' ')}`;
        const out = execSync(cmd, { encoding: 'utf8' }).trim();
        if (!out) return { added: 0, removed: 0 };
        let added = 0, removed = 0;
        out.split(/\n/).forEach(line => {
            const parts = line.split(/\s+/);
            if (parts.length >= 3) {
                const a = parseInt(parts[0], 10);
                const r = parseInt(parts[1], 10);
                if (!isNaN(a)) added += a;
                if (!isNaN(r)) removed += r;
            }
        });
        return { added, removed };
    } catch {
        return { added: 0, removed: 0 };
    }
}

function validateFiles(files: string[]): { details: { file: string; size: number; ok: boolean; reason?: string }[]; aggregateBytes: number; aggregateTooLarge: boolean; risk: string } {
    const details: { file: string; size: number; ok: boolean; reason?: string }[] = [];
    let agg = 0;
    let anyLarge = false;
    for (const f of files) {
        if (!fs.existsSync(f)) {
            details.push({ file: f, size: 0, ok: false, reason: 'missing' });
            continue;
        }
        const stat = fs.statSync(f);
        const ext = path.extname(f).toLowerCase();
        const allowed = EXT_ALLOW.has(ext);
        const tooLarge = stat.size > MAX_FILE_BYTES;
        if (tooLarge) anyLarge = true;
        agg += stat.size;
        details.push({ file: f, size: stat.size, ok: allowed && !tooLarge, reason: !allowed ? 'ext_disallowed' : tooLarge ? 'file_too_large' : undefined });
    }
    const aggregateTooLarge = agg > MAX_AGG_BYTES;
    let risk: string = 'ok';
    if (aggregateTooLarge) risk = 'aggregate_too_large';
    else if (anyLarge) risk = 'large_file';
    else if (details.some(d => !d.ok)) risk = 'file_issue';
    return { details, aggregateBytes: agg, aggregateTooLarge, risk };
}

/**
 * Enhanced task validation that supports segmented large-file processing.
 * If a task targets a single file exceeding size limits BUT includes a message with a
 * line range hint (e.g., "lines 1-600" or "Lines 1201-1800"), we treat the effective
 * working set size as the proportional byte span of those lines. This allows keeping
 * global size thresholds strict while still remediating large legacy files incrementally.
 */
function validateTask(task: DelegationTask): any {
    const base = validateFiles(task.files);
    // Only attempt segment logic for single-file tasks that otherwise fail due to size.
    if (task.files.length === 1 && (base.risk === 'aggregate_too_large' || base.risk === 'large_file')) {
        const msg = (task.message || task.summary || '').toLowerCase();
        const m = msg.match(/lines?\s+(\d+)\s*(?:-|to|–|—)\s*(\d+)/i);
        if (m) {
            const start = parseInt(m[1], 10);
            const end = parseInt(m[2], 10);
            if (!isNaN(start) && !isNaN(end) && end > start) {
                const filePath = task.files[0];
                try {
                    const content = fs.readFileSync(filePath, 'utf8');
                    const lines = content.split(/\n/);
                    const totalLines = lines.length || 1;
                    const clampedStart = Math.max(1, Math.min(start, totalLines));
                    const clampedEnd = Math.max(clampedStart + 1, Math.min(end, totalLines));
                    // Approximate bytes for segment using proportional length to entire file size
                    const stat = fs.statSync(filePath);
                    const fileBytes = stat.size;
                    const segmentLines = (clampedEnd - clampedStart + 1);
                    const estSegmentBytes = Math.max(1, Math.round((segmentLines / totalLines) * fileBytes));
                    // If the estimated segment bytes fit within thresholds, downgrade risk to ok.
                    if (estSegmentBytes <= MAX_AGG_BYTES) {
                        return { ...base, risk: 'ok', segment: { start: clampedStart, end: clampedEnd, estBytes: estSegmentBytes, fileBytes } };
                    }
                } catch { /* ignore segment attempt */ }
            }
        }
    }
    return base;
}

function isDirectDeleteTask(task: any): boolean {
    const directIds = new Set([
        'DEL-REMOVE-ENHANCED-CARD-STUB',
        'DEL-REMOVE-MOBILE-NAV-TEST',
        'DEL-REMOVE-DASHBOARD-BACKUP',
        'DEL-CONTENT-ANALYZER-FIXED-NOTE'
    ]);
    if (directIds.has(task.taskId)) return true;
    const s = (task.summary || '').toLowerCase();
    return /delete unused|remove deprecated|delete obsolete|remove content-analyzer page-fixed/.test(s);
