function readQueueLines(): string[] {
    if (!fs.existsSync(QUEUE)) return [];
    return fs.readFileSync(QUEUE, 'utf8').split(/\r?\n/).filter(Boolean);
}

function parseTasks() {
    const lines = readQueueLines();
    const tasks = [] as any[];
