#!/usr/bin/env node
/**
 * generate-lint-heatmap.js
 * Runs ESLint JSON and emits an artifact summarizing top files by selected high-noise rules.
 */
import { execSync } from 'node:child_process';
import fs from 'node:fs';
import { runMetrics } from './metrics/eslint-metrics-api.mjs';

const RULES_FOCUS = new Set([
  '@typescript-eslint/no-explicit-any',
  '@typescript-eslint/no-unused-vars',
  '@typescript-eslint/no-require-imports'
]);

function run(cmd){
  try { return execSync(cmd,{stdio:'pipe',encoding:'utf8',maxBuffer:10*1024*1024}); }
  catch(e){ return e.stdout || ''; }
}

let raw = run("npx eslint -c scripts/eslint-metrics.flat.mjs 'src/**/*.{ts,tsx,js,jsx}' -f json --no-error-on-unmatched-pattern");
let parsed = [];
try { parsed = JSON.parse(raw); } catch { parsed = []; }
if(parsed.length===0){
  try { parsed = await runMetrics(); } catch(e){ /* degraded heatmap */ }
}

const fileAgg = [];
for(const f of parsed){
  const counts = {};
  for(const m of f.messages){
    if(RULES_FOCUS.has(m.ruleId)) counts[m.ruleId] = (counts[m.ruleId]||0)+1;
  }
  const total = Object.values(counts).reduce((a,b)=>a+b,0);
  if(total>0){
    fileAgg.push({ file: f.filePath, total, counts });
  }
}

fileAgg.sort((a,b)=> b.total - a.total);
const top = fileAgg.slice(0,50);
fs.mkdirSync('artifacts',{recursive:true});
fs.writeFileSync('artifacts/lint-heatmap.json', JSON.stringify({ generated: new Date().toISOString(), focus: Array.from(RULES_FOCUS), top }, null, 2));
console.log('Wrote artifacts/lint-heatmap.json ('+top.length+' files)');

/*
 * Generates a lightweight JSON artifact of current TypeScript diagnostics
 * consumed by twoAgentOrchestration (artifacts/tsc-diagnostics.json).
 *
 * It shells out to `tsc --noEmit --pretty false` and parses lines like:
 * path/to/file.ts:10:5 - error TS2304: Cannot find name 'Foo'.
 */
import { exec } from 'child_process';
import { existsSync, mkdirSync, writeFileSync } from 'fs';
import path from 'path';

interface TSDiagnosticJSON {
    file: string;
    line: number;
    column: number;
    category: 'error' | 'warning' | 'suggestion' | 'message';
    code: number;
    message: string;
}

function stripAnsi(s: string) { return s.replace(/\u001b\[[0-9;]*m/g, ''); }

function parseDiagnostics(output: string): TSDiagnosticJSON[] {
    const lines = stripAnsi(output).split(/\r?\n/);
    const diags: TSDiagnosticJSON[] = [];
    // Patterns observed:
    // 1) path/to/file.ts:10:5 - error TS1234: Message (older formatter)
    // 2) path/to/file.ts(10,5): error TS1234: Message (current formatter)
    const patterns: RegExp[] = [
        /^(.*?):(\d+):(\d+) - (error|warning) TS(\d+): (.*)$/,
        /^(.*)\((\d+),(\d+)\): (error|warning) TS(\d+): (.*)$/
    ];
    for (const line of lines) {
        let match: RegExpMatchArray | null = null;
        for (const r of patterns) { match = line.match(r); if (match) break; }
        if (!match) continue;
        const [, file, lineStr, colStr, category, codeStr, msg] = match;
        diags.push({
            file: path.normalize(file),
            line: Number(lineStr),
            column: Number(colStr),
            category: category as 'error' | 'warning',
            code: Number(codeStr),
            message: msg.trim()
        });
    }
    return diags;
}

function ensureDir(file: string) {
    const dir = path.dirname(file);
    if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
}

// Resolve local TypeScript compiler (do NOT rely on a global tsc on PATH – codespace context may omit it)
const tscBin = (() => {
    try { return require.resolve('typescript/bin/tsc'); } catch { return null; }
})();
const cmd = tscBin ? `node "${tscBin}" --noEmit --pretty false` : 'npx -y tsc --noEmit --pretty false';

exec(cmd, { maxBuffer: 10 * 1024 * 1024 }, (err, stdout, stderr) => {
    const combined = stdout + '\n' + stderr;
    const diagnostics = parseDiagnostics(combined);
    const outFile = path.resolve('artifacts/tsc-diagnostics.json');
    ensureDir(outFile);
    writeFileSync(outFile, JSON.stringify(diagnostics, null, 2), 'utf8');
    // Emit summary to stdout for observability (logging acceptable for build script)
    console.log(`Wrote ${diagnostics.length} TS diagnostics to artifacts/tsc-diagnostics.json (cmd=${cmd}${err ? ' exitCode=' + ((err as any).code ?? 'unknown') : ''})`);
    process.exit(0); // Always exit 0 so pipeline can continue; consumers differentiate via artifact content.
});

