#!/usr/bin/env ts-node
/**
 * prune-if-ready.ts
 * Safely triggers legacy NeuroSEO doc prune when BOTH crawler & semantic adoption ≥95% (aggregate hits dominance)
 * and a guard file `.adoption_sustained` records at least SUSTAIN_DAYS consecutive confirmations.
 *
 * Usage:
 *   ts-node scripts/prune-if-ready.ts            # dry run (default)
 *   CONFIRM=1 ts-node scripts/prune-if-ready.ts  # execute prune script when sustained
 * Env:
 *   ADOPTION_TARGET=95   (override threshold)
 *   SUSTAIN_DAYS=3       (override consecutive day requirement)
 *   DRY_RUN=0            (alias for CONFIRM=1)
 */
import { getApps, initializeApp } from 'firebase-admin/app';
import { getFirestore } from 'firebase-admin/firestore';
import { spawnSync } from 'child_process';
import fs from 'fs';

interface Adoption { crawler: number | null; semantic: number | null; }

async function currentAdoption(): Promise<Adoption> {
    if (!getApps().length) initializeApp();
    const db = getFirestore();
    try {
        const today = new Date().toISOString().slice(0, 10);
        const doc = await db.collection('unifiedMetricsDaily').doc(today).get();
        if (doc.exists) {
            const d: any = doc.data();
            return {
                crawler: typeof d.crawlerAggregateAdoptionPct === 'number' ? d.crawlerAggregateAdoptionPct : null,
                semantic: typeof d.semanticMapAggregateAdoptionPct === 'number' ? d.semanticMapAggregateAdoptionPct : null
            };
        }
    } catch { }
    const [crawlerLegacy, crawlerAgg, semanticLegacy, semanticAgg] = await Promise.all([
        db.collection('neuralCrawlerResults').count().get().then(r => r.data().count).catch(() => 0),
        db.collection('neuralCrawlerResultsAgg').count().get().then(r => r.data().count).catch(() => 0),
        db.collection('semanticMapResults').count().get().then(r => r.data().count).catch(() => 0),
        db.collection('semanticMapResultsAgg').count().get().then(r => r.data().count).catch(() => 0)
    ]);
    const crawlerDen = crawlerLegacy + crawlerAgg;
    const semanticDen = semanticLegacy + semanticAgg;
    return {
        crawler: crawlerDen ? +(crawlerAgg / crawlerDen * 100).toFixed(2) : null,
        semantic: semanticDen ? +(semanticAgg / semanticDen * 100).toFixed(2) : null
    };
}

function updateSustainFile(ok: boolean, sustainDays: number): boolean {
    const file = '.adoption_sustained';
    let entries: string[] = [];
    if (fs.existsSync(file)) {
        entries = fs.readFileSync(file, 'utf8').trim().split(/\n+/).filter(Boolean);
        const last = entries[entries.length - 1];
        if (last?.startsWith(new Date().toISOString().slice(0, 10))) return entries.length >= sustainDays; // already recorded today
    }
    if (ok) { entries.push(`${new Date().toISOString().slice(0, 10)} OK`); }
    else { entries = []; }
    fs.writeFileSync(file, entries.join('\n') + '\n');
    return entries.length >= sustainDays;
}

async function main() {
    const target = parseFloat(process.env.ADOPTION_TARGET || '95');
    const sustainDays = parseInt(process.env.SUSTAIN_DAYS || '3', 10);
    const adoption = await currentAdoption();
    const ok = (adoption.crawler ?? 0) >= target && (adoption.semantic ?? 0) >= target;
    const sustained = updateSustainFile(ok, sustainDays);
    console.log(JSON.stringify({ adoption, target, ok, sustained, sustainDays }, null, 2));
    if (sustained && (process.env.CONFIRM === '1' || process.env.DRY_RUN === '0')) {
        console.log('[prune-if-ready] Sustained adoption achieved – invoking prune script (dryRun unless CONFIRM=1)');
        const args = ['scripts/prune-neuroseo-legacy-docs.ts'];
        const env = { ...process.env, DRY_RUN: process.env.CONFIRM === '1' ? '0' : '1', CONFIRM_PRUNE: process.env.CONFIRM === '1' ? '1' : '0' } as NodeJS.ProcessEnv;
        const res = spawnSync('ts-node', args, { stdio: 'inherit', env });
        process.exit(res.status ?? 0);
    } else {
        console.log('[prune-if-ready] Not sustained / below target – no action.');
    }
}

main().catch(e => { console.error('[prune-if-ready] failed', e); process.exit(1); });

#!/usr/bin/env ts-node
/*
 * NeuroSEO Legacy Prune Script (Dry-Run First)
 * Objective: Identify (and optionally delete) legacy large NeuroSEO documents that now have aggregate counterparts.
 * Collections: semanticMapResults, neuralCrawlerResults
 * Safety:
 *   - DRY RUN by default unless CONFIRM_PRUNE=1 and DRY_RUN=0
 *   - Optionally gate by adoption thresholds (TARGET_* env vars)
 *   - Max deletions per collection via MAX_DELETE (default 100)
 * Selection Criteria:
 *   - Legacy doc size > THRESHOLD_BYTES AND an aggregate exists (userId+url OR historyId for crawler)
 * Env Vars:
 *   DRY_RUN=1 (default) | set DRY_RUN=0 CONFIRM_PRUNE=1 to actually delete
 *   CONFIRM_PRUNE=1 (required for deletion)
 *   THRESHOLD_BYTES=2500
 *   MAX_DELETE=100
 *   TARGET_CRAWLER_PCT / TARGET_SEMANTIC_PCT
 *   OUTPUT_FILE=artifacts/prune-candidates.json
 * Exit Codes:
 *   0 success
 *   4 thresholds not met (aborted)
 *   5 unexpected failure
 */
import { getApps, initializeApp } from 'firebase-admin/app';
import type { QueryDocumentSnapshot } from 'firebase-admin/firestore';
import { getFirestore } from 'firebase-admin/firestore';

interface Candidate { collection: string; id: string; size: number; userId?: string; url?: string; historyId?: string; hasAggregate: boolean; }
interface Summary { generatedAt: string; threshold: number; dryRun: boolean; confirm: boolean; targetCrawler?: number; targetSemantic?: number; adoption?: { crawler?: number | null; semantic?: number | null }; counts: Record<string, { scanned: number; candidates: number; deleted: number }>; }

function approxSize(d: any) { try { return Buffer.byteLength(JSON.stringify(d)); } catch { return 0; } }

async function adoptionSnapshot(db: FirebaseFirestore.Firestore) {
    const [crawlerLegacy, crawlerAgg, semanticLegacy, semanticAgg] = await Promise.all([
        db.collection('neuralCrawlerResults').count().get().then(r => r.data().count).catch(() => 0),
        db.collection('neuralCrawlerResultsAgg').count().get().then(r => r.data().count).catch(() => 0),
        db.collection('semanticMapResults').count().get().then(r => r.data().count).catch(() => 0),
        db.collection('semanticMapResultsAgg').count().get().then(r => r.data().count).catch(() => 0),
    ]);
    const crawlerDenom = crawlerLegacy + crawlerAgg;
    const semanticDenom = semanticLegacy + semanticAgg;
    return {
        crawler: crawlerDenom > 0 ? +((crawlerAgg / crawlerDenom) * 100).toFixed(2) : null,
        semantic: semanticDenom > 0 ? +((semanticAgg / semanticDenom) * 100).toFixed(2) : null,
    };
}

async function buildAggregateKeyIndex(db: FirebaseFirestore.Firestore, collection: string) {
    const snap = await db.collection(collection).select('userId', 'url', 'historyId').get();
    const set = new Set<string>();
    snap.forEach(d => {
        const data: any = d.data();
        if (data.historyId) set.add('h:' + data.historyId);
        else if (data.userId && data.url) set.add('u:' + data.userId + '|' + data.url);
    });
    return set;
}

async function collectCandidates(db: FirebaseFirestore.Firestore, legacyCol: string, aggCol: string, threshold: number, max: number): Promise<{ candidates: Candidate[]; scanned: number }> {
    const keyIndex = await buildAggregateKeyIndex(db, aggCol);
    let last: QueryDocumentSnapshot | undefined; const batchSize = 400;
    const candidates: Candidate[] = []; let scanned = 0;
    while (true) {
        let q = db.collection(legacyCol).limit(batchSize);
        if (last) q = q.startAfter(last);
        const snap = await q.get(); if (snap.empty) break;
        for (const doc of snap.docs) {
            scanned++;
            const data: any = doc.data();
            const size = approxSize(data);
            if (size <= threshold) continue;
            const key = data.historyId ? ('h:' + data.historyId) : (data.userId && data.url ? 'u:' + data.userId + '|' + data.url : null);
            if (!key) continue;
            const hasAggregate = keyIndex.has(key);
            if (hasAggregate) {
                candidates.push({ collection: legacyCol, id: doc.id, size, userId: data.userId, url: data.url, historyId: data.historyId, hasAggregate });
                if (candidates.length >= max) break;
            }
        }
        last = snap.docs[snap.docs.length - 1];
        if (snap.size < batchSize || candidates.length >= max) break;
    }
    return { candidates, scanned };
}

async function main() {
    if (!getApps().length) initializeApp();
    const db = getFirestore();
    const threshold = parseInt(process.env.THRESHOLD_BYTES || '2500', 10);
    const dryRun = process.env.DRY_RUN !== '0';
    const confirm = process.env.CONFIRM_PRUNE === '1';
    const maxDelete = parseInt(process.env.MAX_DELETE || '100', 10);
    const targetCrawler = process.env.TARGET_CRAWLER_PCT ? parseFloat(process.env.TARGET_CRAWLER_PCT) : undefined;
    const targetSemantic = process.env.TARGET_SEMANTIC_PCT ? parseFloat(process.env.TARGET_SEMANTIC_PCT) : undefined;
    const adoption = await adoptionSnapshot(db);
    if ((targetCrawler && adoption.crawler != null && adoption.crawler < targetCrawler) || (targetSemantic && adoption.semantic != null && adoption.semantic < targetSemantic)) {
        console.error('[prune] ABORT thresholds not met', { adoption, targetCrawler, targetSemantic });
        process.exit(4);
    }
    const colPairs = [
        { legacy: 'semanticMapResults', agg: 'semanticMapResultsAgg' },
        { legacy: 'neuralCrawlerResults', agg: 'neuralCrawlerResultsAgg' },
    ];
    const allCandidates: Candidate[] = [];
    const counts: Summary['counts'] = {} as any;
    for (const pair of colPairs) {
        const { candidates, scanned } = await collectCandidates(db, pair.legacy, pair.agg, threshold, maxDelete);
        counts[pair.legacy] = { scanned, candidates: candidates.length, deleted: 0 };
        allCandidates.push(...candidates);
    }
    console.log('[prune] candidates', allCandidates.map(c => ({ collection: c.collection, id: c.id, size: c.size })).slice(0, 20));
    if (confirm && !dryRun) {
        for (const c of allCandidates) {
            await db.collection(c.collection).doc(c.id).delete();
            counts[c.collection].deleted++;
        }
    }
    const summary: Summary = { generatedAt: new Date().toISOString(), threshold, dryRun, confirm, targetCrawler, targetSemantic, adoption, counts };
    console.log('[prune] summary', JSON.stringify(summary, null, 2));
    const out = process.env.OUTPUT_FILE;
    if (out) {
        try {
            const fs = await import('fs');
            fs.mkdirSync(require('path').dirname(out), { recursive: true });
            fs.writeFileSync(out, JSON.stringify({ summary, candidates: allCandidates }, null, 2));
            console.log('[prune] wrote', out);
        } catch (e) {
            console.error('[prune] failed write', (e as any)?.message);
        }
    }
    process.exit(0);
}

main().catch(e => { console.error('[prune] FAILED', e); process.exit(5); });

#!/usr/bin/env node
/**
 * Purge transient snapshot artifacts (TypeScript incremental, metrics snapshots, neuroseo size, provenance snapshots)
 * to ensure a clean baseline before a fresh typecheck or CI run.
 * Safe: Only deletes known generated files/directories; ignores if missing.
 */
'use strict';
const fs = require('fs');
const path = require('path');

const ROOT = process.cwd();
const targets = [
  'tsconfig.tsbuildinfo',
  'metrics-snapshots.log',
  'artifacts/size-reduction.json',
  'artifacts/neuroseo-scan.json',
  'artifacts/provenance-snapshot.json',
  'artifacts/neuroseo-size.json'
];

let removed = 0;
for (const rel of targets) {
  const p = path.join(ROOT, rel);
  try {
    if (fs.existsSync(p)) {
      const stat = fs.statSync(p);
      if (stat.isFile()) {
        fs.rmSync(p, { force: true });
        removed++;
        console.log(`[purge] removed file ${rel}`);
      }
    }
  } catch (err) {
    console.warn(`[purge] failed to remove ${rel}: ${err && err.message ? err.message : err}`);
  }
}
// Optionally prune empty artifacts dir
try {
  const art = path.join(ROOT, 'artifacts');
  if (fs.existsSync(art) && fs.readdirSync(art).length === 0) {
    fs.rmSync(art, { force: true });
    console.log('[purge] removed empty artifacts/ directory');
  }
} catch (_err) {
  /* ignore */
}
console.log(`[purge] Completed. Removed ${removed} artifact(s).`);

#!/usr/bin/env ts-node
/*
 * Feature Alias Usage Report
 * Goal: Detect lingering source references to transitional alias keys (e.g., ai_insights) before final removal.
 * Method: Walk src/ and scan .ts/.tsx/.js/.mjs/.cjs skipping common excluded dirs.
 * Output: Logs match lines; optional OUTPUT_FILE JSON.
 * Exit Code: 0 (always) unless STRICT=1 then 2 on unauthorized matches.
 */
import { readFileSync, readdirSync, statSync, mkdirSync, writeFileSync } from 'fs';
import { join } from 'path';

interface Match { file: string; line: number; alias: string; context: string; allowed: boolean; }

const root = process.cwd();
const aliasKeys = (process.env.ALIAS_KEYS || 'ai_insights').split(',').map(s => s.trim()).filter(Boolean);
const ignoreKnown = process.env.IGNORE_KNOWN === '1';
const strict = process.env.STRICT === '1';

const allowPatterns = [
    /ai_insights\s*:\s*"advanced_analytics"/, // mapping in access-control
    /transitional alias feature key/i,
];

function shouldScanDir(p: string) {
    return !/(node_modules|\.next|playwright-report|test-results|\.git)/.test(p);
}

function walk(dir: string, files: string[] = []): string[] {
    for (const entry of readdirSync(dir)) {
        const full = join(dir, entry);
        try {
            const st = statSync(full);
            if (st.isDirectory()) { if (shouldScanDir(full)) walk(full, files); }
            else if (/\.(ts|tsx|js|mjs|cjs)$/.test(entry)) files.push(full);
        } catch { /* ignore */ }
    }
    return files;
}

function scanFile(file: string): Match[] {
    const content = readFileSync(file, 'utf8');
    const lines = content.split(/\r?\n/);
    const matches: Match[] = [];
    lines.forEach((lineText, idx) => {
        for (const alias of aliasKeys) {
            if (!alias) continue;
            if (lineText.includes(alias)) {
                const allowed = allowPatterns.some(p => p.test(lineText));
                if (allowed && ignoreKnown) return;
                const context = lineText.trim().slice(0, 160);
                matches.push({ file: file.replace(root + '/', ''), line: idx + 1, alias, context, allowed });
            }
        }
    });
    return matches;
}

async function main() {
    const files = walk(join(root, 'src'));
    const results: Match[] = [];
    for (const f of files) results.push(...scanFile(f));
    const unauthorized = results.filter(r => !r.allowed);
    console.log('[alias-usage] matches', results.length);
    unauthorized.forEach(m => console.log(`[alias-usage] ${m.file}:${m.line} ${m.alias} :: ${m.context}`));
    if (results.length === 0) console.log('[alias-usage] No occurrences found.');
    const out = process.env.OUTPUT_FILE;
    if (out) {
        try {
            mkdirSync(require('path').dirname(out), { recursive: true });
            writeFileSync(out, JSON.stringify({ generatedAt: new Date().toISOString(), aliasKeys, results }, null, 2));
            console.log('[alias-usage] wrote', out);
        } catch (e) {
            console.error('[alias-usage] failed write', (e as any)?.message);
        }
    }
    if (strict && unauthorized.length > 0) process.exit(2);
}

main().catch(e => { console.error('[alias-usage] FAILED', e); process.exit(1); });

#!/usr/bin/env ts-node
/*
 * T14 Migration – Size Reduction Report
 * Computes size reduction statistics between legacy collections (semanticMapResults, neuralCrawlerResults)
 * and their aggregate counterparts (semanticMapResultsAgg, neuralCrawlerResultsAgg).
 * Output: logs summary + optional JSON (OUTPUT_FILE)
 * Usage:
 *   ts-node scripts/report-neuroseo-size-reduction.ts
 *   OUTPUT_FILE=artifacts/size-reduction.json ts-node scripts/report-neuroseo-size-reduction.ts
 */
import { getApps, initializeApp } from 'firebase-admin/app';
import { getFirestore } from 'firebase-admin/firestore';

interface Stats {
    legacyCount: number; aggCount: number; matched: number; legacyBytes: number; aggBytes: number; reductionPct: number | null;
}

function approxSize(v: any) { try { return Buffer.byteLength(JSON.stringify(v)); } catch { return 0; } }

async function collectPairSizes(db: FirebaseFirestore.Firestore, legacyCol: string, aggCol: string, matchFields: string[]): Promise<Stats> {
    const stats: Stats = { legacyCount: 0, aggCount: 0, matched: 0, legacyBytes: 0, aggBytes: 0, reductionPct: null };
    const legacySnap = await db.collection(legacyCol).limit(5000).get(); // cap for safety
    stats.legacyCount = legacySnap.size;
    if (!legacySnap.empty) {
        const aggSnap = await db.collection(aggCol).limit(5000).get();
        stats.aggCount = aggSnap.size;
        const aggIndex = new Map<string, FirebaseFirestore.QueryDocumentSnapshot>();
        aggSnap.docs.forEach(d => {
            const data: any = d.data();
            const key = matchFields.map(f => data[f] ?? '').join('|');
            aggIndex.set(key, d);
        });
        for (const doc of legacySnap.docs) {
            const data: any = doc.data();
            const key = matchFields.map(f => data[f] ?? '').join('|');
            const legacySize = approxSize(data);
            const aggDoc = aggIndex.get(key);
            if (aggDoc) {
                stats.matched++;
                stats.legacyBytes += legacySize;
                stats.aggBytes += approxSize(aggDoc.data());
            }
        }
        if (stats.matched > 0) {
            const avgLegacy = stats.legacyBytes / stats.matched;
            const avgAgg = stats.aggBytes / stats.matched;
            stats.reductionPct = +(((1 - (avgAgg / avgLegacy)) * 100)).toFixed(2);
        }
    }
    return stats;
}

async function main() {
    if (!getApps().length) initializeApp();
    const db = getFirestore();
    const semantic = await collectPairSizes(db, 'semanticMapResults', 'semanticMapResultsAgg', ['userId', 'url']);
    const crawler = await collectPairSizes(db, 'neuralCrawlerResults', 'neuralCrawlerResultsAgg', ['userId', 'url']);
    const summary = { generatedAt: new Date().toISOString(), semantic, crawler };
    console.log('[size-reduction] summary', JSON.stringify(summary, null, 2));
    const out = process.env.OUTPUT_FILE;
    if (out) {
        try { const fs = await import('fs'); fs.mkdirSync(require('path').dirname(out), { recursive: true }); fs.writeFileSync(out, JSON.stringify(summary, null, 2)); console.log(`[size-reduction] wrote ${out}`); } catch (e) { console.error('[size-reduction] failed to write OUTPUT_FILE', (e as any)?.message); }
    }
}

main().catch(e => { console.error('[size-reduction] FAILED', e); process.exit(1); });

