function generateSecurePassword(): string {
  const length = 16;
  const charset = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789!@#$%^&*";
  let password = "";
  for (let i = 0; i < length; i++) {
    const randomIndex = randomInt(0, charset.length);
    password += charset[randomIndex];
  }
  return password;
}

function updateEnvFile(filePath: string, updates: Record<string, string>): void {
  const envPath = path.resolve(process.cwd(), filePath);
  let content = "";
  try {
    content = fs.readFileSync(envPath, "utf8");
  } catch {
    content = "";
  }

  for (const [key, value] of Object.entries(updates)) {
    const regex = new RegExp(`^${key}=.*$`, "m");
    if (regex.test(content)) {
      content = content.replace(regex, `${key}=${value}`);
    } else {
      if (content.length && !content.endsWith("\n")) content += "\n";
      content += `${key}=${value}\n`;
    }
  }

  fs.writeFileSync(envPath, content, "utf8");
}

// Run the rotation
rotateTestUsers().catch(console.error);

#!/usr/bin/env node

/**
 * Role-Based Test Runner
 *
 * This script orchestrates the execution of role-based tests with proper
 * sequencing, user management, and comprehensive reporting.
 */

const { execSync } = require("child_process");
const fs = require("fs");
const path = require("path");

class RoleBasedTestRunner {
  constructor() {
    this.testResults = {
      freeTier: { status: "pending", duration: 0, errors: [] },
      enterpriseTier: { status: "pending", duration: 0, errors: [] },
      overall: {
        status: "pending",
        totalDuration: 0,
        startTime: null,
        endTime: null,
      },
    };

    this.configFile = "playwright.config.role-based.ts";
    this.logFile = path.join("test-results", "role-based-test-run.log");
  }

  getErrorMessage(error) {
    if (!error) return String(error);
    if (typeof error === "string") return error;
    if (error && error.message) return error.message;
    if (error && error.stack) return String(error.stack).split("\n")[0];
    return String(error);
  }

  log(message, level = "INFO") {
    const timestamp = new Date().toISOString();
    const logMessage = `[${timestamp}] [${level}] ${message}`;

    console.log(logMessage);

    // Write to log file
    try {
      fs.appendFileSync(this.logFile, logMessage + "\n");
    } catch (error) {
      // Ignore file write errors
    }
  }

  async checkPrerequisites() {
    this.log("🔍 Checking prerequisites...");

    // Check if dev server is running
    try {
      execSync("curl -f http://localhost:3000 > /dev/null 2>&1", {
        stdio: "ignore",
      });
      this.log("✅ Development server is running");
    } catch (error) {
      this.log("❌ Development server is not running", "ERROR");
      this.log(
        "💡 Please start the development server with: npm run dev",
        "INFO"
      );
      throw new Error("Development server not running");
    }

    // Check if role-based config exists
    if (!fs.existsSync(this.configFile)) {
      this.log(`❌ Config file ${this.configFile} not found`, "ERROR");
      throw new Error("Role-based config file missing");
    }

    // Ensure test results directory exists
    const testResultsDir = path.join(process.cwd(), "test-results");
    if (!fs.existsSync(testResultsDir)) {
      fs.mkdirSync(testResultsDir, { recursive: true });
      this.log("📁 Created test-results directory");
    }

    this.log("✅ All prerequisites satisfied");
  }

  async runFreeTierTests() {
    this.log("🆓 Starting Free Tier Tests...");
    const startTime = Date.now();

    try {
      this.testResults.freeTier.status = "running";

      const command = `npx playwright test --config=${this.configFile} --project=free-tier-worker`;
      this.log(`🚀 Executing: ${command}`);

      execSync(command, {
        stdio: "inherit",
        cwd: process.cwd(),
        env: {
          ...process.env,
          PLAYWRIGHT_HTML_REPORT: "test-results/free-tier-report",
        },
      });

      this.testResults.freeTier.status = "passed";
      this.log("✅ Free Tier Tests completed successfully");
    } catch (error) {
      this.testResults.freeTier.status = "failed";
      this.testResults.freeTier.errors.push(this.getErrorMessage(error));
      this.log(`❌ Free Tier Tests failed: ${this.getErrorMessage(error)}`, "ERROR");
      throw error;
    } finally {
      this.testResults.freeTier.duration = Date.now() - startTime;
      this.log(
        `⏱️ Free Tier Tests duration: ${this.testResults.freeTier.duration}ms`
      );
    }
  }

  async runEnterpriseTierTests() {
    this.log("🏢 Starting Enterprise Tier Tests...");
    const startTime = Date.now();

    try {
      this.testResults.enterpriseTier.status = "running";

      const command = `npx playwright test --config=${this.configFile} --project=enterprise-tier-worker`;
      this.log(`🚀 Executing: ${command}`);

      execSync(command, {
        stdio: "inherit",
        cwd: process.cwd(),
        env: {
          ...process.env,
          PLAYWRIGHT_HTML_REPORT: "test-results/enterprise-tier-report",
        },
      });

      this.testResults.enterpriseTier.status = "passed";
      this.log("✅ Enterprise Tier Tests completed successfully");
    } catch (error) {
      this.testResults.enterpriseTier.status = "failed";
      this.testResults.enterpriseTier.errors.push(this.getErrorMessage(error));
      this.log(`❌ Enterprise Tier Tests failed: ${this.getErrorMessage(error)}`, "ERROR");
      throw error;
    } finally {
      this.testResults.enterpriseTier.duration = Date.now() - startTime;
      this.log(
        `⏱️ Enterprise Tier Tests duration: ${this.testResults.enterpriseTier.duration}ms`
      );
    }
  }

  async runMobileTests() {
    this.log("📱 Starting Mobile Tests...");

    try {
      const commands = [
        `npx playwright test --config=${this.configFile} --project=mobile-free-tier`,
        `npx playwright test --config=${this.configFile} --project=mobile-enterprise-tier`,
      ];

      for (const command of commands) {
        this.log(`🚀 Executing: ${command}`);
        execSync(command, {
          stdio: "inherit",
          cwd: process.cwd(),
        });
      }

      this.log("✅ Mobile Tests completed successfully");
    } catch (error) {
      this.log(`⚠️ Mobile Tests had issues: ${this.getErrorMessage(error)}`, "WARN");
      // Don't fail the entire test run for mobile issues
    }
  }

  async runCompatibilityTests() {
    this.log("🌐 Starting Cross-Browser Compatibility Tests...");

    try {
      const command = `npx playwright test --config=${this.configFile} --project=firefox-compatibility`;
      this.log(`🚀 Executing: ${command}`);

      execSync(command, {
        stdio: "inherit",
        cwd: process.cwd(),
      });

      this.log("✅ Compatibility Tests completed successfully");
    } catch (error) {
      this.log(`⚠️ Compatibility Tests had issues: ${this.getErrorMessage(error)}`, "WARN");
      // Don't fail the entire test run for compatibility issues
    }
  }

  generateFinalReport() {
    this.log("📊 Generating final test report...");

    const report = {
      summary: {
        overallStatus: this.testResults.overall.status,
        totalDuration: this.testResults.overall.totalDuration,
        startTime: this.testResults.overall.startTime,
        endTime: this.testResults.overall.endTime,
      },
      freeTier: this.testResults.freeTier,
      enterpriseTier: this.testResults.enterpriseTier,
      metadata: {
        configFile: this.configFile,
        nodeVersion: process.version,
        platform: process.platform,
        architecture: process.arch,
      },
    };

    const reportPath = path.join(
      "test-results",
      "role-based-final-report.json"
    );
    fs.writeFileSync(reportPath, JSON.stringify(report, null, 2));

    this.log(`📝 Final report written to: ${reportPath}`);

    // Display summary
    console.log("\n🎯 TEST EXECUTION SUMMARY");
    console.log("=".repeat(50));
    console.log(
      `Free Tier Tests: ${this.testResults.freeTier.status.toUpperCase()}`
    );
    console.log(
      `Enterprise Tier Tests: ${this.testResults.enterpriseTier.status.toUpperCase()}`
    );
    console.log(
      `Overall Status: ${this.testResults.overall.status.toUpperCase()}`
    );
    console.log(`Total Duration: ${this.testResults.overall.totalDuration}ms`);
    console.log("=".repeat(50));
  }

  async run() {
    this.testResults.overall.startTime = new Date().toISOString();
    const overallStartTime = Date.now();

    try {
      this.log("🚀 Starting Role-Based Test Execution");

      // Prerequisites
      await this.checkPrerequisites();

      // Sequential execution of role-based tests
      await this.runFreeTierTests();
      await this.runEnterpriseTierTests();

      // Optional additional tests (don't fail main execution)
      await this.runMobileTests();
      await this.runCompatibilityTests();

      this.testResults.overall.status = "passed";
      this.log("🎉 All role-based tests completed successfully!");
    } catch (error) {
      this.testResults.overall.status = "failed";
      this.log(`💥 Test execution failed: ${this.getErrorMessage(error)}`, "ERROR");
      throw error;
    } finally {
      this.testResults.overall.endTime = new Date().toISOString();
      this.testResults.overall.totalDuration = Date.now() - overallStartTime;

      this.generateFinalReport();
    }
  }
}

// CLI execution
if (require.main === module) {
  const runner = new RoleBasedTestRunner();

  runner
    .run()
    .then(() => {
      console.log("✅ Test execution completed successfully");
      process.exit(0);
    })
    .catch((error) => {
      console.error("❌ Test execution failed:", error);
      process.exit(1);
    });
}

module.exports = RoleBasedTestRunner;

/**
 * Forbidden Fields Scan (Governance)
 * Scans Firestore (if emulator vars present) and codebase for persisted forbidden derived fields
 * Currently targets marketingCampaigns collection documents for presence of ctr / roi.
 * Exits with non-zero code if violations found.
 */
import fs from 'fs';
import path from 'path';

// Sync with FORBIDDEN_DERIVED_FIELDS in src/lib/guards/forbidden-derived-fields.ts
const FORBIDDEN_FIELDS = ['roi', 'ctr', 'conversion', 'winRate', 'ltv'];

// Heuristic: Only flag if forbidden field appears on an object literal being persisted (set/add/update) to marketingCampaigns or similar collections.
const WRITE_KEYWORDS = ['add(', 'set(', 'update(', 'batch.set', 'batch.update'];
const PERSIST_HINTS = ['marketingCampaigns'];

async function scanCodebase(root: string): Promise<string[]> {
    const violations: string[] = [];
    function walk(p: string) {
        const stat = fs.statSync(p);
        if (stat.isDirectory()) { for (const e of fs.readdirSync(p)) walk(path.join(p, e)); return; }
        if (!/\.(ts|tsx|js|mjs|cjs)$/i.test(p)) return;
        const text = fs.readFileSync(p, 'utf8');
        // Skip obvious UI (app routes pages/components/hooks) unless they include firestore write keywords
        const isUi = /\/app\//.test(p) || /\/hooks\//.test(p) || /\/components\//.test(p);
        const writeLikely = WRITE_KEYWORDS.some(k => text.includes(k)) && PERSIST_HINTS.some(h => text.includes(h));
        if (isUi && !writeLikely) return; // ignore read-only UI references
        FORBIDDEN_FIELDS.forEach(f => {
            const re = new RegExp(`\\b${f}\\b`, 'g');
            if (re.test(text)) {
                if (p.includes('marketing-write-guard')) return; // allow legacy guard definition
                if (p.includes('forbidden-derived-fields')) return; // allow central guard definition
                if (!writeLikely) return; // ignore if not part of a likely write context
                // Exempt aggregation/read-only service modules (heuristic: 'metrics.service')
                if (/marketing-metrics\.service/.test(p)) return;
                violations.push(`Potential persistence of forbidden field '${f}' in ${p}`);
            }
        });
    }
    walk(root);
    return violations;
}

async function scanFirestore(): Promise<string[]> {
    const project = process.env.FIREBASE_PROJECT_ID || process.env.GCLOUD_PROJECT;
    if (!project) return []; // Skip if not configured
    let admin: any;
    try { admin = require('firebase-admin'); } catch { return []; }
    if (!admin.apps?.length) {
        try { admin.initializeApp({ projectId: project }); } catch { /* ignore */ }
    }
    const db = admin.firestore?.();
    if (!db) return [];
    const violations: string[] = [];
    try {
        const snap = await db.collection('marketingCampaigns').limit(200).get();
        snap.forEach((doc: any) => {
            const data = doc.data();
            FORBIDDEN_FIELDS.forEach(f => { if (f in data) violations.push(`Firestore doc marketingCampaigns/${doc.id} contains forbidden field '${f}'`); });
        });
    } catch { /* ignore firestore errors in local non-emulator context */ }
    return violations;
}

(async () => {
    const codeViolations = await scanCodebase(path.join(process.cwd(), 'src'));
    const firestoreViolations = await scanFirestore();
    const all = [...codeViolations, ...firestoreViolations];
    if (all.length) {
        console.error('\x1b[31mForbidden fields scan FAILED:\x1b[0m');
        all.forEach(v => console.error(' -', v));
        process.exit(1);
    } else {
        console.log('Forbidden fields scan passed (no forbidden references or persisted fields found).');
    }
})();

#!/usr/bin/env ts-node
/*
 * T14 Migration – Large NeuroSEO Docs Scanner (Dry Run)
 * Purpose: Enumerate large semanticMapResults & neuralCrawlerResults documents exceeding a size threshold
 *          and compute proposed aggregate (data-minimized) structures WITHOUT writing.
 * Threshold: DEFAULT_THRESHOLD_BYTES=2500 (override via THRESHOLD_BYTES env)
 * Batching: BATCH_SIZE (default 100)
 * Output: Logs each oversized doc summary + proposed aggregate JSON (truncated) & final summary counts.
 * Write Mode: Currently dry-run only (no writes). Future WRITE=1 flag can enable persistence once reviewed.
 * Usage:
 *   npm run scan:neuroseo-large                      # dry run with defaults
 *   THRESHOLD_BYTES=3000 npm run scan:neuroseo-large  # custom threshold
 *   BATCH_SIZE=50 npm run scan:neuroseo-large         # smaller batch
 */
import { getApps, initializeApp } from 'firebase-admin/app';
import type { QueryDocumentSnapshot } from 'firebase-admin/firestore';
import { getFirestore, FieldValue } from 'firebase-admin/firestore';

interface SemanticMapFullDoc {
    userId?: string;
    url?: string;
    overallScore?: number;
    topicClusters?: Array<{ topic: string; semanticScore?: number; opportunity?: string }>;
    keywordAnalysis?: Array<{ keyword: string; semanticRelevance?: number }>;
    contentAnalysis?: {
        readabilityScore?: number; contentDepth?: number; topicCoverage?: number; semanticRichness?: number; expertiseSignals?: number;
    };
    semanticGraph?: { nodes?: any[]; edges?: any[] };
    recommendations?: any[];
    createdAt?: any;
}

interface NeuralCrawlerFullDoc {
    userId?: string; url?: string; historyId?: string; wordCount?: number; readingTime?: number;
    images?: any[]; links?: Array<{ type: 'internal' | 'external' }>; seoAnalysis?: { titleLength?: number; metaDescriptionLength?: number };
    issues?: any[]; entities?: any[]; headings?: Record<string, string[]>; createdAt?: any;
}

function approxSize(obj: unknown): number {
    try { return Buffer.byteLength(JSON.stringify(obj)); } catch { return 0; }
}

export function deriveSemanticMapAggregate(full: SemanticMapFullDoc): Record<string, unknown> {
    const topTopicClusters = (full.topicClusters || [])
        .slice(0, 5)
        .map(tc => ({ topic: tc.topic, semanticScore: tc.semanticScore ?? null, opportunity: tc.opportunity ?? null }));
    const topKeywords = (full.keywordAnalysis || [])
        .slice(0, 8)
        .map(k => ({ keyword: k.keyword, semanticRelevance: k.semanticRelevance ?? null }));
    const ca = full.contentAnalysis || {};
    return {
        userId: full.userId || null,
        url: full.url || null,
        overallScore: full.overallScore ?? null,
        topicClustersCount: full.topicClusters?.length || 0,
        keywordAnalysisCount: full.keywordAnalysis?.length || 0,
        topTopicClusters,
        topKeywords,
        readabilityScore: ca.readabilityScore ?? null,
        contentDepth: ca.contentDepth ?? null,
        topicCoverage: ca.topicCoverage ?? null,
        semanticRichness: ca.semanticRichness ?? null,
        expertiseSignals: ca.expertiseSignals ?? null,
        graphNodesCount: full.semanticGraph?.nodes?.length || 0,
        graphEdgesCount: full.semanticGraph?.edges?.length || 0,
        recommendationsCount: full.recommendations?.length || 0,
        version: 1,
        createdAt: full.createdAt || new Date()
    };
}

export function deriveNeuralCrawlerAggregate(full: NeuralCrawlerFullDoc): Record<string, unknown> {
    const internalLinks = full.links?.filter(l => l.type === 'internal').length || 0;
    const externalLinks = full.links?.filter(l => l.type === 'external').length || 0;
    const headingsCounts = full.headings ? Object.fromEntries(Object.entries(full.headings).map(([k, v]) => [k, Array.isArray(v) ? v.length : 0])) : {};
    return {
        userId: full.userId || null,
        historyId: full.historyId || null,
        url: full.url || null,
        wordCount: full.wordCount || 0,
        readingTime: full.readingTime || 0,
        imagesCount: full.images?.length || 0,
        linksInternal: internalLinks,
        linksExternal: externalLinks,
        titleLength: full.seoAnalysis?.titleLength ?? null,
        metaDescriptionLength: full.seoAnalysis?.metaDescriptionLength ?? null,
        issuesCount: full.issues?.length || 0,
        entitiesCount: full.entities?.length || 0,
        headings: headingsCounts,
        version: 1,
        createdAt: full.createdAt || new Date()
    };
}

interface ScanResultEntry {
    collection: string;
    id: string;
    size: number;
    proposedAggregateSize: number | null;
    reductionPct: number | null;
    userId: string | null;
    url: string | null;
    aggregatePreview: any;
    wrote?: boolean;
    skippedWriteReason?: string;
}

async function ensureAggregateDoc(db: FirebaseFirestore.Firestore, collection: string, legacy: any, aggregate: any): Promise<{ wrote: boolean; reason?: string }> {
    // Duplicate avoidance: match by historyId if present else userId+url
    try {
        if (legacy.historyId) {
            const q = await db.collection(collection).where('historyId', '==', legacy.historyId).limit(1).get();
            if (!q.empty) return { wrote: false, reason: 'exists_historyId' };
        } else if (legacy.userId && legacy.url) {
            const q2 = await db.collection(collection).where('userId', '==', legacy.userId).where('url', '==', legacy.url).limit(1).get();
            if (!q2.empty) return { wrote: false, reason: 'exists_user_url' };
        }
        await db.collection(collection).add({ ...aggregate, createdAt: aggregate.createdAt || FieldValue.serverTimestamp() });
        return { wrote: true };
    } catch (e) {
        return { wrote: false, reason: 'write_error' };
    }
}

async function scanCollection(db: FirebaseFirestore.Firestore, name: string, threshold: number, derive: (d: any) => any, opts: { write: boolean; output: ScanResultEntry[] }): Promise<{ scanned: number; oversized: number }> {
    const batchSize = parseInt(process.env.BATCH_SIZE || '100', 10);
    console.log(`[scan] collection=${name} threshold=${threshold} batchSize=${batchSize}`);
    let last: QueryDocumentSnapshot | undefined;
    let scanned = 0, oversized = 0;
    while (true) {
        let q = db.collection(name).limit(batchSize);
        if (last) q = q.startAfter(last);
        const snap = await q.get();
        if (snap.empty) break;
        for (const doc of snap.docs) {
            scanned++;
            const data = doc.data();
            const size = approxSize(data);
            if (size > threshold) {
                oversized++;
                const aggregate = derive(data);
                const aggSize = approxSize(aggregate);
                let wrote = false; let skippedWriteReason: string | undefined;
                if (opts.write) {
                    const targetCollection = name === 'semanticMapResults' ? 'semanticMapResultsAgg' : (name === 'neuralCrawlerResults' ? 'neuralCrawlerResultsAgg' : `${name}Agg`);
                    const res = await ensureAggregateDoc(db, targetCollection, data, aggregate);
                    wrote = res.wrote; skippedWriteReason = res.reason;
                }
                const entry: ScanResultEntry = {
                    collection: name,
                    id: doc.id,
                    size,
                    proposedAggregateSize: aggSize,
                    reductionPct: aggSize ? +(((1 - (aggSize / size)) * 100).toFixed(2)) : null,
                    userId: (data as any).userId || null,
                    url: (data as any).url || null,
                    aggregatePreview: aggregate,
                    wrote,
                    skippedWriteReason
                };
                opts.output.push(entry);
                console.log(JSON.stringify(entry, null, 2));
            }
        }
        last = snap.docs[snap.docs.length - 1];
        if (snap.size < batchSize) break;
    }
    console.log(`[scan] complete collection=${name} scanned=${scanned} oversized>${threshold}=${oversized}`);
    return { scanned, oversized };
}

async function main(): Promise<void> {
    const threshold = parseInt(process.env.THRESHOLD_BYTES || '2500', 10);
    if (!getApps().length) initializeApp();
    const db = getFirestore();
    const write = process.env.WRITE === '1';
    const outputFile = process.env.OUTPUT_FILE;
    const results: ScanResultEntry[] = [];
    console.log(`[scan] starting neuroseo large document scan write=${write} threshold=${threshold}`);
    const semantic = await scanCollection(db, 'semanticMapResults', threshold, deriveSemanticMapAggregate, { write, output: results });
    const crawler = await scanCollection(db, 'neuralCrawlerResults', threshold, deriveNeuralCrawlerAggregate, { write, output: results });
    console.log('[scan] summary', { threshold, semantic, crawler, write });
    if (outputFile) {
        try {
            const fs = await import('fs');
            fs.writeFileSync(outputFile, JSON.stringify({ generatedAt: new Date().toISOString(), threshold, write, semantic, crawler, entries: results }, null, 2));
            console.log(`[scan] wrote summary JSON -> ${outputFile}`);
        } catch (e) {
            console.error('[scan] failed to write OUTPUT_FILE', (e as any)?.message);
        }
    }
    if (!write) console.log('[scan] DRY RUN – no aggregate documents written. Enable WRITE=1 to persist.');
}

main().catch(e => { console.error('[scan] FAILED', e); process.exit(1); });

/*
  Seeds Firestore with example rows under dashboardTables/{widgetId}/rows.
  Usage:
    WIDGET_ID=my-table COUNT=25 ts-node -P scripts/tsconfig.json scripts/seed-dashboard-table-rows.ts
  Env:
    WIDGET_ID: target widget id (default: demo-table)
    COUNT: number of rows to seed (default: 25)
*/

import { adminDb } from '../src/lib/firebase-admin';

type Row = {
    metric: string;
    value: string;
    valueNum: number;
    change: string;
    changeNum: number;
    createdAt: Date;
    teamId?: string;
    userId?: string;
};

async function main() {
    const widgetId = process.env.WIDGET_ID || 'demo-table';
    const count = Number(process.env.COUNT || 25);
    const teamId = process.env.TEAM_ID || undefined;
    const userId = process.env.USER_ID || undefined;
    const stringOnly = (process.env.STRING_ONLY || 'false').toLowerCase() === 'true';
    // Minimal deterministic RNG (LCG)
    let seed = 0x2F6E2B1 ^ widgetId.split('').reduce((a, c) => (a * 33) ^ c.charCodeAt(0), 5381);
    const rng = () => {
        seed = (1664525 * seed + 1013904223) >>> 0;
        return seed / 0xffffffff;
    };

    const col = adminDb
        .collection('dashboardTables')
        .doc(widgetId)
        .collection('rows');

    // Wipe existing rows for deterministic results (safe for demo widgets).
    const snapshot = await col.get();
    const batch = adminDb.batch();
    snapshot.docs.forEach((d) => batch.delete(d.ref));
    await batch.commit();

    const rows: Row[] = [];
    for (let i = 0; i < count; i++) {
        // Deterministic numeric values
        const base = Math.floor(1000 + (1 - rng()) * 9000);
        const trend = (i % 2 === 0 ? 1 : -1) * ((i % 9) + Math.floor(rng() * 5));
        const valueNum = base - i * 13; // strictly decreasing by index
        const changeNum = trend; // signed delta percentage points
        const value = valueNum.toLocaleString('en-US');
        const change = `${changeNum >= 0 ? '+' : ''}${changeNum}%`;

        rows.push({
            metric: `Metric ${String(i + 1).padStart(2, '0')}`,
            value: stringOnly ? `${value}` : value,
            valueNum: stringOnly ? undefined as any : valueNum,
            change: stringOnly ? `${change}` : change,
            changeNum: stringOnly ? undefined as any : changeNum,
            createdAt: new Date(),
            teamId,
            userId,
        });
    }

    // Write in batches of 500
    let pending = adminDb.batch();
    let idx = 0;
    for (const r of rows) {
        const ref = col.doc();
        pending.set(ref, r);
        idx++;
        if (idx % 500 === 0) {
            await pending.commit();
            pending = adminDb.batch();
        }
    }
    await pending.commit();

    console.log(
        JSON.stringify(
            { status: 'ok', widgetId, seeded: rows.length, sample: rows.slice(0, 3) },
            null,
            2,
        ),
    );
}

main().catch((err) => {
    console.error('Seeding failed', err);
    process.exit(1);
});

