/**
 * Firebase Secret Manager Setup Script
 *
 * This script helps you set up the required secrets in Firebase Secret Manager
 * that are needed for the deployment to work properly.
 *
 * Run with: npx ts-node scripts/setup-firebase-secrets.ts
 */

import { execSync } from "child_process";
import readline from "readline";

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout,
});

interface Secret {
  name: string;
  description: string;
  example?: string;
}

const requiredSecrets: Secret[] = [
  {
    name: "STRIPE_SECRET_KEY",
    description: "Stripe Secret Key (starts with sk_test_ or sk_live_)",
    example: "sk_test_...",
  },
  {
    name: "STRIPE_WEBHOOK_SECRET",
    description: "Stripe Webhook Endpoint Secret (starts with whsec_)",
    example: "whsec_...",
  },
  {
    name: "GEMINI_API_KEY",
    description: "Google Gemini API Key",
    example: "AIza...",
  },
  {
    name: "GOOGLE_API_KEY",
    description: "Google Cloud API Key",
    example: "AIza...",
  },
  {
    name: "OPENAI_API_KEY",
    description: "OpenAI API Key (starts with sk-)",
    example: "sk-proj-...",
  },
  {
    name: "NEXT_PUBLIC_RECAPTCHA_SITE_KEY",
    description: "reCAPTCHA Site Key (public)",
    example: "6Le...",
  },
  {
    name: "RECAPTCHA_SECRET_KEY",
    description: "reCAPTCHA Secret Key (private)",
    example: "6Le...",
  },
];

const PROJECT_ID = "rankpilot-h3jpc";

function askQuestion(question: string): Promise<string> {
  return new Promise((resolve) => {
    rl.question(question, resolve);
  });
}

async function checkFirebaseAuth(): Promise<boolean> {
  try {
    execSync("firebase projects:list", { stdio: "pipe" });
    return true;
  } catch (err: unknown) {
    console.error("❌ Firebase CLI not authenticated.", err);
    console.error("Please run: firebase login");
    return false;
  }
}

async function secretExists(secretName: string): Promise<boolean> {
  try {
    execSync(`gcloud secrets describe ${secretName} --project=${PROJECT_ID}`, {
      stdio: "pipe",
    });
    return true;
  } catch (err: unknown) {
    return false;
  }
}

async function createSecret(
  secretName: string,
  secretValue: string
): Promise<void> {
  try {
    // Create the secret
    console.log(`📝 Creating secret ${secretName}...`);
    execSync(
      `echo "${secretValue}" | gcloud secrets create ${secretName} --data-file=- --project=${PROJECT_ID}`,
      { stdio: "pipe" }
    );
    console.log(`✅ Secret ${secretName} created successfully`);
  } catch (err: unknown) {
    console.error(`❌ Failed to create secret ${secretName}:`, err);
  }
}

async function updateSecret(
  secretName: string,
  secretValue: string
): Promise<void> {
  try {
    console.log(`📝 Updating secret ${secretName}...`);
    execSync(
      `echo "${secretValue}" | gcloud secrets versions add ${secretName} --data-file=- --project=${PROJECT_ID}`,
      { stdio: "pipe" }
    );
    console.log(`✅ Secret ${secretName} updated successfully`);
  } catch (err: unknown) {
    console.error(`❌ Failed to update secret ${secretName}:`, err);
  }
}

async function setupSecret(secret: Secret): Promise<void> {
  console.log(`\n🔑 Setting up ${secret.name}`);
  console.log(`📋 ${secret.description}`);
  if (secret.example) {
    console.log(`💡 Example format: ${secret.example}`);
  }

  const exists = await secretExists(secret.name);
  if (exists) {
    console.log(`📋 Secret ${secret.name} already exists`);
    const update = await askQuestion("Do you want to update it? (y/N): ");
    if (update.toLowerCase() !== "y") {
      console.log(`⏭️ Skipping ${secret.name}`);
      return;
    }
  }

  const value = await askQuestion(`Enter ${secret.name}: `);
  if (!value.trim()) {
    console.log(`⏭️ Skipping ${secret.name} (empty value)`);
    return;
  }

  if (exists) {
    await updateSecret(secret.name, value.trim());
  } else {
    await createSecret(secret.name, value.trim());
  }
}

async function enableSecretManagerAPI(): Promise<void> {
  try {
    console.log("🔧 Enabling Secret Manager API...");
    execSync(
      `gcloud services enable secretmanager.googleapis.com --project=${PROJECT_ID}`,
      { stdio: "pipe" }
    );
    console.log("✅ Secret Manager API enabled");
  } catch (err: unknown) {
    console.error(`❌ Failed to enable Secret Manager API:`, err);
  }
}

async function checkGCloudAuth(): Promise<boolean> {
  try {
    execSync(
      'gcloud auth list --filter=status:ACTIVE --format="value(account)"',
      { stdio: "pipe" }
    );
    return true;
  } catch (err: unknown) {
    console.error("❌ Google Cloud CLI not authenticated.", err);
    console.error("Please run: gcloud auth login");
    return false;
  }
}

async function setGCloudProject(): Promise<void> {
  try {
    console.log(`🔧 Setting Google Cloud project to ${PROJECT_ID}...`);
    execSync(`gcloud config set project ${PROJECT_ID}`, { stdio: "pipe" });
    console.log("✅ Project set successfully");
  } catch (err: unknown) {
    console.error(`❌ Failed to set project:`, err);
  }
}

async function listExistingSecrets(): Promise<void> {
  try {
    console.log("\n📋 Existing secrets in Firebase Secret Manager:");
    const output = execSync(`gcloud secrets list --project=${PROJECT_ID}`, {
      encoding: "utf8",
    });
    console.log(output);
  } catch (err: unknown) {
    console.error("❌ Could not list existing secrets", err);
  }
}

async function main(): Promise<void> {
  console.log("🚀 Firebase Secret Manager Setup");
  console.log("==================================\n");

  // Check prerequisites
  console.log("🔍 Checking prerequisites...");

  const firebaseAuth = await checkFirebaseAuth();
  if (!firebaseAuth) {
    process.exit(1);
  }

  const gcloudAuth = await checkGCloudAuth();
  if (!gcloudAuth) {
    process.exit(1);
  }

  await setGCloudProject();
  await enableSecretManagerAPI();
  await listExistingSecrets();

  console.log("\n🔑 Setting up required secrets...");
  console.log(
    "Note: These secrets are required for Firebase deployment to work."
  );

  // Process each secret
  for (const secret of requiredSecrets) {
    await setupSecret(secret);
  }

  console.log("\n✅ Secret setup complete!");
  console.log("\n📋 Next steps:");
  console.log(
    "1. Make sure the same secrets are added to GitHub repository secrets"
  );
  console.log("2. Run deployment: firebase deploy");
  console.log("3. Or push to master branch to trigger auto-deployment");

  rl.close();
}

// Handle errors
process.on("uncaughtException", (error) => {
  console.error("❌ Uncaught exception:", error);
  rl.close();
  process.exit(1);
});

process.on("unhandledRejection", (reason, promise) => {
  console.error("❌ Unhandled rejection at:", promise, "reason:", reason);
  rl.close();
  process.exit(1);
});

main().catch((error) => {
  console.error("❌ Script failed:", error);
  rl.close();
  process.exit(1);
});

#!/usr/bin/env ts-node
/*
 * NeuroSEO Size Snapshot Wrapper
 * Purpose: Combine size reduction stats + approximate adoption in one dated artifact.
 * Usage: OUTPUT_DIR=artifacts ts-node scripts/snapshot-neuroseo-size.ts
 */
import { getApps, initializeApp } from 'firebase-admin/app';
import { getFirestore } from 'firebase-admin/firestore';

async function adoption(db: FirebaseFirestore.Firestore) {
    const [crawlerLegacy, crawlerAgg, semanticLegacy, semanticAgg] = await Promise.all([
        db.collection('neuralCrawlerResults').count().get().then(r => r.data().count).catch(() => 0),
        db.collection('neuralCrawlerResultsAgg').count().get().then(r => r.data().count).catch(() => 0),
        db.collection('semanticMapResults').count().get().then(r => r.data().count).catch(() => 0),
        db.collection('semanticMapResultsAgg').count().get().then(r => r.data().count).catch(() => 0),
    ]);
    const crawlerDenom = crawlerLegacy + crawlerAgg; const semanticDenom = semanticLegacy + semanticAgg;
    return {
        crawlerAggregateAdoptionApprox: crawlerDenom > 0 ? +((crawlerAgg / crawlerDenom) * 100).toFixed(2) : null,
        semanticMapAggregateAdoptionApprox: semanticDenom > 0 ? +((semanticAgg / semanticDenom) * 100).toFixed(2) : null,
    };
}

async function runSizeReport(): Promise<any> {
    const { getApps: ga2 } = await import('firebase-admin/app');
    const { getFirestore: gf2 } = await import('firebase-admin/firestore');
    if (!ga2().length) initializeApp();
    const db = gf2();
    async function collectPairSizes(legacyCol: string, aggCol: string, matchFields: string[]) {
        const stats: any = { legacyCount: 0, aggCount: 0, matched: 0, legacyBytes: 0, aggBytes: 0, reductionPct: null };
        const legacySnap = await db.collection(legacyCol).limit(5000).get(); stats.legacyCount = legacySnap.size;
        if (!legacySnap.empty) {
            const aggSnap = await db.collection(aggCol).limit(5000).get(); stats.aggCount = aggSnap.size;
            const aggIndex = new Map<string, FirebaseFirestore.QueryDocumentSnapshot>();
            aggSnap.docs.forEach(d => { const data: any = d.data(); const key = matchFields.map(f => (data as any)[f] ?? '').join('|'); aggIndex.set(key, d); });
            for (const doc of legacySnap.docs) {
                const data: any = doc.data(); const key = matchFields.map(f => (data as any)[f] ?? '').join('|'); const legacySize = Buffer.byteLength(JSON.stringify(data)); const aggDoc = aggIndex.get(key);
                if (aggDoc) { stats.matched++; stats.legacyBytes += legacySize; stats.aggBytes += Buffer.byteLength(JSON.stringify(aggDoc.data())); }
            }
            if (stats.matched > 0) { const avgLegacy = stats.legacyBytes / stats.matched; const avgAgg = stats.aggBytes / stats.matched; stats.reductionPct = +(((1 - (avgAgg / avgLegacy)) * 100)).toFixed(2); }
        }
        return stats;
    }
    const semantic = await collectPairSizes('semanticMapResults', 'semanticMapResultsAgg', ['userId', 'url']);
    const crawler = await collectPairSizes('neuralCrawlerResults', 'neuralCrawlerResultsAgg', ['userId', 'url']);
    return { semantic, crawler };
}

async function main() {
    if (!getApps().length) initializeApp();
    const db = getFirestore();
    const [sizeReport, adopt] = await Promise.all([runSizeReport(), adoption(db)]);
    const snapshot = { generatedAt: new Date().toISOString(), ...sizeReport, adoption: adopt };
    console.log('[snapshot-size] snapshot', JSON.stringify(snapshot, null, 2));
    const dir = process.env.OUTPUT_DIR;
    if (dir) {
        try {
            const fs = await import('fs');
            fs.mkdirSync(dir, { recursive: true });
            const file = `${dir}/size-reduction-${new Date().toISOString().split('T')[0]}.json`;
            fs.writeFileSync(file, JSON.stringify(snapshot, null, 2));
            console.log('[snapshot-size] wrote', file);
        } catch (e) {
            console.error('[snapshot-size] write failed', (e as any)?.message);
        }
    }
}

main().catch(e => { console.error('[snapshot-size] FAILED', e); process.exit(1); });

/**
 * Shared invoice upsert utility (scaffold).
 * NOTE: Payment/Stripe logic is intentionally simple here; unification task will
 * replace route-local implementation once reviewed. Avoid heavy mutations.
 */
// Note: Using relative imports because script context may not apply tsconfig path aliases.
import { db } from '../../src/lib/firebase';
import { collection, query, where, getDocs, setDoc, doc } from 'firebase/firestore';
import { getLogger } from '../../src/lib/logging/app-logger';

export interface MinimalStripeInvoiceLike {
    id: string;
    customer?: string | null;
    period_end?: number;
    created: number;
    status?: string | null;
    amount_paid?: number | null;
    amount_due?: number | null;
    due_date?: number | null;
    status_transitions?: { paid_at?: number | null };
    lines?: { data?: any[] };
    metadata?: Record<string, any>;
    currency?: string;
}

export async function upsertFinanceInvoice(invoice: MinimalStripeInvoiceLike) {
    const logger = getLogger('stripe-invoice-util');
    try {
        const customerId = invoice.customer as string | undefined;
        if (!customerId) return;
        const usersQ = query(collection(db, 'users'), where('stripeCustomerId', '==', customerId));
        const snap = await getDocs(usersQ);
        if (snap.empty) return;
        const userId = snap.docs[0].id;
        const period = new Date(((invoice.period_end || invoice.created) * 1000)).toISOString().slice(0, 7);
        const status = invoice.status || 'open';
        const amount = (invoice.amount_paid || invoice.amount_due || 0) / 100;
        const issuedAt = new Date(invoice.created * 1000);
        const dueAt = invoice.due_date ? new Date(invoice.due_date * 1000) : null;
        const paidAt = invoice.status === 'paid' && invoice.status_transitions?.paid_at ? new Date(invoice.status_transitions.paid_at * 1000) : null;
        const firstLine: any = invoice.lines?.data?.[0];
        const planTier = firstLine?.price?.metadata?.planTier || invoice.metadata?.planTier || null;
        const ref = doc(db, 'financeInvoices', invoice.id);
        await setDoc(ref, { userId, period, amount, status, issuedAt, dueAt, paidAt, planTier, currency: invoice.currency, updatedAt: new Date(), createdAt: new Date() }, { merge: true });
    } catch (e) {
        logger.degraded('invoice.upsert.failed', { invoiceId: invoice.id, error: (e as Error).message });
    }
}

