  if (loading && !forceAdmin) return <LoadingScreen fullScreen text="Loading admin context..." />;
  if ((!user || role !== 'admin') && !forceAdmin) return <LoadingScreen fullScreen text="Redirecting..." />;

  interface CardDef { title: string; value: unknown; unit?: string; help?: string; icon: any; variant?: 'percent' | 'ms' | 'raw'; extra?: React.ReactNode }
  const renderCard = (c: CardDef) => {
    const state = c.variant === 'percent' ? classify(c.value as number | null) : '';
    return (
      <Card key={c.title} className="overflow-hidden">
        <CardHeader className="pb-2">
          <CardTitle className="flex items-center gap-2 text-sm font-medium">
            <c.icon className="h-4 w-4" /> {c.title}
          </CardTitle>
          {c.help && <CardDescription className="text-xs">{c.help}</CardDescription>}
          {c.extra}
        </CardHeader>
        <CardContent className="space-y-2">
          <div className={`text-lg font-semibold ${badgeClass(state)}`}>{c.value == null ? (busy ? '…' : '—') : (c.unit === '$' ? `$${c.value}` : `${c.value}${c.unit}`)}</div>
          {c.variant === 'percent' && <Progress value={typeof c.value === 'number' ? c.value : 0} className={state==='critical'? 'bg-red-200': state==='warn'? 'bg-amber-200':'bg-green-200'} />}
        </CardContent>
      </Card>
    );
  };

  const alerts = data?.alerts || [];
  const routeP95Map: Record<string, number | null> = (data?.p95 || {});
  const routeLatencyRows = Object.entries(routeP95Map)
    .filter(([r,v]) => typeof v === 'number' && v != null)
    .sort((a,b)=> (b[1]||0) - (a[1]||0))
    .slice(0, 12);
  const maxRouteP95 = routeLatencyRows.reduce((m, [,v]) => v!>m? v!:m, 0);

  return (
    <main className="container mx-auto py-6 space-y-6">
      <ToolPageHeader
        title="Observability"
        description="Unified operational KPIs: provenance, latency, adoption, AI usage & cost."
        badges={[{ label: 'Admin', variant: 'outline' }]}
        showBreadcrumb
      />
      <div className="grid gap-4 md:grid-cols-4 sm:grid-cols-2">{cards.map(renderCard)}</div>
      <section className="space-y-4">
        <h2 className="text-sm font-semibold tracking-wide flex items-center gap-2"><LineIcon className="h-4 w-4" />Historical (Last ~14 Days)</h2>
        <div className="grid gap-4 md:grid-cols-3 sm:grid-cols-2">
          <Card>
            <CardHeader className="pb-2"><CardTitle className="text-sm">Provenance %</CardTitle><CardDescription className="text-xs">Daily snapshot coverage</CardDescription></CardHeader>
            <CardContent><Sparkline values={histProvenance} ma7Values={maProvenance} color="bg-green-500" testId="sparkline-provenance" /></CardContent>
          </Card>
          <Card>
            <CardHeader className="pb-2"><CardTitle className="text-sm">Latency P95</CardTitle><CardDescription className="text-xs">Avg per-route p95</CardDescription></CardHeader>
            <CardContent><Sparkline values={histP95} ma7Values={maP95} color="bg-blue-500" testId="sparkline-latencyP95" /></CardContent>
          </Card>
          <Card>
            <CardHeader className="pb-2"><CardTitle className="text-sm">AI Cost ($)</CardTitle><CardDescription className="text-xs">Daily cost estimate</CardDescription></CardHeader>
            <CardContent><Sparkline values={histCost} ma7Values={maCost} color="bg-purple-500" testId="sparkline-cost" /></CardContent>
          </Card>
        </div>
        <div className="grid gap-4 md:grid-cols-4 sm:grid-cols-2">
          <Card>
            <CardHeader className="pb-2"><CardTitle className="text-sm">Crawler Adoption %</CardTitle><CardDescription className="text-xs">Aggregate hits share</CardDescription></CardHeader>
            <CardContent><Sparkline values={histCrawlerAdopt} ma7Values={maCrawler} color="bg-amber-500" testId="sparkline-crawlerAdoption" /></CardContent>
          </Card>
          <Card>
            <CardHeader className="pb-2"><CardTitle className="text-sm">SemanticMap Adoption %</CardTitle><CardDescription className="text-xs">Aggregate hits share</CardDescription></CardHeader>
            <CardContent><Sparkline values={histSemanticAdopt} ma7Values={maSemantic} color="bg-amber-600" testId="sparkline-semanticAdoption" /></CardContent>
          </Card>
          <Card>
            <CardHeader className="pb-2"><CardTitle className="text-sm">Team Util %</CardTitle><CardDescription className="text-xs">Team limiter utilization</CardDescription></CardHeader>
            <CardContent><Sparkline values={histTeamUtil} ma7Values={maTeamUtil} color="bg-cyan-500" testId="sparkline-teamUtil" /></CardContent>
          </Card>
          <Card>
            <CardHeader className="pb-2"><CardTitle className="text-sm">Fallback Rate %</CardTitle><CardDescription className="text-xs">AI fallback share</CardDescription></CardHeader>
            <CardContent><Sparkline values={histFallback} ma7Values={maFallback} color="bg-red-500" testId="sparkline-fallbackRate" /></CardContent>
          </Card>
        </div>
        {(histCacheHit.length || histRateLimitReject.length) && (
          <div className="grid gap-4 md:grid-cols-2 sm:grid-cols-2">
            <Card>
              <CardHeader className="pb-2"><CardTitle className="text-sm">Cache Hit Ratio %</CardTitle><CardDescription className="text-xs">Edge/runtime response caching</CardDescription></CardHeader>
              <CardContent><Sparkline values={histCacheHit} ma7Values={maCacheHit} color="bg-green-500" testId="sparkline-cacheHit" /></CardContent>
            </Card>
            <Card>
              <CardHeader className="pb-2"><CardTitle className="text-sm">Rate Limit Rejection %</CardTitle><CardDescription className="text-xs">Requests rejected by limiters</CardDescription></CardHeader>
              <CardContent><Sparkline values={histRateLimitReject} ma7Values={maRateLimitReject} color="bg-orange-600" testId="sparkline-rateLimitReject" /></CardContent>
            </Card>
          </div>
        )}
      </section>
      <section className="space-y-2">
        <h2 className="text-sm font-semibold tracking-wide">Active Alerts</h2>
        {alerts.length === 0 && <p className="text-xs text-muted-foreground">No active alerts.</p>}
        <ul className="space-y-1">
          {alerts.map(a => (
            <li key={a.type+ a.level} className={`text-xs rounded px-2 py-1 border ${a.level==='critical'? 'border-red-500 text-red-600':'border-amber-500 text-amber-600'}`}>{a.message} (value={a.value ?? '—'})</li>
          ))}
        </ul>
      </section>
      {filteredAlertHistory.length > 0 && (
        <section className="space-y-2">
          <div className="flex items-center gap-3">
            <h2 className="text-sm font-semibold tracking-wide">Alert History (Preview)</h2>
            <label className="text-[10px] flex items-center gap-1">Filter:
              <select value={alertFilter} onChange={e=> setAlertFilter(e.target.value)} data-testid="alert-filter" className="border rounded px-1 py-0.5 text-[10px] bg-background">
                <option value="all">All</option>
                {uniqueAlertTypes.map(t=> <option key={t} value={t}>{t}</option>)}
              </select>
            </label>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full border-collapse text-xs">
              <thead>
                <tr className="text-left border-b border-border/40">
                  <th className="py-1 pr-3 font-medium">Date</th>
                  <th className="py-1 pr-3 font-medium">Type</th>
                  <th className="py-1 pr-3 font-medium">Level</th>
                  <th className="py-1 pr-3 font-medium">Message</th>
                  <th className="py-1 pr-3 font-medium">MA7 (If Key)</th>
                </tr>
              </thead>
              <tbody>
                {filteredAlertHistory.slice(0,30).map((h:AlertEntry,i:number)=>{
                  const ma = h.type==='provenanceCoverage'? h.ma7Provenance :
                    h.type==='crawlerAggregateAdoption'? h.ma7CrawlerAdoption :
                    h.type==='semanticMapAggregateAdoption'? h.ma7SemanticAdoption :
                    h.type==='fallbackRate'? h.ma7FallbackRate :
                    h.type==='latencyOverallP95'? h.ma7LatencyP95 :
                    h.type==='cacheHitRatio'? h.ma7CacheHitRatio :
                    h.type==='rateLimitRejectionRate'? h.ma7RateLimitRejectionRate : null;
                  let maClass = '';
                  if (typeof ma === 'number' && typeof h.value === 'number') {
                    const delta = (Number(h.value) - ma) / (ma || 1);
                    if (h.type==='latencyOverallP95' || h.type==='fallbackRate' || h.type==='rateLimitRejectionRate') {
                      if (delta > 0.15) maClass='text-red-600'; else if (delta > 0.05) maClass='text-amber-600'; else maClass='text-green-600';
                    } else { // higher is better metrics
                      if (delta < -0.15) maClass='text-red-600'; else if (delta < -0.05) maClass='text-amber-600'; else maClass='text-green-600';
                    }
                  }
                  return (
                    <tr key={i} className="border-b border-border/20 last:border-none">
                      <td className="py-1 pr-3 font-mono text-[11px]">{(h.date as string) || '—'}</td>
                      <td className="py-1 pr-3">{h.type}</td>
                      <td className="py-1 pr-3">{h.level}</td>
                      <td className="py-1 pr-3 truncate max-w-[280px]">{h.message}</td>
                      <td className={`py-1 pr-3 ${maClass}`}>{typeof ma === 'number'? ma: '—'}</td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
          <p className="text-[10px] text-muted-foreground">Persisted daily alert snapshots (max 30). Filter to inspect specific alert types.</p>
        </section>
      )}
      <section className="space-y-2">
        <h2 className="text-sm font-semibold tracking-wide">Route Latency (p95)</h2>
        {routeLatencyRows.length === 0 && <p className="text-xs text-muted-foreground">No route latency data yet.</p>}
        {routeLatencyRows.length > 0 && (
          <div className="overflow-x-auto">
            <table className="w-full border-collapse text-xs">
              <thead>
                <tr className="text-left border-b border-border/40">
                  <th className="py-1 pr-3 font-medium">Route</th>
                  <th className="py-1 pr-3 font-medium">p95 (ms)</th>
                  <th className="py-1 font-medium w-40">Relative</th>
                </tr>
              </thead>
              <tbody>
                {routeLatencyRows.map(([route, val]) => {
                  const pct = maxRouteP95 ? ((val! / maxRouteP95) * 100) : 0;
                  const barColor = pct > 80 ? 'bg-red-500' : pct > 60 ? 'bg-amber-500' : pct > 40 ? 'bg-yellow-500' : 'bg-green-500';
                  return (
                    <tr key={route} className="border-b border-border/20 last:border-none">
                      <td className="py-1 pr-3 align-middle font-mono text-[11px]">{route}</td>
                      <td className="py-1 pr-3 align-middle">{val}</td>
                      <td className="py-1 align-middle">
                        <div className="h-3 w-full bg-muted rounded-sm relative overflow-hidden">
                          <div className={`h-full ${barColor}`} style={{ width: pct+'%' }} />
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
        <p className="text-[10px] text-muted-foreground">Top {routeLatencyRows.length} routes by current p95. Aim to keep critical user paths &lt; 500ms.</p>
      </section>
      {perModel && (
        <section className="space-y-2">
          <h2 className="text-sm font-semibold tracking-wide">AI Cost Breakdown (Per Model)</h2>
          <div className="overflow-x-auto">
            <table className="w-full border-collapse text-xs">
              <thead>
                <tr className="text-left border-b border-border/40">
                  <th className="py-1 pr-3 font-medium">Model/Provider</th>
                  <th className="py-1 pr-3 font-medium">Tokens In</th>
                  <th className="py-1 pr-3 font-medium">Tokens Out</th>
                  <th className="py-1 pr-3 font-medium">Cost ($)</th>
                </tr>
              </thead>
              <tbody>
                {Object.entries(perModel as Record<string,{tokensIn:number;tokensOut:number;cost:number}>).map(([m, v]) => (
                  <tr key={m} className="border-b border-border/20 last:border-none">
                    <td className="py-1 pr-3 font-mono text-[11px]">{m}</td>
                    <td className="py-1 pr-3">{v.tokensIn}</td>
                    <td className="py-1 pr-3">{v.tokensOut}</td>
                    <td className="py-1 pr-3">${v.cost.toFixed(4)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          <p className="text-[10px] text-muted-foreground">Breakdown derived from in-process token accounting; costs approximate and subject to provider rounding.</p>
        </section>
      )}
    </main>
  );
}

"use client";
import React, { useEffect, useState } from 'react';
import type { ChangeEvent } from 'react';
import { FeatureGate } from '@/components/subscription/FeatureGate';
import type { AutomationRecipe, AutomationRunLog, AutomationActionType } from '@/lib/automation/recipes';
import { createAutomationRecipe, listAutomationRecipes, updateAutomationRecipe, defaultRecipeTemplate, listRecentAutomationRuns, countPendingEmails } from '@/lib/automation/recipes';
import { useAuth } from '@/context/AuthContext';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Switch } from '@/components/ui/switch';
import { Label } from '@/components/ui/label';
import { Separator } from '@/components/ui/separator';
import { useHydration } from '@/components/HydrationContext';
import { useToast } from '@/hooks/use-toast';

const ACTIONS: { id: string; label: string; desc: string }[] = [
  { id: 'runNeuroSEOAnalysis', label: 'Run NeuroSEO Analysis', desc: 'Executes a fresh analysis with placeholder inputs' },
  { id: 'sendDigestEmail', label: 'Send Digest Email', desc: 'Enqueue generic digest email' },
  { id: 'generateContentRewrite', label: 'Generate Content Rewrite', desc: 'Create rewrite variants for up to 3 URLs' },
  { id: 'salesRefreshMetrics', label: 'Sales: Refresh Metrics Snapshot', desc: 'Store pipeline + win-rate snapshot' },
  { id: 'salesForecastSnapshot', label: 'Sales: Forecast Snapshot', desc: 'Persist lightweight forecast (pipeline * 0.8)' },
  { id: 'salesPipelineDigest', label: 'Sales: Pipeline Digest Email', desc: 'Email current pipeline / win-rate' },
  { id: 'financeRevenueSnapshot', label: 'Finance: Revenue Snapshot', desc: 'Store monthly revenue KPIs' },
  { id: 'financeInvoiceAgingDigest', label: 'Finance: Invoice Aging Digest', desc: 'Email counts by aging bucket' },
];

export default function AutomationRecipesPage() {
  const { user } = useAuth();
  const teamId = (user as any)?.teamId;
  const { toast } = useToast();
  const hydrated = useHydration();
  const [recipes, setRecipes] = useState<AutomationRecipe[]>([]);
  const [loading, setLoading] = useState(false);
  const [creating, setCreating] = useState(false);
  const [newName, setNewName] = useState('');
  const [interval, setInterval] = useState(1440);
  const [selectedActions, setSelectedActions] = useState<string[]>(['runNeuroSEOAnalysis']);
  const [analysisUrls, setAnalysisUrls] = useState<string>('https://example.com');
  const [analysisKeywords, setAnalysisKeywords] = useState<string>('example');
  const [digestTo, setDigestTo] = useState<string>('digest@example.com');
  const [digestSubject, setDigestSubject] = useState<string>('NeuroSEO Digest');
  const [salesDigestTo, setSalesDigestTo] = useState<string>('sales-digest@example.com');
  const [financeAgingTo, setFinanceAgingTo] = useState<string>('finance-aging@example.com');
  const [range, setRange] = useState<'30d' | '90d' | 'ytd'>('30d');
  const [cronExpr, setCronExpr] = useState<string>('');
  const [validationError, setValidationError] = useState<string>('');
  const [runLogs, setRunLogs] = useState<Record<string, AutomationRunLog[]>>({});
  const [pendingEmails, setPendingEmails] = useState<Record<string, number>>({});

  useEffect(() => {
    if (!user) return;
    void (async () => {
      setLoading(true);
      try {
  const list = await listAutomationRecipes(user.uid, teamId);
        setRecipes(list);
        // Fetch run logs & pending emails for each recipe sequentially (small N expected)
        const logsMap: Record<string, AutomationRunLog[]> = {};
        const emailMap: Record<string, number> = {};
        for (const r of list) {
          try {
            logsMap[r.id!] = await listRecentAutomationRuns(r.id!, 5);
            emailMap[r.id!] = await countPendingEmails(r.id!);
          } catch { /* swallow */ }
        }
        setRunLogs(logsMap);
        setPendingEmails(emailMap);
      } catch (e: unknown) {
        console.error(e);
      } finally {
        setLoading(false);
      }
    })();
  }, [user]);

  const create = async () => {
    if (!user) return;
    try {
      setCreating(true);
      setValidationError('');
      if (cronExpr && interval) {
        setValidationError('Use either interval OR cron, not both.');
        return;
      }
  const tpl = defaultRecipeTemplate(user.uid, teamId);
      tpl.name = newName || 'Automation Recipe';
      if (cronExpr.trim()) {
        tpl.schedule = { cron: cronExpr.trim() } as AutomationRecipe['schedule'];
      } else {
        tpl.schedule.intervalMinutes = interval;
      }
      tpl.actions = selectedActions as AutomationActionType[];
      tpl.actionConfigs = {
        runNeuroSEOAnalysis: {
          urls: analysisUrls.split('\n').map(l=>l.trim()).filter(Boolean).slice(0,5),
          keywords: analysisKeywords.split(',').map(k=>k.trim()).filter(Boolean).slice(0,10)
        },
        sendDigestEmail: {
          to: digestTo,
          subject: digestSubject,
          urls: analysisUrls.split('\n').map(l=>l.trim()).filter(Boolean).slice(0,5),
          keywords: analysisKeywords.split(',').map(k=>k.trim()).filter(Boolean).slice(0,10)
        },
        generateContentRewrite: {
          urls: analysisUrls.split('\n').map(l=>l.trim()).filter(Boolean).slice(0,3),
          keywords: analysisKeywords.split(',').map(k=>k.trim()).filter(Boolean).slice(0,5)
  },
  salesRefreshMetrics: { range },
  salesForecastSnapshot: {},
  salesPipelineDigest: { to: salesDigestTo, range },
  financeRevenueSnapshot: {},
  financeInvoiceAgingDigest: { to: financeAgingTo },
      };
      const created = await createAutomationRecipe(tpl);
      setRecipes(r => [created, ...r]);
      setNewName('');
      toast({ title: 'Recipe created', description: created.name });
    } catch (e: unknown) {
      const err = e as { message?: string };
      toast({ title: 'Create failed', description: err.message || 'Unknown error', variant: 'destructive' });
    } finally { setCreating(false); }
  };

  const toggleActive = async (r: AutomationRecipe) => {
    try {
      const updated = await updateAutomationRecipe(r.id!, { active: !r.active });
      setRecipes(list => list.map(x => x.id === r.id ? updated : x));
    } catch (e: unknown) {
      const err = e as { message?: string };
      toast({ title: 'Update failed', description: err.message || 'Unknown error', variant: 'destructive' });
    }
  };

  const hydrationDisabled = !hydrated || loading || creating;

  return (
    <FeatureGate requiredTier="agency" feature="automation_recipes" showUpgrade>
      <div className="space-y-6 p-4 md:p-6">
        <div>
          <h1 className="text-2xl font-semibold tracking-tight">Automation Recipes</h1>
          <p className="text-muted-foreground">Schedule recurring AI-driven operations.</p>
        </div>
        <Card>
          <CardHeader>
            <CardTitle>Create Recipe</CardTitle>
            <CardDescription>Define interval & select actions</CardDescription>
          </CardHeader>
            <CardContent className="space-y-4">
              <div className="space-y-2">
                <Label htmlFor="name">Name</Label>
                <Input id="name" value={newName} onChange={(e: ChangeEvent<HTMLInputElement>) => setNewName(e.target.value)} placeholder="Weekly NeuroSEO Digest" disabled={hydrationDisabled} />
              </div>
              <div className="space-y-3">
                <div className="space-y-2">
                  <Label>Interval (minutes)</Label>
                  <Input type="number" min={5} value={interval} onChange={(e: ChangeEvent<HTMLInputElement>) => setInterval(Number(e.target.value))} disabled={hydrationDisabled || !!cronExpr.trim()} />
                  <p className="text-xs text-muted-foreground">1440 = daily, 10080 = weekly. Disabled if cron is set.</p>
                </div>
                <div className="space-y-2">
                  <Label>Cron Expression (optional)</Label>
                  <Input placeholder="m h * * * or @daily" value={cronExpr} onChange={(e: ChangeEvent<HTMLInputElement>) => setCronExpr(e.target.value)} disabled={hydrationDisabled} />
                  <p className="text-xs text-muted-foreground">Supports m h * * * plus @daily / @hourly. Use instead of interval.</p>
                </div>
                {validationError && <p className="text-xs text-destructive">{validationError}</p>}
              </div>
              <div className="space-y-2">
                <Label>Actions</Label>
                <div className="grid gap-3 md:grid-cols-2">
                  {ACTIONS.map(a => {
                    const checked = selectedActions.includes(a.id);
                    return (
                      <label key={a.id} className="flex items-start space-x-2 rounded border p-3 cursor-pointer hover:bg-muted/30">
                        <input type="checkbox" checked={checked} disabled={hydrationDisabled} onChange={() => setSelectedActions(prev => checked ? prev.filter(x => x !== a.id) : [...prev, a.id])} />
                        <span className="text-sm"><span className="font-medium">{a.label}</span><br/><span className="text-xs text-muted-foreground">{a.desc}</span></span>
                      </label>
                    );
                  })}
                </div>
              </div>
              {selectedActions.includes('runNeuroSEOAnalysis') && (
                <div className="space-y-2">
                  <Label>Analysis URLs (one per line)</Label>
                  <Textarea value={analysisUrls} onChange={(e: ChangeEvent<HTMLTextAreaElement>)=>setAnalysisUrls(e.target.value)} rows={3} disabled={hydrationDisabled} />
                  <Label className="mt-2">Analysis Keywords (comma separated)</Label>
                  <Input value={analysisKeywords} onChange={(e: ChangeEvent<HTMLInputElement>)=>setAnalysisKeywords(e.target.value)} disabled={hydrationDisabled} />
                </div>
              )}
              {selectedActions.includes('sendDigestEmail') && (
                <div className="space-y-2">
                  <Label>Digest Recipient</Label>
                  <Input value={digestTo} onChange={(e: ChangeEvent<HTMLInputElement>)=>setDigestTo(e.target.value)} disabled={hydrationDisabled} />
                  <Label className="mt-2">Digest Subject</Label>
                  <Input value={digestSubject} onChange={(e: ChangeEvent<HTMLInputElement>)=>setDigestSubject(e.target.value)} disabled={hydrationDisabled} />
                </div>
              )}
              {selectedActions.includes('generateContentRewrite') && (
                <div className="space-y-2 text-xs text-muted-foreground">
                  <p>Will generate rewrite variants for up to 3 URLs (placeholder content) using provided keywords.</p>
                </div>
              )}
              {(selectedActions.includes('salesRefreshMetrics') || selectedActions.includes('salesPipelineDigest')) && (
                <div className="space-y-2">
                  <Label>Sales Range</Label>
                  <select className="border rounded px-2 py-1 text-sm" value={range} disabled={hydrationDisabled} onChange={(e: ChangeEvent<HTMLSelectElement>) => setRange(e.target.value as '30d'|'90d'|'ytd')}>
                    <option value="30d">Last 30d</option>
                    <option value="90d">Last 90d</option>
                    <option value="ytd">Year to Date</option>
                  </select>
                </div>
              )}
              {selectedActions.includes('salesPipelineDigest') && (
                <div className="space-y-2">
                  <Label>Sales Digest Recipient</Label>
                  <Input value={salesDigestTo} onChange={(e: ChangeEvent<HTMLInputElement>) => setSalesDigestTo(e.target.value)} disabled={hydrationDisabled} />
                </div>
              )}
              {selectedActions.includes('financeInvoiceAgingDigest') && (
                <div className="space-y-2">
                  <Label>Finance Aging Digest Recipient</Label>
                  <Input value={financeAgingTo} onChange={(e: ChangeEvent<HTMLInputElement>) => setFinanceAgingTo(e.target.value)} disabled={hydrationDisabled} />
                </div>
              )}
              <Button onClick={() => void create()} disabled={hydrationDisabled}>Create</Button>
            </CardContent>
        </Card>
        <Separator />
        <div className="space-y-4">
          <h2 className="text-xl font-semibold">Existing Recipes</h2>
          {recipes.length === 0 && <p className="text-sm text-muted-foreground">No recipes yet.</p>}
          <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
            {recipes.map(r => {
              const logs = runLogs[r.id!] || [];
              const pending = pendingEmails[r.id!] || 0;
              return (
                <Card key={r.id} className="flex flex-col">
                  <CardHeader className="pb-2">
                    <CardTitle className="text-base flex items-center justify-between">
                      <span>{r.name}</span>
                      <Switch checked={r.active} disabled={hydrationDisabled} onCheckedChange={() => void toggleActive(r)} />
                    </CardTitle>
                    <CardDescription className="text-xs">{r.schedule.cron ? `Cron: ${r.schedule.cron}` : r.schedule.intervalMinutes ? `${r.schedule.intervalMinutes}m interval` : r.schedule.atHourUTC !== undefined ? `Daily @ ${r.schedule.atHourUTC}:00 UTC` : 'Custom'}
                    </CardDescription>
                  </CardHeader>
                  <CardContent className="text-xs text-muted-foreground space-y-2 flex-1">
                    <div>Actions: {r.actions.join(', ')}</div>
                    <div>Last Run: {r.lastRun ? r.lastRun.toLocaleString() : '—'}</div>
                    <div>Next Run: {r.nextRun ? r.nextRun.toLocaleString() : '—'}</div>
                    <div>Pending Emails: {pending}</div>
                    {logs.length > 0 && (
                      <div className="border-t pt-2 space-y-1">
                        <div className="font-medium text-muted-foreground/70">Recent Runs</div>
                        {logs.map(l => (
                          <div key={l.id} className="flex flex-col border rounded p-1 bg-muted/30">
                            <div className="flex justify-between"><span>{new Date(l.startedAt).toLocaleTimeString()}</span><span className={l.status==='ok' ? 'text-success-foreground' : l.status==='partial' ? 'text-warning-foreground' : 'text-destructive-foreground'}>{l.status}</span></div>
                            <div className="truncate">{l.actions.map((a)=>`${a.type}:${a.status}`).join(' | ')}</div>
                          </div>
                        ))}
                      </div>
                    )}
                  </CardContent>
                </Card>
              );
            })}
          </div>
        </div>
      </div>
    </FeatureGate>
  );
}

﻿"use client";

import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import LoadingScreen from "@/components/ui/loading-screen";
import { Separator } from "@/components/ui/separator";
import { useAuth } from "@/context/AuthContext";
import { useSubscription } from "@/hooks/useSubscription";
import { fetchBillingData, type BillingDataResult } from "@/lib/billing/fetch-billing-data";
import type { NormalizedUsageMetrics } from '@/lib/billing/fetch-usage-metrics';
import { fetchUsageMetrics } from '@/lib/billing/fetch-usage-metrics';
import { db, functions } from "@/lib/firebase";
import { getLogger } from "@/lib/logging/app-logger";
import { httpsCallable } from "firebase/functions";
import { motion } from "framer-motion";
import {
  AlertTriangle,
  CheckCircle,
  CreditCard,
  Crown,
  DollarSign,
  Download,
  ExternalLink,
  RefreshCw,
  Settings,
  TrendingUp
} from "lucide-react";
import Link from "next/link";
import { useEffect, useState } from "react";
import { toast } from "sonner";

// FIN-02: Wiring live usage metrics and payment method is implemented via fetchUsageMetrics and /api/billing/payment-method

export default function BillingPage() {
  const [isLoading, setIsLoading] = useState(false);
  const [isMounted, setIsMounted] = useState(false);
  const { user, loading } = useAuth();
  const [billing, setBilling] = useState<BillingDataResult | null>(null);
  const [fetchError, setFetchError] = useState<string | null>(null);
  const { canUseFeature } = useSubscription();
  const billingPortalEnabled = canUseFeature('billing_portal_access');
  interface PaymentMethod { brand:string; last4:string; expMonth:number; expYear:number }
  const [paymentMethodState, setPaymentMethodState] = useState<PaymentMethod|null>(null);
  const [isManagingPortal, setIsManagingPortal] = useState(false);

  useEffect(() => {
    setIsMounted(true);
  }, []);

  // Firestore fetch side-effect
  useEffect(() => {
    if (!user?.uid) return;
    let cancelled = false;
    void (async () => {
      const _logger = getLogger("billing-ui");
      try {
        const data = await fetchBillingData(db, user.uid, { invoiceLimit: 10 });
        if (cancelled) return;
        setBilling(data);
      } catch (e) {
        if (cancelled) return;
        const err = e as any;
        setFetchError(err?.message || "Failed to load billing data");
        _logger.error("billing-ui.client.fetch.error", { error: err?.message });
      }
    })();
    return () => {
      cancelled = true;
    };
  }, [user?.uid, db, fetchBillingData, getLogger]);

  // Payment method fetch (server API)
  useEffect(() => {
    if (!user) return;
    let cancelled = false;
    void (async () => {
      try {
        const token = await user.getIdToken?.();
        const res = await fetch("/api/billing/payment-method", { headers: { authorization: `Bearer ${token}` } });
        if (!res.ok) return;
        const json = await res.json();
        if (cancelled) return;
        setPaymentMethodState(json.paymentMethod || null);
      } catch {
        /* silent */
      }
    })();
    return () => {
      cancelled = true;
    };
  }, [user]);

  const subscription = billing?.subscription || null;
  const PAGE_SIZE = 10;
  interface InvoiceLite { id:string; amount:number; period?:string; description?:string; date?:string; createdAt?:Date; issuedAt?:{ toDate:()=>Date }; [k:string]:any }
  const [invoices, setInvoices] = useState<InvoiceLite[]>(billing?.invoices as InvoiceLite[] || []);
  const [page, setPage] = useState(0);
  const [hasMore, setHasMore] = useState(false);
  const [loadingMore, setLoadingMore] = useState(false);

  // Normalize initial invoices to include description/date for display parity with API pagination
  useEffect(() => {
    if (billing?.invoices) {
      const normalized = (billing.invoices || []).map((inv: any) => {
        const createdAt: Date = inv?.createdAt?.toDate?.() || inv?.issuedAt?.toDate?.() || (inv?.date ? new Date(inv.date) : new Date(`${inv?.period || '1970-01'}-01T00:00:00Z`));
        return {
          ...inv,
          description: inv?.description || `Invoice ${inv?.period}`,
          date: inv?.date || createdAt.toISOString(),
          createdAt,
        };
      });
      setInvoices(normalized);
      setHasMore((billing.invoices || []).length === PAGE_SIZE);
    }
  }, [billing?.invoices, PAGE_SIZE]);

  const pageCount = Math.max(1, Math.ceil(invoices.length / PAGE_SIZE));
  const paginated = invoices.slice(page * PAGE_SIZE, (page + 1) * PAGE_SIZE);

  async function maybeLoadMore(nextPage: number) {
    if (nextPage * PAGE_SIZE < invoices.length) return;
    if (!hasMore || loadingMore) return;
    setLoadingMore(true);
    try {
      const last = invoices[invoices.length - 1];
      // Use composite cursor if API returned one previously (stored on last invoice as _cursor maybe later) else fallback
      const cursor = last?.periodAndCreatedAtCursor || last?.period;
      const token = await user?.getIdToken?.();
      const res = await fetch(`/api/billing/invoices?limit=${PAGE_SIZE}&cursor=${encodeURIComponent(cursor)}`, { headers: { authorization: `Bearer ${token}` } });
      if (res.ok) {
        const json = await res.json();
        const newOnes = (json.invoices || []).filter((inv: any) => !invoices.some(i => i.id === inv.id));
        // Attach composite cursor to each invoice for subsequent pagination
        if (json.nextCursor && newOnes.length) {
          // store on the last currently loaded invoice for retrieval
          newOnes[newOnes.length - 1].periodAndCreatedAtCursor = json.nextCursor;
        }
        if (newOnes.length) setInvoices(prev => [...prev, ...newOnes]);
        setHasMore(json.hasMore);
      }
    } catch {
      /* silent */
    } finally {
      setLoadingMore(false);
    }
  }

  function changePage(delta: number) {
    const next = Math.min(Math.max(0, page + delta), pageCount - 1);
    if (next !== page) {
      setPage(next);
      if (delta > 0) void maybeLoadMore(next);
    }
  }

  // Align with server contract (expMonth/expYear)
  const paymentMethod: PaymentMethod = paymentMethodState || { brand: "••••", last4: "----", expMonth: 0, expYear: 0 };
  const [usageMetrics, setUsageMetrics] = useState<NormalizedUsageMetrics | null>(null);
  useEffect(() => {
    if (!user?.uid) return;
    let cancelled = false;
    void (async () => {
      const m = await fetchUsageMetrics(db, user.uid);
      if (!cancelled) setUsageMetrics(m);
    })();
    return () => {
      cancelled = true;
    };
  }, [user?.uid, db, fetchUsageMetrics]);
  const usage = usageMetrics ? { keywordsTracked: usageMetrics.keywordsTracked, keywordsLimit: usageMetrics.keywordsLimit, competitorAnalysis: usageMetrics.competitorAnalysis, competitorLimit: usageMetrics.competitorLimit, reportsGenerated: usageMetrics.reportsGenerated, currentPeriodStart: usageMetrics.periodStart.toISOString(), currentPeriodEnd: usageMetrics.periodEnd.toISOString() } : { keywordsTracked: 0, keywordsLimit: 0, competitorAnalysis: 0, competitorLimit: 0, reportsGenerated: 0, currentPeriodStart: subscription ? (subscription.currentPeriodEnd ? subscription.currentPeriodEnd.toISOString() : new Date().toISOString()) : new Date().toISOString(), currentPeriodEnd: subscription ? (subscription.currentPeriodEnd ? subscription.currentPeriodEnd.toISOString() : new Date().toISOString()) : new Date().toISOString() };

  // Derive current plan summary (needed for UI display). Previously missing -> TS2304.
  const currentPlan = subscription ? {
    name: subscription.tier || 'Unknown',
    price: (billing?.effectiveMonthly ?? 0),
    billingCycle: 'monthly' as const,
    nextBillingDate: subscription.currentPeriodEnd ? subscription.currentPeriodEnd.toISOString() : new Date().toISOString(),
    status: subscription.status || 'active'
  } : {
    name: 'Free',
    price: 0,
    billingCycle: 'monthly' as const,
    nextBillingDate: new Date().toISOString(),
    status: 'free'
  };

  const handleUpgrade = (plan?: string) => {
    toast.info("Redirecting to upgrade options...");
    // Redirect to pricing page with optional preselected plan
    if (typeof window !== "undefined") {
      const url = plan ? `/pricing?plan=${plan}` : "/pricing";
      window.location.href = url;
    }
  };

  const handleDowngrade = () => {
    toast.info("Contact support to downgrade your plan.");
  };

  const handleUpdatePayment = () => {
    setIsLoading(true);
    // Simulate API call
    setTimeout(() => {
      setIsLoading(false);
      toast.success("Payment method updated successfully!");
    }, 1500);
  };

  const handleManageBilling = async () => {
    try {
      setIsManagingPortal(true);
      const createPortalSession = httpsCallable(functions, "createPortalSession");
  const result: any = await createPortalSession({ userId: user?.uid });
  const url = result?.data?.url;
      if (url) {
        if (typeof window !== 'undefined') window.open(url, '_blank');
      } else {
        toast.error('Failed to open billing portal');
      }
    } catch (e) {
      const err = e as any;
      toast.error(err?.message || 'Failed to open billing portal');
    } finally {
      setIsManagingPortal(false);
    }
  };

  const handleCancelSubscription = () => {
    if (
      confirm(
        "Are you sure you want to cancel your subscription? This action cannot be undone."
      )
    ) {
      toast.error(
        "Subscription cancelled. You'll have access until your next billing date."
      );
    }
  };

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleDateString("en-US", {
      year: "numeric",
      month: "long",
      day: "numeric",
    });
  };

  const getStatusBadge = (status: string) => {
    switch (status) {
      case "active":
        return (
          <Badge className="bg-success/15 text-success-foreground border border-success/40">
            Active
          </Badge>
        );
      case "past_due":
        return <Badge variant="destructive">Past Due</Badge>;
      case "cancelled":
        return <Badge variant="secondary">Cancelled</Badge>;
      default:
        return <Badge variant="outline">{status}</Badge>;
    }
  };

  if (loading || !isMounted) {
    return <LoadingScreen fullScreen text="Loading billing information..." />;
  }

  // Removed erroneous self-referential redeclaration of currentPlan (was masking original definition in incremental build).

  if (!user) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <Card className="w-full max-w-md">
          <CardHeader className="text-center">
            <AlertTriangle className="h-12 w-12 text-warning-foreground mx-auto mb-4" />
            <CardTitle>Access Required</CardTitle>
            <CardDescription>
              Please log in to view your billing information
            </CardDescription>
          </CardHeader>
          <CardContent>
            <Button asChild className="w-full">
              <Link href="/login">Sign In</Link>
            </Button>
          </CardContent>
        </Card>
      </div>
    );
  }


  if(fetchError) {
  return <div className="min-h-screen flex items-center justify-center"><Card className="w-full max-w-md"><CardHeader className="text-center"><AlertTriangle className="h-12 w-12 text-destructive-foreground mx-auto mb-4" /><CardTitle>Billing Load Error</CardTitle><CardDescription>{fetchError}</CardDescription></CardHeader><CardContent className="flex justify-center"><Button variant="outline" onClick={()=>{setFetchError(null); setBilling(null);}}><RefreshCw className="h-4 w-4 mr-2" />Retry</Button></CardContent></Card></div>;
  }

  if(!billing && user) {
    return <LoadingScreen fullScreen text="Loading billing information..." />;
  }

  return (
    <main role="main" className="min-h-screen bg-gradient-to-br from-background via-background to-muted/20" aria-label="Billing portal main content">
      <div className="max-w-7xl mx-auto px-4 py-8" data-testid="billing-root">
        {/* Header */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          className="mb-8"
        >
          <div className="flex items-center gap-3 mb-4">
            <CreditCard className="h-8 w-8 text-primary" />
            <h1 className="text-3xl font-bold font-headline">
              Billing & Subscription
            </h1>
          </div>
          <p className="text-muted-foreground">
            Manage your subscription, billing details, and view usage statistics
          </p>
        </motion.div>

        <div className="grid lg:grid-cols-3 gap-8">
          {/* Current Plan */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.1 }}
            className="lg:col-span-2 space-y-6"
          >
            <Card data-testid="usage-section">
              <CardHeader>
                <div className="flex items-center justify-between">
                  <CardTitle className="flex items-center gap-2">
                    <Crown className="h-5 w-5 text-primary" />
                    Current Plan
                  </CardTitle>
                  {getStatusBadge(currentPlan.status)}
                </div>
              </CardHeader>
              <CardContent className="space-y-6">
                <div className="flex items-center justify-between">
                  <div>
                    <h3 className="text-2xl font-bold">{currentPlan.name}</h3>
                    <p className="text-muted-foreground">
                      ${currentPlan.price}/{currentPlan.billingCycle}
                    </p>
                  </div>
                  <div className="text-right">
                    <p className="text-sm text-muted-foreground">
                      Next billing date
                    </p>
                    <p className="font-semibold">
                      {formatDate(currentPlan.nextBillingDate)}
                    </p>
                  </div>
                </div>

                <Separator />

                <div className="flex gap-3">
                  <Button onClick={() => handleUpgrade()}>
                      <TrendingUp className="h-4 w-4 mr-2" />
                      Upgrade Plan
                  </Button>
                  <Button variant="outline" onClick={handleDowngrade}>
                    Downgrade
                  </Button>
                  <Button
                    variant="destructive"
                    onClick={handleCancelSubscription}
                  >
                    Cancel Subscription
                  </Button>
                </div>
              </CardContent>
            </Card>

            {/* Usage Statistics */}
            <Card data-testid="billing-history">
              <CardHeader>
                <CardTitle>Usage This Month</CardTitle>
                <CardDescription>
                  {formatDate(usage.currentPeriodStart)} -{" "}
                  {formatDate(usage.currentPeriodEnd)}
                </CardDescription>
              </CardHeader>
              <CardContent className="space-y-6">
                <div className="space-y-4">
                  <div>
                    <div className="flex justify-between items-center mb-2">
                      <span className="text-sm font-medium">
                        Keywords Tracked
                      </span>
                      <span className="text-sm text-muted-foreground">
                        {usage.keywordsTracked} / {usage.keywordsLimit === -1 ? '∞' : usage.keywordsLimit}
                      </span>
                    </div>
                    <div className="w-full bg-muted rounded-full h-2">
                      <div
                        className="bg-primary h-2 rounded-full transition-all duration-300"
                        style={{
                          width: `${(usage.keywordsLimit && usage.keywordsLimit > 0) ? Math.min(100, (usage.keywordsTracked / usage.keywordsLimit) * 100) : 0}%`,
                        }}
                      />
                    </div>
                  </div>

                  <div>
                    <div className="flex justify-between items-center mb-2">
                      <span className="text-sm font-medium">
                        Competitor Analysis
                      </span>
                      <span className="text-sm text-muted-foreground">
                        {usage.competitorAnalysis} / {usage.competitorLimit === -1 ? '∞' : usage.competitorLimit}
                      </span>
                    </div>
                    <div className="w-full bg-muted rounded-full h-2">
                      <div
                        className="bg-primary h-2 rounded-full transition-all duration-300"
                        style={{
                          width: `${(usage.competitorLimit && usage.competitorLimit > 0) ? Math.min(100, (usage.competitorAnalysis / usage.competitorLimit) * 100) : 0}%`,
                        }}
                      />
                    </div>
                  </div>

                  <div>
                    <div className="flex justify-between items-center">
                      <span className="text-sm font-medium">
                        Reports Generated
                      </span>
                      <span className="text-sm text-muted-foreground">
                        {usage.reportsGenerated} this month
                      </span>
                    </div>
                  </div>
                </div>
              </CardContent>
            </Card>

            {/* Billing History */}
            <Card>
              <CardHeader>
                <CardTitle>Billing History</CardTitle>
                <CardDescription>
                  Download invoices and view payment history
                </CardDescription>
              </CardHeader>
              <CardContent>
                <div className="space-y-4">
                  {paginated.map((invoice) => (
                    <div
                      key={invoice.id}
                      data-testid="invoice-row"
                      className="flex items-center justify-between p-4 border rounded-lg"
                      aria-label={`Invoice ${invoice.id}`}
                    >
                      <div className="flex items-center gap-4">
                        <div className="p-2 bg-muted rounded-lg">
                          <DollarSign className="h-4 w-4" />
                        </div>
                        <div>
                          <p className="font-medium">{invoice.description}</p>
                          <p className="text-sm text-muted-foreground">
                            {formatDate(invoice.date || new Date().toISOString())}
                          </p>
                        </div>
                      </div>
                      <div className="flex items-center gap-4">
                        <div className="text-right">
                          <p className="font-semibold">${invoice.amount}</p>
                          <div className="flex items-center gap-1">
                            <CheckCircle className="h-3 w-3 text-success-foreground" />
                            <span className="text-xs text-success-foreground/90">Paid</span>
                          </div>
                        </div>
                        <Button size="sm" variant="outline">
                          <Download className="h-4 w-4 mr-2" />
                          Download
                        </Button>
                      </div>
                    </div>
                  ))}
                  {invoices.length === 0 && (
                    <div className="text-sm text-muted-foreground text-center py-6">No invoices yet.</div>
                  )}
                  {invoices.length > PAGE_SIZE && (
                    <div className="flex items-center justify-between pt-4" aria-label="Invoice pagination controls">
                      <Button size="sm" variant="outline" disabled={page===0} onClick={()=>changePage(-1)}>Previous</Button>
                      <p className="text-xs text-muted-foreground">Page {page+1} / {pageCount}{hasMore ? '+' : ''}</p>
                      <div className="flex gap-2">
                        {hasMore && page+1>=pageCount && (
                          <Button size="sm" disabled={loadingMore} onClick={()=>changePage(1)}>{loadingMore ? 'Loading…' : 'Load More'}</Button>
                        )}
                        <Button size="sm" variant="outline" disabled={page+1>=pageCount} onClick={()=>changePage(1)}>Next</Button>
                      </div>
                    </div>
                  )}
                  {hasMore && page+1>=pageCount && (
                    <div className="pt-2">
                      <button
                        type="button"
                        data-testid="view-all-invoices"
                        className="text-xs text-muted-foreground underline hover:text-foreground"
                        aria-label="View all invoices in billing portal"
                        onClick={() => void handleManageBilling()}
                      >
                        View all invoices
                      </button>
                    </div>
                  )}
                </div>
              </CardContent>
            </Card>
          </motion.div>

          {/* Payment Method & Quick Actions */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.2 }}
            className="space-y-6"
          >
            {/* Payment Method */}
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <CreditCard className="h-5 w-5" />
                  Payment Method
                </CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="flex items-center gap-3 p-3 border rounded-lg">
                  <div className="p-2 bg-muted rounded">
                    <CreditCard className="h-4 w-4" />
                  </div>
                  <div className="flex-1">
                    <p className="font-medium">
                      {paymentMethod.brand} ending in {paymentMethod.last4}
                    </p>
                    <p className="text-sm text-muted-foreground">
                      Expires {paymentMethod.expMonth}/
                      {paymentMethod.expYear}
                    </p>
                  </div>
                </div>
                <Button
                  className="w-full"
                  variant="outline"
                  onClick={handleUpdatePayment}
                  disabled={isLoading}
                >
                  {isLoading ? (
                    <div className="flex items-center gap-2">
                      <RefreshCw className="h-4 w-4 animate-spin" />
                      Updating...
                    </div>
                  ) : (
                    <>
                      <Settings className="h-4 w-4 mr-2" />
                      Update Payment Method
                    </>
                  )}
                </Button>
                <Button className="w-full" onClick={() => void handleManageBilling()} disabled={isManagingPortal}>
                  {isManagingPortal ? (
                    <div className="flex items-center gap-2">
                      <RefreshCw className="h-4 w-4 animate-spin" />
                      Opening Portal...
                    </div>
                  ) : (
                    <>
                      <Settings className="h-4 w-4 mr-2" />
                      Manage Subscription
                    </>
                  )}
                </Button>
              </CardContent>
            </Card>

            {/* Quick Actions */}
            <Card>
              <CardHeader>
                <CardTitle>Quick Actions</CardTitle>
              </CardHeader>
              <CardContent className="space-y-3">
                <Button
                  asChild
                  className="w-full justify-start"
                  variant="outline"
                >
                  <Link href="/pricing">
                    <TrendingUp className="h-4 w-4 mr-2" />
                    View All Plans
                  </Link>
                </Button>
                <Button
                  asChild
                  className="w-full justify-start"
                  variant="outline"
                >
                  <Link href="/contact">
                    <ExternalLink className="h-4 w-4 mr-2" />
                    Contact Billing Support
                  </Link>
                </Button>
                <Button
                  asChild
                  className="w-full justify-start"
                  variant="outline"
                >
                  <Link href="/settings">
                    <Settings className="h-4 w-4 mr-2" />
                    Account Settings
                  </Link>
                </Button>
              </CardContent>
            </Card>

            {/* Billing Information */}
            <Card>
              <CardHeader>
                <CardTitle>Billing Information</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="text-sm space-y-2">
                  <div className="flex justify-between">
                    <span className="text-muted-foreground">
                      Billing cycle:
                    </span>
                    <span className="capitalize">
                      {currentPlan.billingCycle}
                    </span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-muted-foreground">Auto-renewal:</span>
                    <span className="text-success-foreground">Enabled</span>
                    {/* semantic success */}
                    {/* replaced raw tailwind green with success token */}
                    {/* above line kept for minimal diff readability */}
                  </div>
                  <div className="flex justify-between">
                    <span className="text-muted-foreground">Tax ID:</span>
                    <span>Not provided</span>
                  </div>
                </div>
                <Separator />
                <div className="text-xs text-muted-foreground">
                  <p>
                    Your subscription will automatically renew on{" "}
                    {formatDate(currentPlan.nextBillingDate)} unless cancelled.
                  </p>
                </div>
              </CardContent>
            </Card>
          </motion.div>
        </div>
      </div>
    </main>
  );
}

