interface Project {
  id: string;
  name: string;
  description: string;
  status: "active" | "completed" | "paused" | "planning";
  priority: "low" | "medium" | "high" | "critical";
  assignedMembers: string[];
  keywords: string[];
  targetUrls: string[];
  createdAt: Date;
  updatedAt: Date;
  deadline?: Date;
  progress: number;
  metrics: {
    totalKeywords: number;
    rankedKeywords: number;
    avgPosition: number;
    trafficIncrease: number;
  };
}

const statusConfig = {
  active: { color: "bg-success", label: "Active", icon: CheckCircle },
  completed: { color: "bg-primary", label: "Completed", icon: CheckCircle },
  paused: { color: "bg-warning", label: "Paused", icon: Clock },
  planning: { color: "bg-muted", label: "Planning", icon: AlertCircle },
};

const priorityConfig = {
  low: { color: "bg-muted", label: "Low" },
  medium: { color: "bg-warning", label: "Medium" },
  high: { color: "bg-accent", label: "High" },
  critical: { color: "bg-destructive", label: "Critical" },
};

export default function TeamProjectsPage() {
  const { user, loading: authLoading } = useAuth();
  useSubscription(); // invoke hook without destructuring to avoid unused-variable lint warnings
  const router = useRouter();
  const [projects, setProjects] = useState<Project[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState("");
  const [filterStatus, setFilterStatus] = useState<string>("all");
  const [filterPriority, setFilterPriority] = useState<string>("all");
  const [showCreateDialog, setShowCreateDialog] = useState(false);
  const [editingProject, setEditingProject] = useState<Project | null>(null);

  const [projectForm, setProjectForm] = useState({
    name: "",
    description: "",
    status: "planning" as Project["status"],
    priority: "medium" as Project["priority"],
    keywords: "",
    targetUrls: "",
    deadline: "",
  });

  const [teamId, setTeamId] = useState<string | null>(null);

  useEffect(() => {
    if (!user?.uid) return;
    (async () => {
      const tQ = query(collection(db, 'teams'), where('memberIds', 'array-contains', user.uid));
      const tSnap = await getDocs(tQ);
      if (!tSnap.empty) setTeamId(tSnap.docs[0].id);
      else {
        const uSnap = await getDoc(doc(db, 'users', user.uid));
        const uData = uSnap.exists() ? (uSnap.data() as any) : undefined;
        const tId = typeof uData?.teamId === 'string' ? uData.teamId : (user as any)?.teamId;
        if (typeof tId === 'string') setTeamId(tId);
      }
    })();
  }, [user?.uid]);

  const fetchProjects = async () => {
    try {
      setLoading(true);
      if (!teamId) { setProjects([]); return; }
      // Read projects with teamId
      const q = query(collection(db, 'projects'), where('teamId', '==', teamId), orderBy('name'));
      const snap = await getDocs(q);
      const items: Project[] = snap.docs.map(d => {
        const data = d.data() as any;
        return {
          id: d.id,
          name: data.name,
          description: data.description,
          status: data.status || 'active',
          priority: data.priority || 'medium',
          assignedMembers: data.assignedMembers || [],
          keywords: data.keywords || [],
          targetUrls: data.targetUrls || [],
          createdAt: data.createdAt?.toDate?.() || new Date(),
          updatedAt: data.updatedAt?.toDate?.() || new Date(),
          deadline: data.deadline?.toDate?.(),
          progress: data.progress ?? 0,
          metrics: data.metrics || { totalKeywords: 0, rankedKeywords: 0, avgPosition: 0, trafficIncrease: 0 },
        } as Project;
      });
      setProjects(items);
    } catch (error) {
      console.error("Error fetching projects:", error);
      toast.error("Failed to load projects");
    } finally {
      setLoading(false);
    }
  };

  const handleCreateProject = async () => {
    try {
      if (!projectForm.name.trim()) {
        toast.error("Project name is required");
        return;
      }

      if (!teamId) { toast.error('Team not resolved'); return; }
      await addDoc(collection(db, 'projects'), {
        name: projectForm.name,
        description: projectForm.description,
        status: projectForm.status,
        priority: projectForm.priority,
        assignedMembers: [user?.email || user?.uid],
        keywords: projectForm.keywords.split(',').map(k => k.trim()).filter(Boolean),
        targetUrls: projectForm.targetUrls.split(',').map(u => u.trim()).filter(Boolean),
        createdAt: serverTimestamp(),
        updatedAt: serverTimestamp(),
        deadline: projectForm.deadline ? new Date(projectForm.deadline) : null,
        progress: 0,
        metrics: { totalKeywords: 0, rankedKeywords: 0, avgPosition: 0, trafficIncrease: 0 },
        teamId,
        userId: user?.uid
      });
      await fetchProjects();
      setShowCreateDialog(false);
      setProjectForm({
        name: "",
        description: "",
        status: "planning",
        priority: "medium",
        keywords: "",
        targetUrls: "",
        deadline: "",
      });
      toast.success("Project created successfully");
    } catch (error) {
      console.error("Error creating project:", error);
      toast.error("Failed to create project");
    }
  };

  const handleDeleteProject = async (projectId: string) => {
    try {
  await deleteDoc(doc(db, 'projects', projectId));
  setProjects(projects.filter((p) => p.id !== projectId));
      toast.success("Project deleted successfully");
    } catch (error) {
      console.error("Error deleting project:", error);
      toast.error("Failed to delete project");
    }
  };

  const filteredProjects = projects.filter((project) => {
    const matchesSearch = project.name
      .toLowerCase()
      .includes(searchTerm.toLowerCase());
    const matchesStatus = filterStatus === "all" || project.status === filterStatus;
    const matchesPriority =
      filterPriority === "all" || project.priority === filterPriority;

    return matchesSearch && matchesStatus && matchesPriority;
  });

  useEffect(() => { if (teamId) fetchProjects(); }, [teamId]);

  if (authLoading || loading) {
    return <LoadingScreen fullScreen text="Loading team projects..." />;
  }

  if (!user) {
    router.push("/login");
    return null;
  }

  return (
  <FeatureGate feature="team_management" requiredTier="enterprise" showUpgrade>
  <main className="container mx-auto py-6 space-y-6">
      <ToolPageHeader
        title="Team Projects"
        description="Manage and track your team's SEO projects and campaigns"
        badges={[
          { label: "Collaboration", variant: "secondary" },
          { label: "Enterprise", variant: "outline", className: "text-primary border-primary/40" },
        ]}
        showBreadcrumb
      >
        <Dialog open={showCreateDialog} onOpenChange={setShowCreateDialog}>
          <DialogTrigger asChild>
            <Button className="flex items-center gap-2">
              <Plus className="h-4 w-4" />
              New Project
            </Button>
          </DialogTrigger>
          <DialogContent className="max-w-2xl">
            <DialogHeader>
              <DialogTitle>Create New Project</DialogTitle>
              <DialogDescription>
                Set up a new SEO project for your team to collaborate on.
              </DialogDescription>
            </DialogHeader>
            <div className="grid gap-4 py-4">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label htmlFor="name">Project Name</Label>
                  <Input
                    id="name"
                    value={projectForm.name}
                    onChange={(e) =>
                      setProjectForm({ ...projectForm, name: e.target.value })
                    }
                    placeholder="Enter project name"
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="status">Status</Label>
                  <Select
                    value={projectForm.status}
                    onValueChange={(value: Project["status"]) =>
                      setProjectForm({ ...projectForm, status: value })
                    }
                  >
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="planning">Planning</SelectItem>
                      <SelectItem value="active">Active</SelectItem>
                      <SelectItem value="paused">Paused</SelectItem>
                      <SelectItem value="completed">Completed</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              </div>
              <div className="space-y-2">
                <Label htmlFor="description">Description</Label>
                <Textarea
                  id="description"
                  value={projectForm.description}
                  onChange={(e) =>
                    setProjectForm({
                      ...projectForm,
                      description: e.target.value,
                    })
                  }
                  placeholder="Describe the project goals and scope"
                  rows={3}
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label htmlFor="priority">Priority</Label>
                  <Select
                    value={projectForm.priority}
                    onValueChange={(value: Project["priority"]) =>
                      setProjectForm({ ...projectForm, priority: value })
                    }
                  >
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="low">Low</SelectItem>
                      <SelectItem value="medium">Medium</SelectItem>
                      <SelectItem value="high">High</SelectItem>
                      <SelectItem value="critical">Critical</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div className="space-y-2">
                  <Label htmlFor="deadline">Deadline</Label>
                  <Input
                    id="deadline"
                    type="date"
                    value={projectForm.deadline}
                    onChange={(e) =>
                      setProjectForm({
                        ...projectForm,
                        deadline: e.target.value,
                      })
                    }
                  />
                </div>
              </div>
              <div className="space-y-2">
                <Label htmlFor="keywords">Target Keywords</Label>
                <Input
                  id="keywords"
                  value={projectForm.keywords}
                  onChange={(e) =>
                    setProjectForm({ ...projectForm, keywords: e.target.value })
                  }
                  placeholder="keyword 1, keyword 2, keyword 3"
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="urls">Target URLs</Label>
                <Input
                  id="urls"
                  value={projectForm.targetUrls}
                  onChange={(e) =>
                    setProjectForm({ ...projectForm, targetUrls: e.target.value })
                  }
                  placeholder="https://example.com, https://example.com/page"
                />
              </div>
            </div>
            <div className="flex justify-end gap-2">
              <Button
                variant="outline"
                onClick={() => setShowCreateDialog(false)}
              >
                Cancel
              </Button>
              <Button onClick={handleCreateProject}>Create Project</Button>
            </div>
          </DialogContent>
        </Dialog>
  </ToolPageHeader>
  <SuiteAccentProvider value="marketing">
  <DashboardSurface as="section" className="space-y-8 p-6">

  {/* Filters */}
  <div className="flex flex-col md:flex-row gap-4">
          <div className="flex-1">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-muted-foreground" />
              <Input
                placeholder="Search projects..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="pl-10"
              />
            </div>
          </div>
          <Select value={filterStatus} onValueChange={setFilterStatus}>
            <SelectTrigger className="w-full md:w-40">
              <SelectValue placeholder="Filter by status" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">All Statuses</SelectItem>
              <SelectItem value="active">Active</SelectItem>
              <SelectItem value="planning">Planning</SelectItem>
              <SelectItem value="paused">Paused</SelectItem>
              <SelectItem value="completed">Completed</SelectItem>
            </SelectContent>
          </Select>
          <Select value={filterPriority} onValueChange={setFilterPriority}>
            <SelectTrigger className="w-full md:w-40">
              <SelectValue placeholder="Filter by priority" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">All Priorities</SelectItem>
              <SelectItem value="critical">Critical</SelectItem>
              <SelectItem value="high">High</SelectItem>
              <SelectItem value="medium">Medium</SelectItem>
              <SelectItem value="low">Low</SelectItem>
            </SelectContent>
          </Select>
      </div>

  {/* Projects Grid */}
  <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
          {filteredProjects.map((project) => {
            const StatusIcon = statusConfig[project.status].icon;
            return (
              <Card key={project.id} className="hover:shadow-lg transition-shadow">
                <CardHeader className="pb-3">
                  <div className="flex items-start justify-between">
                    <div className="flex-1">
                      <CardTitle className="text-lg">{project.name}</CardTitle>
                      <CardDescription className="mt-1">
                        {project.description}
                      </CardDescription>
                    </div>
                    <DropdownMenu>
                      <DropdownMenuTrigger asChild>
                        <Button variant="ghost" size="sm">
                          <MoreVertical className="h-4 w-4" />
                        </Button>
                      </DropdownMenuTrigger>
                      <DropdownMenuContent align="end">
                        <DropdownMenuItem
                          onClick={() => setEditingProject(project)}
                        >
                          <Edit className="h-4 w-4 mr-2" />
                          Edit
                        </DropdownMenuItem>
                        <DropdownMenuItem
                          onClick={() => handleDeleteProject(project.id)}
                          className="text-destructive-foreground"
                        >
                          <Trash2 className="h-4 w-4 mr-2" />
                          Delete
                        </DropdownMenuItem>
                      </DropdownMenuContent>
                    </DropdownMenu>
                  </div>
                  <div className="flex items-center gap-2 mt-3">
                    <Badge
                      variant="secondary"
                      className={`${statusConfig[project.status].color} text-white`}
                    >
                      <StatusIcon className="h-3 w-3 mr-1" />
                      {statusConfig[project.status].label}
                    </Badge>
                    <Badge
                      variant="outline"
                      className={`${priorityConfig[project.priority].color} text-white border-transparent`}
                    >
                      {priorityConfig[project.priority].label}
                    </Badge>
                  </div>
                </CardHeader>
                <CardContent className="space-y-4">
                  {/* Progress */}
                  <div className="space-y-2">
                    <div className="flex justify-between text-sm">
                      <span>Progress</span>
                      <span className="font-medium">{project.progress}%</span>
                    </div>
                    <div className="w-full bg-muted rounded-full h-2">
                      <div
                        className="bg-primary h-2 rounded-full transition-all"
                        style={{ width: `${project.progress}%` }}
                      />
                    </div>
                  </div>

                  {/* Metrics */}
                  <div className="grid grid-cols-2 gap-3 text-sm">
                    <div className="space-y-1">
                      <div className="flex items-center gap-1">
                        <Target className="h-3 w-3 text-muted-foreground" />
                        <span className="text-muted-foreground">Keywords</span>
                      </div>
                      <div className="font-medium">
                        {project.metrics.rankedKeywords}/{project.metrics.totalKeywords}
                      </div>
                    </div>
                    <div className="space-y-1">
                      <div className="flex items-center gap-1">
                        <TrendingUp className="h-3 w-3 text-muted-foreground" />
                        <span className="text-muted-foreground">Traffic</span>
                      </div>
                      <div className="font-medium text-success-foreground">
                        +{project.metrics.trafficIncrease}%
                      </div>
                    </div>
                  </div>

                  {/* Team Members */}
                  <div className="space-y-2">
                    <div className="flex items-center gap-1 text-sm text-muted-foreground">
                      <Users className="h-3 w-3" />
                      <span>Team ({project.assignedMembers.length})</span>
                    </div>
                    <div className="flex -space-x-2">
                      {project.assignedMembers.slice(0, 3).map((member, index) => (
                        <div
                          key={index}
                          className="w-8 h-8 rounded-full bg-primary text-white flex items-center justify-center text-xs font-medium border-2 border-background"
                        >
                          {member.charAt(0).toUpperCase()}
                        </div>
                      ))}
                      {project.assignedMembers.length > 3 && (
                        <div className="w-8 h-8 rounded-full bg-muted text-muted-foreground flex items-center justify-center text-xs font-medium border-2 border-background">
                          +{project.assignedMembers.length - 3}
                        </div>
                      )}
                    </div>
                  </div>

                  {/* Deadline */}
                  {project.deadline && (
                    <div className="flex items-center gap-2 text-sm text-muted-foreground">
                      <Calendar className="h-3 w-3" />
                      <span>Due {project.deadline.toLocaleDateString()}</span>
                    </div>
                  )}
                </CardContent>
              </Card>
            );
        })}
      </div>

      {filteredProjects.length === 0 && (
        <div className="text-center py-12">
            <Folder className="h-16 w-16 text-muted-foreground mx-auto mb-4" />
            <h3 className="text-lg font-medium mb-2">No projects found</h3>
            <p className="text-muted-foreground mb-4">
              {searchTerm || filterStatus !== "all" || filterPriority !== "all"
                ? "Try adjusting your filters or search term."
                : "Create your first project to get started."}
            </p>
            <Button onClick={() => setShowCreateDialog(true)}>
              <Plus className="h-4 w-4 mr-2" />
              Create Project
          </Button>
        </div>
      )}
      </DashboardSurface>
      </SuiteAccentProvider>
    </main>
  </FeatureGate>
  );
}

"use client";

import { useState, useEffect } from "react";
import { FeatureGate } from '@/components/subscription/FeatureGate';
import { ToolPageHeader } from "@/components/tool-page-header";
import { useAuth } from "@/context/AuthContext";
import { useRouter } from "next/navigation";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import LoadingScreen from "@/components/ui/loading-screen";
import {
  FileText,
  Plus,
  Search,
  Download,
  Share2,
  Calendar,
  MoreVertical,
  Edit,
  Trash2,
  Eye,
  Users,
  Clock,
} from "lucide-react";
import { toast } from "sonner";
import { db } from "@/lib/firebase";
import { collection, addDoc, getDocs, query, where, orderBy, doc, deleteDoc, serverTimestamp, getDoc } from "firebase/firestore";

interface Report {
  id: string;
  title: string;
  description: string;
  type: "weekly" | "monthly" | "quarterly" | "custom";
  status: "draft" | "published" | "scheduled";
  createdBy: string;
  createdAt: Date;
  lastModified: Date;
  scheduledDate?: Date;
  metrics: {
    totalViews: number;
    downloads: number;
    shares: number;
  };
  content: {
    keywordTracking: boolean;
    competitorAnalysis: boolean;
    contentPerformance: boolean;
    technicalSEO: boolean;
  };
  recipients: string[];
  tags: string[];
}

const reportTypeConfig = {
  weekly: { color: "bg-primary", label: "Weekly" },
  monthly: { color: "bg-success", label: "Monthly" },
  quarterly: { color: "bg-accent", label: "Quarterly" },
  custom: { color: "bg-warning", label: "Custom" },
};

const statusConfig = {
  draft: { color: "bg-muted", label: "Draft" },
  published: { color: "bg-success", label: "Published" },
  scheduled: { color: "bg-primary", label: "Scheduled" },
};

export default function TeamReportsPage() {
  const { user, loading: authLoading } = useAuth();
  const router = useRouter();
  const [reports, setReports] = useState<Report[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState("");
  const [filterType, setFilterType] = useState<string>("all");
  const [filterStatus, setFilterStatus] = useState<string>("all");
  const [showCreateDialog, setShowCreateDialog] = useState(false);
  const [, setEditingReport] = useState<Report | null>(null);

  const [reportForm, setReportForm] = useState({
    title: "",
    description: "",
    type: "monthly" as Report["type"],
    status: "draft" as Report["status"],
    scheduledDate: "",
    recipients: "",
    tags: "",
    content: {
      keywordTracking: true,
      competitorAnalysis: true,
      contentPerformance: true,
      technicalSEO: false,
    },
  });

  const [teamId, setTeamId] = useState<string | null>(null);

  useEffect(() => {
    if (!user?.uid) return;
    (async () => {
      // Resolve teamId
      const tQ = query(collection(db, 'teams'), where('memberIds', 'array-contains', user.uid));
      const tSnap = await getDocs(tQ);
      if (!tSnap.empty) setTeamId(tSnap.docs[0].id);
      else {
        const uSnap = await getDoc(doc(db, 'users', user.uid));
        const uData = uSnap.exists() ? (uSnap.data() as any) : undefined;
        const tId = typeof uData?.teamId === 'string' ? uData.teamId : (user as any)?.teamId;
        if (typeof tId === 'string') setTeamId(tId);
      }
    })();
  }, [user?.uid]);

  const fetchReports = async () => {
    try {
      setLoading(true);
      if (!teamId) { setReports([]); return; }
      const q = query(collection(db, 'teams', teamId, 'reports'), orderBy('lastModified', 'desc'));
      const snap = await getDocs(q);
      const items: Report[] = snap.docs.map(d => {
        const data = d.data() as any;
        return {
          id: d.id,
          title: data.title,
          description: data.description,
          type: data.type,
          status: data.status,
          createdBy: data.createdBy,
          createdAt: data.createdAt?.toDate?.() || new Date(),
          lastModified: data.lastModified?.toDate?.() || new Date(),
          scheduledDate: data.scheduledDate?.toDate?.(),
          metrics: data.metrics || { totalViews: 0, downloads: 0, shares: 0 },
          content: data.content || { keywordTracking: true, competitorAnalysis: true, contentPerformance: true, technicalSEO: false },
          recipients: data.recipients || [],
          tags: data.tags || [],
        } as Report;
      });
      setReports(items);
    } catch (error) {
      console.error("Error fetching reports:", error);
      toast.error("Failed to load reports");
    } finally {
      setLoading(false);
    }
  };

  const handleCreateReport = async () => {
    try {
      if (!reportForm.title.trim()) {
        toast.error("Report title is required");
        return;
      }

      if (!teamId) { toast.error('Team not resolved'); return; }
      await addDoc(collection(db, 'teams', teamId, 'reports'), {
        title: reportForm.title,
        description: reportForm.description,
        type: reportForm.type,
        status: reportForm.status,
        createdBy: user?.email || user?.uid,
        createdAt: serverTimestamp(),
        lastModified: serverTimestamp(),
        scheduledDate: reportForm.status === 'scheduled' && reportForm.scheduledDate ? new Date(reportForm.scheduledDate) : null,
        metrics: { totalViews: 0, downloads: 0, shares: 0 },
        content: reportForm.content,
        recipients: reportForm.recipients.split(',').map(r => r.trim()).filter(Boolean),
        tags: reportForm.tags.split(',').map(t => t.trim()).filter(Boolean),
      });
      await fetchReports();
      setShowCreateDialog(false);
      setReportForm({
        title: "",
        description: "",
        type: "monthly",
        status: "draft",
        scheduledDate: "",
        recipients: "",
        tags: "",
        content: {
          keywordTracking: true,
          competitorAnalysis: true,
          contentPerformance: true,
          technicalSEO: false,
        },
      });
      toast.success("Report created successfully");
    } catch (error) {
      console.error("Error creating report:", error);
      toast.error("Failed to create report");
    }
  };

  const handleDeleteReport = async (reportId: string) => {
    try {
      if (!teamId) return;
      await deleteDoc(doc(db, 'teams', teamId, 'reports', reportId));
      setReports(reports.filter((r) => r.id !== reportId));
      toast.success("Report deleted successfully");
    } catch (error) {
      console.error("Error deleting report:", error);
      toast.error("Failed to delete report");
    }
  };

  const handleDownloadReport = async () => {
    try {
      toast.success("Report download started");
      // Simulate download
    } catch (error) {
      console.error("Error downloading report:", error);
      toast.error("Failed to download report");
    }
  };

  const filteredReports = reports.filter((report) => {
    const matchesSearch = report.title
      .toLowerCase()
      .includes(searchTerm.toLowerCase());
    const matchesType = filterType === "all" || report.type === filterType;
    const matchesStatus = filterStatus === "all" || report.status === filterStatus;

    return matchesSearch && matchesType && matchesStatus;
  });

  useEffect(() => { if (teamId) fetchReports(); }, [teamId]);

  if (authLoading || loading) {
    return <LoadingScreen fullScreen text="Loading team reports..." />;
  }

  if (!user) {
    router.push("/login");
    return null;
  }

  return (
    <FeatureGate feature="team_management" requiredTier="enterprise" showUpgrade>
    <main className="container mx-auto py-6 space-y-8">
      <ToolPageHeader
        title="Team Reports"
        description="Create, manage, and share SEO performance reports with your team"
        badges={[
          { label: "Collaboration", variant: "secondary" },
          { label: "Enterprise", variant: "outline", className: "text-primary border-primary/40" },
        ]}
        showBreadcrumb
      >
        <Dialog open={showCreateDialog} onOpenChange={setShowCreateDialog}>
          <DialogTrigger asChild>
            <Button className="flex items-center gap-2">
              <Plus className="h-4 w-4" />
              New Report
            </Button>
          </DialogTrigger>
          <DialogContent className="max-w-2xl">
            <DialogHeader>
              <DialogTitle>Create New Report</DialogTitle>
              <DialogDescription>
                Set up a new report template for your team to use.
              </DialogDescription>
            </DialogHeader>
            <div className="grid gap-4 py-4">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label htmlFor="title">Report Title</Label>
                  <Input
                    id="title"
                    value={reportForm.title}
                    onChange={(e) =>
                      setReportForm({ ...reportForm, title: e.target.value })
                    }
                    placeholder="Enter report title"
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="type">Report Type</Label>
                  <Select
                    value={reportForm.type}
                    onValueChange={(value: Report["type"]) =>
                      setReportForm({ ...reportForm, type: value })
                    }
                  >
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="weekly">Weekly</SelectItem>
                      <SelectItem value="monthly">Monthly</SelectItem>
                      <SelectItem value="quarterly">Quarterly</SelectItem>
                      <SelectItem value="custom">Custom</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              </div>
              <div className="space-y-2">
                <Label htmlFor="description">Description</Label>
                <Input
                  id="description"
                  value={reportForm.description}
                  onChange={(e) =>
                    setReportForm({
                      ...reportForm,
                      description: e.target.value,
                    })
                  }
                  placeholder="Describe the report content and purpose"
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label htmlFor="status">Status</Label>
                  <Select
                    value={reportForm.status}
                    onValueChange={(value: Report["status"]) =>
                      setReportForm({ ...reportForm, status: value })
                    }
                  >
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="draft">Draft</SelectItem>
                      <SelectItem value="published">Published</SelectItem>
                      <SelectItem value="scheduled">Scheduled</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                {reportForm.status === "scheduled" && (
                  <div className="space-y-2">
                    <Label htmlFor="scheduledDate">Scheduled Date</Label>
                    <Input
                      id="scheduledDate"
                      type="datetime-local"
                      value={reportForm.scheduledDate}
                      onChange={(e) =>
                        setReportForm({
                          ...reportForm,
                          scheduledDate: e.target.value,
                        })
                      }
                    />
                  </div>
                )}
              </div>
              <div className="space-y-2">
                <Label htmlFor="recipients">Recipients</Label>
                <Input
                  id="recipients"
                  value={reportForm.recipients}
                  onChange={(e) =>
                    setReportForm({ ...reportForm, recipients: e.target.value })
                  }
                  placeholder="email1@company.com, email2@company.com"
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="tags">Tags</Label>
                <Input
                  id="tags"
                  value={reportForm.tags}
                  onChange={(e) =>
                    setReportForm({ ...reportForm, tags: e.target.value })
                  }
                  placeholder="tag1, tag2, tag3"
                />
              </div>
            </div>
            <div className="flex justify-end gap-2">
              <Button
                variant="outline"
                onClick={() => setShowCreateDialog(false)}
              >
                Cancel
              </Button>
              <Button onClick={handleCreateReport}>Create Report</Button>
            </div>
          </DialogContent>
        </Dialog>
      </ToolPageHeader>

  {/* Filters */}
  <div className="flex flex-col md:flex-row gap-4">
        <div className="flex-1">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-muted-foreground" />
            <Input
              placeholder="Search reports..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="pl-10"
            />
          </div>
        </div>
        <Select value={filterType} onValueChange={setFilterType}>
          <SelectTrigger className="w-full md:w-40">
            <SelectValue placeholder="Filter by type" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">All Types</SelectItem>
            <SelectItem value="weekly">Weekly</SelectItem>
            <SelectItem value="monthly">Monthly</SelectItem>
            <SelectItem value="quarterly">Quarterly</SelectItem>
            <SelectItem value="custom">Custom</SelectItem>
          </SelectContent>
        </Select>
        <Select value={filterStatus} onValueChange={setFilterStatus}>
          <SelectTrigger className="w-full md:w-40">
            <SelectValue placeholder="Filter by status" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">All Statuses</SelectItem>
            <SelectItem value="draft">Draft</SelectItem>
            <SelectItem value="published">Published</SelectItem>
            <SelectItem value="scheduled">Scheduled</SelectItem>
          </SelectContent>
        </Select>
      </div>

  {/* Reports Grid */}
  <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
        {filteredReports.map((report) => (
          <Card key={report.id} className="hover:shadow-lg transition-shadow">
            <CardHeader className="pb-3">
              <div className="flex items-start justify-between">
                <div className="flex-1">
                  <CardTitle className="text-lg">{report.title}</CardTitle>
                  <CardDescription className="mt-1">
                    {report.description}
                  </CardDescription>
                </div>
                <DropdownMenu>
                  <DropdownMenuTrigger asChild>
                    <Button variant="ghost" size="sm">
                      <MoreVertical className="h-4 w-4" />
                    </Button>
                  </DropdownMenuTrigger>
                  <DropdownMenuContent align="end">
                    <DropdownMenuItem>
                      <Eye className="h-4 w-4 mr-2" />
                      View
                    </DropdownMenuItem>
                    <DropdownMenuItem
                      onClick={() => handleDownloadReport()}
                    >
                      <Download className="h-4 w-4 mr-2" />
                      Download
                    </DropdownMenuItem>
                    <DropdownMenuItem>
                      <Share2 className="h-4 w-4 mr-2" />
                      Share
                    </DropdownMenuItem>
                    <DropdownMenuItem
                      onClick={() => setEditingReport(report)}
                    >
                      <Edit className="h-4 w-4 mr-2" />
                      Edit
                    </DropdownMenuItem>
                    <DropdownMenuItem
                      onClick={() => handleDeleteReport(report.id)}
                      className="text-destructive-foreground"
                    >
                      <Trash2 className="h-4 w-4 mr-2" />
                      Delete
                    </DropdownMenuItem>
                  </DropdownMenuContent>
                </DropdownMenu>
              </div>
              <div className="flex items-center gap-2 mt-3">
                <Badge
                  variant="secondary"
                  className={`${reportTypeConfig[report.type].color} text-white`}
                >
                  {reportTypeConfig[report.type].label}
                </Badge>
                <Badge
                  variant="outline"
                  className={`${statusConfig[report.status].color} text-white border-transparent`}
                >
                  {statusConfig[report.status].label}
                </Badge>
              </div>
            </CardHeader>
            <CardContent className="space-y-4">
              {/* Content Sections */}
              <div className="space-y-2">
                <div className="text-sm font-medium">Content Sections</div>
                <div className="flex flex-wrap gap-1">
                  {report.content.keywordTracking && (
                    <Badge variant="outline" className="text-xs">
                      Keywords
                    </Badge>
                  )}
                  {report.content.competitorAnalysis && (
                    <Badge variant="outline" className="text-xs">
                      Competitors
                    </Badge>
                  )}
                  {report.content.contentPerformance && (
                    <Badge variant="outline" className="text-xs">
                      Content
                    </Badge>
                  )}
                  {report.content.technicalSEO && (
                    <Badge variant="outline" className="text-xs">
                      Technical
                    </Badge>
                  )}
                </div>
              </div>

              {/* Metrics */}
              <div className="grid grid-cols-3 gap-3 text-sm">
                <div className="space-y-1 text-center">
                  <div className="flex items-center justify-center gap-1">
                    <Eye className="h-3 w-3 text-muted-foreground" />
                  </div>
                  <div className="font-medium">{report.metrics.totalViews}</div>
                  <div className="text-xs text-muted-foreground">Views</div>
                </div>
                <div className="space-y-1 text-center">
                  <div className="flex items-center justify-center gap-1">
                    <Download className="h-3 w-3 text-muted-foreground" />
                  </div>
                  <div className="font-medium">{report.metrics.downloads}</div>
                  <div className="text-xs text-muted-foreground">Downloads</div>
                </div>
                <div className="space-y-1 text-center">
                  <div className="flex items-center justify-center gap-1">
                    <Share2 className="h-3 w-3 text-muted-foreground" />
                  </div>
                  <div className="font-medium">{report.metrics.shares}</div>
                  <div className="text-xs text-muted-foreground">Shares</div>
                </div>
              </div>

              {/* Recipients */}
              <div className="space-y-2">
                <div className="flex items-center gap-1 text-sm text-muted-foreground">
                  <Users className="h-3 w-3" />
                  <span>Recipients ({report.recipients.length})</span>
                </div>
                <div className="text-xs text-muted-foreground">
                  {report.recipients.slice(0, 2).join(", ")}
                  {report.recipients.length > 2 && ` +${report.recipients.length - 2} more`}
                </div>
              </div>

              {/* Schedule Info */}
              {report.scheduledDate && (
                <div className="flex items-center gap-2 text-sm text-muted-foreground">
                  <Clock className="h-3 w-3" />
                  <span>Scheduled for {report.scheduledDate.toLocaleDateString()}</span>
                </div>
              )}

              {/* Created Info */}
              <div className="flex items-center gap-2 text-xs text-muted-foreground pt-2 border-t">
                <Calendar className="h-3 w-3" />
                <span>Created {report.createdAt.toLocaleDateString()}</span>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      {filteredReports.length === 0 && (
        <div className="text-center py-12">
          <FileText className="h-16 w-16 text-muted-foreground mx-auto mb-4" />
          <h3 className="text-lg font-medium mb-2">No reports found</h3>
          <p className="text-muted-foreground mb-4">
            {searchTerm || filterType !== "all" || filterStatus !== "all"
              ? "Try adjusting your filters or search term."
              : "Create your first report to get started."}
          </p>
          <Button onClick={() => setShowCreateDialog(true)}>
            <Plus className="h-4 w-4 mr-2" />
            Create Report
          </Button>
        </div>
      )}
  </main>
  </FeatureGate>
  );
}

"use client";

import { useEffect, useState } from "react";
import { FeatureGate } from '@/components/subscription/FeatureGate';
import { ToolPageHeader } from "@/components/tool-page-header";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { db } from "@/lib/firebase";
import { collection, query, where, getDocs, doc, getDoc, updateDoc, documentId } from "firebase/firestore";
import { useAuth } from "@/context/AuthContext";

export default function TeamSettingsPage() {
  const { user } = useAuth();
  const [loading, setLoading] = useState(true);
  // Define Team type for type safety
  type Team = {
    id: string;
    name: string;
    description: string;
    members: Array<{ userId: string; name: string; email: string; role: string }>;
    projects: string[] | ProjectLite[];
    integrations: Array<{ id: string; name: string; status: string }>;
  };
  const [team, setTeam] = useState<Team | null>(null);
  interface ProjectLite { id:string; name?:string; [k:string]:unknown }
  const [allProjects, setAllProjects] = useState<ProjectLite[]>([]);
  interface EditState { name:string; description:string; members: Team['members']; projects: ProjectLite[]; integrations: Team['integrations']; }
  const [editState, setEditState] = useState<EditState|null>(null);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (!user) return;
    setLoading(true);
    (async () => {
      try {
        // 1) Prefer teams where current user's UID is in scalar memberIds array
        //    (array-contains works on primitives, not nested objects)
        let teamDoc: Team | null = null;
        const byMemberIdsQ = query(collection(db, "teams"), where("memberIds", "array-contains", user.uid));
        const byMemberIdsSnap = await getDocs(byMemberIdsQ);
        if (!byMemberIdsSnap.empty) {
          teamDoc = { id: byMemberIdsSnap.docs[0].id, ...byMemberIdsSnap.docs[0].data() } as Team;
        }

        // 2) Fallback: read users/{uid}.teamId and load that team
        if (!teamDoc) {
          const userDocSnap = await getDoc(doc(db, "users", user.uid));
          const userData = userDocSnap.exists() ? (userDocSnap.data() as Record<string, unknown>) : undefined;
          const teamIdFromUser = userData ? (userData.teamId as string | undefined) : undefined;
          if (typeof teamIdFromUser === "string" && teamIdFromUser) {
            const teamSnap = await getDoc(doc(db, "teams", teamIdFromUser));
            if (teamSnap.exists()) {
              teamDoc = { id: teamSnap.id, ...teamSnap.data() } as Team;
            }
          }
        }

        // 3) Legacy fallback (if your auth user object was extended elsewhere)
        if (!teamDoc && typeof (user as unknown as Record<string, unknown>).teamId === "string") {
          const docSnap = await getDoc(doc(db, "teams", (user as unknown as Record<string, unknown>).teamId as string));
          if (docSnap.exists()) teamDoc = { id: docSnap.id, ...docSnap.data() } as Team;
        }
        if (!teamDoc) throw new Error("Team not found");

        // Fetch only the team's projects (limit 10 per 'in' query)
  const teamData = teamDoc as unknown as Record<string, unknown>;
  const projectIds: string[] = Array.isArray(teamData.projects) ? (teamData.projects as unknown as string[]) : [];
        let allProjectsArr: unknown[] = [];
        if (projectIds.length > 0) {
          try {
            const chunk = <T,>(arr: T[], size: number) => arr.reduce<T[][]>((acc, _, i) => (i % size ? acc : [...acc, arr.slice(i, i + size)]), []);
            const chunks = chunk(projectIds, 10);
            for (const ids of chunks) {
              const projQ = query(collection(db, "projects"), where(documentId(), "in", ids));
              const projSnap = await getDocs(projQ);
              allProjectsArr = allProjectsArr.concat(projSnap.docs.map(d => ({ id: d.id, ...d.data() })));
            }
          } catch (projErr) {
            console.warn("Project fetch skipped due to permissions or network:", projErr);
            // Fallback to minimal project list with IDs only
            allProjectsArr = projectIds.map(id => ({ id, name: id }));
          }
        }

        setTeam(teamDoc);
        setAllProjects(allProjectsArr as ProjectLite[]);
        {
          const td = teamDoc as unknown as Record<string, unknown>;
          setEditState({
            name: (td.name as string) ?? "",
            description: (td.description as string) ?? "",
            members: Array.isArray(td.members) ? (td.members as Team['members']) : [],
            projects: (allProjectsArr as ProjectLite[]).filter(p => Array.isArray(td.projects) && (td.projects as unknown as string[]).includes(p.id)) as ProjectLite[],
            integrations: Array.isArray(td.integrations) ? (td.integrations as Team['integrations']) : [],
          });
        }
      } catch (e: unknown) {
        console.error("TeamSettings load error:", e);
        setError("Failed to load team data.");
      } finally {
        setLoading(false);
      }
    })();
  }, [user?.uid]);

  // Handlers for editing
  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    setEditState(prev => prev ? ({ ...prev, [e.target.name]: e.target.value }) : prev);
  };
  const handleMemberRoleChange = (id: string, role: string) => {
    setEditState(prev => prev ? ({
      ...prev,
      members: prev.members.map(m => (m.userId === id ? { ...m, role } : m)),
    }) : prev);
  };
  const handleProjectToggle = (projectId: string) => {
    setEditState(prev => {
      if(!prev) return prev;
      const exists = prev.projects.some(p => p.id === projectId);
      return {
        ...prev,
        projects: exists
          ? prev.projects.filter(p => p.id !== projectId)
          : [...prev.projects, allProjects.find(p => p.id === projectId)!],
      };
    });
  };
  const handleSave = async () => {
    if (!team) return;
    setSaving(true);
    setError(null);
    try {
      if(!editState) return;
      await updateDoc(doc(db, "teams", team.id), {
        name: editState.name,
        description: editState.description,
        members: editState.members,
        projects: editState.projects.map(p => p.id),
        integrations: editState.integrations,
      });
  setTeam({ ...team, ...editState } as Team);
    } catch (e: unknown) {
      setError("Failed to save changes.");
    } finally {
      setSaving(false);
    }
  };

  return (
    <FeatureGate feature="team_management" requiredTier="agency" showUpgrade>
    <main className="container mx-auto py-6 space-y-8">
      <ToolPageHeader
        title="Team Settings"
        description="Configure your team's details, members, integrations, and permissions"
        badges={[
          { label: "Collaboration", variant: "secondary" },
          { label: "Enterprise", variant: "outline", className: "text-primary border-primary/40" },
        ]}
        showBreadcrumb
      />
      {loading && <div>Loading...</div>}
  {error && <div className="text-destructive-foreground">{error}</div>}
      {!loading && team && editState && (
        <>
          {/* Team Info */}
          <Card>
            <CardHeader>
              <CardTitle>Team Information</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div>
                <label className="block text-sm font-medium mb-1">Team Name</label>
                <input
                  className="input input-bordered w-full"
                  name="name"
                  value={editState.name}
                  onChange={handleInputChange}
                  disabled={saving}
                />
              </div>
              <div>
                <label className="block text-sm font-medium mb-1">Description</label>
                <textarea
                  className="input input-bordered w-full min-h-[60px]"
                  name="description"
                  value={editState.description}
                  onChange={handleInputChange}
                  disabled={saving}
                />
              </div>
            </CardContent>
          </Card>

          {/* Team Members */}
          <Card>
            <CardHeader>
              <CardTitle>Team Members</CardTitle>
            </CardHeader>
            <CardContent>
              <table className="w-full text-sm mb-4">
                <thead>
                  <tr className="text-muted-foreground">
                    <th className="text-left py-1">Name</th>
                    <th className="text-left py-1">Email</th>
                    <th className="text-left py-1">Role</th>
                    <th className="text-left py-1">Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {editState.members.map((m: { userId: string; name: string; email: string; role: string }) => (
                    <tr key={m.userId} className="border-b last:border-0">
                      <td className="py-2">{m.name}</td>
                      <td>{m.email}</td>
                      <td>
                        <select
                          className="input input-sm"
                          value={m.role}
                          onChange={(e) => handleMemberRoleChange(m.userId, e.target.value)}
                          disabled={saving}
                        >
                          <option value="owner">Owner</option>
                          <option value="admin">Admin</option>
                          <option value="member">Member</option>
                        </select>
                      </td>
                      <td>
                        <button className="btn btn-xs btn-error" disabled={saving}>Remove</button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
              <button className="btn btn-sm btn-primary" disabled={saving}>Invite Member</button>
            </CardContent>
          </Card>

          {/* Project Assignment */}
          <Card>
            <CardHeader>
              <CardTitle>Project Assignment</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="space-y-2">
                {allProjects.map((project) => (
                  <div key={project.id} className="flex items-center gap-2">
                    <input
                      type="checkbox"
                      className="checkbox"
                      checked={editState.projects.some((p: ProjectLite) => p.id === project.id)}
                      onChange={() => handleProjectToggle(project.id)}
                      disabled={saving}
                    />
                    <span>{project.name}</span>
                  </div>
                ))}
              </div>
            </CardContent>
          </Card>

          {/* Permissions Matrix */}
          <Card>
            <CardHeader>
              <CardTitle>Permissions</CardTitle>
            </CardHeader>
            <CardContent>
              <table className="w-full text-sm">
                <thead>
                  <tr className="text-muted-foreground">
                    <th className="text-left py-1">Feature</th>
                    <th className="text-center py-1">Owner</th>
                    <th className="text-center py-1">Admin</th>
                    <th className="text-center py-1">Member</th>
                  </tr>
                </thead>
                <tbody>
                  {[
                    { feature: "Manage Projects" },
                    { feature: "Invite Members" },
                    { feature: "View Analytics" },
                    { feature: "Edit Settings" },
                  ].map((row) => (
                    <tr key={row.feature} className="border-b last:border-0">
                      <td className="py-2">{row.feature}</td>
                      <td className="text-center">
                        <input type="checkbox" className="checkbox" defaultChecked disabled />
                      </td>
                      <td className="text-center">
                        <input type="checkbox" className="checkbox" defaultChecked />
                      </td>
                      <td className="text-center">
                        <input type="checkbox" className="checkbox" />
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </CardContent>
          </Card>

          {/* Integrations */}
          <Card>
            <CardHeader>
              <CardTitle>Integrations</CardTitle>
            </CardHeader>
            <CardContent className="space-y-2">
              {editState.integrations.map((integration: { id: string; name: string; status: string }) => (
                <div key={integration.id} className="flex items-center gap-2">
                  <span className="font-medium">{integration.name}</span>
                  {integration.status === "connected" ? (
                    <span className="badge badge-success">Connected</span>
                  ) : (
                    <button className="btn btn-xs btn-primary" disabled={saving}>Connect</button>
                  )}
                </div>
              ))}
            </CardContent>
          </Card>

          {/* Danger Zone */}
          <Card>
            <CardHeader>
              <CardTitle>Danger Zone</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="space-y-2">
                <button className="btn btn-sm btn-error w-full" disabled={saving}>Delete Team</button>
                <button className="btn btn-sm btn-warning w-full" disabled={saving}>Transfer Ownership</button>
              </div>
            </CardContent>
          </Card>

          {/* Save Button */}
          <div className="flex justify-end">
            <button className="btn btn-primary" onClick={handleSave} disabled={saving}>
              {saving ? "Saving..." : "Save Changes"}
            </button>
          </div>
        </>
      )}
  </main>
  </FeatureGate>
  );
}

"use client";

import { Badge } from "@/components/ui/badge";
