export default function LoginPage() {
  // Auth guard - redirect authenticated users away from login page
  const { shouldRender } = useAuthGuard();
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [errors, setErrors] = useState<{
    email?: string;
    password?: string;
    form?: string;
  }>({});
  const router = useRouter();

  const { user, loading, role } = useAuth();

  // Improved redirection logic
  useEffect(() => {
    if (!loading && user && shouldRender) {
      const redirectPath = role === "admin" ? "/adminonly" : "/dashboard";
      router.push(redirectPath);
    }
  }, [user, loading, role, router, shouldRender]);

  if (loading) {
    return <LoadingScreen fullScreen text="Verifying your credentials..." />;
  }

  if (!shouldRender) {
    return <LoadingScreen fullScreen text="Redirecting..." />;
  }

  function validate() {
    const newErrors: typeof errors = {};
    if (!email.trim()) newErrors.email = "Email is required.";
    else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()))
      newErrors.email = "Invalid email address.";
    if (!password) newErrors.password = "Password is required.";
    return newErrors;
  }

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    const newErrors = validate();
    setErrors(newErrors);
    if (Object.keys(newErrors).length > 0) return;

    try {
      const userCredential = await signInWithEmailAndPassword(
        auth,
        email,
        password
      );

      // Update login tracking with enhanced auth service
      try {
        await EnhancedAuthService.updateLoginTracking(userCredential.user.uid);
      } catch (trackingError) {
        console.warn("Login tracking update failed:", trackingError);
      }

      // Redirection is handled by the useEffect hook after auth state updates
    } catch (error: unknown) {
      setErrors({ form: safeErrorMessage(error) || "Login failed. Please try again." });
    }
  };

  const handleGoogleSignIn = async () => {
    const provider = new GoogleAuthProvider();
    try {
      const result = await signInWithPopup(auth, provider);
      const user = result.user;

      const userDocRef = doc(db, "users", user.uid);
      const docSnap = await getDoc(userDocRef);
      if (!docSnap.exists()) {
        await setDoc(userDocRef, {
          email: user.email,
          displayName: user.displayName,
          role: "user",
          createdAt: serverTimestamp(),
        });
      }
      // Redirection is handled by the useEffect hook after auth state updates
    } catch (error: unknown) {
      setErrors({
        form: safeErrorMessage(error) || "Google sign-in failed. Please try again.",
      });
    }
  };

  if (loading) {
    return <LoadingScreen fullScreen text="Verifying your credentials..." />;
  }

  return (
    <div className="inset-0 flex items-center justify-center bg-background">
      <div className="w-full max-w-md p-8 space-y-6 rounded-1xl shadow-xl border bg-card text-card-foreground">
  <h2 className="text-2xl font-bold text-center mb-2">Welcome Back</h2>
  <p className="text-sm text-muted-foreground text-center -mt-2 mb-4">Access your unified NeuroSEO™ workspace.</p>
        <form onSubmit={handleLogin} className="space-y-4" noValidate>
          <div>
            <label
              htmlFor="email"
              className="block text-sm font-medium mb-1 text-foreground"
            >
              Email
            </label>
            <input
              id="email"
              type="email"
              required
              placeholder="you@example.com"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              className="w-full px-3 py-2 border border-input rounded-lg bg-background text-foreground ring-1 ring-border focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 ring-offset-background transition"
              disabled={loading}
            />
            {errors.email && (
              <p className="text-destructive-foreground text-xs mt-1">{errors.email}</p>
            )}
          </div>
          <div className="relative">
            <label
              htmlFor="password"
              className="block text-sm font-medium mb-1 text-foreground"
            >
              Password
            </label>
            <input
              id="password"
              type={showPassword ? "text" : "password"}
              required
              placeholder="Enter your password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              className="w-full px-3 py-2 border border-input rounded-lg pr-10 bg-background text-foreground ring-1 ring-border focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 ring-offset-background transition"
              disabled={loading}
            />
            <button
              type="button"
              tabIndex={-1}
              className="absolute right-3 top-9 text-muted-foreground"
              onClick={() => setShowPassword((v) => !v)}
            >
              {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
            </button>
            {errors.password && (
              <p className="text-destructive-foreground text-xs mt-1">{errors.password}</p>
            )}
          </div>
          {errors.form && (
            <p className="text-destructive-foreground text-xs mt-1">{errors.form}</p>
          )}
          <button
            type="submit"
            data-testid="login-button"
            className="w-full py-2 rounded-lg bg-primary text-primary-foreground font-semibold text-lg hover:bg-primary/90 transition"
            disabled={loading}
          >
            Login
          </button>
          <p className="text-center text-xs text-muted-foreground mt-2">Secure session persists until you sign out. MFA & SSO available on higher tiers.</p>
        </form>

        <div className="relative my-4">
          <div className="absolute inset-0 flex items-center">
            <span className="w-full border-t" />
          </div>
          <div className="relative flex justify-center text-xs uppercase">
            <span className="bg-card px-2 text-muted-foreground">
              Or continue with
            </span>
          </div>
        </div>

        <button
          onClick={handleGoogleSignIn}
          className="w-full inline-flex items-center justify-center py-2 border border-input rounded-lg shadow-sm bg-card text-sm font-medium text-foreground hover:bg-accent focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2 ring-offset-background"
          disabled={loading}
        >
          <GoogleIcon />
          Sign in with Google
        </button>

  <p className="text-center text-sm text-muted-foreground">New here? <Link href="/register" className="text-primary hover:underline">Create an account</Link></p>
      </div>
    </div>
  );
}

"use client";

import LoadingScreen from "@/components/ui/loading-screen";
import { useAuth } from "@/context/AuthContext";
import { useAuthGuard } from "@/hooks/useAuthGuard";
import { auth } from "@/lib/firebase";
import { createUserWithEmailAndPassword } from "firebase/auth";
import { Eye, EyeOff } from "lucide-react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { useState } from "react";
import ReCAPTCHA from "react-google-recaptcha";

export default function RegisterPage() {
  // Auth guard - redirect authenticated users away from register page
  const { shouldRender } = useAuthGuard();
  const router = useRouter();
  const { loading } = useAuth();
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [confirmPassword, setConfirmPassword] = useState("");
  const [showConfirm, setShowConfirm] = useState(false);
  const [captchaToken, setCaptchaToken] = useState("");
  const [agreeTerms, setAgreeTerms] = useState(false);
  const [errors, setErrors] = useState<{
    email?: string;
    password?: string;
    confirmPassword?: string;
    terms?: string;
    captcha?: string;
    form?: string;
  }>({});

  if (loading) {
    return <LoadingScreen fullScreen text="Setting up your account..." />;
  }

  if (!shouldRender) {
    return <LoadingScreen fullScreen text="Redirecting..." />;
  }

  function validate() {
    const newErrors: typeof errors = {};
    if (!email.trim()) newErrors.email = "Email is required.";
    else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()))
      newErrors.email = "Invalid email address.";
    if (!password) newErrors.password = "Password is required.";
    else if (password.length < 6)
      newErrors.password = "Password must be at least 6 characters.";
    if (!confirmPassword)
      newErrors.confirmPassword = "Please confirm your password.";
    else if (password !== confirmPassword)
      newErrors.confirmPassword = "Passwords do not match.";
    if (!agreeTerms)
      newErrors.terms = "You must agree to the Terms & Conditions.";
    if (process.env.NEXT_PUBLIC_RECAPTCHA_SITE_KEY && !captchaToken)
      newErrors.captcha = "Please verify that you're human.";
    return newErrors;
  }

  async function handleRegister(e: React.FormEvent) {
    e.preventDefault();
    const newErrors = validate();
    setErrors(newErrors);
    if (Object.keys(newErrors).length > 0) return;
    try {
      await createUserWithEmailAndPassword(
        auth,
        email.trim(),
        password.trim()
      );
      // User document will be created by ensureUserSubscription in AuthContext
      // This ensures consistent subscription structure across all auth methods
      router.push("/dashboard");
    } catch (error: unknown) {
      const message = error instanceof Error ? error.message : 'Registration failed. Please try again.';
      setErrors({
        form: message,
      });
    }
  }

  return (
    <div className="inset-0 flex items-center justify-center bg-background">
      <form
        onSubmit={handleRegister}
        className="w-full max-w-md p-8 space-y-6 rounded-1xl shadow-xl border bg-card text-card-foreground -mt-16"
      >
  <h2 className="text-2xl font-bold text-center mb-2">Create Your Account</h2>
  <p className="text-sm text-muted-foreground text-center -mt-2">Launch your NeuroSEO™ growth workspace in under a minute.</p>
        <div>
          <label htmlFor="email" className="block font-medium mb-1 text-foreground">Work Email</label>
          <input
            id="email"
            type="email"
            role="textbox"
            autoComplete="email"
            aria-label="Email address"
            aria-describedby="email-error"
              placeholder="you@example.com"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
              className="w-full px-3 py-2 border border-input rounded-lg bg-background text-foreground ring-1 ring-border focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 ring-offset-background transition"
          />
          <p id="email-error" className="text-xs text-destructive-foreground mt-1">{errors.email}</p>
        </div>
        <div className="relative">
          <label htmlFor="password" className="block font-medium mb-1 text-foreground">Password</label>
          <input
            id="password"
            type={showPassword ? "text" : "password"}
            role="textbox"
            autoComplete="new-password"
            aria-label="Password"
            aria-describedby="password-error"
              placeholder="Create a password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
              className="w-full px-3 py-2 border border-input rounded-lg pr-10 bg-background text-foreground ring-1 ring-border focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 ring-offset-background transition"
          />
          <button
            type="button"
            tabIndex={-1}
            aria-label={showPassword ? "Hide password" : "Show password"}
            className="absolute right-3 top-9 text-muted-foreground"
            onClick={() => setShowPassword((v) => !v)}
          >
            {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
          </button>
          <p id="password-error" className="text-xs text-destructive-foreground mt-1">{errors.password}</p>
        </div>
        <div className="relative">
          <label htmlFor="confirmPassword" className="block font-medium mb-1 text-foreground">Confirm Password</label>
          <input
            id="confirmPassword"
            type={showConfirm ? "text" : "password"}
            role="textbox"
            autoComplete="new-password"
            aria-label="Confirm password"
            aria-describedby="confirmPassword-error"
              placeholder="Re-enter your password"
            value={confirmPassword}
            onChange={(e) => setConfirmPassword(e.target.value)}
              className="w-full px-3 py-2 border border-input rounded-lg pr-10 bg-background text-foreground ring-1 ring-border focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 ring-offset-background transition"
          />
          <button
            type="button"
            tabIndex={-1}
            aria-label={showConfirm ? "Hide confirm password" : "Show confirm password"}
            className="absolute right-3 top-9 text-muted-foreground"
            onClick={() => setShowConfirm((v) => !v)}
          >
            {showConfirm ? <EyeOff size={18} /> : <Eye size={18} />}
          </button>
          <p id="confirmPassword-error" className="text-xs text-destructive-foreground mt-1">{errors.confirmPassword}</p>
        </div>
        {process.env.NEXT_PUBLIC_RECAPTCHA_SITE_KEY && (
          <div>
            <ReCAPTCHA
              sitekey={process.env.NEXT_PUBLIC_RECAPTCHA_SITE_KEY}
              onChange={(token) => setCaptchaToken(token || "")}
            />
            <p className="text-xs text-destructive-foreground mt-1">{errors.captcha}</p>
          </div>
        )}
