                    if (!invoices.length) actionResults.push({ action, status: 'skipped', message: 'No invoices' });
                    else {
                        const periods = Array.from(new Set(invoices.map(i => i.period))).sort();
                        const last = periods.at(-1)!;
                        const current = invoices.filter(i => i.period === last);
                        const paid = current.filter(i => i.status === 'paid');
                        const mrr = paid.reduce((s, i) => s + (i.amount || 0), 0);
                        const onTime = paid.filter(i => { const paidAt = i.paidAt?.toDate?.(); const due = i.dueAt?.toDate?.(); return paidAt && due && paidAt.getTime() <= due.getTime(); });
                        const onTimePct = paid.length ? (onTime.length / paid.length) * 100 : 0;
                        const outstanding = current.filter(i => i.status !== 'paid').length;
                        await adminDb.collection('financeRevenueSnapshots').add({ userId: data.userId, teamId: data.teamId || null, period: last, mrr, onTimePct: Number(onTimePct.toFixed(1)), outstanding, createdAt: new Date() });
                        actionResults.push({ action, status: 'ok', message: 'Revenue snapshot stored' });
                    }
                } catch (e: unknown) { actionResults.push({ action, status: 'error', message: errMsg(e, 'Revenue snapshot failed') }); }
            } else if (action === 'financeInvoiceAgingDigest') {
                try {
                    const to: string = cfg?.to || 'finance-aging@example.com';
                    const invSnap = await adminDb.collection('financeInvoices').where(data.teamId ? 'teamId' : 'userId', '==', data.teamId || data.userId).get();
                    const invoices = invSnap.docs.map(d => d.data() as InvoiceDoc);
                    const nowTs = Date.now();
                    const buckets: Record<string, number> = { '0-30': 0, '31-60': 0, '61-90': 0, '90+': 0 };
                    invoices.filter(i => i.status !== 'paid').forEach(i => {
                        const due = i.dueAt?.toDate?.()?.getTime?.();
                        if (!due) return; const days = Math.floor((nowTs - due) / 86400000);
                        if (days <= 30) buckets['0-30']++; else if (days <= 60) buckets['31-60']++; else if (days <= 90) buckets['61-90']++; else buckets['90+']++;
                    });
                    const body = `Invoice Aging Digest\n0-30: ${buckets['0-30']}\n31-60: ${buckets['31-60']}\n61-90: ${buckets['61-90']}\n90+: ${buckets['90+']}`;
                    await adminDb.collection('emailQueue').add({ userId: data.userId, teamId: data.teamId || null, recipeId, to, subject: 'Invoice Aging Digest', body, status: 'pending', createdAt: new Date() });
                    await adminDb.collection('financeInvoiceAgingSummaries').add({ userId: data.userId, teamId: data.teamId || null, buckets, createdAt: new Date() });
                    actionResults.push({ action, status: 'ok', message: 'Invoice aging digest enqueued' });
                } catch (e: unknown) { actionResults.push({ action, status: 'error', message: errMsg(e, 'Aging digest failed') }); }
            } else if (action === 'financeAccountingSeedSampleJournals') {
                try {
                    // Seed three core balanced journal entries (revenue, COGS, salaries)
                    const now = new Date();
                    const period = now.toISOString().slice(0, 7);
                    const baseRevenue = 50000;
                    // Revenue recognition
                    await adminDb.collection('accountingJournalEntries').add({ userId: data.userId, teamId: data.teamId || null, date: now.toISOString().slice(0, 10), period, lines: [{ account: 'ASSET_AR', side: 'debit', amount: baseRevenue }, { account: 'REV_SUBS', side: 'credit', amount: baseRevenue }], source: 'seed', createdAt: new Date(), updatedAt: new Date() });
                    // Hosting COGS
                    const cogs = Math.round(baseRevenue * 0.12);
                    await adminDb.collection('accountingJournalEntries').add({ userId: data.userId, teamId: data.teamId || null, date: now.toISOString().slice(0, 10), period, lines: [{ account: 'COGS_HOSTING', side: 'debit', amount: cogs }, { account: 'LIAB_AP', side: 'credit', amount: cogs }], source: 'seed', createdAt: new Date(), updatedAt: new Date() });
                    // Salaries OPEX
                    const sal = Math.round(baseRevenue * 0.30);
                    await adminDb.collection('accountingJournalEntries').add({ userId: data.userId, teamId: data.teamId || null, date: now.toISOString().slice(0, 10), period, lines: [{ account: 'OPEX_SAL', side: 'debit', amount: sal }, { account: 'ASSET_CASH', side: 'credit', amount: sal }], source: 'seed', createdAt: new Date(), updatedAt: new Date() });
                    actionResults.push({ action, status: 'ok', message: 'Sample journals seeded' });
                } catch (e: unknown) { actionResults.push({ action, status: 'error', message: errMsg(e, 'Seed failed') }); }
            } else if (action === 'financeAccountingGeneratePnL') {
                try {
                    const period = new Date().toISOString().slice(0, 7);
                    const jeSnap = await adminDb.collection('accountingJournalEntries').where(data.teamId ? 'teamId' : 'userId', '==', data.teamId || data.userId).get();
                    if (jeSnap.empty) { actionResults.push({ action, status: 'skipped', message: 'No journal entries' }); }
                    else {
                        let revenue = 0, cogs = 0, opex = 0;
                        jeSnap.docs.filter(d => (d.data() as JournalEntryDoc).period === period).forEach(d => {
                            ((d.data() as JournalEntryDoc).lines || []).forEach((l: JournalLine) => {
                                const side = l.side; const amt = l.amount || 0; const acct = l.account || '';
                                const add = (normal: 'debit' | 'credit') => side === normal ? amt : -amt;
                                if (acct.startsWith('REV_')) revenue += add('credit');
                                else if (acct.startsWith('COGS_')) cogs += Math.abs(add('debit'));
                                else if (acct.startsWith('OPEX_')) opex += Math.abs(add('debit'));
                            });
                        });
                        const grossProfit = revenue - cogs; const netIncome = grossProfit - opex;
                        await adminDb.collection('accountingReportSnapshots').add({ userId: data.userId, teamId: data.teamId || null, type: 'pnl', period, figures: { revenue, cogs, grossProfit, opex, netIncome }, createdAt: new Date() });
                        actionResults.push({ action, status: 'ok', message: 'P&L snapshot stored' });
                    }
                } catch (e: unknown) { actionResults.push({ action, status: 'error', message: errMsg(e, 'PnL failed') }); }
            } else if (action === 'financeAccountingGenerateBalanceSheet') {
                try {
                    const period = new Date().toISOString().slice(0, 7);
                    const jeSnap = await adminDb.collection('accountingJournalEntries').where(data.teamId ? 'teamId' : 'userId', '==', data.teamId || data.userId).get();
                    if (jeSnap.empty) { actionResults.push({ action, status: 'skipped', message: 'No journal entries' }); }
                    else {
                        let assets = 0, liabilities = 0, equity = 0;
                        jeSnap.docs.filter(d => {
                            const p = (d.data() as JournalEntryDoc).period;
                            return !!p && p <= period;
                        }).forEach(d => {
                            ((d.data() as JournalEntryDoc).lines || []).forEach((l: JournalLine) => {
                                const side = l.side; const amt = l.amount || 0; const acct = l.account || '';
                                const signed = (normal: 'debit' | 'credit') => side === normal ? amt : -amt;
                                if (acct.startsWith('ASSET_')) assets += signed('debit');
                                else if (acct.startsWith('LIAB_')) liabilities += signed('credit');
                                else if (acct.startsWith('EQUITY_')) equity += signed('credit');
                            });
                        });
                        await adminDb.collection('accountingReportSnapshots').add({ userId: data.userId, teamId: data.teamId || null, type: 'balance_sheet', period, figures: { assets, liabilities, equity }, createdAt: new Date() });
                        actionResults.push({ action, status: 'ok', message: 'Balance Sheet snapshot stored' });
                    }
                } catch (e: unknown) { actionResults.push({ action, status: 'error', message: errMsg(e, 'Balance sheet failed') }); }
            } else if (action === 'financeAccountingReconcile') {
                try {
                    const invSnap = await adminDb.collection('financeInvoices').where(data.teamId ? 'teamId' : 'userId', '==', data.teamId || data.userId).get();
                    const unpaid = invSnap.docs.filter(d => ((d.data() as InvoiceDoc).status) !== 'paid').length;
                    await adminDb.collection('accountingReportSnapshots').add({ userId: data.userId, teamId: data.teamId || null, type: 'reconciliation', period: new Date().toISOString().slice(0, 7), figures: { unpaid }, createdAt: new Date() });
                    actionResults.push({ action, status: 'ok', message: 'Reconciliation snapshot stored' });
                } catch (e: unknown) { actionResults.push({ action, status: 'error', message: errMsg(e, 'Reconcile failed') }); }
            } else {
                actionResults.push({ action, status: 'skipped' });
            }
        }
        const finished = new Date();
        await ref.update({ lastRun: started, nextRun: data.nextRun || null, updatedAt: new Date() });
        try { await adminDb.collection('automationRuns').add({ recipeId, userId: data.userId, teamId: data.teamId || null, startedAt: started, finishedAt: finished, actions: actionResults, status: actionResults.some(a => a.status === 'error') ? 'partial' : 'ok', createdAt: new Date() }); } catch { }
        return NextResponse.json(enforceProvenance({ success: true, recipeId, actions: actionResults, provenance: 'live' }, { path: 'automation/run-now' }));
    } catch (e: unknown) {
        return NextResponse.json(enforceProvenance({ success: false, error: errMsg(e, 'Run now failed'), provenance: 'synthetic' }, { path: 'automation/run-now', note: 'exception' }), { status: 500 });
    }
}, { path: 'automation/run-now' });

import type { NextRequest } from 'next/server';
import { NextResponse } from 'next/server';
import { getLogger } from '@/lib/logging/app-logger';
import { adminDb, adminAuth } from '@/lib/firebase-admin';
import { enforceProvenance, withProvenance } from '@/lib/middleware/provenance';

// Composite cursor pagination over financeInvoices
// Refinement (FIN-02): order by period desc, then createdAt desc to avoid skipping invoices when multiple share the same period.
// Cursor format: `${period}|${createdAtMs}` (createdAt in epoch ms). Backward compatibility: plain period cursor still accepted.
// Requires composite index: (userId, period desc, createdAt desc)

export const GET = withProvenance(async function GET(req: Request) {
    const nreq = req as NextRequest;
    const logger = getLogger('billing-invoices');
    try {
        const authHeader = req.headers.get('authorization') || req.headers.get('Authorization');
        if (!authHeader) {
            const res = NextResponse.json(enforceProvenance({ error: 'auth_required' }, { path: 'billing/invoices', note: 'auth' }), { status: 401 });
            res.headers.set('x-billing-diagnostics', 'auth=missing');
            return res;
        }
        const token = authHeader.replace('Bearer ', '');
        const decoded = await adminAuth.verifyIdToken(token);
        const uid = decoded.uid;
        const { searchParams } = new URL(nreq.url);
        const limitParam = parseInt(searchParams.get('limit') || '10', 10);
        const limitVal = Math.min(Math.max(1, isNaN(limitParam) ? 10 : limitParam), 50);
        const rawCursor = searchParams.get('cursor') || undefined; // period or period|createdAtMs
        // Build base query with composite ordering
        let q: FirebaseFirestore.Query = adminDb
            .collection('financeInvoices')
            .where('userId', '==', uid)
            .orderBy('period', 'desc')
            .orderBy('createdAt', 'desc')
            .limit(limitVal + 1); // fetch one extra for hasMore
        if (rawCursor) {
            if (rawCursor.includes('|')) {
                const [periodCursor, createdAtMsStr] = rawCursor.split('|');
                const createdAtMs = parseInt(createdAtMsStr, 10);
                const createdAtDate = isNaN(createdAtMs) ? new Date(0) : new Date(createdAtMs);
                q = q.startAfter(periodCursor, createdAtDate);
            } else {
                // Legacy period-only cursor: skip entire period by using minimal createdAt sentinel.
                q = q.startAfter(rawCursor, new Date(0));
            }
        }
        const snap = await q.get();
        let docs = snap.docs.map(d => {
            const raw = d.data() as Record<string, unknown>;
            return { id: d.id, ...raw } as Record<string, unknown>;
        });
        const hasMore = docs.length > limitVal;
        if (hasMore) docs = docs.slice(0, limitVal);
        docs = docs.map((invRaw) => {
            const inv = invRaw as Record<string, unknown>;
            // Normalize createdAt for cursor generation
            const toDate = (v: unknown): Date | undefined => {
                if (!v) return undefined;
                if (v instanceof Date) return v;
                const maybe = v as { toDate?: () => Date };
                return typeof maybe.toDate === 'function' ? maybe.toDate() : undefined;
            };
            const createdAt: Date = toDate(inv.createdAt) || toDate(inv.issuedAt) || new Date(String(inv.date || `${inv.period}-01T00:00:00Z`));
            return {
                ...inv,
                description: (inv.description as string) || `Invoice ${String(inv.period)}`,
                date: (inv.date as string) || createdAt.toISOString(),
                createdAt: createdAt, // ensure returned
            };
        });
        const last = docs[docs.length - 1] as Record<string, unknown> | undefined;
        const nextCursor = hasMore && last ? `${String(last.period)}|${(last.createdAt as Date).getTime()}` : undefined;
        logger.debug('billing-invoices.page', { uid, count: docs.length, hasMore, nextCursor });
        const res = NextResponse.json(enforceProvenance({ invoices: docs, hasMore, nextCursor }, { path: 'billing/invoices', note: 'page' }));
        res.headers.set('x-billing-diagnostics', `auth=ok; items=${docs.length}; hasMore=${hasMore}`);
        return res;
    } catch (e: unknown) {
        logger.error('billing-invoices.error', { error: (e as any)?.message });
        const res = NextResponse.json(enforceProvenance({ error: 'internal_error' }, { path: 'billing/invoices', note: 'exception' }), { status: 500 });
        res.headers.set('x-billing-diagnostics', 'auth=unknown; error=exception');
        return res;
    }
}, { path: 'billing/invoices' });

/**
 * RankPilot Admin Chatbot API Route
 * Verifies auth and proxies to Firebase Functions HTTPS endpoint
 */

import { adminAuth, adminDb } from '@/lib/firebase-admin';
import type { NextRequest } from 'next/server';
import { NextResponse } from 'next/server';
import { enforceProvenance, withProvenance } from '@/lib/middleware/provenance';
import { recordRouteLatency, recordError, recordRateLimitRejection } from '@/lib/metrics/unified-metrics';
import { enforceTeamRateLimit, TeamRateLimitError } from '@/lib/rate-limit/team-rate-limit';

// Types
interface AdminChatRequest {
    message: string;
    sessionId?: string;
}

interface ChatResponse {
    response: string;
    sessionId: string;
    timestamp: string;
    tokensUsed: number;
    context: {
        type: string;
        dataUsed: string[];
    };
}

export const POST = withProvenance(async function POST(request: NextRequest) {
    const nreq = request;
    const start = Date.now();
    try {
        // Parse request body
        const body: AdminChatRequest = await nreq.json();
        const { message, sessionId } = body;

        // Validate input
        if (!message?.trim()) {
            return NextResponse.json(
                { error: 'Message is required' },
                { status: 400 }
            );
        }

        // Get user from authentication header
        const authHeader = nreq.headers.get('authorization');
        if (!authHeader?.startsWith('Bearer ')) {
            return NextResponse.json(
                { error: 'Authentication required: missing Bearer token' },
                { status: 401 }
            );
        }

        const idToken = authHeader.split(' ')[1];
        let uid: string;
        try {
            const decoded = await adminAuth.verifyIdToken(idToken);
            uid = decoded.uid;
        } catch (e) {
            recordError('chat/admin', '4xx_user');
            recordRouteLatency('chat/admin', Date.now() - start);
            return NextResponse.json(enforceProvenance({ error: 'Invalid or expired token. Try reloading to refresh your session.', provenance: 'synthetic' }, { path: 'chat/admin' }), { status: 401 });
        }

        // Optional team-aware rate limiting (when user has teamId)
        try {
            const userDoc = await adminDb.collection('users').doc(uid).get();
            const udata = userDoc.exists ? userDoc.data() as Record<string, unknown> : undefined;
            const teamId = typeof udata?.teamId === 'string' ? udata.teamId : undefined;
            if (teamId) {
                try { await enforceTeamRateLimit(adminDb, teamId, { routeKey: 'chat/admin' }); }
                catch (e: unknown) {
                    if (e instanceof TeamRateLimitError) {
                        recordRateLimitRejection('chat/admin');
                        recordRateLimitRejection(`team:${teamId}`);
                        recordRouteLatency('chat/admin', Date.now() - start);
                        return NextResponse.json(enforceProvenance({ error: 'rate_limited', retryAfter: e.retryAfterSeconds, provenance: 'synthetic' }, { path: 'chat/admin' }), { status: 429, headers: { 'Retry-After': String(e.retryAfterSeconds) } });
                    }
                }
            }
        } catch (err) { void err; /* ignore */ }

        const projectId = process.env.FIREBASE_PROJECT_ID || process.env.NEXT_PUBLIC_FIREBASE_PROJECT_ID || 'rankpilot-h3jpc';
        const region = 'australia-southeast2';
        const useEmulator = false; // Force production Functions URL when testing locally without emulators
        const emulatorHost = process.env.FUNCTIONS_EMULATOR_HOST || 'localhost';
        const emulatorPort = process.env.FUNCTIONS_EMULATOR_PORT || '5001';
        const functionUrl = useEmulator
            ? `http://${emulatorHost}:${emulatorPort}/${projectId}/${region}/adminChatHandler`
            : `https://${region}-${projectId}.cloudfunctions.net/adminChatHandler`;

        let res: Response;
        try {
            res = await fetch(functionUrl, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${idToken}`,
                },
                body: JSON.stringify({
                    data: { uid, message, sessionId, chatType: 'admin' }
                }),
            });
        } catch (e) {
            recordError('chat/admin', '5xx_server');
            recordRouteLatency('chat/admin', Date.now() - start);
            return NextResponse.json(enforceProvenance({ error: 'Admin chat service unreachable', provenance: 'synthetic' }, { path: 'chat/admin' }), { status: 503 });
        }

        const rawText = await res.text();
        let payload: unknown = null;
        try {
            payload = rawText ? JSON.parse(rawText) : null;
        } catch (err) { void err; }
        if (!res.ok) {
            const p = (payload as Record<string, unknown> | null) || {};
            const errMsg = (((p as Record<string, unknown>)['error'] as Record<string, unknown> | undefined)?.['message'] as string | undefined)
                || ((p as Record<string, unknown>)['error'] as string | undefined)
                || (((p as Record<string, unknown>)['result'] as Record<string, unknown> | undefined)?.['error'] as Record<string, unknown> | undefined)?.['message'] as string | undefined
                || ((rawText || '').slice(0, 200) || 'Admin chat service unavailable');
            const code = res.status === 401 ? 401 : res.status === 403 ? 403 : res.status === 400 ? 400 : 503;
            const hint = code === 401
                ? ' (auth failed: ensure you are signed in; token may be expired)'
                : code === 403
                    ? ' (forbidden: check Function auth and App Check settings)'
                    : '';
            if (code >= 500) recordError('chat/admin', '5xx_server'); else if (code >= 400) recordError('chat/admin', '4xx_user');
            recordRouteLatency('chat/admin', Date.now() - start);
            return NextResponse.json(enforceProvenance({ error: `${errMsg}${hint}`, upstreamStatus: res.status, provenance: 'synthetic' }, { path: 'chat/admin' }), { status: code });
        }

        const container: Record<string, unknown> = (payload as Record<string, unknown> | null) || {};
        const data: ChatResponse = ((container as Record<string, unknown>)?.result ?? (container as Record<string, unknown>)?.data ?? payload) as unknown as ChatResponse;
        if (!data) {
            recordError('chat/admin', '5xx_server');
            recordRouteLatency('chat/admin', Date.now() - start);
            return NextResponse.json(enforceProvenance({ error: 'Invalid response from admin chat service', provenance: 'synthetic' }, { path: 'chat/admin' }), { status: 502 });
        }

        const resp = NextResponse.json(enforceProvenance({ ...data, provenance: 'live' }, { path: 'chat/admin' }));
        recordRouteLatency('chat/admin', Date.now() - start);
        return resp;

    } catch (error) {
        console.error('Admin chat API error:', error);

        // Handle Firebase Function errors
        if (error && typeof error === 'object' && 'code' in (error as Record<string, unknown>)) {
            const firebaseError = error as { code?: string };

            switch (firebaseError.code) {
                case 'unauthenticated':
                    recordError('chat/admin', '4xx_user');
                    recordRouteLatency('chat/admin', Date.now() - start);
                    return NextResponse.json(enforceProvenance({ error: 'Authentication required', provenance: 'synthetic' }, { path: 'chat/admin' }), { status: 401 });
                case 'permission-denied':
                    recordError('chat/admin', '4xx_user');
                    recordRouteLatency('chat/admin', Date.now() - start);
                    return NextResponse.json(enforceProvenance({ error: 'Admin access required', provenance: 'synthetic' }, { path: 'chat/admin' }), { status: 403 });
                case 'invalid-argument':
                    recordError('chat/admin', '4xx_user');
                    recordRouteLatency('chat/admin', Date.now() - start);
                    return NextResponse.json(enforceProvenance({ error: 'Invalid request data', provenance: 'synthetic' }, { path: 'chat/admin' }), { status: 400 });
                default:
                    recordError('chat/admin', '5xx_server');
                    recordRouteLatency('chat/admin', Date.now() - start);
                    return NextResponse.json(enforceProvenance({ error: 'Admin chat service unavailable', provenance: 'synthetic' }, { path: 'chat/admin' }), { status: 503 });
            }
        }

        recordError('chat/admin', '5xx_server');
        recordRouteLatency('chat/admin', Date.now() - start);
        return NextResponse.json(enforceProvenance({ error: 'Internal server error', provenance: 'synthetic' }, { path: 'chat/admin' }), { status: 500 });
    }
}, { path: 'chat/admin' });

// GET endpoint for admin chat history
export const GET = withProvenance(async function GET(request: NextRequest) {
    const nreq = request;
    const start = Date.now();
    try {
        const { searchParams } = new URL(nreq.url);
        const sessionId = searchParams.get('sessionId');
        const limit = parseInt(searchParams.get('limit') || '20');

        // Get user from authentication
        const authHeader = nreq.headers.get('authorization');
        if (!authHeader?.startsWith('Bearer ')) {
            recordError('chat/admin', '4xx_user');
            recordRouteLatency('chat/admin', Date.now() - start);
            return NextResponse.json(enforceProvenance({ error: 'Authentication required', provenance: 'synthetic' }, { path: 'chat/admin' }), { status: 401 });
        }

        const idToken = authHeader.split(' ')[1];
        const decoded = await adminAuth.verifyIdToken(idToken);
        const uid = decoded.uid;

        const collectionName = 'adminChats';

        // Determine session
        let currentSessionId = sessionId || '';
        if (!currentSessionId) {
            const latestSessionSnap = await adminDb
                .collection(collectionName)
                .doc(uid)
                .collection('sessions')
                .orderBy('lastActivity', 'desc')
                .limit(1)
                .get();

            if (latestSessionSnap.empty) {
                return NextResponse.json({ messages: [], sessionId: null, hasMore: false });
            }
            currentSessionId = latestSessionSnap.docs[0].id;
        }

        // Fetch messages
        const messagesSnap = await adminDb
            .collection(collectionName)
            .doc(uid)
            .collection('sessions')
            .doc(currentSessionId)
            .collection('messages')
            .orderBy('timestamp', 'asc')
            .limit(limit)
            .get();

        interface RawMsg { question?: string; response?: string; timestamp?: { toDate?: () => Date } | Date; tokensUsed?: number; }
        const messages: Array<{ id: string; message: string; response: string; timestamp: string; isUser: boolean; tokensUsed?: number; }> = [];
        messagesSnap.docs.forEach((doc) => {
            const d = doc.data() as Partial<RawMsg> | undefined;
            const tsRaw = d?.timestamp;
            const ts = tsRaw && typeof tsRaw === 'object' && 'toDate' in tsRaw && typeof (tsRaw as any).toDate === 'function'
                ? (tsRaw as any).toDate().toISOString()
                : new Date().toISOString();
            if (typeof d?.question === 'string') {
                messages.push({
                    id: `${doc.id}_user`,
                    message: d.question,
                    response: '',
                    timestamp: ts,
                    isUser: true,
                });
            }
            messages.push({
                id: `${doc.id}_ai`,
                message: '',
                response: typeof d?.response === 'string' ? d.response : '',
                timestamp: ts,
                isUser: false,
                tokensUsed: typeof d?.tokensUsed === 'number' ? d.tokensUsed : 0,
            });
        });

        const resp = NextResponse.json(enforceProvenance({
            messages,
            sessionId: currentSessionId,
            hasMore: false,
            provenance: 'live'
        }, { path: 'chat/admin' }));
        recordRouteLatency('chat/admin', Date.now() - start);
        return resp;

    } catch (error) {
        console.error('Admin chat history API error:', error);
        recordError('chat/admin', '5xx_server');
        recordRouteLatency('chat/admin', Date.now() - start);
        return NextResponse.json(enforceProvenance({ error: 'Failed to retrieve admin chat history', provenance: 'synthetic' }, { path: 'chat/admin' }), { status: 500 });
    }
}, { path: 'chat/admin' });

import { NextResponse, type NextRequest } from 'next/server';
import { adminAuth, adminDb } from '@/lib/firebase-admin';
import { FieldValue } from 'firebase-admin/firestore';
import { enforceProvenanceOnChunk } from '@/lib/middleware/provenance';
import { recordRouteLatency, recordError, recordFallback, recordRateLimitRejection } from '@/lib/metrics/unified-metrics';
import { enforceTeamRateLimit, TeamRateLimitError } from '@/lib/rate-limit/team-rate-limit';
import { fallbackOneShot } from '@/lib/ai/aiClient';
import OpenAI from 'openai';

export const dynamic = 'force-dynamic';
export const runtime = 'nodejs';

function estimateTokens(text: string): number {
    if (!text) return 0;
    const words = text.trim().split(/\s+/).length;
    return Math.ceil(words * 1.3);
}

export async function POST(req: NextRequest): Promise<Response> {
    const start = Date.now();
    try {
        const authHeader = req.headers.get('authorization');
        if (!authHeader?.startsWith('Bearer ')) {
            recordError('chat/admin/stream', '4xx_user');
            recordRouteLatency('chat/admin/stream', Date.now() - start);
            return new Response('Unauthorized', { status: 401 });
        }
        const idToken = authHeader.split(' ')[1];
        const decoded = await adminAuth.verifyIdToken(idToken);
        const uid = decoded.uid;

        const body = await req.json().catch(() => ({}));
        const { message, sessionId } = body as { message?: string; sessionId?: string };
        if (!message?.trim()) {
            recordError('chat/admin/stream', '4xx_user');
            recordRouteLatency('chat/admin/stream', Date.now() - start);
            return NextResponse.json({ error: 'Message required' }, { status: 400 });
        }

        // Optional team-aware rate limiting
        try {
            const userDoc = await adminDb.collection('users').doc(uid).get();
            const udata = userDoc.exists ? userDoc.data() as any : undefined;
            const teamId = typeof udata?.teamId === 'string' ? udata.teamId : undefined;
            if (teamId) {
                try { await enforceTeamRateLimit(adminDb, teamId, { routeKey: 'chat/admin/stream' }); }
                catch (e: unknown) {
                    if (e instanceof TeamRateLimitError) {
                        recordRateLimitRejection('chat/admin/stream');
                        recordRateLimitRejection(`team:${teamId}`);
                        recordRouteLatency('chat/admin/stream', Date.now() - start);
                        return new Response(JSON.stringify({ error: 'rate_limited', retryAfter: e.retryAfterSeconds }), { status: 429, headers: { 'Retry-After': String(e.retryAfterSeconds) } });
                    }
                }
            }
        } catch (_err) { /* ignore */ }

        // Determine session
        let currentSessionId = sessionId || '';
        if (!currentSessionId) {
            const latest = await adminDb.collection('adminChats').doc(uid).collection('sessions')
                .orderBy('lastActivity', 'desc').limit(1).get();
            if (latest.empty) {
                currentSessionId = `session_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`;
            } else {
                currentSessionId = latest.docs[0].id;
            }
        }

        // Select provider (OpenAI when key available)
        const openaiKey = process.env.OPENAI_API_KEY;
        let provider: 'openai' | 'synthetic' = openaiKey ? 'openai' : 'synthetic';
        if (!openaiKey) recordFallback('admin_stream:no_openai_key');

        // Minimal circuit breaker (separate for admin stream)
        const now = Date.now();
        // @ts-ignore
        if (!(global as unknown).__adminOpenAICB) { (global as unknown).__adminOpenAICB = { fail: 0, until: 0 }; }
        // @ts-ignore
        const cb = (global as unknown).__adminOpenAICB as { fail: number; until: number };
        const circuitOpen = now < cb.until;
        if (provider === 'openai' && circuitOpen) { provider = 'synthetic'; recordFallback('admin_stream:circuit_open'); }

        // Streaming response (SSE)
        const encoder = new TextEncoder();
        const readable = new ReadableStream({
            async start(controller) {
                try {
                    controller.enqueue(encoder.encode(`data: ${JSON.stringify(enforceProvenanceOnChunk({ info: 'provider_selected', provider, provenance: provider === 'openai' ? 'live' : 'synthetic' }, { path: 'chat/admin/stream' }))}\n\n`));

                    let fullResponse = '';
                    if (provider === 'openai') {
                        try {
                            const openai = new OpenAI({ apiKey: openaiKey! });
                            const stream = await openai.chat.completions.create({
                                model: 'gpt-4o-mini',
                                messages: [
                                    { role: 'system', content: 'You are RankPilot Admin AI. Answer concisely.' },
                                    { role: 'user', content: message }
                                ],
                                temperature: 0.2,
                                max_tokens: 600,
                                stream: true,
                            }) as AsyncIterable<OpenAI.Chat.Completions.ChatCompletionChunk>;
                            for await (const part of stream) {
                                const token = part?.choices?.[0]?.delta?.content;
                                if (token) {
                                    fullResponse += token;
                                    controller.enqueue(encoder.encode(`data: ${JSON.stringify({ token, provenance: 'live' })}\n\n`));
                                }
                            }
                            // reset CB on success
                            cb.fail = 0; cb.until = 0;
                        } catch (e) {
                            // trip circuit after repeated failures
                            cb.fail = (cb.fail || 0) + 1;
                            if (cb.fail >= 4) { cb.until = Date.now() + 120000; cb.fail = 0; }
                            provider = 'synthetic';
                            recordFallback('admin_stream:openai_failure');
                        }
                    }

                    if (provider !== 'openai') {
                        // fallback one-shot
                        const text = await fallbackOneShot('You are RankPilot Admin AI. Answer concisely.', message, 600);
                        fullResponse = text;
                        controller.enqueue(encoder.encode(`data: ${JSON.stringify({ token: text, fallback: true, provenance: 'synthetic' })}\n\n`));
                    }

                    // Persist
                    try {
                        const tokensUsed = estimateTokens(fullResponse);
                        const msgCollection = adminDb.collection('adminChats').doc(uid).collection('sessions').doc(currentSessionId).collection('messages');
                        await msgCollection.add({
                            question: message,
                            response: fullResponse,
                            timestamp: FieldValue.serverTimestamp(),
                            tokensUsed,
                            chatType: 'admin',
                            metadata: { streamed: true, provider }
                        });
                        await adminDb.collection('adminChats').doc(uid).collection('sessions').doc(currentSessionId).set({
                            lastMessage: fullResponse.slice(0, 100),
                            lastActivity: FieldValue.serverTimestamp(),
                            messageCount: FieldValue.increment(1),
                            chatType: 'admin',
                            lastProvider: provider,
                            lastProviderAt: FieldValue.serverTimestamp(),
                        }, { merge: true });
                    } catch { }

                    controller.enqueue(encoder.encode(`data: ${JSON.stringify(enforceProvenanceOnChunk({ final: true, sessionId: currentSessionId, timestamp: new Date().toISOString(), tokensUsed: estimateTokens(fullResponse), provider, provenance: provider === 'openai' ? 'live' : 'synthetic' }, { path: 'chat/admin/stream' }))}\n\n`));
                    controller.enqueue(encoder.encode('data: [DONE]\n\n'));
                    controller.close();
                } catch (e: unknown) {
                    recordError('chat/admin/stream', '5xx_server');
                    controller.enqueue(encoder.encode(`data: ${JSON.stringify(enforceProvenanceOnChunk({ error: (e as any)?.message || 'stream_error', provenance: 'synthetic' }, { path: 'chat/admin/stream' }))}\n\n`));
                    controller.enqueue(encoder.encode('data: [DONE]\n\n'));
                    controller.close();
                }
            }
        });

        const response = new Response(readable, {
            headers: {
                'Content-Type': 'text/event-stream',
                'Cache-Control': 'no-cache, no-transform',
                'Connection': 'keep-alive',
                'Transfer-Encoding': 'chunked'
            }
        });
        recordRouteLatency('chat/admin/stream', Date.now() - start);
        return response;
    } catch (e: unknown) {
        recordError('chat/admin/stream', '5xx_server');
        recordRouteLatency('chat/admin/stream', Date.now() - start);
        return NextResponse.json({ error: (e as any)?.message || 'Stream init failed' }, { status: 500 });
    }
}

/**
 * RankPilot Customer Chatbot API Route
 * Verifies auth and proxies to Firebase Functions HTTPS endpoint
 */

import { maybeEmbedMessage } from '@/lib/chat/embedding';
import { maybeSummarizeSession } from '@/lib/chat/sessionSummarizer';
import { adminAuth, adminDb } from '@/lib/firebase-admin';
import { recordError, recordRateLimitRejection, recordRouteLatency } from '@/lib/metrics/unified-metrics';
import { enforceProvenance, withProvenance } from '@/lib/middleware/provenance';
import { enforceTeamRateLimit, TeamRateLimitError } from '@/lib/rate-limit/team-rate-limit';
import { safeErrorMessage } from '@/lib/utils';
import { FieldValue } from 'firebase-admin/firestore';
import type { NextRequest } from 'next/server';
import { NextResponse } from 'next/server';

// Force dynamic to avoid any accidental caching of auth state in edge/runtime
export const dynamic = 'force-dynamic';
export const runtime = 'nodejs';

// Types
interface ChatRequest {
    message?: string; // optional when uploading attachments only
    url?: string;
    sessionId?: string;
    attachments?: { type: 'image' | 'audio'; mediaUrl: string; name?: string }[];
}

interface ChatResponse {
    response: string;
    sessionId: string;
    timestamp: string;
    tokensUsed: number;
    context: {
        type: string;
        dataUsed: string[];
    };
}

function isChatResponse(v: unknown): v is ChatResponse {
    if (!v || typeof v !== 'object') return false;
    const o = v as Record<string, unknown>;
    return typeof o.response === 'string'
        && typeof o.sessionId === 'string'
        && typeof o.timestamp === 'string'
        && typeof o.tokensUsed === 'number'
        && !!o.context
        && typeof (o.context as any).type === 'string'
        && Array.isArray((o.context as any).dataUsed);
}

// Shared quota limits (align with streaming route)
const QUOTA_LIMITS: Record<string, { messages: number; tokens: number }> = {
    free: { messages: 50, tokens: 15000 },
    starter: { messages: 200, tokens: 60000 },
    agency: { messages: 500, tokens: 150000 },
    enterprise: { messages: 2000, tokens: 600000 },
    admin: { messages: 10000, tokens: 2000000 },
};

async function getUserTier(uid: string): Promise<string> {
    try {
        const snap = await adminDb.collection('users').doc(uid).get();
        return (snap.data()?.subscriptionTier as string) || 'free';
    } catch { return 'free'; }
}

async function checkAndIncrementMessageQuota(uid: string, tier: string) {
    const limits = QUOTA_LIMITS[tier] || QUOTA_LIMITS.free;
    const dateKey = new Date().toISOString().slice(0, 10);
    const ref = adminDb.collection('usageCounters').doc(`${uid}_${dateKey}`);
    await adminDb.runTransaction(async tx => {
        type UsageData = { messages?: number; tokens?: number; tier?: string; date?: string };
        const snap = await tx.get(ref);
        const data = snap.exists ? (snap.data() as UsageData) : { messages: 0, tokens: 0, tier, date: dateKey };
        if ((data.messages || 0) >= limits.messages) throw new Error('Daily message quota reached');
        tx.set(ref, { messages: FieldValue.increment(1), tokens: data.tokens || 0, tier, date: dateKey, updatedAt: FieldValue.serverTimestamp() }, { merge: true });
    });
}

async function incrementTokenUsage(uid: string, tier: string, tokens: number) {
    if (!tokens) return;
    const dateKey = new Date().toISOString().slice(0, 10);
    const ref = adminDb.collection('usageCounters').doc(`${uid}_${dateKey}`);
    const limits = QUOTA_LIMITS[tier] || QUOTA_LIMITS.free;
    await adminDb.runTransaction(async tx => {
        type UsageData = { messages?: number; tokens?: number; tier?: string; date?: string };
        const snap = await tx.get(ref);
        const data = snap.exists ? (snap.data() as UsageData) : { messages: 0, tokens: 0, tier, date: dateKey };
        if ((data.tokens || 0) >= limits.tokens) return; // already capped
        const remaining = limits.tokens - (data.tokens || 0);
        const toAdd = Math.min(remaining, tokens);
        if (toAdd <= 0) return;
        tx.set(ref, { tokens: FieldValue.increment(toAdd), updatedAt: FieldValue.serverTimestamp() }, { merge: true });
    });
}

function estimateTokens(text: string): number {
    if (!text) return 0;
    const words = text.trim().split(/\s+/).length;
    return Math.ceil(words * 1.3);
}

export const POST = withProvenance(async function POST(request: NextRequest) {
    const start = Date.now();
    try {
        // Parse request body (defensive)
        let body: ChatRequest;
        try {
            body = await request.json();
        } catch {
            return NextResponse.json({ error: 'Invalid JSON body' }, { status: 400 });
        }
        const { message, url, sessionId, attachments } = body || {} as ChatRequest;

        const isAttachmentOnly = (!message || !message.trim()) && Array.isArray(attachments) && attachments.length > 0;
        if (!isAttachmentOnly && !message?.trim()) {
            return NextResponse.json({ error: 'Message is required' }, { status: 400 });
        }

        // Get user from authentication header
        const authHeaderRaw = request.headers.get('authorization') || '';
        if (!authHeaderRaw.startsWith('Bearer ')) {
            return NextResponse.json(
                { error: 'Authentication required: missing Bearer token' },
                { status: 401 }
            );
        }

        const idToken = authHeaderRaw.split(' ')[1];
        if (!idToken) {
            return NextResponse.json({ error: 'Authentication required: empty token' }, { status: 401 });
        }

        // Verify ID token and get UID
        let uid: string;
        try {
            const decoded = await adminAuth.verifyIdToken(idToken);
            uid = decoded.uid;
        } catch (e: unknown) {
            return NextResponse.json({ error: 'Invalid or expired token. Try reloading to refresh your session.', details: process.env.NODE_ENV !== 'production' ? safeErrorMessage(e) : undefined }, { status: 401 });
        }

        // Load user doc (for teamId before any limiting)
        let userDoc: FirebaseFirestore.DocumentSnapshot | null = null;
        let teamId: string | undefined;
        try {
            userDoc = await adminDb.collection('users').doc(uid).get();
            const ud = userDoc.exists ? (userDoc.data() as Record<string, unknown>) : undefined;
            teamId = typeof ud?.teamId === 'string' ? ud.teamId : undefined;
        } catch { /* ignore */ }

        // Team-aware rate limiting (Phase 1 PERF-01)
        if (teamId) {
            try {
                await enforceTeamRateLimit(adminDb as any, teamId, { routeKey: 'chat/customer' });
            } catch (e: unknown) {
                if (e instanceof TeamRateLimitError) {
                    recordRateLimitRejection('chat/customer');
                    recordRateLimitRejection(`team:${teamId}`);
                    recordRouteLatency('chat/customer', Date.now() - start);
                    return NextResponse.json(enforceProvenance({ error: 'rate_limited', retryAfter: e.retryAfterSeconds, provenance: 'synthetic' }, { path: 'chat/customer' }), { status: 429, headers: { 'Retry-After': String(e.retryAfterSeconds) } });
                }
            }
        }

        // Attachment-only persistence flow (no AI call)
        if (isAttachmentOnly) {
            const collectionName = 'chatLogs';
            let currentSessionId = sessionId || '';
            if (!currentSessionId) {
                const latestSessionSnap = await adminDb
                    .collection(collectionName)
                    .doc(uid)
                    .collection('sessions')
                    .orderBy('lastActivity', 'desc')
                    .limit(1)
                    .get();
                if (latestSessionSnap.empty) {
                    currentSessionId = `session_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`;
                } else {
                    currentSessionId = latestSessionSnap.docs[0].id;
                }
            }

            const batch = adminDb.batch();
            attachments!.forEach(att => {
                const msgRef = adminDb
                    .collection(collectionName)
                    .doc(uid)
                    .collection('sessions')
                    .doc(currentSessionId)
                    .collection('messages')
                    .doc();
                batch.set(msgRef, {
                    question: '',
                    response: '',
                    timestamp: new Date(),
                    chatType: 'customer',
                    tokensUsed: 0,
                    isAttachment: true,
                    attachmentType: att.type,
                    mediaUrl: att.mediaUrl,
                    originalName: att.name || null,
                });
            });
            const sessionRef = adminDb
                .collection(collectionName)
                .doc(uid)
                .collection('sessions')
                .doc(currentSessionId);
            batch.set(sessionRef, {
                lastActivity: new Date(),
                chatType: 'customer',
            }, { merge: true });
            await batch.commit();
            const resp = NextResponse.json(enforceProvenance({ success: true, sessionId: currentSessionId, provenance: 'live' }, { path: 'chat/customer' }));
            recordRouteLatency('chat/customer', Date.now() - start);
            return resp;
        }

        // Call the callable HTTPS endpoint so request.auth is populated server-side
        const projectId = process.env.FIREBASE_PROJECT_ID || process.env.NEXT_PUBLIC_FIREBASE_PROJECT_ID || 'rankpilot-h3jpc';
        const region = 'australia-southeast2';
        const useEmulator = false; // Force production Functions URL when testing locally without emulators
        const emulatorHost = process.env.FUNCTIONS_EMULATOR_HOST || 'localhost';
        const emulatorPort = process.env.FUNCTIONS_EMULATOR_PORT || '5001';
        const functionUrl = useEmulator
            ? `http://${emulatorHost}:${emulatorPort}/${projectId}/${region}/customerChatHandler`
            : `https://${region}-${projectId}.cloudfunctions.net/customerChatHandler`;

        let res: Response;
        try {
            res = await fetch(functionUrl, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${idToken}`,
                },
                body: JSON.stringify({
                    data: { uid, message, url, sessionId, chatType: 'customer' }
                }),
            });
        } catch (e: unknown) {
            return NextResponse.json({ error: 'Chat service unreachable', details: process.env.NODE_ENV !== 'production' ? safeErrorMessage(e) : undefined }, { status: 503 });
        }

        const rawText = await res.text();
        let payload: unknown = null;
        try {
            payload = rawText ? JSON.parse(rawText) : null;
        } catch {
            // Not JSON; likely HTML or error text
        }

        if (!res.ok) {
            const p = payload as unknown;
            function extractErrorMessage(obj: unknown): string | undefined {
                if (!obj || typeof obj !== 'object') return undefined;
                const o = obj as Record<string, unknown>;
                if ('error' in o) {
                    const err = o.error;
                    if (typeof err === 'string') return err;
                    if (err && typeof err === 'object') {
                        const em = (err as Record<string, unknown>).message;
                        if (typeof em === 'string') return em;
                    }
                }
                if ('result' in o && o.result && typeof o.result === 'object') {
                    const r = o.result as Record<string, unknown>;
                    if ('error' in r && r.error && typeof r.error === 'object') {
                        const em = (r.error as Record<string, unknown>).message;
                        if (typeof em === 'string') return em;
                    }
                }
                return undefined;
            }
            const extracted = extractErrorMessage(p);
            const errMsg = extracted || ((rawText || '').slice(0, 200) || 'Chat service unavailable');
            const code = res.status === 401 ? 401 : res.status === 403 ? 403 : res.status === 400 ? 400 : 503;
            // Provide helpful hints for common 401/403 causes during local dev
            const hint = code === 401
                ? ' (auth failed: ensure you are signed in; token may be expired)'
                : code === 403
                    ? ' (forbidden: check Function auth and App Check settings)'
                    : '';
            const resp = NextResponse.json(enforceProvenance({ error: `${errMsg}${hint}`, upstreamStatus: res.status, provenance: 'synthetic' }, { path: 'chat/customer' }), { status: code });
            if (code >= 500) recordError('chat/customer', '5xx_server'); else if (code >= 400) recordError('chat/customer', '4xx_user');
            recordRouteLatency('chat/customer', Date.now() - start);
            return resp;
        }

        const anyPayload = payload as unknown;
        let data: ChatResponse | undefined;
        if (anyPayload && typeof anyPayload === 'object') {
            const ap = anyPayload as Record<string, unknown>;
            const candidates: unknown[] = [];
            if (ap.result && typeof ap.result === 'object') candidates.push(ap.result);
            if (ap.data && typeof ap.data === 'object') candidates.push(ap.data);
            candidates.push(ap);
            for (const c of candidates) { if (isChatResponse(c)) { data = c; break; } }
        }
        if (!data) {
            recordError('chat/customer', '5xx_server');
            recordRouteLatency('chat/customer', Date.now() - start);
            return NextResponse.json(enforceProvenance({ error: 'Invalid response from chat service', provenance: 'synthetic' }, { path: 'chat/customer' }), { status: 502 });
        }

        // Attempt meta extraction (same pattern as streaming if model returned hidden tags)
        let intent: string | undefined; let actions: string[] | undefined; let priority: number | undefined;
        const metaMatch = data.response?.match?.(/<rp_meta>([\s\S]*?)<\/rp_meta>/);
        if (metaMatch) {
            try {
                const parsed: unknown = JSON.parse(metaMatch[1].trim());
                if (parsed && typeof parsed === 'object') {
                    const p = parsed as Record<string, unknown>;
                    intent = typeof p.intent === 'string' ? p.intent : undefined;
                    actions = Array.isArray(p.actions) ? p.actions.filter(a => typeof a === 'string').slice(0, 5) as string[] : undefined;
                    priority = typeof p.priority === 'number' ? p.priority : undefined;
                    data = { ...data, response: data.response.replace(metaMatch[0], '').trim() };
                }
            } catch { /* ignore */ }
        }

        // Retrieval augmentation for next turn: embed current question (if embeddings enabled) and store metadata
        if (process.env.RANKPILOT_ENABLE_EMBEDDINGS === '1' && data.sessionId && message) {
            // Fire-and-forget embedding
            const sessionDocRef = adminDb.collection('chatLogs').doc(uid).collection('sessions').doc(data.sessionId);
            try {
                // Persist message doc (non-stream path may not yet have stored this Q/A pair)
                const msgRef = await sessionDocRef.collection('messages').add({
                    question: message,
                    response: data.response,
                    timestamp: FieldValue.serverTimestamp(),
                    tokensUsed: data.tokensUsed || estimateTokens(data.response),
                    chatType: 'customer',
                    metadata: { streamed: false, intent, actions, priority }
                });
                sessionDocRef.set({
                    lastMessage: data.response.slice(0, 100),
                    lastActivity: FieldValue.serverTimestamp(),
                    messageCount: FieldValue.increment(1),
                    chatType: 'customer'
                }, { merge: true });
                maybeEmbedMessage({ uid, sessionId: data.sessionId, messageDocId: msgRef.id, question: message }).catch(() => { });
            } catch { /* ignore */ }
        }

        // Quota enforcement (post-response ensures not blocking messaging if function consumed; small risk of overage on race)
        let quotaWarning: string | undefined;
        try {
            const tier = await getUserTier(uid);
            await checkAndIncrementMessageQuota(uid, tier);
            const estTokens = data.tokensUsed || estimateTokens(data.response);
            await incrementTokenUsage(uid, tier, estTokens);
        } catch (quotaErr: unknown) {
            quotaWarning = safeErrorMessage(quotaErr);
        }

        if (data.sessionId) {
            // Fire-and-forget summarization
            maybeSummarizeSession({ uid, sessionId: data.sessionId, latestUserMessage: body.message, latestAIResponse: data.response }).catch(() => { });
        }

        if (quotaWarning) {
            const resp = NextResponse.json(enforceProvenance({ ...data, quotaWarning, provenance: 'live' }, { path: 'chat/customer' }), { status: 200, headers: { 'X-Quota-Warning': quotaWarning } });
            recordRouteLatency('chat/customer', Date.now() - start);
            return resp;
        }
        const resp = NextResponse.json(enforceProvenance({ ...data, provenance: 'live' }, { path: 'chat/customer' }));
        recordRouteLatency('chat/customer', Date.now() - start);
        return resp;

    } catch (error: unknown) {
        console.error('Customer chat API error:', error);

        // Handle Firebase Function errors
        if (error && typeof error === 'object' && 'code' in error) {
            const fe = error as Record<string, unknown>;
            const code = typeof fe.code === 'string' ? fe.code : undefined;

            switch (code) {
                case 'unauthenticated':
                    recordError('chat/customer', '4xx_user');
                    return NextResponse.json(enforceProvenance({ error: 'Authentication required', provenance: 'synthetic' }, { path: 'chat/customer' }), { status: 401 });
                case 'permission-denied':
                    recordError('chat/customer', '4xx_user');
                    return NextResponse.json(enforceProvenance({ error: 'Permission denied', provenance: 'synthetic' }, { path: 'chat/customer' }), { status: 403 });
                case 'invalid-argument':
                    recordError('chat/customer', '4xx_user');
                    return NextResponse.json(enforceProvenance({ error: 'Invalid request data', provenance: 'synthetic' }, { path: 'chat/customer' }), { status: 400 });
                default:
                    recordError('chat/customer', '5xx_server');
                    return NextResponse.json(enforceProvenance({ error: 'Chat service unavailable', provenance: 'synthetic' }, { path: 'chat/customer' }), { status: 503 });
            }
        }

        recordError('chat/customer', '5xx_server');
        recordRouteLatency('chat/customer', Date.now() - start);
        return NextResponse.json(enforceProvenance({ error: 'Internal server error', details: process.env.NODE_ENV !== 'production' ? safeErrorMessage(error) : undefined, provenance: 'synthetic' }, { path: 'chat/customer' }), { status: 500 });
    }
}, { path: 'chat/customer' });

// GET endpoint for chat history (customer)
export const GET = withProvenance(async function GET(request: NextRequest) {
    const start = Date.now();
    try {
        const { searchParams } = new URL(request.url);
        const sessionId = searchParams.get('sessionId');
        const limit = Math.min(parseInt(searchParams.get('limit') || '20', 10), 100);
        const before = searchParams.get('before'); // ISO timestamp of earliest currently loaded message

        // Get user from authentication
        const authHeader = request.headers.get('authorization');
        if (!authHeader?.startsWith('Bearer ')) {
            recordError('chat/customer', '4xx_user');
            return NextResponse.json(enforceProvenance({ error: 'Authentication required', provenance: 'synthetic' }, { path: 'chat/customer' }), { status: 401 });
        }
        const idToken = authHeader.split(' ')[1] || '';
        if (!idToken) {
            recordError('chat/customer', '4xx_user');
            return NextResponse.json(enforceProvenance({ error: 'Authentication required', provenance: 'synthetic' }, { path: 'chat/customer' }), { status: 401 });
        }
        const decoded = await adminAuth.verifyIdToken(idToken);
        const uid = decoded.uid;

        const collectionName = 'chatLogs';

        // Determine session
        let currentSessionId = sessionId || '';
        if (!currentSessionId) {
            const latestSessionSnap = await adminDb
                .collection(collectionName)
                .doc(uid)
                .collection('sessions')
                .orderBy('lastActivity', 'desc')
                .limit(1)
                .get();

            if (latestSessionSnap.empty) {
                return NextResponse.json({ messages: [], sessionId: null, hasMore: false });
            }
            currentSessionId = latestSessionSnap.docs[0].id;
        }

        // Build base query
        let queryRef: FirebaseFirestore.Query = adminDb
            .collection(collectionName)
            .doc(uid)
            .collection('sessions')
            .doc(currentSessionId)
            .collection('messages')
            .orderBy('timestamp', 'desc');

        if (before) {
            const beforeDate = new Date(before as string);
            if (!isNaN(beforeDate.getTime())) {
                queryRef = queryRef.where('timestamp', '<', beforeDate);
            }
        }

        // Fetch (grab one extra to determine hasMore)
        const messagesSnap = await queryRef.limit(limit + 1).get();

        let hasMore = false;
        let workingDocs = messagesSnap.docs;
        if (messagesSnap.size > limit) {
            hasMore = true;
            workingDocs = messagesSnap.docs.slice(0, limit);
        }

        const messages: unknown[] = [];
        // Reverse to chronological ascending (oldest first within this page)
        const orderedDocs = [...workingDocs].reverse();
        orderedDocs.forEach((doc) => {
            const d = doc.data() as Record<string, unknown>;
            let ts = new Date().toISOString();
            if (d.timestamp && typeof d.timestamp === 'object' && 'toDate' in d.timestamp && typeof ((d.timestamp as { toDate?: unknown }).toDate) === 'function') {
                try {
                    ts = (d.timestamp as { toDate: () => Date }).toDate().toISOString();
                } catch { ts = new Date().toISOString(); }
            }
            if (d.isAttachment) {
                messages.push({
                    id: `${doc.id}_att`,
                    message: (typeof d.originalName === 'string' && d.originalName) || (typeof d.attachmentType === 'string' ? d.attachmentType : ''),
                    response: '',
                    timestamp: ts,
                    isUser: true,
                    type: typeof d.attachmentType === 'string' ? d.attachmentType : undefined,
                    mediaUrl: typeof d.mediaUrl === 'string' ? d.mediaUrl : undefined,
                });
                return; // skip pairing
            }
            if (typeof d.question === 'string') {
                messages.push({
                    id: `${doc.id}_user`,
                    message: d.question,
                    response: '',
                    timestamp: ts,
                    isUser: true,
                });
            }
            messages.push({
                id: `${doc.id}_ai`,
                message: '',
                response: typeof d.response === 'string' ? d.response : '',
                timestamp: ts,
                isUser: false,
                tokensUsed: typeof d.tokensUsed === 'number' ? d.tokensUsed : 0,
            });
        });
        // hasMore already computed

        // Fetch session summary/meta
        let sessionSummary: string | undefined; let pendingActions: string[] | undefined; let keywords: string[] | undefined; let summaryUpdatedAt: string | undefined;
        try {
            const sessionDoc = await adminDb.collection(collectionName).doc(uid).collection('sessions').doc(currentSessionId).get();
            if (sessionDoc.exists) {
                const sDataRaw = sessionDoc.data() as Record<string, unknown>;
                const ss = sDataRaw.sessionSummary; if (typeof ss === 'string') sessionSummary = ss;
                const pa = sDataRaw.pendingActions; if (Array.isArray(pa)) pendingActions = pa.filter((a: unknown): a is string => typeof a === 'string');
                const kw = sDataRaw.keywords; if (Array.isArray(kw)) keywords = kw.filter((k: unknown): k is string => typeof k === 'string');
                const su = sDataRaw.summaryUpdatedAt;
                if (su && typeof su === 'object' && 'toDate' in su && typeof (su as { toDate?: unknown }).toDate === 'function') {
                    try { summaryUpdatedAt = (su as { toDate: () => Date }).toDate().toISOString(); } catch { summaryUpdatedAt = undefined; }
                }
            }
        } catch { /* ignore */ }

        const resp = NextResponse.json(enforceProvenance({
            messages,
            sessionId: currentSessionId,
            hasMore,
            sessionSummary,
            pendingActions,
            keywords,
            summaryUpdatedAt,
            provenance: 'live'
        }, { path: 'chat/customer' }));
        recordRouteLatency('chat/customer', Date.now() - start);
        return resp;

    } catch (error) {
        console.error('Chat history API error:', error);
        recordError('chat/customer', '5xx_server');
        recordRouteLatency('chat/customer', Date.now() - start);
        return NextResponse.json(enforceProvenance({ error: 'Failed to retrieve chat history', provenance: 'synthetic' }, { path: 'chat/customer' }), { status: 500 });
    }
}, { path: 'chat/customer' });

import type { NextRequest } from 'next/server';
import { NextResponse } from 'next/server';
import { adminAuth, adminDb } from '@/lib/firebase-admin';
import OpenAI from 'openai';
import { FieldValue } from 'firebase-admin/firestore';
import { maybeSummarizeSession } from '@/lib/chat/sessionSummarizer';
import { maybeEmbedMessage } from '@/lib/chat/embedding';
import { buildQueryEmbedding, retrieveSimilarMessages, maybeClusterKeywords } from '@/lib/chat/retrievalAndClustering';
import { retrieveSiteChunks } from '@/lib/site-ingestion/retrieval';
import { fallbackOneShot } from '@/lib/ai/aiClient';
import { enforceProvenanceOnChunk } from '@/lib/middleware/provenance';
import { recordRouteLatency, recordError, recordFallback, recordRateLimitRejection } from '@/lib/metrics/unified-metrics';
import { enforceTeamRateLimit, TeamRateLimitError } from '@/lib/rate-limit/team-rate-limit';

// Quota limits by tier (daily)
const QUOTA_LIMITS: Record<string, { messages: number; tokens: number }> = {
    free: { messages: 50, tokens: 15000 },
    starter: { messages: 200, tokens: 60000 },
    agency: { messages: 500, tokens: 150000 },
    enterprise: { messages: 2000, tokens: 600000 },
    admin: { messages: 10000, tokens: 2000000 },
};

// Lightweight typed aliases to avoid explicit `any` usage
type UsageCounter = {
    messages?: number;
    tokens?: number;
    tier?: string;
    date?: string;
    providerCounts?: Record<string, number>;
};

type SiteChunk = {
    score: number;
    meta?: { title?: string };
    content: string;
};

async function checkAndIncrementMessageQuota(uid: string, tier: string) {
    const limits = QUOTA_LIMITS[tier] || QUOTA_LIMITS.free;
    const dateKey = new Date().toISOString().slice(0, 10); // YYYY-MM-DD
    const docRef = adminDb.collection('usageCounters').doc(`${uid}_${dateKey}`);
    await adminDb.runTransaction(async (tx) => {
        const snap = await tx.get(docRef);
        const data = snap.exists ? (snap.data() as UsageCounter) : { messages: 0, tokens: 0, tier, date: dateKey };
        if ((data.messages || 0) >= limits.messages) {
            throw new Error('Daily message quota reached');
        }
        tx.set(docRef, {
            messages: FieldValue.increment(1),
            tokens: (data.tokens || 0),
            tier,
            date: dateKey,
            updatedAt: FieldValue.serverTimestamp(),
        }, { merge: true });
    });
}

async function incrementTokenUsage(uid: string, tier: string, tokens: number) {
    const dateKey = new Date().toISOString().slice(0, 10);
    const docRef = adminDb.collection('usageCounters').doc(`${uid}_${dateKey}`);
    const limits = QUOTA_LIMITS[tier] || QUOTA_LIMITS.free;
    await adminDb.runTransaction(async (tx) => {
        const snap = await tx.get(docRef);
        const data = snap.exists ? (snap.data() as UsageCounter) : { messages: 0, tokens: 0, tier, date: dateKey };
        if (((data.tokens || 0) + tokens) > limits.tokens) {
            // Mark as capped; still increment up to limit
            const remaining = Math.max(0, limits.tokens - (data.tokens || 0));
            if (remaining > 0) {
                tx.set(docRef, { tokens: FieldValue.increment(remaining), updatedAt: FieldValue.serverTimestamp() }, { merge: true });
            }
            return;
        }
        tx.set(docRef, { tokens: FieldValue.increment(tokens), updatedAt: FieldValue.serverTimestamp() }, { merge: true });
    });
}

function estimateTokens(text: string): number {
    if (!text) return 0;
    // Rough heuristic (~1.3 tokens per word for English prose / mixed content)
    const words = text.trim().split(/\s+/).length;
    return Math.ceil(words * 1.3);
}

export const dynamic = 'force-dynamic';
export const runtime = 'nodejs';

async function getUserTier(uid: string): Promise<string> {
    try {
        const snap = await adminDb.collection('users').doc(uid).get();
        return (snap.data()?.subscriptionTier as string) || 'free';
    } catch { return 'free'; }
}

// In-memory OpenAI failure tracking (simple circuit breaker)
let openAIConsecutiveFailures = 0;
let openAICircuitOpenUntil = 0; // epoch ms
const OPENAI_FAILURE_THRESHOLD = 5;
const OPENAI_CIRCUIT_DURATION_MS = 2 * 60 * 1000; // 2 minutes

function openAICircuitOpen() {
    return Date.now() < openAICircuitOpenUntil;
}

function recordOpenAISuccess() {
    openAIConsecutiveFailures = 0;
    openAICircuitOpenUntil = 0;
}

function recordOpenAIFailure() {
    openAIConsecutiveFailures++;
    if (openAIConsecutiveFailures >= OPENAI_FAILURE_THRESHOLD) {
        openAICircuitOpenUntil = Date.now() + OPENAI_CIRCUIT_DURATION_MS;
        openAIConsecutiveFailures = 0; // reset counter after tripping
    }
}

const sleep = (ms: number): Promise<void> => new Promise((res) => setTimeout(res, ms));

export async function POST(req: NextRequest): Promise<Response> {
    const start = Date.now();
    try {
        const authHeader = req.headers.get('authorization');
        if (!authHeader?.startsWith('Bearer ')) {
            recordError('chat/customer/stream', '4xx_user');
            recordRouteLatency('chat/customer/stream', Date.now() - start);
            return new Response('Unauthorized', { status: 401 });
        }
        const idToken = authHeader.split(' ')[1];
        const decoded = await adminAuth.verifyIdToken(idToken);
        const uid = decoded.uid;

        const body = await req.json().catch(() => ({}));
        const { message, sessionId, url, teamId } = body as { message?: string; sessionId?: string; url?: string; teamId?: string };
        if (teamId) {
            try { await enforceTeamRateLimit(adminDb, teamId, { routeKey: 'chat/customer/stream' }); } catch (e: unknown) {
                if (e instanceof TeamRateLimitError) {
                    recordRateLimitRejection('chat/customer/stream');
                    recordRateLimitRejection(`team:${teamId}`);
                    recordRouteLatency('chat/customer/stream', Date.now() - start);
                    return new Response(JSON.stringify({ error: 'rate_limited', retryAfter: e.retryAfterSeconds }), { status: 429, headers: { 'Retry-After': String(e.retryAfterSeconds) } });
                }
            }
        }
        if (!message?.trim()) {
            recordError('chat/customer/stream', '4xx_user');
            recordRouteLatency('chat/customer/stream', Date.now() - start);
            return NextResponse.json({ error: 'Message required' }, { status: 400 });
        }

        const openaiKey = process.env.OPENAI_API_KEY; // may be absent; we will fallback
        const tier = await getUserTier(uid);
        const systemPrompt = `You are RankPilot AI (tier:${tier}). Provide concise, actionable SEO assistance. Use markdown. Also output a hidden JSON control block at the END of your response inside <rp_meta></rp_meta> tags with keys: intent(one of performance|keyword_strategy|structured_data|technical_seo|competitor|content_optimization|general), actions(string[] max 5 short imperatives), priority(integer 1-5).`;

        // Determine session early to fetch memory
        let currentSessionId = sessionId || '';
        if (!currentSessionId) {
            const latest = await adminDb.collection('chatLogs').doc(uid).collection('sessions')
                .orderBy('lastActivity', 'desc').limit(1).get();
            if (latest.empty) {
                currentSessionId = `session_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`;
            } else {
                currentSessionId = latest.docs[0].id;
            }
        }
        // Load session memory summary/pending actions/keywords
        let memoryBlock = '';
        try {
            const sessDoc = await adminDb.collection('chatLogs').doc(uid).collection('sessions').doc(currentSessionId).get();
            if (sessDoc.exists) {
                const sData = sessDoc.data() as { sessionSummary?: string; pendingActions?: string[]; keywords?: string[] } | undefined;
                if (sData?.sessionSummary) memoryBlock += `\nConversation Memory Summary:\n${sData.sessionSummary}`;
                if (Array.isArray(sData?.pendingActions) && sData!.pendingActions!.length) memoryBlock += `\nPending Actions:\n- ${sData!.pendingActions!.slice(0, 8).join('\n- ')}`;
                if (Array.isArray(sData?.keywords) && sData!.keywords!.length) memoryBlock += `\nFocus Keywords: ${sData!.keywords!.slice(0, 5).join(', ')}`;
            }
        } catch { /* ignore */ }

        // Enforce daily message quota prior to token spend
        try { await checkAndIncrementMessageQuota(uid, tier); } catch (qErr: unknown) {
            recordError('chat/customer/stream', '4xx_user');
            recordRouteLatency('chat/customer/stream', Date.now() - start);
            return NextResponse.json({ error: (qErr as any)?.message || 'Quota exceeded' }, { status: 429 });
        }

        // Retrieval augmentation (if embeddings enabled)
        let retrievalBlock = '';
        let siteBlock = '';
        if (process.env.RANKPILOT_ENABLE_EMBEDDINGS === '1') {
            try {
                const qEmb = await buildQueryEmbedding(openaiKey || '', message);
                if (qEmb) {
                    const similar = await retrieveSimilarMessages({ uid, sessionId: currentSessionId, queryEmbedding: qEmb, topK: 3 });
                    if (similar.length) {
                        retrievalBlock = '\nRelevant Prior Exchanges (use insights, avoid repetition):\n' + similar.map(s => `Q: ${s.question}\nA: ${s.response.slice(0, 400)}`).join('\n---\n');
                    }
                    try {
                        const siteChunksResult = await retrieveSiteChunks({ uid, queryEmbedding: qEmb, topK: 4 });
                        const siteChunks = siteChunksResult.chunks || [];
                        if (siteChunks.length) {
                            siteBlock = '\nSite Knowledge Snippets (cite if used, prefer higher score):\n' + siteChunks.map((c: SiteChunk) => `• (${c.score.toFixed(2)}) ${c.meta?.title ? c.meta.title + ' - ' : ''}${c.content.slice(0, 260)}`).join('\n');
                        }
                    } catch { /* ignore site retrieval errors */ }
                }
            } catch { /* ignore retrieval errors */ }
        }
        // Token guard for context additions
        const MAX_CONTEXT_TOKENS = 900;
        function approxTokens(str: string) { return Math.ceil(str.split(/\s+/).length * 1.3); }
        let combined = `${memoryBlock}${siteBlock}${retrievalBlock}`;
        let totalTokens = approxTokens(combined);
        if (totalTokens > MAX_CONTEXT_TOKENS) {
            const segments: Array<{ label: string; value: string }> = [
                { label: 'memory', value: memoryBlock },
                { label: 'site', value: siteBlock },
                { label: 'retrieval', value: retrievalBlock }
            ];
            let kept = '';
            let used = 0;
            for (const seg of segments) {
                const segTokens = approxTokens(seg.value);
                if (!seg.value) continue;
                if (used + segTokens <= MAX_CONTEXT_TOKENS * 0.96) {
                    kept += seg.value;
                    used += segTokens;
                } else {
                    const remaining = Math.floor((MAX_CONTEXT_TOKENS * 0.96) - used);
                    if (remaining > 40) {
                        const words = seg.value.split(/\s+/).slice(0, Math.floor(remaining / 1.3));
                        kept += words.join(' ');
                    }
                    break;
                }
            }
            combined = kept;
        }
        const finalSystemPrompt = combined
            ? `${systemPrompt}${combined}\nIntegrate memory + site knowledge + prior dialog context. Avoid redundancy; cite site snippets when used.`
            : systemPrompt;

        let openAIStream: AsyncIterable<{ choices?: Array<{ delta?: { content?: string } }> }> | null = null;
        let provider: 'openai' | 'gemini' = 'gemini';
        if (openaiKey && !openAICircuitOpen()) {
            const maxAttempts = 3;
            for (let attempt = 0; attempt < maxAttempts; attempt++) {
                try {
                    const openai = new OpenAI({ apiKey: openaiKey });
                    openAIStream = (await openai.chat.completions.create({
                        model: 'gpt-4o-mini',
                        messages: [
                            { role: 'system', content: finalSystemPrompt },
                            { role: 'user', content: message }
                        ],
                        temperature: 0.2,
                        max_tokens: 800,
                        stream: true,
                    })) as unknown as AsyncIterable<{ choices?: Array<{ delta?: { content?: string } }> }>;
                    provider = 'openai';
                    recordOpenAISuccess();
                    break;
                } catch (e) {
                    recordOpenAIFailure();
                    if (attempt < maxAttempts - 1) {
                        const delay = 100 * Math.pow(3, attempt); // 100, 300, 900
                        await sleep(delay);
                        continue;
                    }
                }
            }
        }
        if (!openAIStream) {
            provider = 'gemini';
        }

        // Record fallback if provider not OpenAI (either key missing, circuit open, or failures)
        if (provider !== 'openai') {
            const reason = openAICircuitOpen() ? 'circuit_open' : (openaiKey ? 'openai_failure' : 'no_openai_key');
            recordFallback(reason);
        }

        const encoder = new TextEncoder();
        const readable = new ReadableStream({
            async start(controller) {
                let fullResponse = '';
                let metaBuffer = '';
                let tokensUsed = 0;
                try {
                    // Emit provider info early
                    controller.enqueue(encoder.encode(`data: ${JSON.stringify(enforceProvenanceOnChunk({ info: 'provider_selected', provider, openaiCircuitOpen: openAICircuitOpen(), provenance: provider === 'openai' ? 'live' : 'synthetic' }, { path: 'chat/customer/stream' }))}\n\n`));
                    if (openAIStream) {
                        for await (const part of openAIStream) {
                            const content = part?.choices?.[0]?.delta?.content;
                            if (content) {
                                fullResponse += content;
                                controller.enqueue(encoder.encode(`data: ${JSON.stringify({ token: content, provenance: provider === 'openai' ? 'live' : 'synthetic' })}\n\n`));
                            }
                        }
                    } else {
                        // One-shot fallback (non-streaming)
                        fullResponse = await fallbackOneShot(finalSystemPrompt, message, 800);
                        controller.enqueue(encoder.encode(`data: ${JSON.stringify({ token: fullResponse, fallback: true, provenance: 'synthetic' })}\n\n`));
                    }
                    // Persist conversation to Firestore
                    try {
                        tokensUsed = estimateTokens(fullResponse);
                        let intent: string | undefined; let actions: string[] | undefined; let priority: number | undefined;
                        const metaMatch = fullResponse.match(/<rp_meta>([\s\S]*?)<\/rp_meta>/);
                        if (metaMatch) {
                            metaBuffer = metaMatch[1];
                            try {
                                const parsed = JSON.parse(metaBuffer.trim());
                                intent = parsed.intent;
                                actions = Array.isArray(parsed.actions) ? parsed.actions.slice(0, 5) : undefined;
                                priority = typeof parsed.priority === 'number' ? parsed.priority : undefined;
                                fullResponse = fullResponse.replace(metaMatch[0], '').trim();
                            } catch { /* ignore */ }
                        }
                        await incrementTokenUsage(uid, tier, tokensUsed);
                        const msgCollection = adminDb.collection('chatLogs').doc(uid).collection('sessions').doc(currentSessionId).collection('messages');
                        const addedRef = await msgCollection.add({
                            question: message,
                            response: fullResponse,
                            timestamp: FieldValue.serverTimestamp(),
                            tokensUsed,
                            chatType: 'customer',
                            metadata: { streamed: true, url: url || null, intent, actions, priority, provider, fallback: provider !== 'openai', openaiCircuitOpen: openAICircuitOpen() }
                        });
                        await adminDb.collection('chatLogs').doc(uid).collection('sessions').doc(currentSessionId).set({
                            lastMessage: fullResponse.slice(0, 100),
                            lastActivity: FieldValue.serverTimestamp(),
                            messageCount: FieldValue.increment(1),
                            chatType: 'customer',
                            lastProvider: provider,
                            lastProviderAt: FieldValue.serverTimestamp(),
                            openAICircuitOpen: openAICircuitOpen()
                        }, { merge: true });
                        // Provider usage analytics (per-day doc)
                        try {
                            const dateKey = new Date().toISOString().slice(0, 10);
                            await adminDb.collection('usageCounters').doc(`${uid}_${dateKey}`).set({ [`providerCounts.${provider}`]: FieldValue.increment(1) }, { merge: true });
                        } catch { }
                        maybeSummarizeSession({ uid, sessionId: currentSessionId, latestUserMessage: message, latestAIResponse: fullResponse })
                            .then(r => { if (r.updated) { controller.enqueue(encoder.encode(`data: ${JSON.stringify({ info: 'summary_updated' })}\n\n`)); } })
                            .catch(() => { });
                        maybeEmbedMessage({ uid, sessionId: currentSessionId, messageDocId: addedRef.id, question: message })
                            .then(() => openaiKey ? maybeClusterKeywords({ uid, sessionId: currentSessionId, apiKey: openaiKey }).catch(() => { }) : null)
                            .catch(() => { });
                    } catch { /* ignore persistence errors */ }
                    controller.enqueue(encoder.encode(`data: ${JSON.stringify(enforceProvenanceOnChunk({ final: true, sessionId: currentSessionId, timestamp: new Date().toISOString(), tokensUsed, provider, fallback: provider !== 'openai', openaiCircuitOpen: openAICircuitOpen(), provenance: provider === 'openai' ? 'live' : 'synthetic' }, { path: 'chat/customer/stream' }))}\n\n`));
                    controller.enqueue(encoder.encode('data: [DONE]\n\n'));
                    controller.close();
                } catch (e: unknown) {
                    recordError('chat/customer/stream', '5xx_server');
                    controller.enqueue(encoder.encode(`data: ${JSON.stringify(enforceProvenanceOnChunk({ error: e instanceof Error ? e.message : String(e ?? 'stream_error'), providerTried: provider, openaiCircuitOpen: openAICircuitOpen(), provenance: 'synthetic' }, { path: 'chat/customer/stream' }))}\n\n`));
                    controller.enqueue(encoder.encode('data: [DONE]\n\n'));
                    controller.close();
                }
            }
        });

        const response = new Response(readable, {
            headers: {
                'Content-Type': 'text/event-stream',
                'Cache-Control': 'no-cache, no-transform',
                'Connection': 'keep-alive',
                'Transfer-Encoding': 'chunked'
            }
        });
        recordRouteLatency('chat/customer/stream', Date.now() - start);
        return response;
    } catch (e: unknown) {
        recordError('chat/customer/stream', '5xx_server');
        recordRouteLatency('chat/customer/stream', Date.now() - start);
        return NextResponse.json({ error: e instanceof Error ? e.message : String(e ?? 'Stream init failed') }, { status: 500 });
    }
}

import { NextResponse } from "next/server";
import { db } from "@/lib/firebase/index";
import {
  collection,
  getDocs,
  doc,
  writeBatch,
} from "firebase/firestore";

// Define types for better type safety
interface UserQuotas {
  monthlyAnalyses: number;
  keywordTracking: number;
  competitorTracking: number;
  used?: {
    monthlyAnalyses: number;
    keywordTracking: number;
    competitorTracking: number;
  };
  resetDate?: Date;
  lastUpdated?: Date;
}

interface UserData {
  email?: string;
  subscriptionTier?: string;
  quotas?: UserQuotas;
  role?: string;
  plan?: string;
  planType?: string;
  dataCleanupDate?: Date;
  cleanupVersion?: string;
  isTestUser?: boolean;
  [key: string]: unknown; // Allow additional properties
}

type TierType = "free" | "starter" | "agency" | "enterprise" | "admin";
type RoleType = "free" | "starter" | "agency" | "enterprise" | "admin" | "user";

// Define expected quotas for each tier
const TIER_QUOTAS: Record<TierType, UserQuotas> = {
  free: { monthlyAnalyses: 3, keywordTracking: 10, competitorTracking: 3 },
  starter: { monthlyAnalyses: 20, keywordTracking: 50, competitorTracking: 10 },
  agency: {
    monthlyAnalyses: 100,
    keywordTracking: 200,
    competitorTracking: 25,
  },
  enterprise: {
    monthlyAnalyses: 500,
    keywordTracking: 1000,
    competitorTracking: 100,
  },
  admin: { monthlyAnalyses: -1, keywordTracking: -1, competitorTracking: -1 }, // unlimited
};

// Role-to-tier mapping for cleanup
const ROLE_TO_TIER_MAP: Record<RoleType, TierType> = {
  free: "free",
  starter: "starter",
  agency: "agency",
  enterprise: "enterprise",
  admin: "admin",
  user: "free", // default user role maps to free tier
};

interface CleanupResults {
  totalUsers: number;
  quotasFixed: number;
  tiersFixed: number;
  rolesFixed: number;
  testUsersIdentified: number;
  productionUsers: number;
  errors: string[];
}

// Test user patterns to identify
const TEST_USER_PATTERNS = [
  "@test.com",
  "@rankpilot.com",
  "test.com",
  "abc.com",
  ".user1@",
  "admin.",
  "starter.",
  "agency.",
  "enterprise.",
  "free.",
];

export async function POST(): Promise<NextResponse> {
  try {
    console.log("🚨 Starting comprehensive user data cleanup...");

    const usersSnapshot = await getDocs(collection(db, "users"));
    const cleanupResults: CleanupResults = {
      totalUsers: usersSnapshot.docs.length,
      quotasFixed: 0,
      tiersFixed: 0,
      rolesFixed: 0,
      testUsersIdentified: 0,
      productionUsers: 0,
      errors: [],
    };

    const batch = writeBatch(db);
    let batchCount = 0;

    for (const userDoc of usersSnapshot.docs) {
      const userId = userDoc.id;
      const userData = userDoc.data() as UserData;
      const userRef = doc(db, "users", userId);

      // Identify if this is a test user
      const isTestUser = TEST_USER_PATTERNS.some((pattern) =>
        (userData.email || "").includes(pattern)
      );

      if (isTestUser) {
        cleanupResults.testUsersIdentified++;
      } else {
        cleanupResults.productionUsers++;
      }

      const updates: Partial<UserData> = {};
      let needsUpdate = false;

      // 1. Fix empty/null subscription tiers
      let subscriptionTier = userData.subscriptionTier;
      if (!subscriptionTier || subscriptionTier.trim() === "") {
        // If user has a role, map it to tier
        if (userData.role && userData.role in ROLE_TO_TIER_MAP) {
          subscriptionTier = ROLE_TO_TIER_MAP[userData.role as RoleType];
        } else {
          subscriptionTier = "free"; // default
        }
        updates.subscriptionTier = subscriptionTier;
        cleanupResults.tiersFixed++;
        needsUpdate = true;
      }

      // 2. Initialize missing quotas based on tier
      if (!userData.quotas) {
        const tierKey = subscriptionTier as TierType;
        const expectedQuotas = TIER_QUOTAS[tierKey] || TIER_QUOTAS.free;
        updates.quotas = {
          ...expectedQuotas,
          used: {
            monthlyAnalyses: 0,
            keywordTracking: 0,
            competitorTracking: 0,
          },
          resetDate: new Date(),
          lastUpdated: new Date(),
        };
        cleanupResults.quotasFixed++;
        needsUpdate = true;
      } else {
        // Update existing quotas to match tier if they don't match
        const tierKey = subscriptionTier as TierType;
        const expectedQuotas = TIER_QUOTAS[tierKey] || TIER_QUOTAS.free;
        const currentQuotas = userData.quotas;

        let quotasNeedUpdate = false;
        const updatedQuotas = { ...currentQuotas };

        Object.keys(expectedQuotas).forEach((quotaKey) => {
          const key = quotaKey as keyof UserQuotas;
          if (
            currentQuotas[key] !== expectedQuotas[key] &&
            typeof currentQuotas[key] === "number" &&
            typeof expectedQuotas[key] === "number"
          ) {
            (updatedQuotas as any)[key] = expectedQuotas[key];
            quotasNeedUpdate = true;
          }
        });

        if (quotasNeedUpdate) {
          updatedQuotas.lastUpdated = new Date();
          updates.quotas = updatedQuotas;
          cleanupResults.quotasFixed++;
          needsUpdate = true;
        }
      }

      // 3. Fix role field inconsistencies
      if (userData.role && userData.role !== subscriptionTier) {
        // For test users, align role with tier
        if (isTestUser) {
          updates.role = subscriptionTier;
          cleanupResults.rolesFixed++;
          needsUpdate = true;
        } else {
          // For production users, remove inconsistent role field
          updates.role = subscriptionTier;
          cleanupResults.rolesFixed++;
          needsUpdate = true;
        }
      } else if (!userData.role) {
        // Add missing role field
        updates.role = subscriptionTier;
        cleanupResults.rolesFixed++;
        needsUpdate = true;
      }

      // 4. Remove conflicting plan/planType fields if they exist
      if (userData.plan && userData.plan !== subscriptionTier) {
        updates.plan = subscriptionTier;
        needsUpdate = true;
      }

      if (userData.planType && userData.planType !== subscriptionTier) {
        updates.planType = subscriptionTier;
        needsUpdate = true;
      }

      // 5. Add metadata for tracking
      if (needsUpdate) {
        updates.dataCleanupDate = new Date();
        updates.cleanupVersion = "2025-07-25-tier-consistency";
        updates.isTestUser = isTestUser;

        batch.update(userRef, updates);
        batchCount++;

        // Commit batch every 500 operations to avoid limits
        if (batchCount >= 500) {
          await batch.commit();
          batchCount = 0;
        }
      }
    }

    // Commit any remaining operations
    if (batchCount > 0) {
      await batch.commit();
    }

    return NextResponse.json({
      success: true,
      results: cleanupResults,
      message: "User data cleanup completed successfully",
      recommendations: {
        testUserCleanup: `${cleanupResults.testUsersIdentified} test users identified - consider moving to separate environment`,
        monitoringSetup:
          "Set up quota monitoring to prevent future inconsistencies",
        tierValidation:
          "Implement tier validation on user registration/updates",
      },
    });
  } catch (error) {
    console.error("Error during user cleanup:", error);
    const errorMessage =
      error instanceof Error ? error.message : "Unknown error occurred";
    return NextResponse.json(
      {
        success: false,
        error: errorMessage,
        recommendation: "Review Firebase security rules and retry cleanup",
      },
      { status: 500 }
    );
  }
}

import type { NextRequest } from 'next/server';
import { NextResponse } from 'next/server';
import { adminDb } from '@/lib/firebase-admin';

export const dynamic = 'force-dynamic';

export async function POST(_req: NextRequest): Promise<NextResponse> {
  if (process.env.NODE_ENV === 'production' || process.env.CI_PRODUCTION === '1') {
    return NextResponse.json({ ok: false, reason: 'disabled' }, { status: 404 });
  }

  const today = new Date().toISOString().slice(0, 10);
  const ref = adminDb.collection('kpiDaily').doc(today);

  try {
    await adminDb.runTransaction(async (tx) => {
      const snap = await tx.get(ref);
      if (snap.exists) return; // no-op if already seeded

      const doc: Record<string, unknown> = {
        date: today,
        provenanceCoveragePct: 95,
        p95LatencyOverall: 450,
        crawlerAggregateAdoptionPct: 70,
        semanticMapAggregateAdoptionPct: 68,
        aiCostEstimate: 1.23,
        createdAt: new Date(),
        updatedAt: new Date(),
        // Provide initial smoothing = metric values so deltas start at 0
        smoothedProvenance: 95,
        smoothedLatencyP95: 450,
        smoothedCrawlerAdoption: 70,
        smoothedSemanticAdoption: 68,
        // Include MA7 fields mirroring values for immediate delta badge availability
        ma7Provenance: 95,
        ma7LatencyP95: 450,
        ma7CrawlerAdoption: 70,
        ma7SemanticAdoption: 68,
      };

      // Use a narrow any cast only for the Firestore write to satisfy the client typings.
      tx.set(ref, doc as any);
    });

    return NextResponse.json({ ok: true, seeded: true, date: today });
  } catch (e: unknown) {
    const message = (e as Error)?.message ?? 'seed_failed';
    return NextResponse.json({ ok: false, error: message }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import { collection, query, limit, getDocs } from 'firebase/firestore';
import { db } from '@/lib/firebase';

// Dev-only diagnostics endpoint: validates current user Firestore read access for key collections
// Returns status per collection; avoid exposing data (only sizes / error codes)
export async function GET() {
    if (process.env.NODE_ENV !== 'development') {
        return NextResponse.json({ error: 'Not available in production' }, { status: 403 });
    }
    const targets = [
        'financeInvoices',
        'marketingCampaigns',
        'salesDeals',
        'contentBriefs',
        'seoAudits',
        'neuroSeoAnalyses',
        'linkAnalyses'
    ];
    const results: Record<string, unknown> = {};
    for (const colName of targets) {
        try {
            const q = query(collection(db, colName), limit(1));
            const snap = await getDocs(q);
            results[colName] = { ok: true, count: snap.size };
        } catch (e: unknown) {
            const err = e as any;
            results[colName] = { ok: false, error: err?.code || err?.message };
        }
    }
    return NextResponse.json({ ts: new Date().toISOString(), results });
}

import type { NextRequest } from 'next/server';
import { adminAuth, adminDb } from '@/lib/firebase-admin';
import { generateInsights as aiGenerateInsights } from '@/ai/flows/generate-insights';
import { enforceProvenanceOnChunk } from '@/lib/middleware/provenance';

export const dynamic = 'force-dynamic';
export const runtime = 'nodejs';

interface ActivityLite { type: string; tool: string; details?: unknown; resultsSummary?: string; }

async function fetchRecentActivities(uid: string, limit = 25): Promise<ActivityLite[]> {
    try {
        const colRef = adminDb.collection('users').doc(uid).collection('activities');
        const snap = await colRef.orderBy('timestamp', 'desc').limit(limit).get();
        return snap.docs.map((d) => {
            const data = d.data() as Record<string, unknown> | undefined;
            return {
                type: typeof data?.['type'] === 'string' ? (data?.['type'] as string) : 'unknown',
                tool: typeof data?.['tool'] === 'string' ? (data?.['tool'] as string) : 'unknown',
                details: data?.details,
                resultsSummary:
                  typeof data?.['resultsSummary'] === 'string' ? (data?.['resultsSummary'] as string) : undefined,
            };
        });
    } catch (e: unknown) {
        // On any failure return an empty list (caller handles empty state)
        return [];
    }
}

export async function GET(req: NextRequest) {
    const authHeader = req.headers.get('authorization');
    if (!authHeader?.startsWith('Bearer ')) {
        return new Response('Unauthorized', { status: 401 });
    }
    try {
        const idToken = authHeader.split(' ')[1];
        const decoded = await adminAuth.verifyIdToken(idToken);
        const uid = decoded.uid;

        const activities = await fetchRecentActivities(uid);

        const encoder = new TextEncoder();
        const stream = new ReadableStream<Uint8Array>({
            async start(controller: ReadableStreamDefaultController<Uint8Array>) {
                let closed = false;
                const safeEnqueue = (chunk: string) => {
                    if (closed) return;
                    try {
                        controller.enqueue(encoder.encode(chunk));
                    } catch {
                        closed = true;
                        try {
                            controller.close();
                        } catch {
                            // ignore close errors
                        }
                    }
                };
                const safeClose = () => {
                    if (closed) return;
                    closed = true;
                    try {
                        controller.close();
                    } catch {
                        // ignore close errors
                    }
                };
                const send = (obj: Record<string, unknown>, note?: string) => {
                    const payload = enforceProvenanceOnChunk(obj, { path: 'insights/stream', note });
                    safeEnqueue(`data: ${JSON.stringify(payload)}\n\n`);
                };
                send({ type: 'init', activityCount: activities.length, provenance: 'live' });

                // If no activities, end early
                if (!activities.length) {
                    send({ type: 'final', insights: [], provenance: 'live' });
                    safeEnqueue('data: [DONE]\n\n');
                    safeClose();
                    return;
                }

                // Emit activities in small batches for progressive UI enrichment
                const batchSize = 5;
                for (let i = 0; i < activities.length; i += batchSize) {
                    const batch = activities.slice(i, i + batchSize);
                    send({ type: 'activity_batch', batch });
                    await new Promise((resolve) => setTimeout(resolve, 120));
                }

                // Run AI flow (non-stream) then emit each insight one by one
                try {
                    const aiResult = await aiGenerateInsights({ activities: activities.slice(0, 20) });
                    for (const insight of aiResult.insights) {
                        send({ type: 'insight', insight });
                        await new Promise((resolve) => setTimeout(resolve, 80));
                    }
                    send({ type: 'final', total: aiResult.insights.length });
                } catch (e: unknown) {
                    const msg = e instanceof Error ? e.message : String(e);
                    send({ type: 'error', message: msg || 'insight_generation_failed', provenance: 'synthetic' });
                } finally {
                    safeEnqueue('data: [DONE]\n\n');
                    safeClose();
                }
            }
        });

        const res = new Response(stream, {
            headers: {
                'Content-Type': 'text/event-stream',
                'Cache-Control': 'no-cache, no-transform',
                Connection: 'keep-alive',
            },
        });
        // Abort handling (only if request supports signal)
        const signal = (req as unknown as { signal?: AbortSignal }).signal;
        if (signal) {
            signal.addEventListener('abort', () => {
                // stream will naturally end on client disconnect
            });
        }
        return res;
    } catch (e: unknown) {
        const msg = e instanceof Error ? e.message : String(e);
        const payload = enforceProvenanceOnChunk(
            { error: msg || 'stream_init_failed', provenance: 'synthetic' },
            { path: 'insights/stream', note: 'init-failure' }
        );
        return new Response(JSON.stringify(payload), { status: 500 });
    }
}

/**
 * Competitive Intelligence API Route
 * Handles competitor tracking and analysis via Firecrawl MCP
 */

import { extractErrorMessage } from '@/lib/errors/extract-error-message';
import { firecrawlCompetitiveIntelligence } from '@/lib/intelligence/firecrawl-competitive-intelligence';
import { enforceProvenance, withProvenance } from '@/lib/middleware/provenance';
import { getApps, initializeApp } from 'firebase-admin/app';
import { getAuth } from 'firebase-admin/auth';
import type { NextRequest } from 'next/server';
import { NextResponse } from 'next/server';

// Initialize Firebase Admin if not already initialized
if (!getApps().length) {
    const projectId = process.env.FIREBASE_PROJECT_ID || 'rankpilot-h3jpc';

    try {
        initializeApp({
            projectId,
        });
    } catch (error) {
        console.error('[CompetitiveIntelligenceAPI] Firebase Admin initialization error:', error);
    }
}

interface CompetitorRequestBody {
    action: 'add' | 'analyze' | 'list' | 'update' | 'delete' | 'report' | 'get';
    competitorId?: string;
    domain?: string;
    name?: string;
    industry?: string;
    targetKeywords?: string[];
    trackingConfig?: unknown;
    reportConfig?: {
        competitorIds: string[];
        analysisType: 'overview' | 'keyword-gap' | 'content-gap' | 'technical' | 'comprehensive';
    };
}

export const POST = withProvenance(async function POST(request: NextRequest) {
    const nreq = request;
    try {
        const authHeader = nreq.headers.get('authorization');
        if (!authHeader?.startsWith('Bearer ')) {
            return NextResponse.json(enforceProvenance({ success: false, error: 'Missing or invalid authorization header', provenance: 'synthetic' }, { path: 'intelligence/competitive', note: 'auth' }), { status: 401 });
        }

        const token = authHeader.split('Bearer ')[1];
        const auth = getAuth();

        let decodedToken: { uid: string; tier?: string } | null = null;
        try {
            decodedToken = await auth.verifyIdToken(token) as { uid: string; tier?: string };
        } catch (error) {
            console.error('[CompetitiveIntelligenceAPI] Token verification error:', error);
            return NextResponse.json(enforceProvenance({ success: false, error: 'Invalid authentication token', provenance: 'synthetic' }, { path: 'intelligence/competitive', note: 'auth' }), { status: 401 });
        }

        const userId = decodedToken!.uid;
        const userTier = decodedToken!.tier || 'free';

        // Check tier access for competitive intelligence
        if (!['agency', 'enterprise', 'admin'].includes(userTier)) {
            return NextResponse.json(enforceProvenance({ success: false, error: 'Competitive intelligence requires Agency tier or higher', provenance: 'synthetic' }, { path: 'intelligence/competitive', note: 'tier' }), { status: 403 });
        }

        const body: CompetitorRequestBody = await nreq.json();

        // Narrow trackingConfig if present
        const tc = body.trackingConfig;
        const trackingConfig = (tc && typeof tc === 'object' && 'crawlFrequency' in tc)
            ? {
                crawlFrequency: (tc as any).crawlFrequency as 'daily' | 'weekly' | 'monthly',
                pages: Array.isArray((tc as any).pages) ? (tc as any).pages as string[] : [],
                metrics: Array.isArray((tc as any).metrics) ? (tc as any).metrics as any[] : [],
                alertThresholds: (typeof (tc as any).alertThresholds === 'object' && (tc as any).alertThresholds)
                    ? (tc as any).alertThresholds as Record<string, number>
                    : {}
            }
            : undefined;

        switch (body.action) {
            case 'add':
                if (!body.domain) {
                    return NextResponse.json(enforceProvenance({ success: false, error: 'Domain is required for adding competitor', provenance: 'synthetic' }, { path: 'intelligence/competitive', note: 'validation' }), { status: 400 });
                }

                const competitor = await firecrawlCompetitiveIntelligence.addCompetitor(
                    userId,
                    body.domain,
                    {
                        name: body.name,
                        industry: body.industry,
                        targetKeywords: body.targetKeywords,
                        trackingConfig
                    }
                );

                return NextResponse.json(enforceProvenance({ success: true, competitor: { id: competitor.id, domain: competitor.domain, name: competitor.name, industry: competitor.industry, created: competitor.metadata.created }, provenance: 'live' }, { path: 'intelligence/competitive', note: 'add' }));

            case 'analyze':
                if (!body.competitorId) {
                    return NextResponse.json(enforceProvenance({ success: false, error: 'Competitor ID is required for analysis', provenance: 'synthetic' }, { path: 'intelligence/competitive', note: 'validation' }), { status: 400 });
                }

                await firecrawlCompetitiveIntelligence.analyzeCompetitor(body.competitorId);

                return NextResponse.json(enforceProvenance({ success: true, message: 'Analysis completed successfully', provenance: 'live' }, { path: 'intelligence/competitive', note: 'analyze' }));

            case 'list':
                const userCompetitors = firecrawlCompetitiveIntelligence.getUserCompetitors(userId);

                return NextResponse.json(enforceProvenance({ success: true, competitors: userCompetitors.map(c => ({ id: c.id, domain: c.domain, name: c.name, industry: c.industry, trackingFrequency: c.trackingConfig.crawlFrequency, lastAnalysis: c.lastAnalysis ? { timestamp: c.lastAnalysis.timestamp, status: c.lastAnalysis.status, changesCount: c.lastAnalysis.changes.length } : null, analysisCount: c.metadata.analysisCount, created: c.metadata.created })), provenance: 'live' }, { path: 'intelligence/competitive', note: 'list' }));

            case 'update':
                if (!body.competitorId) {
                    return NextResponse.json(enforceProvenance({ success: false, error: 'Competitor ID is required for update', provenance: 'synthetic' }, { path: 'intelligence/competitive', note: 'validation' }), { status: 400 });
                }

                const updated = firecrawlCompetitiveIntelligence.updateCompetitor(
                    body.competitorId,
                    {
                        name: body.name,
                        industry: body.industry,
                        targetKeywords: body.targetKeywords,
                        trackingConfig
                    }
                );

                if (!updated) {
                    return NextResponse.json(enforceProvenance({ success: false, error: 'Competitor not found or update failed', provenance: 'synthetic' }, { path: 'intelligence/competitive', note: 'not_found' }), { status: 404 });
                }

                return NextResponse.json(enforceProvenance({ success: true, message: 'Competitor updated successfully', provenance: 'live' }, { path: 'intelligence/competitive', note: 'update' }));

            case 'delete':
                if (!body.competitorId) {
                    return NextResponse.json(enforceProvenance({ success: false, error: 'Competitor ID is required for deletion', provenance: 'synthetic' }, { path: 'intelligence/competitive', note: 'validation' }), { status: 400 });
                }

                const deleted = firecrawlCompetitiveIntelligence.deleteCompetitor(body.competitorId, userId);

                if (!deleted) {
                    return NextResponse.json(enforceProvenance({ success: false, error: 'Competitor not found or deletion failed', provenance: 'synthetic' }, { path: 'intelligence/competitive', note: 'not_found' }), { status: 404 });
                }

                return NextResponse.json(enforceProvenance({ success: true, message: 'Competitor deleted successfully', provenance: 'live' }, { path: 'intelligence/competitive', note: 'delete' }));

            case 'report':
                if (!body.reportConfig?.competitorIds || body.reportConfig.competitorIds.length === 0) {
                    return NextResponse.json(enforceProvenance({ success: false, error: 'Competitor IDs are required for report generation', provenance: 'synthetic' }, { path: 'intelligence/competitive', note: 'validation' }), { status: 400 });
                }

                const report = await firecrawlCompetitiveIntelligence.generateCompetitiveReport(
                    userId,
                    body.reportConfig.competitorIds,
                    body.reportConfig.analysisType || 'comprehensive'
                );

                return NextResponse.json(enforceProvenance({ success: true, report: { id: report.id, competitors: report.competitors, analysisType: report.analysisType, timeframe: report.timeframe, findings: { opportunitiesCount: report.findings.opportunities.length, threatsCount: report.findings.threats.length, insightsCount: report.findings.insights.length, recommendationsCount: report.findings.recommendations.length }, metadata: report.metadata }, downloadUrl: `/api/intelligence/competitive/download/${report.id}`, provenance: 'live' }, { path: 'intelligence/competitive', note: 'report' }));

            case 'get':
                if (!body.competitorId) {
                    return NextResponse.json(enforceProvenance({ success: false, error: 'Competitor ID is required', provenance: 'synthetic' }, { path: 'intelligence/competitive', note: 'validation' }), { status: 400 });
                }

                const competitorData = firecrawlCompetitiveIntelligence.getCompetitor(body.competitorId);

                if (!competitorData || competitorData.metadata.userId !== userId) {
                    return NextResponse.json(enforceProvenance({ success: false, error: 'Competitor not found', provenance: 'synthetic' }, { path: 'intelligence/competitive', note: 'not_found' }), { status: 404 });
