import { extractErrorMessage } from '@/lib/errors/extract-error-message';
import { enforceProvenance, withProvenance } from '@/lib/middleware/provenance';
import { AIVisibilityEngine } from '@/lib/neuroseo/ai-visibility-engine';
import { NextResponse } from 'next/server';

// Lightweight in-memory cache to reduce repeated analyses during a short window
const cache = new Map<string, { ts: number; data: unknown }>();
const TTL_MS = 1000 * 60 * 5; // 5 minutes

export const POST = withProvenance(async function POST(req: Request) {
    try {
        const body = (await req.json().catch(() => ({}))) ?? {};
        const { url, query, targetAudience, analysisType = 'quick', userId } = body;

        if (!url || !query) {
            return NextResponse.json({ error: 'Missing url or query' }, { status: 400 });
        }

        const cacheKey = `${url}|${query}|${analysisType}`;
        const cached = cache.get(cacheKey);
        if (cached && Date.now() - cached.ts < TTL_MS) {
            return NextResponse.json(cached.data);
        }

        const engine = new AIVisibilityEngine();
        // Reuse engine API: treat single query as targetKeyword list of length 1
        const report = await engine.analyzeVisibility(url, [query], []);

        // Derive simplified shape expected by client page
        const score = Math.round(report.metrics.overallVisibilityScore);
        const citationRate = report.metrics.citationRate;

        const visibility = report.citations.slice(0, 25).map(c => ({
            citation: {
                platform: (c as any).platform || 'unknown',
                position: (c as any).position ?? 0,
                snippet: (c as any).snippet || '',
                confidence: (c as any).confidence ?? 0,
                url: (c as any).url || url
            },
            optimization: {
                recommendations: (c as any).recommendations?.map((r: any) => r?.description) || [],
                priority: 'medium',
                impact: 50
            }
        }));

        const recommendations = (report.recommendations || []).map((r: any) => r?.description ?? '').filter(Boolean).slice(0, 15);

        const platforms = report.competitiveAnalysis.topCompetitors.slice(0, 8).map(comp => ({
            name: new URL(comp.url).hostname.replace('www.', ''),
            citations: Math.round(comp.citationRate * 10),
            position: Math.max(1, Math.round(100 - comp.visibilityScore)),
            trend: 'stable' as const
        }));

        const responsePayload = enforceProvenance({
            score,
            citationRate,
            visibility,
            recommendations,
            platforms,
            meta: { targetAudience: targetAudience || null, analysisType, userId: userId || null, generatedAt: new Date().toISOString() }
        }, { path: 'neuroseo/ai-visibility' });

        cache.set(cacheKey, { ts: Date.now(), data: responsePayload });
        return NextResponse.json(responsePayload);
    } catch (error: unknown) {
        const errMessage = extractErrorMessage(error);
        console.error('[AI Visibility API] Failure', errMessage);
        return NextResponse.json(
            enforceProvenance({ error: 'Internal server error', details: errMessage }, { path: 'neuroseo/ai-visibility', note: 'error' }),
            { status: 500 }
        );
    }
}, { path: 'neuroseo/ai-visibility' });

import type { NextRequest } from 'next/server';
import { NextResponse } from 'next/server';
import { executeNeuroLive } from '@/lib/neuroseo/live-exec';
import { enforceNeuroSeoRateLimit, NeuroSeoRateLimitError } from '@/lib/neuroseo/rate-limit';
import { enforceTeamRateLimit, TeamRateLimitError } from '@/lib/rate-limit/team-rate-limit';
import { enforceProvenance, withProvenance } from '@/lib/middleware/provenance';
import { getLogger } from '@/lib/logging/app-logger';
import { recordRouteLatency, recordError } from '@/lib/metrics/unified-metrics';

export const dynamic = 'force-dynamic';
const logger = getLogger('neuroseo-live-route');

// Feature gate simple env flag (rolling_out). In future, read FEATURE_KEYS.
const ENABLED = true;

export const POST = withProvenance(async function POST(req: NextRequest) {
    const start = Date.now();
    if (!ENABLED) return NextResponse.json(enforceProvenance({ success: false, error: 'Live backend disabled', provenance: 'synthetic' }, { path: 'neuroseo/live', note: 'feature_gate' }), { status: 503 });
    try {
        let body: unknown = {};
        try {
            body = await req.json();
        } catch {
            body = {};
        }
        const { urls, analysisType, userId, forceRefresh, teamId } = (body as any) || {};
        if (!Array.isArray(urls) || urls.length === 0) {
            return NextResponse.json(enforceProvenance({ success: false, error: 'urls[] required', provenance: 'synthetic' }, { path: 'neuroseo/live', note: 'validation' }), { status: 400 });
        }
        // PERF-01 / TEAM-01: Prefer team-aware limiter when teamId supplied; otherwise fallback to legacy per-user neuroseo limiter for backward compatibility during transition.
        try {
            if (typeof teamId === 'string' && teamId) {
                const { adminDb } = (global as any).adminDb ? { adminDb: (global as any).adminDb } : await import('@/lib/firebase-admin');
                await enforceTeamRateLimit(adminDb, teamId, { routeKey: 'neuroseo/live' });
            } else {
                const scopeId = userId || 'anonymous';
                await enforceNeuroSeoRateLimit((global as any).adminDb || (await import('@/lib/firebase-admin')).adminDb, scopeId, {});
            }
        } catch (e: unknown) {
            if (e instanceof TeamRateLimitError || e instanceof NeuroSeoRateLimitError) {
                const retryAfterSeconds = (e as any)?.retryAfterSeconds || 60;
                return NextResponse.json(enforceProvenance({ success: false, error: 'rate_limited', retryAfter: retryAfterSeconds, provenance: 'synthetic' }, { path: 'neuroseo/live', note: 'rate_limit' }), { status: 429, headers: { 'Retry-After': String(retryAfterSeconds) } });
            }
            throw e;
        }
        const result = await executeNeuroLive({ urls, analysisType, userId: userId || 'anonymous' }, { forceRefresh });
        const resp = NextResponse.json(enforceProvenance({ ...result }, { path: 'neuroseo/live' }), { status: 200 });
        recordRouteLatency('neuroseo/live', Date.now() - start);
        return resp;
    } catch (err: unknown) {
        const errMessage = err instanceof Error ? err.message : String(err);
        logger.error('live.route.error', { message: errMessage });
        recordRouteLatency('neuroseo/live', Date.now() - start);
        recordError('neuroseo/live', '5xx_server');
        return NextResponse.json(enforceProvenance({ error: errMessage || 'analysis failed', provenance: 'synthetic' }, { path: 'neuroseo/live' }), { status: 500 });
    }
}, { path: 'neuroseo/live' });

