import type { NextRequest } from 'next/server';
import { neuroSEOOrchestrator } from '@/lib/neuroseo/enhanced-orchestrator';
import { getLogger } from '@/lib/logging/app-logger';
import { createDeterministicRng, tagSynthetic } from '@/lib/synthetic/synthetic-utils';
import { adminDb } from '@/lib/firebase-admin';
import { CompactAnalysisSchema } from '@/lib/neuroseo/live-exec';
import { recordAnalysisRun, recordCacheHit, recordWorkflowRun, recordWorkflowFailure, recordGuardStrip } from '@/lib/neuroseo/metrics-registry';
import { enforceProvenanceOnChunk } from '@/lib/middleware/provenance';
import { recordRouteLatency, recordFallback, recordCompactDocSize } from '@/lib/metrics/unified-metrics';
import { enforceTeamRateLimit, TeamRateLimitError } from '@/lib/rate-limit/team-rate-limit';
import { enforceNeuroSeoRateLimit, NeuroSeoRateLimitError } from '@/lib/neuroseo/rate-limit';

export const dynamic = 'force-dynamic';
export const runtime = 'nodejs';

const logger = getLogger('api.neuroseo.stream').withTrace();

interface StreamPayload { urls?: string[]; analysisType?: string; userId?: string; timeoutMs?: number; teamId?: string; }

function sseEncoder(): (controller: ReadableStreamDefaultController, event: string, data: Record<string, unknown>) => void {
    const encoder = new TextEncoder();
    return (controller: ReadableStreamDefaultController, event: string, data: Record<string, unknown>) => {
        controller.enqueue(encoder.encode(`event: ${event}\n`));
        controller.enqueue(encoder.encode(`data: ${JSON.stringify(data)}\n\n`));
    };
}

async function persistCompact(urls: string[], analysisType: string, userId: string | undefined, overallScore: number, provenance: 'live' | 'cache' | 'synthetic'): Promise<void> {
    if (!userId) return;
    try {
        const hashKey = Buffer.from(JSON.stringify({ u: [...urls].sort(), t: analysisType }))
            .toString('base64').replace(/[^A-Za-z0-9]/g, '').slice(0, 40);
        const payload = { userId, overallScore, createdAt: new Date(), urls: [...urls].slice(0, 10), hashKey, topKeywords: [], __provenance: provenance, schema: 'v1' };
        const parsed = CompactAnalysisSchema.safeParse(payload as unknown);
        if (!parsed.success) { logger.warn('persist.validation_failed', { issues: parsed.error.issues.length }); return; }
        const size = Buffer.byteLength(JSON.stringify(parsed.data), 'utf8');
        recordCompactDocSize(size);
        if (size > 5000) { logger.warn('persist.size_exceeded', { size }); return; }
        await adminDb.collection('neuroSeoAnalyses').doc(hashKey).set(parsed.data, { merge: true });
        logger.info('persist.stream.success', { hashKey: hashKey.slice(0, 16), provenance, size });
    } catch (e: unknown) { logger.warn('persist.stream.degraded', { message: (e as any)?.message }); }
}

export async function POST(request: NextRequest): Promise<Response> {
    let payload: StreamPayload;
    try { payload = await request.json(); } catch { return new Response(JSON.stringify({ error: 'Invalid JSON body' }), { status: 400 }); }
    const { urls = [], analysisType = 'comprehensive', userId = 'anonymous', timeoutMs = 12000, teamId } = payload;
    if (!Array.isArray(urls) || urls.length === 0) { recordGuardStrip(); return new Response(JSON.stringify({ error: 'urls array required' }), { status: 400 }); }
    if (urls.length > 50) { recordGuardStrip(); return new Response(JSON.stringify({ error: 'too_many_urls' }), { status: 400 }); }

    recordWorkflowRun();
    const startHr = process.hrtime.bigint();
    const deadline = Date.now() + timeoutMs;
    let finished = false; let finalProvenance: string | undefined;

    const stream = new ReadableStream({
        async start(controller) {
            const write = sseEncoder();
            const finalize = (provenance: string, ok = true) => {
                if (finished) return; finished = true;
                const durationMs = Number(process.hrtime.bigint() - startHr) / 1_000_000;
                recordRouteLatency('neuroseo/stream', durationMs);
                write(controller, 'end', { ok, durationMs, provenance: finalProvenance || provenance });
                try { controller.close(); } catch { }
            };
            request.signal.addEventListener('abort', () => { logger.warn('client.disconnected'); finalize(finalProvenance || 'aborted', false); });
            write(controller, 'ack', { received: urls.length, analysisType });
            try {
                // TEAM-01: Apply team limiter if teamId provided else legacy per-user limiter for transition period.
                const g = globalThis as unknown as { adminDb?: typeof adminDb };
                if (typeof teamId === 'string' && teamId) {
                    const { adminDb: _adminDb } = g.adminDb ? { adminDb: g.adminDb } : await import('@/lib/firebase-admin');
                    await enforceTeamRateLimit(_adminDb, teamId, { routeKey: 'neuroseo/stream' });
                } else {
                    const admin = g.adminDb || (await import('@/lib/firebase-admin')).adminDb;
                    await enforceNeuroSeoRateLimit(admin, userId, {});
                }
                const allowedTypes = ['comprehensive', 'quick', 'competitor'] as const;
                const atype = (allowedTypes as readonly string[]).includes(analysisType) ? (analysisType as typeof allowedTypes[number]) : 'comprehensive';
                const orchestration = neuroSEOOrchestrator.runAnalysisStream({ urls, analysisType: atype, userId });
                for await (const evt of orchestration) {
                    if (evt.type === 'cached') { recordCacheHit(); finalProvenance = 'cache'; }
                    if (evt.type === 'complete') { recordAnalysisRun(); finalProvenance = evt.data.provenance; await persistCompact(urls, analysisType, userId, evt.data.overallScore, evt.data.provenance); }
                    write(controller, evt.type, enforceProvenanceOnChunk(evt.data as any, { path: 'neuroseo/stream' }) as unknown as Record<string, unknown>);
                    if (Date.now() > deadline && !finished && evt.type !== 'complete') {
                        logger.warn('stream.timeout', { partial: true }); recordFallback('timeout');
                        const rng = createDeterministicRng([urls.join('|'), analysisType, 'synthetic-stream']);
                        const synthetic = tagSynthetic({ analysisId: 'synthetic_' + Date.now().toString(36), urls, overallScore: Math.round(rng() * 30 + 60), cached: false });
                        write(controller, 'fallback', enforceProvenanceOnChunk({ provenance: 'synthetic', overallScore: synthetic.overallScore }, { path: 'neuroseo/stream' }) as unknown as Record<string, unknown>);
                        await persistCompact(urls, analysisType, userId, synthetic.overallScore, 'synthetic');
                        finalProvenance = 'synthetic'; finalize('synthetic'); return;
                    }
                }
                finalize(finalProvenance || 'live');
            } catch (error: unknown) {
                if (error instanceof TeamRateLimitError || error instanceof NeuroSeoRateLimitError) {
                    write(controller, 'rate_limited', enforceProvenanceOnChunk({ error: 'rate_limited', retryAfter: (error as any)?.retryAfterSeconds || 60, provenance: 'synthetic' }, { path: 'neuroseo/stream' }) as unknown as Record<string, unknown>);
                    recordFallback('rate_limited');
                    finalize('synthetic', false);
                    return;
                }
                logger.error('stream.failed', { error: (error as any)?.message }); recordWorkflowFailure(); recordFallback('backend_error');
                write(controller, 'error', enforceProvenanceOnChunk({ message: (error as any)?.message || 'analysis failed', provenance: 'synthetic' }, { path: 'neuroseo/stream' }) as unknown as Record<string, unknown>);
                const rng = createDeterministicRng([urls.join('|'), analysisType, 'synthetic-error']);
                const synthetic = tagSynthetic({ analysisId: 'synthetic_' + Date.now().toString(36), urls, overallScore: Math.round(rng() * 30 + 60), cached: false });
                write(controller, 'fallback', enforceProvenanceOnChunk({ provenance: 'synthetic', overallScore: synthetic.overallScore }, { path: 'neuroseo/stream' }) as unknown as Record<string, unknown>);
                await persistCompact(urls, analysisType, userId, synthetic.overallScore, 'synthetic');
                finalProvenance = 'synthetic'; finalize('synthetic', false);
            }
        }
    });
    return new Response(stream, { headers: { 'Content-Type': 'text/event-stream', 'Cache-Control': 'no-cache, no-transform', 'Connection': 'keep-alive' } });
}

import { runFirecrawl } from '@/lib/crawler/firecrawl-client';
import { recordCrawlerError, recordCrawlerQuota, recordCrawlerSuccess, recordRateLimitRejection, recordRouteLatency, recordTeamRateLimitAllowed } from '@/lib/metrics/unified-metrics';
import { enforceProvenance, withProvenance } from '@/lib/middleware/provenance';
import type { NextRequest } from 'next/server';
import { NextResponse } from 'next/server';
import { enforceFirecrawlQuota } from './firecrawl-quota';

 // GET /api/seo-audit/firecrawl?url=...&depth=1&limit=5
 export const GET = withProvenance(async function GET(req: NextRequest) {
     const started = Date.now();
    try {
        const urlObj = new URL(req.url);
        const target = urlObj.searchParams.get('url');
        const depth = Number(urlObj.searchParams.get('depth') || '1');
        const limit = Number(urlObj.searchParams.get('limit') || '5');
        if (!target) {
            return NextResponse.json(enforceProvenance({ success: false, error: 'url_required', provenance: 'synthetic' }, { path: 'seo-audit/firecrawl', note: 'validation' }), { status: 400 });
        }
        let parsedTarget: URL;
        try { parsedTarget = new URL(target); } catch { return NextResponse.json(enforceProvenance({ success: false, error: 'malformed_url', provenance: 'synthetic' }, { path: 'seo-audit/firecrawl', note: 'validation' }), { status: 400 }); }
        const phaseStart = { quota: Date.now(), crawl: 0 };
        // Quota enforcement (env override FIRECRAWL_HOURLY_LIMIT default 100). Scope: global (future: team/user scope keys)
        const quotaLimit = parseInt(process.env.FIRECRAWL_HOURLY_LIMIT || '100', 10) || 100;
        // Derive scope (team preferred > user > global) – expecting optional headers for now
        const teamId = req.headers.get('x-team-id') || undefined;
        const userId = req.headers.get('x-user-id') || undefined;
        const scopeKey = teamId ? `team:${teamId}` : (userId ? `user:${userId}` : 'global');
        const quota = await enforceFirecrawlQuota(quotaLimit, scopeKey);
        const quotaTimeMs = Date.now() - phaseStart.quota;
        if (!quota.allowed) {
            recordRateLimitRejection('seo-audit/firecrawl');
            return NextResponse.json(
                enforceProvenance({ success: false, error: 'rate_limited', provenance: 'synthetic', quota: { remaining: quota.remaining, resetAt: quota.resetAt.toISOString() } }, { path: 'seo-audit/firecrawl', note: 'rate_limit' }),
                { status: 429, headers: { 'Retry-After': String(quota.retryAfterSeconds || 60) } }
            );
        }
        recordTeamRateLimitAllowed('seo-audit/firecrawl');
        recordCrawlerQuota(quotaLimit, quota.remaining);
        // robots.txt respect (basic) – fetch only if depth>1
        if (depth > 1) {
            try {
                const robotsUrl = `${parsedTarget.origin}/robots.txt`;
                // Use standard fetch (omit Next.js specific revalidate option for test compatibility)
                const robotsRes = await fetch(robotsUrl);
                if (robotsRes.ok) {
                    const txt = await robotsRes.text();
                    const disallow: string[] = [];
                    let userAgentAll = true; // simplistic: treat all Disallow lines as global
                    txt.split(/\n+/).forEach(line => {
                        const m = line.match(/^Disallow:\s*(\S+)/i);
                        if (m) disallow.push(m[1]);
                    });
                    const path = parsedTarget.pathname || '/';
                    if (userAgentAll && disallow.some(rule => rule === '/' || (rule && rule !== '/' && path.startsWith(rule)))) {
                        return NextResponse.json(enforceProvenance({ success: false, error: 'robots_blocked', provenance: 'synthetic' }, { path: 'seo-audit/firecrawl', note: 'robots' }), { status: 403 });
                    }
                }
            } catch { /* ignore robots failures per degradation policy */ }
        }
        phaseStart.crawl = Date.now();
        const crawl = await runFirecrawl(target, { depth, limit });
        const crawlTimeMs = crawl.elapsedMs;
        const elapsedMs = Date.now() - started; recordRouteLatency('seo-audit/firecrawl', elapsedMs);
        if (crawl.fallback) { recordCrawlerError(crawlTimeMs); } else { recordCrawlerSuccess(crawlTimeMs, 0); }
        const analysisTimeMs = elapsedMs - quotaTimeMs - crawlTimeMs;
        const res = NextResponse.json(enforceProvenance({ success: true, provenance: crawl.fallback ? 'synthetic' : 'live', data: { pages: crawl.pages, fallback: !!crawl.fallback, degradedReason: crawl.degradedReason, timings: { quota_time_ms: quotaTimeMs, crawl_time_ms: crawlTimeMs, analysis_time_ms: analysisTimeMs, total_time_ms: elapsedMs }, quota: { remaining: quota.remaining, resetAt: quota.resetAt.toISOString(), scope: scopeKey } } }, { path: 'seo-audit/firecrawl' }));
        res.headers.set('X-Quota-Remaining', String(quota.remaining));
        res.headers.set('X-Quota-Reset', quota.resetAt.toISOString());
        return res;
    } catch (e: unknown) {
        return NextResponse.json(enforceProvenance({ success: false, error: (e as any)?.message || 'crawl_error', provenance: 'synthetic' }, { path: 'seo-audit/firecrawl', note: 'exception' }), { status: 500 });
    }
}, { path: 'seo-audit/firecrawl' });

import { NextResponse } from 'next/server';
import { enforceProvenance, withProvenance } from '@/lib/middleware/provenance';
import { TeamRateLimitError, applyTeamRateLimit } from '@/lib/rate-limit/team-rate-limit';

// Proxy route to bypass client-side CORS issues when calling callable Cloud Function directly.
// Accepts SEO audit request JSON and forwards to Cloud Function endpoint.
// Includes optional Firebase ID token (Authorization header) for auth preservation.

const REGION = 'australia-southeast2';
const PROJECT = process.env.NEXT_PUBLIC_FIREBASE_PROJECT_ID || 'rankpilot-h3jpc';
const FUNCTION_NAME = 'runSeoAudit';
const FUNCTION_URL = `https://${REGION}-${PROJECT}.cloudfunctions.net/${FUNCTION_NAME}`;

export const POST = withProvenance(async function (req: Request) {
    try {
        const body = await req.json();

        // Basic validation
        if (!body || typeof body.url !== 'string') {
            return NextResponse.json(enforceProvenance({ success: false, error: 'Invalid request: url required', provenance: 'synthetic' }, { path: 'seo-audit/run', note: 'validation' }), { status: 400 });
        }

        // TEAM-01: Apply team rate limit if teamId provided (lightweight - before upstream call)
        if (typeof (body as any).teamId === 'string') {
            const teamId = (body as any).teamId as string;
            try {
                const res = await applyTeamRateLimit(teamId);
                if (res && res.allowed) {
                    (req as any)._teamRateHeaders = { ...res.headers, 'X-RateLimit-Policy': 'bucket' };
                } else if (res && !res.allowed) {
                    return NextResponse.json(enforceProvenance({ success: false, error: 'rate_limited', retryAfter: res.retryAfterSeconds, provenance: 'synthetic' }, { path: 'seo-audit/run', note: 'rate_limit' }), { status: 429, headers: { ...res.headers, 'X-RateLimit-Policy': 'bucket' } });
                }
            } catch (e) {
                if (e instanceof TeamRateLimitError) {
                    return NextResponse.json(enforceProvenance({ success: false, error: 'rate_limited', retryAfter: e.retryAfterSeconds, provenance: 'synthetic' }, { path: 'seo-audit/run', note: 'rate_limit' }), { status: 429, headers: { 'Retry-After': String(e.retryAfterSeconds), 'X-RateLimit-Policy': 'bucket' } });
                }
            }
        }
        // Forward request in callable format ({data: {...}})
        const token = req.headers.get('authorization');
        const cfResp = await fetch(FUNCTION_URL, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                ...(token ? { Authorization: token } : {}),
            },
            body: JSON.stringify({ data: body })
        });

        if (!cfResp.ok) {
            const text = await cfResp.text();
            return NextResponse.json(enforceProvenance({ success: false, error: 'Function call failed', details: text, provenance: 'synthetic' }, { path: 'seo-audit/run', note: 'upstream' }), { status: cfResp.status });
        }

        // Callable functions wrap response JSON in {result: ...} or raw; parse generically
        const json = await cfResp.json();
        const data = json?.result || json;
        const base = NextResponse.json(enforceProvenance({ success: true, data, provenance: 'live' }, { path: 'seo-audit/run' }), { status: 200 });
        const rateHeaders = (req as any)._teamRateHeaders;
        if (rateHeaders) {
            for (const [name, value] of Object.entries(rateHeaders)) {
                base.headers.set(name, value as string);
            }
        }
        return base;
    } catch (e: unknown) {
        return NextResponse.json(enforceProvenance({ success: false, error: (e as any)?.message || 'Proxy error', provenance: 'synthetic' }, { path: 'seo-audit/run', note: 'exception' }), { status: 500 });
    }
}, { path: 'seo-audit/run' });

/**
 * Real-Time Streaming API Route
 * Handles WebSocket connections and Server-Sent Events for real-time data
 */

import { extractErrorMessage } from '@/lib/errors/extract-error-message';
import { allowStreamingMockUser } from '@/lib/flags/demo';
import { realTimeDataStreamer } from '@/lib/streaming/real-time-data-streamer';
import type { NextRequest } from 'next/server';
import { NextResponse } from 'next/server';

interface StreamingRequest {
  action: 'register' | 'subscribe' | 'collaborate' | 'metrics';
  clientId?: string;
  connectionType?: 'websocket' | 'sse';
  dashboardId?: string;
  streamTypes?: string[];
  collaborationEvent?: unknown;
}

export async function POST(request: NextRequest) {
  try {
    const body = (await request.json()) as StreamingRequest;
    const authHeader = request.headers.get('authorization');

    if (!authHeader?.startsWith('Bearer ')) {
      return NextResponse.json({ error: 'Unauthorized - Missing token' }, { status: 401 });
    }

    // For demo purposes, we can use a mock user only if explicitly allowed
    // In production, verify the JWT token here
    const mockUser: { uid: string; tier: 'enterprise' } | null = allowStreamingMockUser()
      ? { uid: 'demo-user', tier: 'enterprise' }
      : null;

    if (!mockUser) {
      return NextResponse.json({ error: 'Unauthorized - Mock user disabled' }, { status: 401 });
    }

    switch (body.action) {
      case 'register': {
        if (!body.clientId) {
          return NextResponse.json({ error: 'Client ID is required' }, { status: 400 });
        }

        const registrationResult = await realTimeDataStreamer.registerClient(
          body.clientId,
          mockUser.uid,
          mockUser.tier,
          body.connectionType || 'websocket',
          body.dashboardId
        );

        if (!registrationResult.success) {
          return NextResponse.json({ error: registrationResult.error }, { status: 400 });
        }

        return NextResponse.json({
          success: true,
          client: registrationResult.client,
          message: 'Client registered successfully'
        });
      }

      case 'subscribe': {
        if (!body.clientId || !body.streamTypes) {
          return NextResponse.json({ error: 'Client ID and stream types are required' }, { status: 400 });
        }

        const subscriptionResult = await realTimeDataStreamer.subscribeToStreams(body.clientId, body.streamTypes);

        return NextResponse.json({
          success: subscriptionResult.success,
          subscribed: subscriptionResult.subscribed,
          error: subscriptionResult.error,
          message: subscriptionResult.success
            ? `Subscribed to ${subscriptionResult.subscribed.length} streams`
            : 'Subscription failed'
        });
      }

      case 'collaborate': {
        if (!body.collaborationEvent) {
          return NextResponse.json({ error: 'Collaboration event data is required' }, { status: 400 });
        }

        const rawEv = body.collaborationEvent as unknown;
        const ev = (rawEv && typeof rawEv === 'object') ? rawEv as { type?: string; userName?: string; dashboardId?: string; data?: unknown } : {};

        const typeVal = typeof ev.type === 'string' ? ev.type : 'widget-edit';
        const dashId = typeof ev.dashboardId === 'string' ? ev.dashboardId : '';
        await realTimeDataStreamer.broadcastCollaboration({
          type: typeVal as 'user-joined' | 'user-left' | 'cursor-move' | 'widget-edit' | 'comment-added',
          userId: mockUser.uid,
          userName: typeof ev.userName === 'string' ? ev.userName : 'Demo User',
          dashboardId: dashId,
          data: ev?.data,
          timestamp: Date.now()
        });

        return NextResponse.json({
          success: true,
          message: 'Collaboration event broadcasted'
        });
      }

      case 'metrics': {
        const metrics = realTimeDataStreamer.getMetrics();
        return NextResponse.json({ success: true, metrics });
      }

      default:
        return NextResponse.json({ error: 'Invalid action' }, { status: 400 });
    }
  } catch (error) {
    console.error('[StreamingAPI] Error:', error);
    return NextResponse.json(
      {
        error: 'Internal server error',
        details: extractErrorMessage(error)
      },
      { status: 500 }
    );
  }
}

export async function GET(request: NextRequest) {
  try {
    const url = new URL(request.url);
    const action = url.searchParams.get('action');
    const clientId = url.searchParams.get('clientId');

    // Server-Sent Events endpoint
    if (action === 'sse') {
      if (!clientId) {
        return NextResponse.json({ error: 'Client ID is required for SSE' }, { status: 400 });
      }

      // Create SSE response
      const encoder = new TextEncoder();

      const customReadable = new ReadableStream({
        start(controller) {
          // Send initial connection message
          controller.enqueue(
            encoder.encode(
              `data: ${JSON.stringify({
                type: 'connection',
                message: 'SSE connection established',
                timestamp: Date.now()
              })}\n\n`
            )
          );

          // Listen for SSE data events
          const handleSSEData = (id: string, data: unknown): void => {
            if (id === clientId) {
              controller.enqueue(encoder.encode(`data: ${JSON.stringify(data)}\n\n`));
            }
          };

          realTimeDataStreamer.on('sse-data', handleSSEData);

          // Heartbeat to keep connection alive
          const heartbeat = setInterval(() => {
            controller.enqueue(
              encoder.encode(
                `data: ${JSON.stringify({
                  type: 'heartbeat',
                  timestamp: Date.now()
                })}\n\n`
              )
            );
          }, 30000);

          // Cleanup on close
          const onAbort = (): void => {
            clearInterval(heartbeat as unknown as number);
            realTimeDataStreamer.off('sse-data', handleSSEData);
            realTimeDataStreamer.disconnectClient(clientId);
            controller.close();
          };

          request.signal.addEventListener('abort', onAbort);
        }
      });

      return new NextResponse(customReadable, {
        headers: {
          'Content-Type': 'text/event-stream',
          'Cache-Control': 'no-cache',
          Connection: 'keep-alive',
          'Access-Control-Allow-Origin': '*',
          'Access-Control-Allow-Headers': 'Cache-Control'
        }
      });
    }

    // Regular GET endpoints
    switch (action) {
      case 'metrics': {
        const metrics = realTimeDataStreamer.getMetrics();
        return NextResponse.json({ success: true, metrics });
      }

      case 'health': {
        return NextResponse.json({
          success: true,
          status: 'healthy',
          uptime: process.uptime(),
          connections: realTimeDataStreamer.getMetrics().totalConnections
        });
      }

      default:
        return NextResponse.json({ error: 'Invalid action' }, { status: 400 });
    }
  } catch (error) {
    console.error('[StreamingAPI] GET Error:', error);
    return NextResponse.json(
      {
        error: 'Internal server error',
        details: extractErrorMessage(error)
      },
      { status: 500 }
    );
  }
}

export async function DELETE(request: NextRequest) {
  try {
    const url = new URL(request.url);
    const clientId = url.searchParams.get('clientId');

    if (!clientId) {
      return NextResponse.json({ error: 'Client ID is required' }, { status: 400 });
    }

    const disconnected = await realTimeDataStreamer.disconnectClient(clientId);

    return NextResponse.json({
      success: disconnected,
      message: disconnected ? 'Client disconnected successfully' : 'Client not found'
    });
  } catch (error) {
    console.error('[StreamingAPI] DELETE Error:', error);
    return NextResponse.json(
      {
        error: 'Internal server error',
        details: extractErrorMessage(error)
      },
      { status: 500 }
    );
  }
}

import { adminDb } from "@/lib/firebase-admin";
import { enforceProvenance } from "@/lib/middleware/provenance";
import type { NextRequest } from "next/server";
import { NextResponse } from "next/server";

type SortBy = "metric" | "value" | "change";
type Direction = "asc" | "desc";

// Simple deterministic generator for demo/server-side mock data
function generateRows(total: number, seed: string): { metric: string; value: string; change: string }[] {
    const rows: { metric: string; value: string; change: string }[] = [];
    let s = 0;
    for (let i = 0; i < seed.length; i++) s = (s + seed.charCodeAt(i)) % 997;
    for (let i = 1; i <= total; i++) {
        const base = (i * 37 + s) % 1000;
        const value = 50000 + base * 123.45;
        const changeBase = ((i * 13 + s) % 40) - 20; // -20..19
        const sign = changeBase >= 0 ? "+" : "";
        rows.push({
            metric: `Metric ${i}`,
            value: `$${value.toLocaleString(undefined, { maximumFractionDigits: 0 })}`,
            change: `${sign}${changeBase}%`,
        });
    }
    return rows;
}

function parseNumeric(val: string): number {
    if (val.endsWith("%")) return parseFloat(val.replace(/%/g, ""));
    return parseFloat(val.replace(/[$,]/g, ""));
}

type TableRow = { metric: string; value: string; change: string };
interface RawRow {
    metric?: string; name?: string; label?: string;
    valueNum?: number; value?: string | number;
    changeNum?: number; change?: string | number;
    [k: string]: unknown;
}

function formatCurrency(val: number): string {
    // Format like $50,000 (no decimals by default)
    return `$${val.toLocaleString(undefined, { maximumFractionDigits: 0 })}`;
}

function formatPercent(val: number): string {
    const sign = val >= 0 ? "+" : "";
    return `${sign}${Math.round(val)}%`;
}

function normalizeRow(docData: RawRow): TableRow {
    // Accept a variety of shapes and normalize to strings expected by client
    const metric = String(docData.metric ?? docData.name ?? docData.label ?? "Metric");

    // Value can be number or string; support valueNum as canonical numeric field
    let valueOut: string;
    if (typeof docData.valueNum === "number") valueOut = formatCurrency(docData.valueNum);
    else if (typeof docData.value === "number") valueOut = formatCurrency(docData.value);
    else if (typeof docData.value === "string") valueOut = docData.value;
    else valueOut = formatCurrency(0);

    // Change can be number or string with %; support changeNum as canonical numeric field
    let changeOut: string;
    if (typeof docData.changeNum === "number") changeOut = formatPercent(docData.changeNum);
    else if (typeof docData.change === "number") changeOut = formatPercent(docData.change);
    else if (typeof docData.change === "string") changeOut = docData.change;
    else changeOut = "+0%";

    return { metric, value: valueOut, change: changeOut };
}

async function fetchFromFirestore(opts: {
    widgetId: string;
    sortBy: SortBy;
    direction: Direction;
    page: number;
    pageSize: number;
    all: boolean;
    teamId?: string | null;
    userId?: string | null;
}): Promise<{ rows: TableRow[]; total: number } | null> {
    try {
        const { widgetId, sortBy, direction, page, pageSize, all, teamId, userId } = opts;
        let base: FirebaseFirestore.Query = adminDb
            .collection("dashboardTables")
            .doc(widgetId)
            .collection("rows");
        if (teamId) base = base.where("teamId", "==", teamId);
        if (userId) base = base.where("userId", "==", userId);

        // Try to get total via aggregation; fallback to rough count if unsupported
        let total = 0;
        try {
            // count() may not be typed; access via indexed lookup to avoid explicit any
            const maybeCountFn: unknown = (base as unknown as Record<string, unknown>)["count"]; // Firestore aggregate query extension
            if (typeof maybeCountFn === "function") {
                const aggSnap = await (maybeCountFn as () => { get: () => Promise<{ data: () => { count?: number } }> })().get();
                const dataFn = typeof aggSnap?.data === 'function' ? aggSnap.data() : {};
                const c = (dataFn as { count?: unknown }).count;
                if (typeof c === 'number') total = c;
            }
        } catch {
            // Fallback: attempt to get first 1 with offset large to detect existence; otherwise assume 0
            // We won't scan entire collection for performance.
            total = 0;
        }

        // Map sort fields. Prefer numeric shadow fields when available.
        const orderField =
            sortBy === "metric" ? "metric" : sortBy === "value" ? ("valueNum" as const) : ("changeNum" as const);

        async function pageQuery(limit: number, cursor?: FirebaseFirestore.QueryDocumentSnapshot) {
            let q: FirebaseFirestore.Query = base.orderBy(orderField, direction);
            if (cursor) q = q.startAfter(cursor);
            q = q.limit(limit);
            const snap = await q.get();
            return snap;
        }

        let docs: FirebaseFirestore.QueryDocumentSnapshot[] = [];

        if (all) {
            // Stream all rows in sorted order in batches
            let last: FirebaseFirestore.QueryDocumentSnapshot | undefined = undefined;
            const batchSize = Math.max(100, Math.min(1000, pageSize || 500));
            // Guard against excessive export sizes; cap at 50k rows
            const maxRows = 50000;
            while (docs.length < maxRows) {
                const snap = await pageQuery(batchSize, last);
                if (snap.empty) break;
                docs.push(...snap.docs);
                last = snap.docs[snap.docs.length - 1];
                if (snap.size < batchSize) break;
            }
            // If total is unknown (0), set to docs length
            if (!total) total = docs.length;
        } else {
            // For paginated view, advance by pages using cursors
            const batchSize = pageSize;
            let last: FirebaseFirestore.QueryDocumentSnapshot | undefined;
            let fetched = 0;
            const targetStartIndex = page * pageSize;

            // Efficiently skip using cursors: fetch chunks until we pass targetStartIndex
            const step = Math.min(1000, Math.max(1, batchSize));
            while (fetched + step <= targetStartIndex) {
                const snap = await pageQuery(step, last);
                if (snap.empty) break;
                fetched += snap.size;
                last = snap.docs[snap.docs.length - 1];
                if (snap.size < step) break;
            }
            // Fetch the page
            const pageSnap = await pageQuery(batchSize, last);
            docs = pageSnap.docs;

            if (!total) {
                // Try to estimate total as last page start + this page size; better than zero
                total = fetched + docs.length;
            }
        }

        if (!docs.length) {
            // No data found in Firestore for this widget
            return { rows: [], total };
        }

        const rows = docs.map((d) => normalizeRow(d.data()));
        return { rows, total };
    } catch (_err) {
        // Firestore might not be configured in this environment; fall back to mock
        return null;
    }
}

export async function GET(req: NextRequest): Promise<NextResponse> {
    try {
        const { searchParams } = new URL(req.url);
        const widgetId = searchParams.get("widgetId") || "global";
        const teamId = searchParams.get("teamId");
        const userId = searchParams.get("userId");
        // Support combined sort parameter: sort=metric.asc | valueNum.desc | changeNum.asc
        function parseSort(): { sortBy: SortBy; direction: Direction } {
            const combined = searchParams.get("sort");
            let sb = (searchParams.get("sortBy") || "metric").toLowerCase();
            let dir = (searchParams.get("direction") || "asc").toLowerCase();
            if (combined) {
                const [fieldRaw, dirRaw] = combined.split(".");
                const field = (fieldRaw || "metric").toLowerCase();
                const mappedField = field === "valuenum" ? "value" : field === "changenum" ? "change" : field;
                sb = ["metric", "value", "change"].includes(mappedField) ? mappedField : "metric";
                dir = (dirRaw === "desc" || dirRaw === "asc") ? dirRaw : "asc";
            }
            return { sortBy: sb as SortBy, direction: dir as Direction };
        }
        const { sortBy, direction } = parseSort();
        const page = Math.max(0, parseInt(searchParams.get("page") || "0", 10) || 0);
        const pageSize = Math.max(1, parseInt(searchParams.get("pageSize") || "10", 10) || 10);
        const format = (searchParams.get("format") || "json").toLowerCase();
        const all = searchParams.get("all") === "1" || searchParams.get("all") === "true";
        // Try Firestore first (real datastore). If unavailable or empty, fall back to deterministic generator.
        let result = await fetchFromFirestore({ widgetId, sortBy, direction, page, pageSize, all, teamId, userId });
        let outRows: TableRow[] = [];
        let total: number;
        if (!result || result.rows.length === 0) {
            // If scoping is requested, do NOT fall back to synthetic data to avoid cross-tenant leakage.
            if (teamId || userId) {
                outRows = [];
                total = 0;
            } else {
                // For demo purposes or when Firestore has no data, use mock generator
                total = Math.min(2000, Math.max(50, parseInt(searchParams.get("total") || "500", 10) || 500));
                const rowsAll = generateRows(total, widgetId);
                const sorted = rowsAll.sort((a, b) => {
                    const dir = direction === "asc" ? 1 : -1;
                    if (sortBy === "metric") return a.metric.localeCompare(b.metric) * dir;
                    if (sortBy === "value") return (parseNumeric(a.value) - parseNumeric(b.value)) * dir;
                    return (parseNumeric(a.change) - parseNumeric(b.change)) * dir;
                });
                outRows = all ? sorted : sorted.slice(page * pageSize, page * pageSize + pageSize);
            }
        } else {
            outRows = result.rows;
            total = result.total;
        }

        if (format === "csv") {
            const header = "Metric,Value,Change";
            const body = outRows
                .map((r) => `${JSON.stringify(r.metric)},${JSON.stringify(r.value)},${JSON.stringify(r.change)}`)
                .join("\n");
            const csv = `${header}\n${body}`;
            const res = new NextResponse(csv, {
                status: 200,
                headers: {
                    "Content-Type": "text/csv; charset=utf-8",
                    "Cache-Control": "no-store",
                    "Content-Disposition": `attachment; filename="table_${widgetId}.csv"`,
                },
            });
            res.headers.set("x-provenance", teamId || userId ? "live_or_empty" : (result ? "live" : "synthetic"));
            return res;
        }

        const provenance = teamId || userId ? (result ? "live" : "live") : (result ? "live" : "synthetic");
        return NextResponse.json(enforceProvenance({ rows: outRows, total, provenance }, { path: 'table-data' }), { status: 200 });
    } catch (err: unknown) {
        const message = ((): string => {
            if (typeof err === 'object' && err && 'message' in err) {
                const m = (err as Record<string, unknown>).message;
                return typeof m === 'string' ? m : 'Unknown error';
            }
            return 'Unknown error';
        })();
        return NextResponse.json(enforceProvenance({ error: message, provenance: 'synthetic' }, { path: 'table-data', note: 'exception' }), { status: 500 });
    }
}

