interface TimestampLike { toDate: () => Date }

type UserDoc = {
  email?: unknown;
  displayName?: unknown;
  role?: unknown;
  createdAt?: unknown;
  lastSignIn?: unknown;
  subscription?: { status?: unknown; tier?: unknown } | unknown;
  activityCount?: unknown;
  [k: string]: unknown;
};

const isTimestampLike = (v: unknown): v is TimestampLike =>
  !!v &&
  typeof v === "object" &&
  "toDate" in v &&
  typeof (v as TimestampLike).toDate === "function";

interface User {
  id: string;
  email: string;
  displayName?: string;
  role: string;
  createdAt?: TimestampLike; // Firestore Timestamp
  lastSignIn?: TimestampLike;
  subscriptionStatus?: string;
  subscriptionTier?: string;
  activityCount?: number;
}

export default function AdminUserManagement(): JSX.Element {
  const { toast } = useToast();
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState("");
  const [roleFilter, setRoleFilter] = useState("all");
  const [selectedUser, setSelectedUser] = useState<User | null>(null);
  const [actionDialogOpen, setActionDialogOpen] = useState(false);
  const [actionType, setActionType] = useState<
    "promote" | "demote" | "suspend"
  >("promote");

  useEffect(() => {
    let mounted = true;

    (async function fetchUsers() {
      try {
        setLoading(true);
        const qy = query(collection(db, "users"), orderBy("createdAt", "desc"), limit(200));
        const snap = await getDocs(qy);
        const list: User[] = snap.docs.map((d) => {
          const data = d.data() as UserDoc;
          const subRaw = data.subscription as unknown;
          const subObj = (subRaw && typeof subRaw === 'object') ? subRaw as { status?: unknown; tier?: unknown } : {};
          return {
            id: d.id,
            email: typeof data.email === "string" ? data.email : "",
            displayName:
              typeof data.displayName === "string" ? data.displayName : undefined,
            role: typeof data.role === "string" ? data.role : "user",
            createdAt: isTimestampLike(data.createdAt) ? data.createdAt : undefined,
            lastSignIn: isTimestampLike(data.lastSignIn) ? data.lastSignIn : undefined,
            subscriptionStatus: typeof subObj.status === 'string' ? subObj.status : undefined,
            subscriptionTier: typeof subObj.tier === 'string' ? subObj.tier : undefined,
            activityCount:
              typeof data.activityCount === "number" ? data.activityCount : undefined,
          };
        });
        if (mounted) setUsers(list);
      } catch (e) {
        if (mounted)
          toast({
            variant: "destructive",
            title: "Error",
            description: "Failed to load users",
          });
      } finally {
        if (mounted) setLoading(false);
      }
    })();

    return () => {
      mounted = false;
    };
  }, [toast]);

  const handleUserAction = async (): Promise<void> => {
    if (!selectedUser) return;

    try {
      const userRef = doc(db, "users", selectedUser.id);
      let newRole = selectedUser.role;

      switch (actionType) {
        case "promote":
          newRole = selectedUser.role === "user" ? "admin" : selectedUser.role;
          break;
        case "demote":
          newRole = selectedUser.role === "admin" ? "user" : selectedUser.role;
          break;
        case "suspend":
          newRole = "suspended";
          break;
      }

      await updateDoc(userRef, { role: newRole });

      // Update local state
      setUsers(
        users.map((user) =>
          user.id === selectedUser.id ? { ...user, role: newRole } : user
        )
      );

      toast({
        title: "Success",
        description: `User ${actionType}d successfully.`,
      });
    } catch (error) {
      toast({
        variant: "destructive",
        title: "Error",
        description: `Failed to ${actionType} user.`,
      });
    } finally {
      setActionDialogOpen(false);
      setSelectedUser(null);
    }
  };

  const filteredUsers = users.filter((user) => {
    const email = typeof user.email === 'string' ? user.email : '';
    const name = typeof user.displayName === 'string' ? user.displayName : '';
    const term = searchTerm.toLowerCase();
    const matchesSearch =
      email.toLowerCase().includes(term) ||
      name.toLowerCase().includes(term);
    const matchesRole = roleFilter === "all" || user.role === roleFilter;
    return matchesSearch && matchesRole;
  });

  const getUserBadge = (role: string) => {
    switch (role) {
      case "admin":
        return (
          <Badge className="bg-destructive/15 text-destructive">
            <Shield className="h-3 w-3 mr-1" />
            Admin
          </Badge>
        );
  case "agency":
        return (
          <Badge className="bg-accent/10 text-accent">
            <Crown className="h-3 w-3 mr-1" />
            Agency
          </Badge>
        );
      case "suspended":
        return <Badge variant="destructive">Suspended</Badge>;
      default:
        return <Badge variant="secondary">User</Badge>;
    }
  };

  const getSubscriptionBadge = (status?: string, tier?: string) => {
    if (status === "active") {
      return (
  <Badge className="bg-success/15 text-success">
          {tier || "Enterprise"}
        </Badge>
      );
    }
    return <Badge variant="outline">Free</Badge>;
  };

  if (loading) {
    return (
      <Card>
        <CardHeader>
          <CardTitle>Loading users...</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="animate-pulse space-y-4">
            {[...Array(5)].map((_, i) => (
              <div key={i} className="h-16 bg-muted rounded" />
            ))}
          </div>
        </CardContent>
      </Card>
    );
  }

  return (
    <div className="space-y-6">
      {/* Overview Cards */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        <Card>
          <CardContent className="p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm font-medium text-muted-foreground">
                  Total Users
                </p>
                <p className="text-2xl font-bold">{users.length}</p>
              </div>
              <Users className="h-8 w-8 text-muted-foreground" />
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm font-medium text-muted-foreground">
                  Admin Users
                </p>
                <p className="text-2xl font-bold">
                  {users.filter((u) => u.role === "admin").length}
                </p>
              </div>
              <Shield className="h-8 w-8 text-muted-foreground" />
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm font-medium text-muted-foreground">
                  Agency Users
                </p>
                <p className="text-2xl font-bold">
                  {
                    users.filter((u) => u.subscriptionStatus === "active")
                      .length
                  }
                </p>
              </div>
              <Crown className="h-8 w-8 text-muted-foreground" />
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm font-medium text-muted-foreground">
                  Active This Month
                </p>
                <p className="text-2xl font-bold">
                  {
                    users.filter((u) => u.activityCount && u.activityCount > 0)
                      .length
                  }
                </p>
              </div>
              <Activity className="h-8 w-8 text-muted-foreground" />
            </div>
          </CardContent>
        </Card>
      </div>

      {/* User Management */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Users className="h-5 w-5" />
            User Management
          </CardTitle>
          <CardDescription>
            View and manage all users in the system.
          </CardDescription>
        </CardHeader>
        <CardContent>
          {/* Filters */}
          <div className="flex gap-4 mb-6">
            <div className="flex-1">
              <div className="relative">
                <Search className="absolute left-2 top-2.5 h-4 w-4 text-muted-foreground" />
                <Input
                  placeholder="Search users by email or name..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="pl-8"
                />
              </div>
            </div>
            <Select value={roleFilter} onValueChange={setRoleFilter}>
              <SelectTrigger className="w-48">
                <Filter className="h-4 w-4 mr-2" />
                <SelectValue placeholder="Filter by role" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">All Roles</SelectItem>
                <SelectItem value="user">Users</SelectItem>
                <SelectItem value="admin">Admins</SelectItem>
                <SelectItem value="agency">Agency Users</SelectItem>
                <SelectItem value="suspended">Suspended</SelectItem>
              </SelectContent>
            </Select>
          </div>

          {/* Users Table */}
          <div className="rounded-md border">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>User</TableHead>
                  <TableHead>Role</TableHead>
                  <TableHead>Subscription</TableHead>
                  <TableHead>Activities</TableHead>
                  <TableHead>Joined</TableHead>
                  <TableHead>Last Seen</TableHead>
                  <TableHead className="w-[70px]">Actions</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {filteredUsers.map((user) => (
                  <TableRow key={user.id}>
                    <TableCell>
                      <div>
                        <div className="font-medium">
                          {user.displayName || "No name"}
                        </div>
                        <div className="text-sm text-muted-foreground flex items-center gap-1">
                          <Mail className="h-3 w-3" />
                          {user.email}
                        </div>
                      </div>
                    </TableCell>
                    <TableCell>{getUserBadge(user.role)}</TableCell>
                    <TableCell>
                      {getSubscriptionBadge(
                        user.subscriptionStatus,
                        user.subscriptionTier
                      )}
                    </TableCell>
                    <TableCell>
                      <div className="text-sm">
                        {user.activityCount || 0} activities
                      </div>
                    </TableCell>
                    <TableCell>
                      <div className="text-sm flex items-center gap-1">
                        <Calendar className="h-3 w-3" />
                        {isTimestampLike(user.createdAt)
                          ? formatDistanceToNow(user.createdAt.toDate(), { addSuffix: true })
                          : "Unknown"}
                      </div>
                    </TableCell>
                    <TableCell>
                      <div className="text-sm text-muted-foreground">
                        {isTimestampLike(user.lastSignIn)
                          ? formatDistanceToNow(user.lastSignIn.toDate(), { addSuffix: true })
                          : "Never"}
                      </div>
                    </TableCell>
                    <TableCell>
                      <DropdownMenu>
                        <DropdownMenuTrigger asChild>
                          <Button variant="ghost" className="h-8 w-8 p-0">
                            <MoreHorizontal className="h-4 w-4" />
                          </Button>
                        </DropdownMenuTrigger>
                        <DropdownMenuContent align="end">
                          {user.role === "user" && (
                            <DropdownMenuItem
                              onClick={() => {
                                setSelectedUser(user);
                                setActionType("promote");
                                setActionDialogOpen(true);
                              }}
                            >
                              Promote to Admin
                            </DropdownMenuItem>
                          )}
                          {user.role === "admin" && (
                            <DropdownMenuItem
                              onClick={() => {
                                setSelectedUser(user);
                                setActionType("demote");
                                setActionDialogOpen(true);
                              }}
                            >
                              Demote to User
                            </DropdownMenuItem>
                          )}
                          {user.role !== "suspended" && (
                            <DropdownMenuItem
                              className="text-destructive"
                              onClick={() => {
                                setSelectedUser(user);
                                setActionType("suspend");
                                setActionDialogOpen(true);
                              }}
                            >
                              Suspend User
                            </DropdownMenuItem>
                          )}
                        </DropdownMenuContent>
                      </DropdownMenu>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </div>

          {filteredUsers.length === 0 && (
            <div className="text-center py-8">
              <Users className="h-12 w-12 text-muted-foreground mx-auto mb-4" />
              <h3 className="text-lg font-medium mb-2">No users found</h3>
              <p className="text-muted-foreground">
                Try adjusting your search criteria.
              </p>
            </div>
          )}
        </CardContent>
      </Card>

      {/* Action Confirmation Dialog */}
      <AlertDialog open={actionDialogOpen} onOpenChange={setActionDialogOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>
              Confirm{" "}
              {actionType === "promote"
                ? "Promotion"
                : actionType === "demote"
                  ? "Demotion"
                  : "Suspension"}
            </AlertDialogTitle>
            <AlertDialogDescription>
              Are you sure you want to {actionType} {selectedUser?.email}?
              {actionType === "suspend" &&
                " This will prevent them from accessing the platform."}
              {actionType === "promote" &&
                " This will give them admin privileges."}
              {actionType === "demote" &&
                " This will remove their admin privileges."}
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction onClick={handleUserAction}>
              {actionType === "promote"
                ? "Promote"
                : actionType === "demote"
                  ? "Demote"
                  : "Suspend"}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

"use client";

import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { Input } from "@/components/ui/input";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { db } from "@/lib/firebase";
import { STRIPE_PLANS } from "@/lib/stripe";
import {
  collection,
  doc,
  getDocs,
  query,
  updateDoc,
  where,
} from "firebase/firestore";
import {
  AlertTriangle,
  CreditCard,
  Crown,
  DollarSign,
  Mail,
  MoreHorizontal,
  Search,
  Users,
  Zap,
} from "lucide-react";
import { useCallback, useEffect, useState } from "react";
import { toast } from "sonner";

interface SubscriptionUser {
  id: string;
  email: string;
  displayName?: string;
  subscription: {
    tier: string;
    status: string;
    current_period_end?: number;
    customer_id?: string;
    subscription_id?: string;
  };
  createdAt: number;
  lastLoginAt?: number;
}

interface TimestampLike { seconds: number }
const isTimestampLike = (v: unknown): v is TimestampLike =>
  v !== null &&
  typeof v === "object" &&
  "seconds" in v &&
  typeof (v as { seconds?: unknown }).seconds === "number";

interface SubscriptionStats {
  total: number;
  active: number;
  canceled: number;
  pastDue: number;
  revenue: number;
  starterCount: number;
  agencyCount: number;
  enterpriseCount: number;
}

export function SubscriptionManagement() {
  const [users, setUsers] = useState<SubscriptionUser[]>([]);
  const [stats, setStats] = useState<SubscriptionStats>({
    total: 0,
    active: 0,
    canceled: 0,
    pastDue: 0,
    revenue: 0,
    starterCount: 0,
    agencyCount: 0,
    enterpriseCount: 0,
  });
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState("");



  const fetchSubscriptionData = useCallback(async (): Promise<void> => {
    try {
      setLoading(true);

      // Fetch all users with subscriptions
      const usersQuery = query(
        collection(db, "users"),
        where("subscription.tier", "!=", "free")
      );

      const usersSnapshot = await getDocs(usersQuery);
      const usersData: SubscriptionUser[] = [];
      let tempStats: SubscriptionStats = {
        total: 0,
        active: 0,
        canceled: 0,
        pastDue: 0,
        revenue: 0,
        starterCount: 0,
        agencyCount: 0,
        enterpriseCount: 0,
      };

      usersSnapshot.forEach((d) => {
        const data = d.data() as Record<string, unknown>;
        const rawSub = (data as Record<string, unknown>).subscription as unknown;
        const safeSub = (rawSub && typeof rawSub === 'object') ? rawSub as Record<string, unknown> : {};
        const tier = typeof safeSub.tier === 'string' ? safeSub.tier : 'free';
        const status = typeof safeSub.status === 'string' ? safeSub.status : 'inactive';
        const current_period_end = typeof safeSub.current_period_end === 'number' ? safeSub.current_period_end : undefined;
        const customer_id = typeof safeSub.customer_id === 'string' ? safeSub.customer_id : undefined;
        const subscription_id = typeof safeSub.subscription_id === 'string' ? safeSub.subscription_id : undefined;
        const user: SubscriptionUser = {
          id: d.id,
          email: typeof data.email === 'string' ? data.email : '',
          displayName: typeof data.displayName === 'string' ? data.displayName : undefined,
          subscription: { tier, status, current_period_end, customer_id, subscription_id },
          createdAt: isTimestampLike(data.createdAt) ? data.createdAt.seconds * 1000 : Date.now(),
          lastLoginAt: isTimestampLike(data.lastLoginAt) ? data.lastLoginAt.seconds * 1000 : undefined
        };

        usersData.push(user);

        // Calculate stats
        tempStats.total++;

        if (user.subscription.status === "active") {
          tempStats.active++;

          // Calculate revenue (rough estimate)
          if (user.subscription.tier === "starter") {
            tempStats.revenue += STRIPE_PLANS.starter.price.monthly;
            tempStats.starterCount++;
          } else if (user.subscription.tier === "agency") {
            tempStats.revenue += STRIPE_PLANS.agency.price.monthly;
            tempStats.agencyCount++;
          } else if (user.subscription.tier === "enterprise") {
            tempStats.revenue += STRIPE_PLANS.enterprise.price.monthly;
            tempStats.enterpriseCount++;
          }
        } else if (user.subscription.status === "canceled") {
          tempStats.canceled++;
        } else if (user.subscription.status === "past_due") {
          tempStats.pastDue++;
        }
      });

      setUsers(usersData);
      setStats(tempStats);
    } catch (error) {
      console.error("Error fetching subscription data:", error);
      toast.error("Failed to load subscription data");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    void fetchSubscriptionData();
  }, [fetchSubscriptionData]);

  const updateUserSubscription = async (
    userId: string,
    updates: Record<string, string>): Promise<void> => {
    try {
      const userRef = doc(db, "users", userId);
  const updateData: Record<string, string> = {};
      Object.keys(updates).forEach((key) => {
        updateData[`subscription.${key}`] = updates[key];
      });

      await updateDoc(userRef, updateData);

      toast.success("Subscription updated successfully");
      fetchSubscriptionData(); // Refresh data
    } catch (error) {
      console.error("Error updating subscription:", error);
      toast.error("Failed to update subscription");
    }
  };

  const filteredUsers = users.filter(
    (user) =>
      user.email.toLowerCase().includes(searchTerm.toLowerCase()) ||
      user.displayName?.toLowerCase().includes(searchTerm.toLowerCase()) ||
      user.subscription.tier.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const getStatusBadge = (status: string) => {
    const variants: {
      [key: string]: "default" | "secondary" | "destructive" | "outline";
    } = {
      active: "default",
      canceled: "destructive",
      past_due: "destructive",
      inactive: "secondary",
    };

    return (
      <Badge variant={variants[status] || "outline"}>
        {status.replace("_", " ").toUpperCase()}
      </Badge>
    );
  };

  const getTierIcon = (tier: string) => {
    switch (tier) {
      case "starter":
        return <Zap className="w-4 h-4" />;
      case "agency":
        return <Crown className="w-4 h-4" />;
      case "enterprise":
        return <CreditCard className="w-4 h-4" />;
      default:
        return null;
    }
  };

  if (loading) {
    return (
      <div className="space-y-6">
        <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
          {[...Array(4)].map((_, i) => (
            <Card key={i}>
              <CardHeader className="animate-pulse">
                <div className="h-4 bg-muted rounded w-3/4"></div>
                <div className="h-8 bg-muted rounded w-1/2"></div>
              </CardHeader>
            </Card>
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Stats Overview */}
      <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">
              Total Subscribers
            </CardTitle>
            <Users className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{stats.total}</div>
            <p className="text-xs text-muted-foreground">
              {stats.active} active, {stats.canceled} canceled
            </p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">
              Monthly Revenue
            </CardTitle>
            <DollarSign className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">${stats.revenue}</div>
            <p className="text-xs text-muted-foreground">
              Estimated from active subscriptions
            </p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Agency Plans</CardTitle>
            <Crown className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{stats.agencyCount}</div>
            <p className="text-xs text-muted-foreground">Most popular tier</p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Issues</CardTitle>
            <AlertTriangle className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{stats.pastDue}</div>
            <p className="text-xs text-muted-foreground">Past due payments</p>
          </CardContent>
        </Card>
      </div>

      {/* Subscription Management */}
      <Card>
        <CardHeader>
          <CardTitle>Subscription Management</CardTitle>
          <CardDescription>
            Manage user subscriptions and billing
          </CardDescription>
        </CardHeader>
        <CardContent>
          <Tabs defaultValue="users" className="space-y-4">
            <TabsList>
              <TabsTrigger value="users">Users</TabsTrigger>
              <TabsTrigger value="analytics">Analytics</TabsTrigger>
            </TabsList>

            <TabsContent value="users" className="space-y-4">
              <div className="flex items-center space-x-2">
                <Search className="w-4 h-4 text-muted-foreground" />
                <Input
                  placeholder="Search users..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="max-w-sm"
                />
              </div>

              <div className="border rounded-md">
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>User</TableHead>
                      <TableHead>Plan</TableHead>
                      <TableHead>Status</TableHead>
                      <TableHead>Joined</TableHead>
                      <TableHead>Last Login</TableHead>
                      <TableHead className="text-right">Actions</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {filteredUsers.map((user) => (
                      <TableRow key={user.id}>
                        <TableCell>
                          <div>
                            <div className="font-medium">
                              {user.displayName || "Anonymous"}
                            </div>
                            <div className="text-sm text-muted-foreground">
                              {user.email}
                            </div>
                          </div>
                        </TableCell>
                        <TableCell>
                          <div className="flex items-center gap-2">
                            {getTierIcon(user.subscription.tier)}
                            <span className="capitalize">
                              {user.subscription.tier}
                            </span>
                          </div>
                        </TableCell>
                        <TableCell>
                          {getStatusBadge(user.subscription.status)}
                        </TableCell>
                        <TableCell>
                          {new Date(user.createdAt).toLocaleDateString()}
                        </TableCell>
                        <TableCell>
                          {user.lastLoginAt
                            ? new Date(user.lastLoginAt).toLocaleDateString()
                            : "Never"}
                        </TableCell>
                        <TableCell className="text-right">
                          <DropdownMenu>
                            <DropdownMenuTrigger asChild>
                              <Button variant="ghost" className="h-8 w-8 p-0">
                                <MoreHorizontal className="h-4 w-4" />
                              </Button>
                            </DropdownMenuTrigger>
                            <DropdownMenuContent align="end">
                              <DropdownMenuItem
                                onClick={() =>
                                  updateUserSubscription(user.id, {
                                    status: "active",
                                  })
                                }
                              >
                                Activate Subscription
                              </DropdownMenuItem>
                              <DropdownMenuItem
                                onClick={() =>
                                  updateUserSubscription(user.id, {
                                    status: "canceled",
                                  })
                                }
                              >
                                Cancel Subscription
                              </DropdownMenuItem>
                              <DropdownMenuItem>
                                <Mail className="mr-2 h-4 w-4" />
                                Send Email
                              </DropdownMenuItem>
                            </DropdownMenuContent>
                          </DropdownMenu>
                        </TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              </div>
            </TabsContent>

            <TabsContent value="analytics" className="space-y-4">
              <div className="grid gap-4 md:grid-cols-3">
                <Card>
                  <CardHeader>
                    <CardTitle className="text-sm">Plan Distribution</CardTitle>
                  </CardHeader>
                  <CardContent>
                    <div className="space-y-2">
                      <div className="flex justify-between">
                        <span className="text-sm">Starter</span>
                        <span className="text-sm font-medium">
                          {stats.starterCount}
                        </span>
                      </div>
                      <div className="flex justify-between">
                        <span className="text-sm">Agency</span>
                        <span className="text-sm font-medium">
                          {stats.agencyCount}
                        </span>
                      </div>
                      <div className="flex justify-between">
                        <span className="text-sm">Enterprise</span>
                        <span className="text-sm font-medium">
                          {stats.enterpriseCount}
                        </span>
                      </div>
                    </div>
                  </CardContent>
                </Card>

                <Card>
                  <CardHeader>
                    <CardTitle className="text-sm">Revenue Breakdown</CardTitle>
                  </CardHeader>
                  <CardContent>
                    <div className="space-y-2">
                      <div className="flex justify-between">
                        <span className="text-sm">Starter (${STRIPE_PLANS.starter.price.monthly})</span>
                        <span className="text-sm font-medium">
                          ${stats.starterCount * STRIPE_PLANS.starter.price.monthly}
                        </span>
                      </div>
                      <div className="flex justify-between">
                        <span className="text-sm">Agency (${STRIPE_PLANS.agency.price.monthly})</span>
                        <span className="text-sm font-medium">
                          ${stats.agencyCount * STRIPE_PLANS.agency.price.monthly}
                        </span>
                      </div>
                      <div className="flex justify-between">
                        <span className="text-sm">Enterprise (${STRIPE_PLANS.enterprise.price.monthly})</span>
                        <span className="text-sm font-medium">
                          ${stats.enterpriseCount * STRIPE_PLANS.enterprise.price.monthly}
                        </span>
                      </div>
                    </div>
                  </CardContent>
                </Card>

                <Card>
                  <CardHeader>
                    <CardTitle className="text-sm">Health Metrics</CardTitle>
                  </CardHeader>
                  <CardContent>
                    <div className="space-y-2">
                      <div className="flex justify-between">
                        <span className="text-sm">Active Rate</span>
                        <span className="text-sm font-medium">
                          {stats.total > 0
                            ? Math.round((stats.active / stats.total) * 100)
                            : 0}
                          %
                        </span>
                      </div>
                      <div className="flex justify-between">
                        <span className="text-sm">Churn Rate</span>
                        <span className="text-sm font-medium">
                          {stats.total > 0
                            ? Math.round((stats.canceled / stats.total) * 100)
                            : 0}
                          %
                        </span>
                      </div>
                      <div className="flex justify-between">
                        <span className="text-sm">Issues</span>
                        <span className="text-sm font-medium text-destructive">
                          {stats.pastDue}
                        </span>
                      </div>
                    </div>
                  </CardContent>
                </Card>
              </div>
            </TabsContent>
          </Tabs>
        </CardContent>
      </Card>
    </div>
  );
}

/**
 * AI Component Lazy Loader
 * RankPilot - Progressive AI Component Loading
 */

'use client';

import type { ReactNode } from 'react';
import React, { Suspense, useEffect, useState } from 'react';
import { useAIComponentLoader, useProgressiveLoader } from '../../hooks/use-web-vitals';
import { LoadingSpinner } from '../ui/loading-spinner';

interface AILazyWrapperProps {
    children: React.ReactNode;
    fallback?: React.ReactNode;
    dependencies?: string[];
    minHeight?: string;
    className?: string;
}

/**
 * Wrapper for AI components with lazy loading and progressive enhancement
 */
export function AILazyWrapper({
    children,
    fallback,
    dependencies = [],
    minHeight = '200px',
    className = ''
}: AILazyWrapperProps): JSX.Element {
    const { isVisible, setRef } = useAIComponentLoader();
    const { loadingStage, isReady } = useProgressiveLoader(dependencies);

    return (
        <div
            ref={setRef}
            className={`${className} transition-all duration-300`}
            style={{ minHeight: !isVisible ? minHeight : 'auto' }}
        >
            {isVisible ? (
                <Suspense fallback={fallback || <AILoadingFallback />}>
                    {isReady ? children : <ProgressiveLoader stage={loadingStage} />}
                </Suspense>
            ) : (
                <div className="flex items-center justify-center" style={{ height: minHeight }}>
                    <div className="text-center text-muted-foreground">
                        <div className="animate-pulse">🤖</div>
                        <div className="text-sm mt-2">AI Component Loading...</div>
                    </div>
                </div>
            )}
        </div>
    );
}

/**
 * Progressive loading indicator showing stages
 */
function ProgressiveLoader({ stage = 0 }: { stage?: number }): JSX.Element {
    const stages = [
        { label: 'Initializing', icon: '⚙️' },
        { label: 'Loading Resources', icon: '📦' },
        { label: 'Optimizing', icon: '⚡' },
        { label: 'Ready', icon: '✅' },
    ];

    const index = Math.max(0, Math.min(stage, stages.length - 1));

    return (
        <div className="flex flex-col items-center justify-center py-8">
            <div className="text-4xl mb-4 animate-spin">
                {stages[index]?.icon || '🔄'}
            </div>
            <div className="text-muted-foreground">
                {stages[index]?.label || 'Loading...'}
            </div>
            <div className="w-48 bg-muted rounded-full h-2 mt-4">
                <div
                    className="bg-primary h-2 rounded-full transition-all duration-300"
                    style={{ width: `${((index + 1) / stages.length) * 100}%` }}
                />
            </div>
        </div>
    );
}

/**
 * Default AI loading fallback
 */
function AILoadingFallback(): JSX.Element {
    return (
        <div className="flex items-center justify-center py-12">
            <div className="text-center">
                <LoadingSpinner size="lg" />
                <div className="text-muted-foreground mt-4">Loading AI Component...</div>
            </div>
        </div>
    );
}

/**
 * Memory-optimized AI component wrapper
 */
export function MemoryOptimizedAI({
    children,
    maxMemory = 100 * 1024 * 1024, // 100MB default
    onMemoryWarning,
}: {
    children: ReactNode;
    maxMemory?: number;
    onMemoryWarning?: () => void;
}): JSX.Element {
    const [memoryUsage, setMemoryUsage] = useState(0);

    useEffect(() => {
        const checkMemory = () => {
            if (typeof performance === 'undefined') return;
            const perf = performance as unknown as { memory?: { usedJSHeapSize?: number } };
            const used = perf.memory?.usedJSHeapSize;
            if (typeof used === 'number') {
                setMemoryUsage(used);
                if (used > maxMemory && typeof onMemoryWarning === 'function') {
                    onMemoryWarning();
                }
            }
        };

        const interval = setInterval(checkMemory, 5000);
        return () => clearInterval(interval);
    }, [maxMemory, onMemoryWarning]);

    return (
        <div className="relative">
            {children}
            {process.env.NODE_ENV === 'development' && (
                <div className="absolute top-2 right-2 text-xs bg-black/75 text-white px-2 py-1 rounded">
                    Memory: {(memoryUsage / 1024 / 1024).toFixed(1)}MB
                </div>
            )}
        </div>
    );
}

/**
 * Error boundary for AI components
 */
interface AIErrorBoundaryState {
    hasError: boolean;
    error?: Error;
}

export class AIErrorBoundary extends React.Component<
    { children: ReactNode; fallback?: ReactNode },
    AIErrorBoundaryState
> {
    constructor(props: { children: ReactNode; fallback?: ReactNode }) {
        super(props);
        this.state = { hasError: false };
    }

    static getDerivedStateFromError(error: Error): AIErrorBoundaryState {
        return { hasError: true, error };
    }

    override componentDidCatch(error: Error, errorInfo: React.ErrorInfo) {
        console.error('AI Component Error:', error, errorInfo);

        // Send to monitoring service
        const w = typeof window !== 'undefined' ? (window as any) : undefined;
        if (w && typeof w.gtag === 'function') {
            w.gtag('event', 'exception', {
                description: `AI Component Error: ${error.message}`,
                fatal: false,
            });
        }
    }

    override render() {
        if (this.state.hasError) {
            return this.props.fallback || (
                <div className="flex flex-col items-center justify-center py-12 text-center">
                    <div className="text-destructive text-4xl mb-4">⚠️</div>
                    <div className="text-muted-foreground font-medium">AI Component Error</div>
                    <div className="text-muted-foreground text-sm mt-2">
                        Something went wrong loading this AI feature
                    </div>
                    <button
                        onClick={() => this.setState({ hasError: false })}
                        className="mt-4 px-4 py-2 bg-primary text-primary-foreground rounded hover:bg-primary/90"
                    >
                        Retry
                    </button>
                </div>
            );
        }

        return this.props.children;
    }
}

/**
 * RankPilot Admin ChatBot Component
 * Advanced chatbot interface for admin users with system management capabilities
 */

'use client';

import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
