import GlobalSearch from '@/components/global-search';
import { LanguageSelector } from '@/components/i18n/LanguageSelector';
import { EnhancedButton } from '@/components/ui/enhanced-button';
import { useTheme } from '@/lib/themes/theme-system';
import { useI18n } from '@/lib/i18n/internationalization-system';
import { useAuth } from '@/context/AuthContext';
import { signOut } from 'firebase/auth';
import { auth } from '@/lib/firebase';

export function CommandPaletteButton() {
  const [open, setOpen] = useState(false);
  const { translate } = useI18n();
  const tr = (k: string, fb: string) => { const v = translate(k); return v === k ? fb : v; };
  // Hotkey Ctrl/Cmd + K
  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key.toLowerCase() === 'k') {
        e.preventDefault();
        setOpen(true);
      }
    };
    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, []);
  return (
    <>
      <Tooltip>
        <TooltipTrigger asChild>
          <EnhancedButton variant="ghost" size="icon" aria-label={tr('commandPalette.open','Command palette')} onClick={() => setOpen(true)}>
            <Command className="h-5 w-5" />
          </EnhancedButton>
        </TooltipTrigger>
        <TooltipContent>{tr('commandPalette.shortcut','Ctrl/Cmd + K')}</TooltipContent>
      </Tooltip>
      {open && <CommandPalette onClose={() => setOpen(false)} />}
    </>
  );
}

interface CommandPaletteProps { onClose: () => void; }

function CommandPalette({ onClose }: CommandPaletteProps) {
  const { theme, setTheme, isDark } = useTheme();
  const { user } = useAuth();
  const { translate } = useI18n();
  const tr = (k: string, fb: string) => { const v = translate(k); return v === k ? fb : v; };
  const cycleTheme = () => {
    const order = ['light', 'dark', 'high-contrast', 'auto'] as const;
    const idx = order.indexOf(theme as typeof order[number]);
    const next = order[(idx + 1) % order.length];
    setTheme(next as any);
    try {
      window.dispatchEvent(
        new CustomEvent('rp_theme_cycle', {
          detail: { from: theme, to: next, at: Date.now() },
        }),
      );
    } catch {
      // ignore dispatch errors in older browsers/environments
    }
  };

  useEffect(() => {
    const handleKey = (e: KeyboardEvent) => { if (e.key === 'Escape') onClose(); };
    window.addEventListener('keydown', handleKey); return () => window.removeEventListener('keydown', handleKey);
  }, [onClose]);

  return (
    <Dialog open={true} onOpenChange={(o) => { if (!o) onClose(); }}>
      <DialogContent className="max-w-2xl p-0 overflow-hidden">
        <div className="border-b px-4 py-3 flex items-center justify-between bg-muted/40">
          <h3 className="text-sm font-medium flex items-center gap-2"><Command className="h-4 w-4"/>{tr('commandPalette.title','Command Center')}</h3>
          <span className="text-xs text-muted-foreground">{tr('commandPalette.escHint','Esc to close')}</span>
        </div>
        <div className="p-4 space-y-6">
          <section className="space-y-2">
            <h4 className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">{tr('commandPalette.section.search','Search')}</h4>
            <GlobalSearch />
          </section>
          <section className="space-y-2">
            <h4 className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">{tr('commandPalette.section.interface','Interface')}</h4>
            <div className="flex items-center gap-2 flex-wrap">
              <EnhancedButton size="sm" variant="outline" onClick={cycleTheme} aria-label="Cycle theme">
                {theme === 'high-contrast' ? <Contrast className="h-4 w-4"/> : isDark() ? <Moon className="h-4 w-4"/> : <Sun className="h-4 w-4"/>}
                <span className="ml-2 text-xs hidden sm:inline">{tr('commandPalette.theme.label','Theme')}: {theme}</span>
              </EnhancedButton>
              <LanguageSelector variant="button" />
            </div>
          </section>
          <section className="space-y-2">
            <h4 className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">{tr('commandPalette.section.account','Account')}</h4>
            <div className="flex items-center gap-2 flex-wrap">
              {user ? (
                <EnhancedButton size="sm" variant="secondary" onClick={() => { signOut(auth); onClose(); }}>
                  <LogOut className="h-4 w-4 mr-1"/> {tr('commandPalette.signOut','Sign Out')}
                </EnhancedButton>
              ) : (
                <EnhancedButton size="sm" variant="secondary" asChild>
                  <a href="/login"><User className="h-4 w-4 mr-1"/> {tr('commandPalette.login','Login')}</a>
                </EnhancedButton>
              )}
            </div>
          </section>
        </div>
      </DialogContent>
    </Dialog>
  );
}

// src/components/competitor-analysis-form.tsx
"use client";

import { Button } from "@/components/ui/button";
import {
  Card,
  CardContent,
  CardDescription,
  CardFooter,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import {
  Form,
  FormControl,
  FormDescription,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { zodResolver } from "@hookform/resolvers/zod";
import { Loader2 } from "lucide-react";
import { useForm } from "react-hook-form";
import { z } from "zod";

const formSchema = z.object({
  yourUrl: z.string().min(1, { message: "Please enter your website URL." }),
  competitorUrls: z
    .string()
    .min(1, { message: "Please enter at least one competitor URL." }),
  keywords: z
    .string()
    .min(1, { message: "Please enter at least one keyword." }),
});

type FormValues = z.infer<typeof formSchema>;

interface CompetitorAnalysisFormProps {
  onSubmit: (values: FormValues) => Promise<void>;
  isLoading: boolean;
}

export default function CompetitorAnalysisForm({
  onSubmit,
  isLoading,
}: CompetitorAnalysisFormProps) {
  const form = useForm<FormValues>({
    resolver: zodResolver(formSchema),
    defaultValues: {
      yourUrl: "",
      competitorUrls: "",
      keywords: "",
    },
  });

  async function handleSubmit(values: FormValues) {
    // Pass the raw form values to the handler
    onSubmit(values);
  }

  return (
    <Card className="h-full">
      <CardHeader>
        <CardTitle className="font-headline">Competitor Analysis</CardTitle>
        <CardDescription className="font-body">
          Compare your keyword rankings against your competitors.
        </CardDescription>
      </CardHeader>
      <Form {...form}>
        <form
          onSubmit={form.handleSubmit(handleSubmit)}
          className="space-y-8"
        >
          <CardContent className="space-y-4">
            <FormField
              control={form.control}
              name="yourUrl"
              render={({ field }) => (
                <FormItem>
                  <FormLabel>Your URL</FormLabel>
                  <FormControl>
                    <Input
                      placeholder="yourwebsite.com"
                      {...field}
                      disabled={isLoading}
                    />
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />
            <FormField
              control={form.control}
              name="competitorUrls"
              render={({ field }) => (
                <FormItem>
                  <FormLabel>Competitor URLs</FormLabel>
                  <FormControl>
                    <Textarea
                      placeholder="competitor1.com, competitor2.com"
                      {...field}
                      disabled={isLoading}
                    />
                  </FormControl>
                  <FormDescription>
                    Comma-separated list of competitor URLs.
                  </FormDescription>
                  <FormMessage />
                </FormItem>
              )}
            />
            <FormField
              control={form.control}
              name="keywords"
              render={({ field }) => (
                <FormItem>
                  <FormLabel>Keywords</FormLabel>
                  <FormControl>
                    <Textarea
                      placeholder="seo tools, content marketing, ai writing"
                      {...field}
                      disabled={isLoading}
                    />
                  </FormControl>
                  <FormDescription>
                    Comma-separated list of keywords to analyze.
                  </FormDescription>
                  <FormMessage />
                </FormItem>
              )}
            />
          </CardContent>
          <CardFooter>
            <Button type="submit" disabled={isLoading}>
              {isLoading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Analyze Competitors
            </Button>
          </CardFooter>
        </form>
      </Form>
    </Card>
  );
}

// src/components/content-analyzer-form.tsx
"use client";

import type { AnalyzeContentInput } from "@/ai/flows/content-optimization";
import { colors } from "@/lib/design-system/colors";
import { zodResolver } from "@hookform/resolvers/zod";
import React from "react";
import { useForm } from "react-hook-form";
import { z } from "zod";
import { EnhancedButton } from "@/components/ui/enhanced-button";
import {
  Form,
  FormControl,
  FormDescription,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import {
  EnhancedCard,
  EnhancedCardContent,
  EnhancedCardDescription,
  EnhancedCardFooter,
  EnhancedCardHeader,
  EnhancedCardTitle,
} from "@/components/ui/enhanced-card";
import { FileText, Sparkles } from "lucide-react";
import { useHydration } from "@/components/HydrationContext";
import { useIsMobile } from "@/lib/mobile-responsive-utils";

const formSchema = z.object({
  content: z
    .string()
    .min(50, { message: "Content must be at least 50 characters long." })
    .max(10000, { message: "Content must be less than 10,000 characters." }),
  targetKeywords: z
    .string()
    .min(3, { message: "Target keywords must be at least 3 characters long." })
    .max(200, { message: "Target keywords must be less than 200 characters." }),
});

type ContentAnalyzerFormValues = z.infer<typeof formSchema>;

interface ContentAnalyzerFormProps {
  onSubmit: (values: AnalyzeContentInput) => Promise<void>;
  isLoading: boolean;
}

export default function ContentAnalyzerForm({
  onSubmit,
  isLoading,
}: ContentAnalyzerFormProps) {
  const hydrated = useHydration();
  const isMobile = useIsMobile();

  const form = useForm<ContentAnalyzerFormValues>({
    resolver: zodResolver(formSchema),
    defaultValues: {
      content: "",
      targetKeywords: "",
    },
  });

  async function handleFormSubmit(values: ContentAnalyzerFormValues) {
    try {
      await onSubmit(values as AnalyzeContentInput);
    } catch (error) {
      console.error("Content analysis failed:", error);
      // Error handling could be improved with toast notifications
    }
  }

  const contentLength = form.watch("content")?.length || 0;
  const keywordsLength = form.watch("targetKeywords")?.length || 0;

  return (
    <EnhancedCard
      className="h-full"
      variant="elevated"
    >
      <EnhancedCardHeader>
        <EnhancedCardTitle className="font-headline flex items-center gap-2">
          <FileText className="h-5 w-5 text-primary" />
          Optimize Your Content
        </EnhancedCardTitle>
        <EnhancedCardDescription className="font-body">
          Paste your content and target keywords to get AI-powered optimization
          suggestions, readability analysis, and SEO improvements.
        </EnhancedCardDescription>
      </EnhancedCardHeader>

      <Form {...form}>
        <form
          onSubmit={form.handleSubmit(handleFormSubmit)}
          className="space-y-6"
          aria-busy={isLoading}
          aria-disabled={isLoading}
        >
          <EnhancedCardContent className="space-y-6">
            <FormField
              control={form.control}
              name="content"
              render={({ field }) => (
                <FormItem>
                  <FormControl>
                    <div className="space-y-2">
                      <FormLabel
                        className="font-body text-sm font-medium flex items-center justify-between"
                        htmlFor="content-input"
                      >
                        Content to Analyze
                        <span
                          className={`text-xs ${
                            contentLength > 9000
                              ? colors.status.error.text
                              : contentLength > 7000
                                ? colors.status.warning.text
                                : colors.text.muted
                          }`}
                        >
                          {contentLength}/10,000 characters
                        </span>
                      </FormLabel>
                      <Textarea
                        id="content-input"
                        placeholder="Paste your article, blog post, or page content here..."
                        className="min-h-[200px] font-body resize-y"
                        {...field}
                        disabled={!hydrated || isLoading}
                        aria-describedby="content-description content-error"
                      />
                      <FormDescription
                        id="content-description"
                        className="font-body text-sm text-muted-foreground"
                      >
                        Paste the text content you want to analyze for SEO
                        optimization, readability, and engagement.
                      </FormDescription>
                      <FormMessage id="content-error" />
                    </div>
                  </FormControl>
                </FormItem>
              )}
            />

            <FormField
              control={form.control}
              name="targetKeywords"
              render={({ field }) => (
                <FormItem>
                  <FormControl>
                    <div className="space-y-2">
                      <FormLabel
                        className="font-body text-sm font-medium flex items-center justify-between"
                        htmlFor="keywords-input"
                      >
                        Target Keywords
                        <span
                          className={`text-xs ${
                            keywordsLength > 180
                              ? colors.status.error.text
                              : keywordsLength > 150
                                ? colors.status.warning.text
                                : colors.text.muted
                          }`}
                        >
                          {keywordsLength}/200 characters
                        </span>
                      </FormLabel>
                      <Input
                        id="keywords-input"
                        placeholder="e.g., SEO best practices, content marketing, digital optimization"
                        {...field}
                        className="font-body"
                        disabled={!hydrated || isLoading}
                        autoComplete="off"
                        aria-describedby="keywords-description keywords-error"
                      />
                      <FormDescription
                        id="keywords-description"
                        className="font-body text-sm text-muted-foreground"
                      >
                        Comma-separated list of keywords you want to optimize
                        for. These will guide the analysis and recommendations.
                      </FormDescription>
                      <FormMessage id="keywords-error" />
                    </div>
                  </FormControl>
                </FormItem>
              )}
            />
          </EnhancedCardContent>

          <EnhancedCardFooter>
            <EnhancedButton
              type="submit"
              className="w-full"
              size={isMobile ? "mobile" : "default"}
              loading={isLoading}
              loadingText="Analyzing content..."
              leftIcon={
                !isLoading ? <Sparkles className="h-4 w-4" /> : undefined
              }
              disabled={
                !hydrated ||
                isLoading ||
                !form.watch("content") ||
                !form.watch("targetKeywords")
              }
              variant="gradient"
            >
              {isLoading
                ? "Analyzing Content..."
                : "Analyze & Optimize Content"}
            </EnhancedButton>
          </EnhancedCardFooter>
        </form>
      </Form>
    </EnhancedCard>
  );
}

// src/components/content-brief-form.tsx
"use client";

import { Button } from "@/components/ui/button";
import {
  Card,
  CardContent,
  CardDescription,
  CardFooter,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import {
  Form,
  FormControl,
  FormDescription,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
